--
-- TOC entry 490 (class 1255 OID 142998)
-- Name: add_return_transaction_item(jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.add_return_transaction_item(p_data jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_txn   RECORD;
  v_price DECIMAL(12,2);
  v_qty   INTEGER;
  v_est   DECIMAL(12,2);
  v_store_price DECIMAL(12,2);
  v_store_value DECIMAL(12,2);
  v_new   return_transaction_items;
  v_dup   RECORD;
BEGIN
  SELECT id, status INTO v_txn
    FROM return_transactions
   WHERE id = (p_data->>'transactionId')::uuid;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Return transaction not found');
  END IF;

  IF v_txn.status IN ('finalized', 'closed_out', 'received') THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Cannot add items to a return with status "%s"', v_txn.status));
  END IF;

  v_price := COALESCE((p_data->>'standardPrice')::decimal, 0);
  v_qty   := COALESCE((p_data->>'quantity')::int, 1);

  v_est := CASE
    WHEN COALESCE((p_data->>'isPartial')::boolean, false) = true
     AND (p_data->>'partialPercentage')::decimal IS NOT NULL
    THEN v_price * v_qty * ((p_data->>'partialPercentage')::decimal / 100)
    ELSE v_price * v_qty
  END;

  v_store_price := ROUND(v_price * 0.70, 2);
  v_store_value := ROUND(v_est * 0.70, 2);

  IF p_data->>'ndc' IS NOT NULL AND p_data->>'lotNumber' IS NOT NULL THEN
    SELECT id INTO v_dup
      FROM return_transaction_items
     WHERE transaction_id = (p_data->>'transactionId')::uuid
       AND ndc = p_data->>'ndc'
       AND lot_number = p_data->>'lotNumber'
     LIMIT 1;
  END IF;

  INSERT INTO return_transaction_items (
    transaction_id, ndc, ndc_10, gtin,
    proprietary_name, generic_name, manufacturer, package_description,
    dosage_form, strength, route,
    lot_number, serial_number, expiration_date,
    standard_price, quantity, full_package_size, quantity_returned,
    is_partial, partial_percentage, estimated_value,
    estimated_store_price, estimated_store_value,
    return_status, non_returnable_reason, return_reason, destination,
    dea_schedule, dea_form_222_required, product_type,
    co_status, bmp_status, memo, scan_source, raw_scan_data
  ) VALUES (
    (p_data->>'transactionId')::uuid,
    NULLIF(TRIM(COALESCE(p_data->>'ndc','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'ndc10','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'gtin','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'proprietaryName','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'genericName','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'manufacturer','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'packageDescription','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'dosageForm','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'strength','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'route','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'lotNumber','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'serialNumber','')), ''),
    CASE WHEN p_data->>'expirationDate' IS NOT NULL
         THEN (p_data->>'expirationDate')::date ELSE NULL END,
    v_price,
    v_qty,
    (p_data->>'fullPackageSize')::int,
    (p_data->>'fullPackageQtyReturned')::int,
    COALESCE((p_data->>'isPartial')::boolean, false),
    (p_data->>'partialPercentage')::decimal,
    v_est,
    v_store_price,
    v_store_value,
    COALESCE(p_data->>'returnStatus', 'tbd'),
    NULLIF(TRIM(COALESCE(p_data->>'nonReturnableReason','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'returnReason','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'destination','')), ''),
    NULLIF(TRIM(COALESCE(p_data->>'deaSchedule','')), ''),
    COALESCE((p_data->>'deaForm222Required')::boolean, false),
    NULLIF(TRIM(COALESCE(p_data->>'productType','')), ''),
    COALESCE(p_data->>'coStatus', 'no'),
    COALESCE(p_data->>'bmpStatus', 'no'),
    NULLIF(TRIM(COALESCE(p_data->>'memo','')), ''),
    COALESCE(p_data->>'scanSource', 'manual'),
    NULLIF(TRIM(COALESCE(p_data->>'rawScanData','')), '')
  ) RETURNING * INTO v_new;

  UPDATE return_transactions SET
    total_items = (
      SELECT COUNT(*) FROM return_transaction_items WHERE transaction_id = v_txn.id
    ),
    total_returnable_value = (
      SELECT COALESCE(SUM(estimated_value), 0) FROM return_transaction_items
      WHERE transaction_id = v_txn.id AND return_status = 'returnable'
    ),
    total_non_returnable_value = (
      SELECT COALESCE(SUM(estimated_value), 0) FROM return_transaction_items
      WHERE transaction_id = v_txn.id AND return_status = 'non_returnable'
    )
  WHERE id = v_txn.id;

  RETURN jsonb_build_object(
    'error', false,
    'data', _rti_to_json(v_new),
    'duplicate', v_dup.id IS NOT NULL,
    'duplicateItemId', v_dup.id
  );
END;
$$;


ALTER FUNCTION public.add_return_transaction_item(p_data jsonb) OWNER TO postgres;

--
-- TOC entry 889 (class 1255 OID 156245)
-- Name: add_return_transaction_item_with_validation(uuid, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.add_return_transaction_item_with_validation(p_transaction_id uuid, p_item_data jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_return_status TEXT;
  v_result JSONB;
  v_merged_data JSONB;
BEGIN
  -- Check if return is locked
  SELECT status INTO v_return_status FROM return_transactions WHERE id = p_transaction_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Return transaction not found');
  END IF;
  
  IF is_return_transaction_locked(v_return_status) THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Cannot add items to return with status "%s". Return is locked after finalization.', v_return_status));
  END IF;
  
  -- Inject transactionId into the item data and call original single-arg function
  v_merged_data := p_item_data || jsonb_build_object('transactionId', p_transaction_id::text);
  SELECT add_return_transaction_item(v_merged_data) INTO v_result;
  RETURN v_result;
END;
$$;


ALTER FUNCTION public.add_return_transaction_item_with_validation(p_transaction_id uuid, p_item_data jsonb) OWNER TO postgres;

--
-- TOC entry 5494 (class 0 OID 0)
-- Dependencies: 889
-- Name: FUNCTION add_return_transaction_item_with_validation(p_transaction_id uuid, p_item_data jsonb); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.add_return_transaction_item_with_validation(p_transaction_id uuid, p_item_data jsonb) IS 'Adds an item to a return transaction with lock status validation';


--
-- TOC entry 831 (class 1255 OID 86304)
-- Name: add_to_pharmacy_cart(uuid, uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.add_to_pharmacy_cart(p_pharmacy_id uuid, p_deal_id uuid, p_quantity integer DEFAULT 1) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_cart_id UUID;
  v_deal RECORD;
  v_existing_quantity INTEGER;
  v_new_quantity INTEGER;
  v_cart_item JSONB;
  v_effective_minimum INTEGER;
BEGIN
  -- Validate quantity
  IF p_quantity < 1 THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Quantity must be at least 1'
    );
  END IF;
  
  -- Get deal details and check if active (including minimum_buy_quantity)
  SELECT id, product_name, deal_price, original_price, quantity, status, image_url, ndc, distributor_name, COALESCE(minimum_buy_quantity, 1) as minimum_buy_quantity
  INTO v_deal
  FROM marketplace_deals
  WHERE id = p_deal_id;
  
  IF v_deal.id IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Deal not found'
    );
  END IF;
  
  -- Only active deals can be added to cart
  IF v_deal.status != 'active' THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'This deal is no longer available (status: ' || v_deal.status || ')'
    );
  END IF;
  
  -- Check if requested quantity is available
  IF p_quantity > v_deal.quantity THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Requested quantity exceeds available stock (' || v_deal.quantity || ' available)'
    );
  END IF;
  
  -- Calculate effective minimum: if available quantity is less than minimum_buy_quantity,
  -- then the remaining stock becomes the effective minimum (allow ordering all remaining stock)
  v_effective_minimum := LEAST(v_deal.minimum_buy_quantity, v_deal.quantity);
  
  -- Check minimum buy quantity (but allow if ordering all remaining stock)
  IF p_quantity < v_effective_minimum THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Minimum order quantity is ' || v_effective_minimum || ' units'
    );
  END IF;
  
  -- Get or create cart for pharmacy
  SELECT id INTO v_cart_id
  FROM pharmacy_cart
  WHERE pharmacy_id = p_pharmacy_id;
  
  IF v_cart_id IS NULL THEN
    INSERT INTO pharmacy_cart (pharmacy_id)
    VALUES (p_pharmacy_id)
    RETURNING id INTO v_cart_id;
  END IF;
  
  -- Check if item already in cart
  SELECT quantity INTO v_existing_quantity
  FROM pharmacy_cart_items
  WHERE cart_id = v_cart_id AND deal_id = p_deal_id;
  
  IF v_existing_quantity IS NOT NULL THEN
    -- Update existing item (add to quantity)
    v_new_quantity := v_existing_quantity + p_quantity;
    
    -- Verify new quantity doesn't exceed stock
    IF v_new_quantity > v_deal.quantity THEN
      RETURN jsonb_build_object(
        'error', true,
        'message', 'Total quantity would exceed available stock. You have ' || v_existing_quantity || ' in cart, ' || v_deal.quantity || ' available.'
      );
    END IF;
    
    UPDATE pharmacy_cart_items
    SET quantity = v_new_quantity, updated_at = NOW()
    WHERE cart_id = v_cart_id AND deal_id = p_deal_id;
  ELSE
    -- Insert new item
    v_new_quantity := p_quantity;
    
    INSERT INTO pharmacy_cart_items (cart_id, deal_id, quantity, unit_price, original_price)
    VALUES (v_cart_id, p_deal_id, p_quantity, v_deal.deal_price, v_deal.original_price);
  END IF;
  
  -- Update cart timestamp
  UPDATE pharmacy_cart SET updated_at = NOW() WHERE id = v_cart_id;
  
  -- Build response with item details
  v_cart_item := jsonb_build_object(
    'dealId', p_deal_id,
    'productName', v_deal.product_name,
    'ndc', v_deal.ndc,
    'distributor', v_deal.distributor_name,
    'quantity', v_new_quantity,
    'unitPrice', v_deal.deal_price,
    'originalPrice', v_deal.original_price,
    'totalPrice', v_new_quantity * v_deal.deal_price,
    'savings', (v_deal.original_price - v_deal.deal_price) * v_new_quantity,
    'imageUrl', v_deal.image_url
  );
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Item added to cart',
    'item', v_cart_item
  );
END;
$$;


