--
-- TOC entry 573 (class 1255 OID 78226)
-- Name: cancel_marketplace_order(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.cancel_marketplace_order(p_pharmacy_id uuid, p_order_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_order RECORD;
BEGIN
  -- Get order
  SELECT id, order_number, status
  INTO v_order
  FROM marketplace_orders
  WHERE id = p_order_id AND pharmacy_id = p_pharmacy_id;
  
  IF v_order.id IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Order not found'
    );
  END IF;
  
  IF v_order.status NOT IN ('pending', 'processing') THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Cannot cancel order with status: ' || v_order.status
    );
  END IF;
  
  -- Cancel the order
  UPDATE marketplace_orders
  SET 
    status = 'cancelled',
    cancelled_at = NOW(),
    updated_at = NOW()
  WHERE id = p_order_id;
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Order cancelled successfully',
    'orderNumber', v_order.order_number
  );
END;
$$;


ALTER FUNCTION public.cancel_marketplace_order(p_pharmacy_id uuid, p_order_id uuid) OWNER TO postgres;

--
-- TOC entry 790 (class 1255 OID 142875)
-- Name: change_return_transaction_status(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.change_return_transaction_status(p_id uuid, p_new_status text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_row return_transactions;
BEGIN
  SELECT * INTO v_row FROM return_transactions WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Return transaction not found');
  END IF;

  -- Validate transitions
  CASE p_new_status
    WHEN 'paused' THEN
      IF v_row.status <> 'in_progress' THEN
        RETURN jsonb_build_object('error', true, 'code', 400,
          'message', format('Cannot pause a return with status "%s". Only in_progress returns can be paused.', v_row.status));
      END IF;

    WHEN 'in_progress' THEN  -- resume
      IF v_row.status <> 'paused' THEN
        RETURN jsonb_build_object('error', true, 'code', 400,
          'message', format('Cannot resume a return with status "%s". Only paused returns can be resumed.', v_row.status));
      END IF;

    WHEN 'completed' THEN
      IF v_row.status NOT IN ('in_progress', 'paused') THEN
        RETURN jsonb_build_object('error', true, 'code', 400,
          'message', format('Cannot complete a return with status "%s".', v_row.status));
      END IF;

    WHEN 'finalized' THEN
      IF v_row.status <> 'completed' THEN
        RETURN jsonb_build_object('error', true, 'code', 400,
          'message', format('Cannot finalize a return with status "%s". Must be completed first.', v_row.status));
      END IF;

    ELSE
      RETURN jsonb_build_object('error', true, 'code', 400,
        'message', format('Invalid target status: %s', p_new_status));
  END CASE;

  -- Apply transition
  UPDATE return_transactions SET
    status       = p_new_status,
    time_out     = CASE WHEN p_new_status = 'completed'  THEN NOW()       ELSE time_out     END,
    finalized_at = CASE WHEN p_new_status = 'finalized'  THEN NOW()       ELSE finalized_at  END
  WHERE id = p_id
  RETURNING * INTO v_row;

  RETURN jsonb_build_object('error', false, 'data', _rt_to_json(v_row));
END;
$$;


ALTER FUNCTION public.change_return_transaction_status(p_id uuid, p_new_status text) OWNER TO postgres;

--
-- TOC entry 819 (class 1255 OID 144336)
-- Name: check_and_surface_ready_items(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.check_and_surface_ready_items() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_surfaced_count INT;
  v_surfaced_items jsonb;
BEGIN
  -- Update status for items whose date has come
  WITH surfaced AS (
    UPDATE wine_cellar
       SET status = 'ready_to_return'
     WHERE status = 'shelved'
       AND expected_returnable_date IS NOT NULL
       AND expected_returnable_date <= CURRENT_DATE
    RETURNING *
  )
  SELECT COUNT(*), COALESCE(jsonb_agg(_wc_to_json(s)), '[]'::jsonb)
    INTO v_surfaced_count, v_surfaced_items
    FROM surfaced s;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'surfacedCount', v_surfaced_count,
      'items',         v_surfaced_items
    )
  );
END;
$$;


