--
-- TOC entry 875 (class 1255 OID 169290)
-- Name: clean_hostname(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.clean_hostname(p_input text) RETURNS text
    LANGUAGE plpgsql IMMUTABLE
    AS $_$
DECLARE
  v_result TEXT;
BEGIN
  IF p_input IS NULL THEN
    RETURN NULL;
  END IF;
  
  v_result := LOWER(TRIM(p_input));
  
  -- Remove protocol prefix
  v_result := REGEXP_REPLACE(v_result, '^https?://', '');
  
  -- Remove trailing slashes
  v_result := REGEXP_REPLACE(v_result, '/+$', '');
  
  -- Remove any path after the hostname
  v_result := SPLIT_PART(v_result, '/', 1);
  
  -- Remove port if present
  v_result := SPLIT_PART(v_result, ':', 1);
  
  -- Return NULL if empty
  IF v_result = '' THEN
    RETURN NULL;
  END IF;
  
  RETURN v_result;
END;
$_$;


ALTER FUNCTION public.clean_hostname(p_input text) OWNER TO postgres;

