--
-- TOC entry 635 (class 1255 OID 67419)
-- Name: create_admin_distributor(text, text, text, text, text, text, text, text, text, text[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_admin_distributor(p_company_name text, p_contact_person text DEFAULT NULL::text, p_email text DEFAULT NULL::text, p_phone text DEFAULT NULL::text, p_address text DEFAULT NULL::text, p_city text DEFAULT NULL::text, p_state text DEFAULT NULL::text, p_zip_code text DEFAULT NULL::text, p_license_number text DEFAULT NULL::text, p_specializations text[] DEFAULT ARRAY[]::text[]) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result JSONB;
    v_new_id UUID;
    v_address_json JSONB;
    v_code TEXT;
BEGIN
    -- Validate required field
    IF p_company_name IS NULL OR TRIM(p_company_name) = '' THEN
        RAISE EXCEPTION 'Company name is required';
    END IF;
    
    -- Generate a code from company name (first 4 chars uppercase)
    v_code := UPPER(SUBSTRING(REGEXP_REPLACE(p_company_name, '[^a-zA-Z]', '', 'g'), 1, 4));
    
    -- Build address JSON
    v_address_json := jsonb_build_object(
        'street', COALESCE(p_address, ''),
        'city', COALESCE(p_city, ''),
        'state', COALESCE(p_state, ''),
        'zipCode', COALESCE(p_zip_code, ''),
        'country', 'USA'
    );
    
    -- Insert new distributor
    INSERT INTO reverse_distributors (
        name,
        code,
        contact_person,
        contact_email,
        contact_phone,
        address,
        license_number,
        specializations,
        is_active,
        created_at
    ) VALUES (
        TRIM(p_company_name),
        v_code,
        NULLIF(TRIM(p_contact_person), ''),
        NULLIF(TRIM(p_email), ''),
        NULLIF(TRIM(p_phone), ''),
        v_address_json,
        NULLIF(TRIM(p_license_number), ''),
        p_specializations,
        TRUE,
        NOW()
    )
    RETURNING id INTO v_new_id;
    
    -- Get the created distributor
    v_result := get_admin_distributor_by_id(v_new_id);
    
    RETURN v_result;
END;
$$;


ALTER FUNCTION public.create_admin_distributor(p_company_name text, p_contact_person text, p_email text, p_phone text, p_address text, p_city text, p_state text, p_zip_code text, p_license_number text, p_specializations text[]) OWNER TO postgres;

--
-- TOC entry 536 (class 1255 OID 169428)
-- Name: create_admin_user(text, text, text, text, jsonb, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_admin_user(p_email text, p_password_hash text, p_name text, p_role text DEFAULT 'support'::text, p_permissions jsonb DEFAULT '[]'::jsonb, p_buying_group_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_admin_id UUID;
  v_admin JSONB;
  v_buying_group_id UUID;
BEGIN
  -- Validate role
  IF p_role NOT IN ('super_admin', 'manager', 'reviewer', 'support') THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Invalid role. Must be one of: super_admin, manager, reviewer, support'
    );
  END IF;
  
  -- Check if email already exists
  IF EXISTS (SELECT 1 FROM admin WHERE email = p_email) THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Email already exists'
    );
  END IF;

  -- Resolve the buying_group_id this new admin belongs to.
  -- - super_admin rows self-reference their own id (set after INSERT)
  -- - sub-admins (manager/reviewer/support) MUST belong to a buying group.
  --   The creator's buying_group_id is passed in as p_buying_group_id.
  IF p_role = 'super_admin' THEN
    v_buying_group_id := NULL; -- will be set to admin.id after insert
  ELSE
    IF p_buying_group_id IS NULL THEN
      RETURN jsonb_build_object(
        'error', true,
        'message', 'buying_group_id is required for sub-admin roles (manager/reviewer/support)'
      );
    END IF;

    -- Validate the buying group exists and is a super_admin row
    IF NOT EXISTS (
      SELECT 1 FROM admin WHERE id = p_buying_group_id AND role = 'super_admin'
    ) THEN
      RETURN jsonb_build_object(
        'error', true,
        'message', 'Invalid buying_group_id: must reference an existing super_admin'
      );
    END IF;

    v_buying_group_id := p_buying_group_id;
  END IF;

  -- Insert new admin
  INSERT INTO admin (
    email, password_hash, name, role, permissions,
    is_active, buying_group_id, created_at, updated_at
  )
  VALUES (
    p_email, p_password_hash, p_name, p_role,
    COALESCE(p_permissions, '[]'::jsonb),
    true, v_buying_group_id, NOW(), NOW()
  )
  RETURNING id INTO v_admin_id;

  -- For super_admin rows, buying_group_id self-references their own id
  IF p_role = 'super_admin' THEN
    UPDATE admin SET buying_group_id = v_admin_id WHERE id = v_admin_id;
  END IF;
  
  -- Fetch created admin
  SELECT jsonb_build_object(
    'id', a.id,
    'email', a.email,
    'name', a.name,
    'role', a.role,
    'roleDisplay', CASE a.role
      WHEN 'super_admin' THEN 'Super Admin'
      WHEN 'manager' THEN 'Manager'
      WHEN 'reviewer' THEN 'Reviewer'
      WHEN 'support' THEN 'Support'
      ELSE a.role
    END,
    'isActive', a.is_active,
    'status', 'active',
    'permissions', COALESCE(a.permissions, '[]'::jsonb),
    'buyingGroupId', a.buying_group_id,
    'createdAt', a.created_at
  )
  INTO v_admin
  FROM admin a
  WHERE a.id = v_admin_id;
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Admin user created successfully',
    'admin', v_admin
  );
END;
$$;


ALTER FUNCTION public.create_admin_user(p_email text, p_password_hash text, p_name text, p_role text, p_permissions jsonb, p_buying_group_id uuid) OWNER TO postgres;

--
-- TOC entry 690 (class 1255 OID 144482)
-- Name: create_batch(date, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_batch(p_batch_month date, p_batch_name text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_name TEXT;
  v_row  return_batches;
BEGIN
  -- Normalise to first of month
  p_batch_month := DATE_TRUNC('month', p_batch_month)::date;

  -- Check duplicate
  IF EXISTS (SELECT 1 FROM return_batches WHERE batch_month = p_batch_month) THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('A batch already exists for %s', TO_CHAR(p_batch_month, 'Month YYYY')));
  END IF;

  v_name := COALESCE(NULLIF(TRIM(p_batch_name), ''), TO_CHAR(p_batch_month, 'Month YYYY'));

  INSERT INTO return_batches (batch_month, batch_name)
  VALUES (p_batch_month, v_name)
  RETURNING * INTO v_row;

  RETURN jsonb_build_object('error', false, 'data', _batch_to_json(v_row));
END;
$$;


ALTER FUNCTION public.create_batch(p_batch_month date, p_batch_name text) OWNER TO postgres;

--
-- TOC entry 488 (class 1255 OID 169042)
-- Name: create_buying_group(text, text, text, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_buying_group(p_name text, p_contact_email text DEFAULT NULL::text, p_contact_phone text DEFAULT NULL::text, p_address text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_admin_email text DEFAULT NULL::text, p_admin_password_hash text DEFAULT NULL::text, p_admin_name text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_admin_id UUID;
  v_group JSONB;
  v_email TEXT;
  v_name TEXT;
BEGIN
  -- Use the buying group name (not admin name)
  v_email := COALESCE(p_admin_email, p_contact_email);
  v_name := p_name;

  IF v_email IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Email is required'
    );
  END IF;

  IF p_admin_password_hash IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Password is required'
    );
  END IF;

  -- Check if email already exists
  IF EXISTS (SELECT 1 FROM admin WHERE email = v_email) THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Email already exists'
    );
  END IF;

  -- Create admin record (which represents the buying group)
  INSERT INTO admin (email, password_hash, name, role, is_active, permissions)
  VALUES (
    v_email,
    p_admin_password_hash,
    v_name,
    'super_admin',
    true,
    '["dashboard","pharmacies","distributors","marketplace","documents","payments","payout_hub","analytics","settings","admins","processors","policies","ndc_pricing","tbd_items","destruction","warehouse"]'::jsonb
  )
  RETURNING id INTO v_admin_id;

  -- Also set the business_name in admin_settings to the group name
  INSERT INTO admin_settings (id, business_name) 
  VALUES (1, p_name) 
  ON CONFLICT (id) DO UPDATE 
  SET business_name = EXCLUDED.business_name,
      updated_at = NOW();

  SELECT jsonb_build_object(
    'id', a.id,
    'name', a.name,
    'contactEmail', a.email,
    'contactPhone', NULL,
    'address', NULL,
    'status', 'active',
    'notes', NULL,
    'createdAt', a.created_at,
    'role', a.role
  )
  INTO v_group
  FROM admin a
  WHERE a.id = v_admin_id;

  RETURN jsonb_build_object(
    'error', false,
    'message', 'Buying group created successfully',
    'buyingGroup', v_group,
    'adminId', v_admin_id
  );
END;
$$;


ALTER FUNCTION public.create_buying_group(p_name text, p_contact_email text, p_contact_phone text, p_address text, p_notes text, p_admin_email text, p_admin_password_hash text, p_admin_name text) OWNER TO postgres;

--
-- TOC entry 905 (class 1255 OID 159027)
-- Name: create_destruction_record_for_transaction_item(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_destruction_record_for_transaction_item(p_transaction_item_id uuid, p_created_by uuid DEFAULT NULL::uuid, p_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_item return_transaction_items;
  v_txn  return_transactions;
  v_existing destruction_records;
  v_new destruction_records;
BEGIN
  SELECT * INTO v_item FROM return_transaction_items WHERE id = p_transaction_item_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Transaction item not found');
  END IF;

  SELECT * INTO v_txn FROM return_transactions WHERE id = v_item.transaction_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Parent transaction not found');
  END IF;

  -- Idempotent: keep one active destruction record per transaction item.
  SELECT * INTO v_existing
  FROM destruction_records
  WHERE transaction_item_id = p_transaction_item_id
    AND status <> 'cancelled'
  ORDER BY created_at DESC
  LIMIT 1;

  IF FOUND THEN
    RETURN jsonb_build_object(
      'error', false,
      'data', jsonb_build_object(
        'id', v_existing.id,
        'pharmacyId', v_existing.pharmacy_id,
        'transactionItemId', v_existing.transaction_item_id,
        'ndc', v_existing.ndc,
        'productName', v_existing.product_name,
        'manufacturer', v_existing.manufacturer,
        'lotNumber', v_existing.lot_number,
        'quantity', v_existing.quantity,
        'weightLbs', v_existing.weight_lbs,
        'destructionReason', v_existing.destruction_reason,
        'status', v_existing.status,
        'federalFormNumber', v_existing.federal_form_number,
        'destructionCompany', v_existing.destruction_company,
        'scheduledDate', v_existing.scheduled_date,
        'pickedUpAt', v_existing.picked_up_at,
        'destroyedAt', v_existing.destroyed_at,
        'formUrl', v_existing.form_url,
        'notes', v_existing.notes,
        'createdBy', v_existing.created_by,
        'createdAt', v_existing.created_at,
        'updatedAt', v_existing.updated_at
      ),
      'message', 'Destruction record already exists'
    );
  END IF;

  INSERT INTO destruction_records (
    pharmacy_id,
    transaction_item_id,
    ndc,
    product_name,
    manufacturer,
    lot_number,
    quantity,
    destruction_reason,
    status,
    notes,
    created_by
  ) VALUES (
    v_txn.pharmacy_id,
    v_item.id,
    v_item.ndc,
    COALESCE(v_item.proprietary_name, v_item.generic_name, ''),
    v_item.manufacturer,
    v_item.lot_number,
    COALESCE(v_item.quantity, 1),
    'non_returnable',
    'pending',
    NULLIF(TRIM(COALESCE(p_notes, v_item.memo, '')), ''),
    p_created_by
  )
  RETURNING * INTO v_new;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'id', v_new.id,
      'pharmacyId', v_new.pharmacy_id,
      'transactionItemId', v_new.transaction_item_id,
      'ndc', v_new.ndc,
      'productName', v_new.product_name,
      'manufacturer', v_new.manufacturer,
      'lotNumber', v_new.lot_number,
      'quantity', v_new.quantity,
      'weightLbs', v_new.weight_lbs,
      'destructionReason', v_new.destruction_reason,
      'status', v_new.status,
      'federalFormNumber', v_new.federal_form_number,
      'destructionCompany', v_new.destruction_company,
      'scheduledDate', v_new.scheduled_date,
      'pickedUpAt', v_new.picked_up_at,
      'destroyedAt', v_new.destroyed_at,
      'formUrl', v_new.form_url,
      'notes', v_new.notes,
      'createdBy', v_new.created_by,
      'createdAt', v_new.created_at,
      'updatedAt', v_new.updated_at
    )
  );
END;
$$;


ALTER FUNCTION public.create_destruction_record_for_transaction_item(p_transaction_item_id uuid, p_created_by uuid, p_notes text) OWNER TO postgres;

--
-- TOC entry 805 (class 1255 OID 86313)
-- Name: create_marketplace_deal(text, text, integer, text, numeric, numeric, text, date, text, uuid, text, text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_marketplace_deal(p_product_name text, p_category text, p_quantity integer, p_unit text, p_original_price numeric, p_deal_price numeric, p_distributor_name text, p_expiry_date date, p_ndc text DEFAULT NULL::text, p_distributor_id uuid DEFAULT NULL::uuid, p_notes text DEFAULT NULL::text, p_image_url text DEFAULT NULL::text, p_created_by uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_deal_id UUID;
  v_deal JSONB;
BEGIN
  -- Validate required fields
  IF p_product_name IS NULL OR p_product_name = '' THEN
    RETURN jsonb_build_object('error', true, 'message', 'Product name is required');
  END IF;
  
  IF p_category IS NULL OR p_category = '' THEN
    RETURN jsonb_build_object('error', true, 'message', 'Category is required');
  END IF;
  
  IF p_quantity IS NULL OR p_quantity <= 0 THEN
    RETURN jsonb_build_object('error', true, 'message', 'Quantity must be greater than 0');
  END IF;
  
  IF p_unit NOT IN ('bottles', 'boxes', 'units', 'packs') THEN
    RETURN jsonb_build_object('error', true, 'message', 'Invalid unit. Must be: bottles, boxes, units, packs');
  END IF;
  
  IF p_original_price IS NULL OR p_original_price <= 0 THEN
    RETURN jsonb_build_object('error', true, 'message', 'Original price must be greater than 0');
  END IF;
  
  IF p_deal_price IS NULL OR p_deal_price <= 0 THEN
    RETURN jsonb_build_object('error', true, 'message', 'Deal price must be greater than 0');
  END IF;
  
  IF p_deal_price >= p_original_price THEN
    RETURN jsonb_build_object('error', true, 'message', 'Deal price must be less than original price');
  END IF;
  
  IF p_distributor_name IS NULL OR p_distributor_name = '' THEN
    RETURN jsonb_build_object('error', true, 'message', 'Distributor name is required');
  END IF;
  
  IF p_expiry_date IS NULL THEN
    RETURN jsonb_build_object('error', true, 'message', 'Expiry date is required');
  END IF;
  
  IF p_expiry_date <= CURRENT_DATE THEN
    RETURN jsonb_build_object('error', true, 'message', 'Expiry date must be in the future');
  END IF;
  
  -- Insert new deal
  INSERT INTO marketplace_deals (
    product_name,
    category,
    ndc,
    quantity,
    original_quantity,
    unit,
    original_price,
    deal_price,
    distributor_id,
    distributor_name,
    expiry_date,
    posted_date,
    status,
    notes,
    image_url,
    created_by,
    created_at,
    updated_at
  ) VALUES (
    p_product_name,
    p_category,
    p_ndc,
    p_quantity,
    p_quantity, -- original_quantity = initial quantity
    p_unit,
    p_original_price,
    p_deal_price,
    p_distributor_id,
    p_distributor_name,
    p_expiry_date,
    CURRENT_DATE,
    'active',
    p_notes,
    p_image_url,
    p_created_by,
    NOW(),
    NOW()
  )
  RETURNING id INTO v_deal_id;
  
  -- Fetch created deal
  SELECT jsonb_build_object(
    'id', d.id,
    'dealNumber', d.deal_number,
    'productName', d.product_name,
    'category', d.category,
    'ndc', d.ndc,
    'quantity', d.quantity,
    'originalQuantity', COALESCE(d.original_quantity, d.quantity),
    'soldQuantity', COALESCE(d.original_quantity, d.quantity) - d.quantity,
    'remainingQuantity', d.quantity,
    'minimumBuyQuantity', COALESCE(d.minimum_buy_quantity, 1),
    'unit', d.unit,
    'originalPrice', d.original_price,
    'dealPrice', d.deal_price,
    'savings', ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0),
    'margin', ROUND((d.deal_price / d.original_price * 100), 0),
    'distributorId', d.distributor_id,
    'distributor', d.distributor_name,
    'expiryDate', d.expiry_date,
    'postedDate', d.posted_date,
    'status', d.status,
    'notes', d.notes,
    'imageUrl', d.image_url,
    'createdAt', d.created_at,
    'isDealOfTheDay', COALESCE(d.is_deal_of_the_day, false),
    'dealOfTheDayUntil', d.deal_of_the_day_until,
    'isDealOfTheWeek', COALESCE(d.is_deal_of_the_week, false),
    'dealOfTheWeekUntil', d.deal_of_the_week_until,
    'isDealOfTheMonth', COALESCE(d.is_deal_of_the_month, false),
    'dealOfTheMonthUntil', d.deal_of_the_month_until
  )
  INTO v_deal
  FROM marketplace_deals d
  WHERE d.id = v_deal_id;
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Deal created successfully',
    'deal', v_deal
  );
END;
$$;


ALTER FUNCTION public.create_marketplace_deal(p_product_name text, p_category text, p_quantity integer, p_unit text, p_original_price numeric, p_deal_price numeric, p_distributor_name text, p_expiry_date date, p_ndc text, p_distributor_id uuid, p_notes text, p_image_url text, p_created_by uuid) OWNER TO postgres;

--
-- TOC entry 903 (class 1255 OID 78221)
-- Name: create_marketplace_order_from_cart(uuid, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_marketplace_order_from_cart(p_pharmacy_id uuid, p_stripe_checkout_session_id text DEFAULT NULL::text, p_stripe_customer_id text DEFAULT NULL::text, p_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_cart_id UUID;
  v_order_id UUID;
  v_order_number TEXT;
  v_subtotal NUMERIC(12, 2);
  v_tax_amount NUMERIC(12, 2);
  v_total_amount NUMERIC(12, 2);
  v_total_savings NUMERIC(12, 2);
  v_item_count INTEGER;
  v_cart_item RECORD;
BEGIN
  -- Get cart ID and validate cart has items
  SELECT id INTO v_cart_id
  FROM pharmacy_cart
  WHERE pharmacy_id = p_pharmacy_id;
  
  IF v_cart_id IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Cart not found'
    );
  END IF;
  
  -- Check cart has items
  SELECT COUNT(*)::INTEGER INTO v_item_count
  FROM pharmacy_cart_items
  WHERE cart_id = v_cart_id;
  
  IF v_item_count = 0 THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Cart is empty'
    );
  END IF;
  
  -- Validate all items are still valid (active deals with available stock and meeting minimum quantity)
  -- Note: If available quantity < minimum_buy_quantity, then remaining stock becomes the effective minimum
  FOR v_cart_item IN
    SELECT 
      ci.id,
      ci.deal_id,
      ci.quantity,
      d.product_name,
      d.status,
      d.quantity as available_quantity,
      COALESCE(d.minimum_buy_quantity, 1) as minimum_buy_quantity,
      LEAST(COALESCE(d.minimum_buy_quantity, 1), d.quantity) as effective_minimum
    FROM pharmacy_cart_items ci
    JOIN marketplace_deals d ON d.id = ci.deal_id
    WHERE ci.cart_id = v_cart_id
  LOOP
    IF v_cart_item.status != 'active' THEN
      RETURN jsonb_build_object(
        'error', true,
        'message', 'Deal "' || v_cart_item.product_name || '" is no longer available',
        'dealId', v_cart_item.deal_id
      );
    END IF;
    
    IF v_cart_item.quantity > v_cart_item.available_quantity THEN
      RETURN jsonb_build_object(
        'error', true,
        'message', 'Insufficient stock for "' || v_cart_item.product_name || '". Available: ' || v_cart_item.available_quantity,
        'dealId', v_cart_item.deal_id
      );
    END IF;
    
    -- Check minimum quantity (effective minimum is the lesser of minimum_buy_quantity and available stock)
    IF v_cart_item.quantity < v_cart_item.effective_minimum THEN
      RETURN jsonb_build_object(
        'error', true,
        'message', 'Minimum order quantity for "' || v_cart_item.product_name || '" is ' || v_cart_item.effective_minimum || ' units',
        'dealId', v_cart_item.deal_id
      );
    END IF;
  END LOOP;
  
  -- Calculate totals from cart
  SELECT 
    COALESCE(SUM(ci.quantity * ci.unit_price), 0),
    COALESCE(SUM((ci.original_price - ci.unit_price) * ci.quantity), 0)
  INTO v_subtotal, v_total_savings
  FROM pharmacy_cart_items ci
  WHERE ci.cart_id = v_cart_id;
  
  -- Calculate tax (8%)
  v_tax_amount := ROUND(v_subtotal * 0.08, 2);
  v_total_amount := v_subtotal + v_tax_amount;
  
  -- Create the order
  INSERT INTO marketplace_orders (
    pharmacy_id,
    status,
    subtotal,
    tax_amount,
    tax_rate,
    shipping_amount,
    discount_amount,
    total_amount,
    total_savings,
    stripe_checkout_session_id,
    stripe_customer_id,
    notes
  ) VALUES (
    p_pharmacy_id,
    'pending',
    v_subtotal,
    v_tax_amount,
    0.08,
    0,
    0,
    v_total_amount,
    v_total_savings,
    p_stripe_checkout_session_id,
    p_stripe_customer_id,
    p_notes
  )
  RETURNING id, order_number INTO v_order_id, v_order_number;
  
  -- Copy cart items to order items
  INSERT INTO marketplace_order_items (
    order_id,
    deal_id,
    product_name,
    ndc,
    category,
    distributor,
    quantity,
    unit_price,
    original_price,
    line_total,
    line_savings
  )
  SELECT
    v_order_id,
    ci.deal_id,
    d.product_name,
    d.ndc,
    d.category,
    d.distributor_name,
    ci.quantity,
    ci.unit_price,
    ci.original_price,
    ci.quantity * ci.unit_price,
    (ci.original_price - ci.unit_price) * ci.quantity
  FROM pharmacy_cart_items ci
  JOIN marketplace_deals d ON d.id = ci.deal_id
  WHERE ci.cart_id = v_cart_id;
  
  -- Return order details
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Order created successfully',
    'order', jsonb_build_object(
      'id', v_order_id,
      'orderNumber', v_order_number,
      'status', 'pending',
      'subtotal', v_subtotal,
      'taxAmount', v_tax_amount,
      'totalAmount', v_total_amount,
      'totalSavings', v_total_savings,
      'itemCount', v_item_count
    )
  );
END;
$$;


ALTER FUNCTION public.create_marketplace_order_from_cart(p_pharmacy_id uuid, p_stripe_checkout_session_id text, p_stripe_customer_id text, p_notes text) OWNER TO postgres;

--
-- TOC entry 486 (class 1255 OID 163232)
-- Name: create_pharmacy_role(uuid, text, text, text[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_pharmacy_role(p_parent_pharmacy_id uuid, p_role_name text, p_description text DEFAULT NULL::text, p_permission_keys text[] DEFAULT '{}'::text[]) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_role_id UUID;
  v_perm_id UUID;
  v_key     TEXT;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM pharmacy WHERE id = p_parent_pharmacy_id AND parent_pharmacy_id IS NULL AND can_manage_branches = TRUE) THEN
    RETURN jsonb_build_object('error', true, 'code', 403, 'message', 'Access denied');
  END IF;

  IF p_role_name IS NULL OR TRIM(p_role_name) = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Role name is required');
  END IF;

  IF EXISTS (SELECT 1 FROM pharmacy_roles WHERE parent_pharmacy_id = p_parent_pharmacy_id AND role_name = TRIM(p_role_name)) THEN
    RETURN jsonb_build_object('error', true, 'code', 409, 'message', 'A role with this name already exists');
  END IF;

  INSERT INTO pharmacy_roles (parent_pharmacy_id, role_name, description)
  VALUES (p_parent_pharmacy_id, TRIM(p_role_name), p_description)
  RETURNING id INTO v_role_id;

  IF array_length(p_permission_keys, 1) > 0 THEN
    FOREACH v_key IN ARRAY p_permission_keys LOOP
      SELECT id INTO v_perm_id FROM pharmacy_permissions WHERE permission_key = v_key;
      IF v_perm_id IS NOT NULL THEN
        INSERT INTO pharmacy_role_permissions (role_id, permission_id) VALUES (v_role_id, v_perm_id)
        ON CONFLICT DO NOTHING;
      END IF;
      v_perm_id := NULL;
    END LOOP;
  END IF;

  RETURN jsonb_build_object('error', false, 'data', jsonb_build_object('roleId', v_role_id, 'roleName', TRIM(p_role_name)));
END;
$$;


ALTER FUNCTION public.create_pharmacy_role(p_parent_pharmacy_id uuid, p_role_name text, p_description text, p_permission_keys text[]) OWNER TO postgres;

