--
-- TOC entry 803 (class 1255 OID 142871)
-- Name: create_return_transaction(uuid, uuid, text, text, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_return_transaction(p_pharmacy_id uuid, p_processor_id uuid DEFAULT NULL::uuid, p_service_type text DEFAULT 'in_store'::text, p_notes text DEFAULT NULL::text, p_force_create boolean DEFAULT false) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_pharmacy      RECORD;
  v_existing      RECORD;
  v_store_num     TEXT;
  v_date_str      TEXT;
  v_base_plate    TEXT;
  v_license_plate TEXT;
  v_collision_cnt INT;
  v_new           return_transactions;
BEGIN
  -- 1. Verify pharmacy exists
  SELECT id, pharmacy_name, store_number
    INTO v_pharmacy
    FROM pharmacy
   WHERE id = p_pharmacy_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Pharmacy not found');
  END IF;

  -- 2. Duplicate prevention (unless force_create)
  IF NOT p_force_create THEN
    SELECT id, license_plate, status
      INTO v_existing
      FROM return_transactions
     WHERE pharmacy_id = p_pharmacy_id
       AND status IN ('in_progress', 'paused')
     LIMIT 1;

    IF FOUND THEN
      RETURN jsonb_build_object(
        'error', true,
        'code', 409,
        'message', format(
          'This pharmacy already has an active return (%s, status: %s). Use forceCreate=true to override.',
          v_existing.license_plate, v_existing.status
        ),
        'existingId', v_existing.id,
        'existingLicensePlate', v_existing.license_plate
      );
    END IF;
  END IF;

  -- 3. Validate service type
  IF p_service_type NOT IN ('in_store', 'self_service', 'express') THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'service_type must be one of: in_store, self_service, express');
  END IF;

  -- 4. Generate license plate: MMDDYY-23HA-XXXX
  v_store_num := COALESCE(v_pharmacy.store_number, UPPER(LEFT(p_pharmacy_id::text, 4)));
  v_date_str  := TO_CHAR(NOW(), 'MMDDYY');
  v_base_plate := v_date_str || '-23HA-' || v_store_num;

  SELECT COUNT(*) INTO v_collision_cnt
    FROM return_transactions
   WHERE license_plate LIKE v_base_plate || '%';

  IF v_collision_cnt = 0 THEN
    v_license_plate := v_base_plate;
  ELSE
    v_license_plate := v_base_plate || '-' || CHR(65 + v_collision_cnt); -- -A, -B, …
  END IF;

  -- 5. Insert
  INSERT INTO return_transactions (
    license_plate, pharmacy_id, processor_id, service_type,
    status, notes, time_in
  ) VALUES (
    v_license_plate, p_pharmacy_id, p_processor_id, p_service_type,
    'in_progress', NULLIF(TRIM(COALESCE(p_notes,'')), ''), NOW()
  ) RETURNING * INTO v_new;

  RETURN jsonb_build_object('error', false, 'data', _rt_to_json(v_new));
END;
$$;


ALTER FUNCTION public.create_return_transaction(p_pharmacy_id uuid, p_processor_id uuid, p_service_type text, p_notes text, p_force_create boolean) OWNER TO postgres;

--
-- TOC entry 532 (class 1255 OID 158926)
-- Name: create_shipment_group(uuid[], integer, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_shipment_group(p_memo_ids uuid[], p_box_count integer DEFAULT 1, p_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_destination TEXT;
  v_group_id    UUID;
  v_memo_count  INTEGER;
  v_memo        debit_memos;
  v_group       shipment_groups;
BEGIN
  -- Validate input
  IF p_memo_ids IS NULL OR array_length(p_memo_ids, 1) = 0 THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'At least one memo ID is required');
  END IF;

  -- Check all memos exist and have RA numbers
  FOR i IN 1..array_length(p_memo_ids, 1) LOOP
    SELECT * INTO v_memo FROM debit_memos WHERE id = p_memo_ids[i];
    IF NOT FOUND THEN
      RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Memo not found: ' || p_memo_ids[i]);
    END IF;
    
    IF v_memo.ra_number IS NULL OR TRIM(v_memo.ra_number) = '' THEN
      RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Memo ' || v_memo.memo_number || ' does not have an RA number');
    END IF;
    
    IF v_memo.ra_status != 'received' THEN
      RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Memo ' || v_memo.memo_number || ' RA status is not "received"');
    END IF;
    
    IF v_memo.shipped_at IS NOT NULL THEN
      RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Memo ' || v_memo.memo_number || ' is already shipped');
    END IF;
    
    IF v_memo.shipment_group_id IS NOT NULL THEN
      RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Memo ' || v_memo.memo_number || ' is already in a shipment group');
    END IF;

    -- Check destination consistency (case-insensitive, trimmed)
    IF v_destination IS NULL THEN
      v_destination := v_memo.destination;
    ELSIF LOWER(TRIM(COALESCE(v_destination, ''))) IS DISTINCT FROM LOWER(TRIM(COALESCE(v_memo.destination, ''))) THEN
      RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'All memos must have the same destination');
    END IF;
  END LOOP;

  -- Create shipment group
  v_memo_count := array_length(p_memo_ids, 1);
  
  INSERT INTO shipment_groups (destination, box_count, total_memos, notes)
  VALUES (v_destination, p_box_count, v_memo_count, p_notes)
  RETURNING id INTO v_group_id;

  -- Assign memos to group
  UPDATE debit_memos 
  SET shipment_group_id = v_group_id
  WHERE id = ANY(p_memo_ids);

  -- Return the created group with memo details
  SELECT * INTO v_group FROM shipment_groups WHERE id = v_group_id;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'group', _shipment_group_to_json(v_group),
      'memoIds', to_jsonb(p_memo_ids),
      'memoCount', v_memo_count
    )
  );
