--
-- TOC entry 489 (class 1255 OID 169045)
-- Name: create_sub_main_admin(text, text, text, jsonb, text, timestamp with time zone, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_sub_main_admin(p_email text, p_name text, p_role text DEFAULT 'sub_admin'::text, p_permissions jsonb DEFAULT '[]'::jsonb, p_invite_token text DEFAULT NULL::text, p_invite_expires_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_created_by uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_admin_id UUID;
  v_admin JSONB;
BEGIN
  IF EXISTS (SELECT 1 FROM sub_main_admin WHERE email = p_email) THEN
    RETURN jsonb_build_object('error', true, 'message', 'Email already exists');
  END IF;

  INSERT INTO sub_main_admin (email, name, role, permissions, invite_token, invite_expires_at, created_by)
  VALUES (p_email, p_name, p_role, p_permissions, p_invite_token, p_invite_expires_at, p_created_by)
  RETURNING id INTO v_admin_id;

  SELECT jsonb_build_object(
    'id', s.id,
    'email', s.email,
    'name', s.name,
    'role', s.role,
    'permissions', CASE 
      WHEN jsonb_typeof(s.permissions) = 'array' THEN s.permissions
      ELSE '[]'::jsonb
    END,
    'is_active', s.is_active,
    'invite_token', s.invite_token,
    'invite_expires_at', s.invite_expires_at,
    'created_at', s.created_at
  )
  INTO v_admin
  FROM sub_main_admin s
  WHERE s.id = v_admin_id;

  RETURN jsonb_build_object('error', false, 'message', 'Sub admin created successfully', 'admin', v_admin);
END;
$$;


ALTER FUNCTION public.create_sub_main_admin(p_email text, p_name text, p_role text, p_permissions jsonb, p_invite_token text, p_invite_expires_at timestamp with time zone, p_created_by uuid) OWNER TO postgres;

--
-- TOC entry 519 (class 1255 OID 169389)
-- Name: create_warehouse(text, text, text, text, text, text, text, text, boolean, boolean, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.create_warehouse(p_name text, p_contact_name text DEFAULT NULL::text, p_phone text DEFAULT NULL::text, p_street text DEFAULT NULL::text, p_city text DEFAULT NULL::text, p_state text DEFAULT NULL::text, p_zip text DEFAULT NULL::text, p_country text DEFAULT 'US'::text, p_is_active boolean DEFAULT true, p_is_default boolean DEFAULT false, p_created_by uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_warehouse_id UUID;
  v_warehouse JSONB;
BEGIN
  -- Validate required fields
  IF p_name IS NULL OR TRIM(p_name) = '' THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Warehouse name is required'
    );
  END IF;
  
  -- If setting as default, remove default from other warehouses
  IF p_is_default = true THEN
    UPDATE warehouses SET is_default = false, updated_at = NOW();
  END IF;
  
  -- Insert new warehouse
  INSERT INTO warehouses (
    name, contact_name, phone, street, city, state, zip, country,
    is_active, is_default, created_by, created_at, updated_at
  )
  VALUES (
    TRIM(p_name), p_contact_name, p_phone, p_street, p_city, p_state, p_zip, p_country,
    p_is_active, p_is_default, p_created_by, NOW(), NOW()
  )
  RETURNING id INTO v_warehouse_id;
  
  -- Fetch the created warehouse
  SELECT jsonb_build_object(
    'id', w.id,
    'name', w.name,
    'contactName', w.contact_name,
    'phone', w.phone,
    'street', w.street,
    'city', w.city,
    'state', w.state,
    'zip', w.zip,
    'country', w.country,
    'isActive', w.is_active,
    'isDefault', w.is_default,
    'createdAt', w.created_at,
    'updatedAt', w.updated_at
  )
  INTO v_warehouse
  FROM warehouses w
  WHERE w.id = v_warehouse_id;
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Warehouse created successfully',
    'warehouse', v_warehouse
  );
END;
$$;


ALTER FUNCTION public.create_warehouse(p_name text, p_contact_name text, p_phone text, p_street text, p_city text, p_state text, p_zip text, p_country text, p_is_active boolean, p_is_default boolean, p_created_by uuid) OWNER TO postgres;

--
-- TOC entry 597 (class 1255 OID 67422)
-- Name: delete_admin_distributor(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.delete_admin_distributor(p_distributor_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result JSONB;
    v_distributor_name TEXT;
    v_deals_count INTEGER;
BEGIN
    -- Check if distributor exists
    IF NOT EXISTS (SELECT 1 FROM reverse_distributors WHERE id = p_distributor_id) THEN
        RAISE EXCEPTION 'Distributor not found';
    END IF;
    
    -- Get distributor name for response
    SELECT name INTO v_distributor_name
    FROM reverse_distributors
    WHERE id = p_distributor_id;
    
    -- Check for existing deals (packages)
    SELECT COUNT(*)::INTEGER INTO v_deals_count
    FROM custom_packages
    WHERE distributor_id = p_distributor_id;
    
    -- Prevent deletion if there are existing deals
    IF v_deals_count > 0 THEN
        RAISE EXCEPTION 'Cannot delete distributor with % existing deal(s). Deactivate instead.', v_deals_count;
    END IF;
    
    -- Delete the distributor
    DELETE FROM reverse_distributors
    WHERE id = p_distributor_id;
    
    -- Build result
    v_result := jsonb_build_object(
        'success', TRUE,
        'message', 'Distributor "' || v_distributor_name || '" deleted successfully',
        'deletedId', p_distributor_id,
        'deletedAt', NOW()
    );
    
    RETURN v_result;
END;
$$;


ALTER FUNCTION public.delete_admin_distributor(p_distributor_id uuid) OWNER TO postgres;

--
-- TOC entry 641 (class 1255 OID 59949)
-- Name: delete_admin_document(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.delete_admin_document(p_document_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result JSONB;
    v_exists BOOLEAN;
    v_document_info JSONB;
BEGIN
    -- Check if document exists and get its info
    SELECT EXISTS(SELECT 1 FROM uploaded_documents WHERE id = p_document_id)
    INTO v_exists;
    
    IF NOT v_exists THEN
        RETURN jsonb_build_object(
            'error', true,
            'message', 'Document not found',
            'code', 404
        );
    END IF;
    
    -- Get document info before deletion
    SELECT jsonb_build_object(
        'id', ud.id,
        'fileName', ud.file_name,
        'pharmacyName', p.pharmacy_name
    )
    INTO v_document_info
    FROM uploaded_documents ud
    LEFT JOIN pharmacy p ON ud.pharmacy_id = p.id
    WHERE ud.id = p_document_id;
    
    -- Delete the document
    DELETE FROM uploaded_documents WHERE id = p_document_id;
    
    -- Return success response
    v_result := jsonb_build_object(
        'success', true,
        'message', 'Document deleted successfully',
        'deletedDocument', v_document_info,
        'deletedAt', NOW()
    );
    
    RETURN v_result;
END;
$$;


ALTER FUNCTION public.delete_admin_document(p_document_id uuid) OWNER TO postgres;

--
-- TOC entry 510 (class 1255 OID 60875)
-- Name: delete_admin_user(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.delete_admin_user(p_admin_id uuid, p_requesting_admin_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_admin_role TEXT;
  v_super_admin_count INTEGER;
BEGIN
  -- Check if admin exists
  SELECT role INTO v_admin_role FROM admin WHERE id = p_admin_id;
  
  IF v_admin_role IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Admin user not found'
    );
  END IF;
  
  -- Prevent self-deletion
  IF p_admin_id = p_requesting_admin_id THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Cannot delete your own account'
    );
  END IF;
  
  -- Prevent deleting last super_admin
  IF v_admin_role = 'super_admin' THEN
    SELECT COUNT(*)::INTEGER INTO v_super_admin_count FROM admin WHERE role = 'super_admin';
    IF v_super_admin_count <= 1 THEN
      RETURN jsonb_build_object(
        'error', true,
        'message', 'Cannot delete the last Super Admin'
      );
    END IF;
  END IF;
  
  -- Delete admin
  DELETE FROM admin WHERE id = p_admin_id;
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Admin user deleted successfully'
  );
END;
$$;


ALTER FUNCTION public.delete_admin_user(p_admin_id uuid, p_requesting_admin_id uuid) OWNER TO postgres;

--
-- TOC entry 864 (class 1255 OID 156278)
-- Name: delete_batch(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.delete_batch(p_batch_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_batch return_batches;
  v_return_count INTEGER;
  v_memo_count INTEGER;
BEGIN
  SELECT * INTO v_batch FROM return_batches WHERE id = p_batch_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Batch not found');
  END IF;

  -- Only allow deletion of open batches
  IF v_batch.status != 'open' THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Cannot delete batch with status "%s". Only open batches can be deleted.', v_batch.status));
  END IF;

  -- Check if batch has any debit memos (shouldn't happen for open batches, but safety check)
  SELECT COUNT(*) INTO v_memo_count FROM debit_memos WHERE batch_id = p_batch_id;
  IF v_memo_count > 0 THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Cannot delete batch with %s existing debit memo(s). Close-out process has begun.', v_memo_count));
  END IF;

  -- Count assigned returns
  SELECT COUNT(*) INTO v_return_count FROM return_transactions WHERE batch_id = p_batch_id;

  -- Unassign all returns from this batch first
  UPDATE return_transactions 
  SET batch_id = NULL 
  WHERE batch_id = p_batch_id;

  -- Delete the batch
  DELETE FROM return_batches WHERE id = p_batch_id;

  RETURN jsonb_build_object(
    'error', false,
    'message', format('Batch "%s" deleted successfully. %s return(s) unassigned.', v_batch.batch_name, v_return_count),
    'deleted_batch', _batch_to_json(v_batch),
    'unassigned_returns', v_return_count
  );
END;
$$;


ALTER FUNCTION public.delete_batch(p_batch_id uuid) OWNER TO postgres;

