--
-- TOC entry 813 (class 1255 OID 142876)
-- Name: delete_return_transaction(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.delete_return_transaction(p_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_row return_transactions;
BEGIN
  SELECT * INTO v_row FROM return_transactions WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Return transaction not found');
  END IF;

  IF v_row.status IN ('finalized', 'closed_out', 'received') THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Cannot delete a return with status "%s".', v_row.status));
  END IF;

  DELETE FROM return_transactions WHERE id = p_id;

  RETURN jsonb_build_object('error', false, 'message', 'Return transaction deleted');
END;
$$;


ALTER FUNCTION public.delete_return_transaction(p_id uuid) OWNER TO postgres;

--
-- TOC entry 916 (class 1255 OID 143002)
-- Name: delete_return_transaction_item(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.delete_return_transaction_item(p_item_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_item return_transaction_items;
  v_txn  RECORD;
BEGIN
  SELECT * INTO v_item FROM return_transaction_items WHERE id = p_item_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Item not found');
  END IF;

  SELECT status INTO v_txn FROM return_transactions WHERE id = v_item.transaction_id;
  IF v_txn.status IN ('finalized', 'closed_out', 'received') THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'Cannot delete items from a finalized return');
  END IF;

  DELETE FROM return_transaction_items WHERE id = p_item_id;

  -- Update transaction totals
  UPDATE return_transactions SET
    total_items = (SELECT COUNT(*) FROM return_transaction_items 
                   WHERE transaction_id = v_item.transaction_id 
                   AND return_status IN ('returnable', 'tbd')),
    total_returnable_value = (
      SELECT COALESCE(SUM(estimated_value), 0) FROM return_transaction_items
       WHERE transaction_id = v_item.transaction_id AND return_status = 'returnable'
    ),
    total_non_returnable_value = (
      SELECT COALESCE(SUM(estimated_value), 0) FROM return_transaction_items
       WHERE transaction_id = v_item.transaction_id AND return_status = 'non_returnable'
    )
  WHERE id = v_item.transaction_id;

  RETURN jsonb_build_object('error', false, 'message', 'Item deleted');
END;
$$;


ALTER FUNCTION public.delete_return_transaction_item(p_item_id uuid) OWNER TO postgres;

--
-- TOC entry 598 (class 1255 OID 156246)
-- Name: delete_return_transaction_item_with_validation(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.delete_return_transaction_item_with_validation(p_item_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_transaction_id UUID;
  v_return_status    TEXT;
BEGIN
  SELECT rti.transaction_id, rt.status
  INTO v_transaction_id, v_return_status
  FROM return_transaction_items rti
  JOIN return_transactions rt ON rt.id = rti.transaction_id
  WHERE rti.id = p_item_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Item not found');
  END IF;

  IF is_return_transaction_locked(v_return_status) THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Cannot delete items from return with status "%s". Return is locked after finalization.', v_return_status));
  END IF;

  DELETE FROM return_transaction_items WHERE id = p_item_id;

  UPDATE return_transactions SET
    total_items = (
      SELECT COUNT(*)::INTEGER FROM return_transaction_items WHERE transaction_id = v_transaction_id
    ),
    total_returnable_value = (
      SELECT COALESCE(SUM(estimated_value), 0)
        FROM return_transaction_items
       WHERE transaction_id = v_transaction_id AND return_status = 'returnable'
    ),
    total_non_returnable_value = (
      SELECT COALESCE(SUM(estimated_value), 0)
        FROM return_transaction_items
       WHERE transaction_id = v_transaction_id AND return_status = 'non_returnable'
    )
  WHERE id = v_transaction_id;

  RETURN jsonb_build_object('error', false, 'message', 'Item deleted successfully');
END;
$$;


