--
-- TOC entry 628 (class 1255 OID 169391)
-- Name: delete_warehouse(uuid, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.delete_warehouse(p_warehouse_id uuid, p_hard_delete boolean DEFAULT false) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_exists BOOLEAN;
  v_is_default BOOLEAN;
  v_warehouse_count INTEGER;
BEGIN
  -- Check if warehouse exists
  SELECT 
    EXISTS(SELECT 1 FROM warehouses WHERE id = p_warehouse_id),
    is_default
  INTO v_exists, v_is_default
  FROM warehouses WHERE id = p_warehouse_id;
  
  IF NOT v_exists THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Warehouse not found'
    );
  END IF;
  
  -- Count total active warehouses
  SELECT COUNT(*) INTO v_warehouse_count FROM warehouses WHERE is_active = true;
  
  -- Prevent deletion if it's the last active warehouse
  IF v_warehouse_count <= 1 THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Cannot delete the last active warehouse'
    );
  END IF;
  
  -- If deleting default warehouse, assign default to another active warehouse
  IF v_is_default = true THEN
    UPDATE warehouses 
    SET is_default = true, updated_at = NOW()
    WHERE id = (
      SELECT id 
      FROM warehouses 
      WHERE id != p_warehouse_id AND is_active = true 
      ORDER BY created_at ASC 
      LIMIT 1
    );
  END IF;
  
  IF p_hard_delete = true THEN
    -- Hard delete
    DELETE FROM warehouses WHERE id = p_warehouse_id;
  ELSE
    -- Soft delete
    UPDATE warehouses 
    SET is_active = false, is_default = false, updated_at = NOW()
    WHERE id = p_warehouse_id;
  END IF;
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Warehouse deleted successfully'
  );
END;
$$;


ALTER FUNCTION public.delete_warehouse(p_warehouse_id uuid, p_hard_delete boolean) OWNER TO postgres;

--
-- TOC entry 672 (class 1255 OID 144353)
-- Name: finalize_return_transaction(uuid, text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.finalize_return_transaction(p_id uuid, p_fedex_tracking text DEFAULT NULL::text, p_box_count integer DEFAULT NULL::integer) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_row   return_transactions;
  v_tbd   INTEGER;
  v_total INTEGER;
BEGIN
  -- Fetch the return
  SELECT * INTO v_row FROM return_transactions WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404,
      'message', 'Return transaction not found');
  END IF;

  -- Must be completed first
  IF v_row.status <> 'completed' THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Cannot finalize a return with status "%s". Must be completed first.', v_row.status));
  END IF;

  -- Check total items
  SELECT COUNT(*) INTO v_total FROM return_transaction_items WHERE transaction_id = p_id;
  IF v_total = 0 THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'Cannot finalize a return with no items.');
  END IF;

  -- Check for TBD items (items without a destination assigned)
  SELECT COUNT(*) INTO v_tbd
    FROM return_transaction_items
   WHERE transaction_id = p_id
     AND return_status = 'tbd';

  IF v_tbd > 0 THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Cannot finalize: %s item(s) still have TBD status. All items must be classified before finalizing.', v_tbd));
  END IF;

  -- FedEx tracking: use provided value or existing value
  IF p_fedex_tracking IS NOT NULL AND TRIM(p_fedex_tracking) <> '' THEN
    v_row.fedex_tracking := TRIM(p_fedex_tracking);
  END IF;

  IF v_row.fedex_tracking IS NULL OR TRIM(v_row.fedex_tracking) = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'Cannot finalize: FedEx tracking number is required. Please enter it before finalizing.');
  END IF;

  -- All validations passed — finalize
  UPDATE return_transactions SET
    status           = 'finalized',
    finalized_at     = NOW(),
    fedex_tracking   = v_row.fedex_tracking,
    box_count        = COALESCE(p_box_count, box_count)
  WHERE id = p_id
  RETURNING * INTO v_row;

  RETURN jsonb_build_object('error', false, 'data', _rt_to_json(v_row));
END;
$$;


ALTER FUNCTION public.finalize_return_transaction(p_id uuid, p_fedex_tracking text, p_box_count integer) OWNER TO postgres;

