--
-- TOC entry 499 (class 1255 OID 156269)
-- Name: fix_batch_destinations(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fix_batch_destinations(p_batch_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_item RECORD;
  v_destination TEXT;
  v_updated_count INTEGER := 0;
BEGIN
  -- Find all returnable items without destinations in the specific batch
  FOR v_item IN 
    SELECT rti.id, rti.ndc
    FROM return_transaction_items rti
    JOIN return_transactions rt ON rt.id = rti.transaction_id
    WHERE rt.batch_id = p_batch_id
    AND rti.return_status = 'returnable' 
    AND (rti.destination IS NULL OR TRIM(rti.destination) = '')
  LOOP
    -- Get auto destination
    v_destination := get_destination_for_ndc(v_item.ndc);
    
    -- Update directly (bypass normal update function to avoid lock checks)
    IF v_destination IS NOT NULL THEN
      UPDATE return_transaction_items 
      SET destination = v_destination 
      WHERE id = v_item.id;
      
      v_updated_count := v_updated_count + 1;
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'error', false, 
    'message', format('Fixed %s items in batch with auto-assigned destinations', v_updated_count),
    'updated_count', v_updated_count
  );
END;
$$;


ALTER FUNCTION public.fix_batch_destinations(p_batch_id uuid) OWNER TO postgres;

--
-- TOC entry 869 (class 1255 OID 156268)
-- Name: fix_missing_destinations(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fix_missing_destinations() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_item RECORD;
  v_destination TEXT;
  v_updated_count INTEGER := 0;
  v_skipped_count INTEGER := 0;
BEGIN
  -- Find all returnable items without destinations on unlocked returns
  FOR v_item IN 
    SELECT rti.id, rti.ndc, rt.status as return_status
    FROM return_transaction_items rti
    JOIN return_transactions rt ON rt.id = rti.transaction_id
    WHERE rti.return_status = 'returnable' 
    AND (rti.destination IS NULL OR TRIM(rti.destination) = '')
  LOOP
    -- Check if the return is locked
    IF is_return_transaction_locked(v_item.return_status) THEN
      v_skipped_count := v_skipped_count + 1;
      CONTINUE;
    END IF;
    
    -- Get auto destination
    v_destination := get_destination_for_ndc(v_item.ndc);
    
    -- Update if we found a destination
    IF v_destination IS NOT NULL THEN
      UPDATE return_transaction_items 
      SET destination = v_destination 
      WHERE id = v_item.id;
      
      v_updated_count := v_updated_count + 1;
    END IF;
  END LOOP;

  RETURN jsonb_build_object(
    'error', false, 
    'message', format('Updated %s items with auto-assigned destinations. Skipped %s items on locked returns.', v_updated_count, v_skipped_count),
    'updated_count', v_updated_count,
    'skipped_count', v_skipped_count
  );
END;
$$;


ALTER FUNCTION public.fix_missing_destinations() OWNER TO postgres;

