--
-- TOC entry 498 (class 1255 OID 169434)
-- Name: get_admin_analytics(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_admin_analytics(p_buying_group_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_result JSONB;
  
  -- Key Metrics - All time totals
  v_total_returns_value NUMERIC;
  v_total_returns INTEGER;
  v_avg_return_value NUMERIC;
  v_active_pharmacies INTEGER;  -- All pharmacies in scope
  
  -- Key Metrics - Current month
  v_current_month_value NUMERIC;
  v_current_month_returns INTEGER;
  v_current_month_pharmacies INTEGER;
  
  -- Key Metrics - Last Month (for % change calculation)
  v_last_month_returns_value NUMERIC;
  v_last_month_returns INTEGER;
  v_last_month_pharmacies INTEGER;
  
  -- Percentage Changes
  v_returns_value_change NUMERIC;
  v_total_returns_change NUMERIC;
  v_avg_value_change NUMERIC;
  v_pharmacies_change NUMERIC;
  
  -- Charts
  v_returns_value_trend JSONB;
  v_top_products JSONB;
  v_distributor_breakdown JSONB;
  v_state_breakdown JSONB;
  
  -- Date boundaries
  v_current_month_start DATE;
  v_last_month_start DATE;
  v_last_month_end DATE;
  v_twelve_months_ago DATE;
BEGIN
  -- Calculate date boundaries
  v_current_month_start := DATE_TRUNC('month', CURRENT_DATE)::DATE;
  v_last_month_start := (DATE_TRUNC('month', CURRENT_DATE) - INTERVAL '1 month')::DATE;
  v_last_month_end := (DATE_TRUNC('month', CURRENT_DATE) - INTERVAL '1 day')::DATE;
  v_twelve_months_ago := (DATE_TRUNC('month', CURRENT_DATE) - INTERVAL '11 months')::DATE;

  -- ============================================================
  -- 1. KEY METRICS - ALL TIME TOTALS (scoped to buying group)
  -- Each record in return_reports is ONE item, data field contains item directly
  -- ============================================================
  
  -- Total Returns Value (sum of creditAmount from each record's data)
  SELECT COALESCE(SUM(
    COALESCE((rr.data->>'creditAmount')::NUMERIC, 0)
  ), 0)
  INTO v_total_returns_value
  FROM return_reports rr
  INNER JOIN pharmacy p ON p.id = rr.pharmacy_id
  WHERE (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id);

  -- Total Returns Count (each record = 1 item)
  SELECT COUNT(*)::INTEGER
  INTO v_total_returns
  FROM return_reports rr
  INNER JOIN pharmacy p ON p.id = rr.pharmacy_id
  WHERE (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id);

  -- Average Return Value
  v_avg_return_value := CASE WHEN v_total_returns > 0 THEN ROUND(v_total_returns_value / v_total_returns, 2) ELSE 0 END;

  -- Active Pharmacies (all pharmacies in scope)
  SELECT COUNT(*)::INTEGER
  INTO v_active_pharmacies
  FROM pharmacy p
  WHERE (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id);

  -- ============================================================
  -- 2. CURRENT MONTH METRICS
  -- ============================================================
  
  -- Current month returns value
  SELECT COALESCE(SUM(
    COALESCE((rr.data->>'creditAmount')::NUMERIC, 0)
  ), 0)
  INTO v_current_month_value
  FROM return_reports rr
  INNER JOIN pharmacy p ON p.id = rr.pharmacy_id
  WHERE rr.created_at >= v_current_month_start
    AND (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id);

  -- Current month returns count
  SELECT COUNT(*)::INTEGER
  INTO v_current_month_returns
  FROM return_reports rr
  INNER JOIN pharmacy p ON p.id = rr.pharmacy_id
  WHERE rr.created_at >= v_current_month_start
    AND (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id);

  -- Current month pharmacies (pharmacies created in current month)
  SELECT COUNT(*)::INTEGER
  INTO v_current_month_pharmacies
  FROM pharmacy p
  WHERE p.created_at >= v_current_month_start
    AND (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id);

  -- ============================================================
  -- 3. LAST MONTH METRICS (for % change calculation)
  -- ============================================================
  
  -- Last month returns value
  SELECT COALESCE(SUM(
    COALESCE((rr.data->>'creditAmount')::NUMERIC, 0)
  ), 0)
  INTO v_last_month_returns_value
  FROM return_reports rr
  INNER JOIN pharmacy p ON p.id = rr.pharmacy_id
  WHERE rr.created_at >= v_last_month_start 
    AND rr.created_at < v_current_month_start
    AND (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id);

  -- Last month returns count
  SELECT COUNT(*)::INTEGER
  INTO v_last_month_returns
  FROM return_reports rr
  INNER JOIN pharmacy p ON p.id = rr.pharmacy_id
  WHERE rr.created_at >= v_last_month_start 
    AND rr.created_at < v_current_month_start
    AND (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id);

  -- Last month pharmacies (pharmacies created in last month)
  SELECT COUNT(*)::INTEGER
  INTO v_last_month_pharmacies
  FROM pharmacy p
  WHERE p.created_at >= v_last_month_start 
    AND p.created_at < v_current_month_start
    AND (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id);

  -- ============================================================
  -- 4. CALCULATE PERCENTAGE CHANGES (current month vs last month)
  -- ============================================================
  
  v_returns_value_change := CASE 
    WHEN v_last_month_returns_value > 0 
    THEN ROUND(((v_current_month_value - v_last_month_returns_value) / v_last_month_returns_value) * 100, 1)
    ELSE 0
  END;

  v_total_returns_change := CASE 
    WHEN v_last_month_returns > 0 
    THEN ROUND(((v_current_month_returns - v_last_month_returns)::NUMERIC / v_last_month_returns) * 100, 1)
    ELSE 0
  END;

  v_avg_value_change := CASE 
    WHEN v_last_month_returns > 0 AND v_last_month_returns_value > 0
    THEN ROUND((((v_current_month_value / NULLIF(v_current_month_returns, 0)) - (v_last_month_returns_value / v_last_month_returns)) / (v_last_month_returns_value / v_last_month_returns)) * 100, 1)
    ELSE 0
  END;

  v_pharmacies_change := CASE 
    WHEN v_last_month_pharmacies > 0 
    THEN ROUND(((v_current_month_pharmacies - v_last_month_pharmacies)::NUMERIC / v_last_month_pharmacies) * 100, 1)
    ELSE 0
  END;

  -- ============================================================
  -- 5. RETURNS VALUE TREND (Past 12 months, scoped to buying group)
  -- Uses report_date from uploaded_documents table (fallback to rr.created_at)
  -- ============================================================
  
  WITH months AS (
    SELECT generate_series(
      v_twelve_months_ago,
      DATE_TRUNC('month', CURRENT_DATE)::DATE,
      '1 month'::interval
    )::DATE AS month_start
  ),
  monthly_data AS (
    SELECT 
      DATE_TRUNC('month', COALESCE(ud.report_date, rr.created_at::DATE))::DATE AS month_start,
      COALESCE(SUM(COALESCE((rr.data->>'creditAmount')::NUMERIC, 0)), 0) AS total_value,
      COUNT(*)::INTEGER AS items_count
    FROM return_reports rr
    INNER JOIN uploaded_documents ud ON ud.id = rr.document_id
    INNER JOIN pharmacy p ON p.id = rr.pharmacy_id
    WHERE COALESCE(ud.report_date, rr.created_at::DATE) >= v_twelve_months_ago
      AND (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id)
    GROUP BY DATE_TRUNC('month', COALESCE(ud.report_date, rr.created_at::DATE))::DATE
  )
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'month', TO_CHAR(m.month_start, 'Mon YYYY'),
      'monthKey', TO_CHAR(m.month_start, 'YYYY-MM'),
      'totalValue', ROUND(COALESCE(md.total_value, 0), 2),
      'itemsCount', COALESCE(md.items_count, 0)
    ) ORDER BY m.month_start
  ), '[]'::jsonb)
  INTO v_returns_value_trend
  FROM months m
  LEFT JOIN monthly_data md ON m.month_start = md.month_start;

  -- ============================================================
  -- 6. TOP 5 PRODUCTS BY RETURNS VALUE (scoped to buying group)
  -- ============================================================
  
  WITH product_returns AS (
    SELECT 
      COALESCE(rr.data->>'itemName', rr.data->>'productDescription', 'Unknown Product') AS product_name,
      SUM(COALESCE((rr.data->>'creditAmount')::NUMERIC, 0)) AS total_value,
      SUM(COALESCE((rr.data->>'quantity')::INTEGER, 1)) AS total_quantity,
      COUNT(*) AS return_count
    FROM return_reports rr
    INNER JOIN pharmacy p ON p.id = rr.pharmacy_id
    WHERE ((rr.data->>'itemName' IS NOT NULL AND rr.data->>'itemName' != '')
        OR (rr.data->>'productDescription' IS NOT NULL AND rr.data->>'productDescription' != ''))
      AND (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id)
    GROUP BY COALESCE(rr.data->>'itemName', rr.data->>'productDescription', 'Unknown Product')
    ORDER BY total_value DESC
    LIMIT 5
  )
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'productName', pr.product_name,
      'totalValue', ROUND(pr.total_value, 2),
      'totalQuantity', pr.total_quantity,
      'returnCount', pr.return_count
    ) ORDER BY pr.total_value DESC
  ), '[]'::jsonb)
  INTO v_top_products
  FROM product_returns pr;

  -- ============================================================
  -- 7. DISTRIBUTOR BREAKDOWN (scoped to buying group)
  -- Only distributors referenced by this tenant's uploaded_documents
  -- ============================================================
  
  WITH distributor_stats AS (
    SELECT 
      rd.id AS distributor_id,
      rd.name AS distributor_name,
      COUNT(DISTINCT rr.pharmacy_id)::INTEGER AS pharmacies_count,
      COUNT(rr.id)::INTEGER AS total_returns,
      COALESCE(SUM(COALESCE((rr.data->>'creditAmount')::NUMERIC, 0)), 0) AS total_value
    FROM reverse_distributors rd
    INNER JOIN uploaded_documents ud ON ud.reverse_distributor_id = rd.id
    INNER JOIN return_reports rr ON rr.document_id = ud.id
    INNER JOIN pharmacy p ON p.id = rr.pharmacy_id
    WHERE rd.is_active = true
      AND (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id)
    GROUP BY rd.id, rd.name
    HAVING COUNT(rr.id) > 0
    ORDER BY total_value DESC
  )
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'distributorId', ds.distributor_id,
      'distributorName', ds.distributor_name,
      'pharmaciesCount', ds.pharmacies_count,
      'totalReturns', ds.total_returns,
      'avgReturnValue', CASE WHEN ds.total_returns > 0 THEN ROUND(ds.total_value / ds.total_returns, 2) ELSE 0 END,
      'totalValue', ROUND(ds.total_value, 2)
    ) ORDER BY ds.total_value DESC
  ), '[]'::jsonb)
  INTO v_distributor_breakdown
  FROM distributor_stats ds;

  -- ============================================================
  -- 8. STATE BREAKDOWN (scoped to buying group)
  -- Groups pharmacies by state from physical_address JSONB field
  -- ============================================================
  
  WITH state_stats AS (
    SELECT 
      CASE 
        WHEN p.physical_address IS NULL THEN 'Unknown'
        WHEN p.physical_address->>'state' IS NULL THEN 'Unknown'
        WHEN TRIM(p.physical_address->>'state') = '' THEN 'Unknown'
        ELSE TRIM(p.physical_address->>'state')
      END AS state,
      COUNT(DISTINCT p.id)::INTEGER AS pharmacies_count,
      COUNT(rr.id)::INTEGER AS total_returns,
      COALESCE(SUM(COALESCE((rr.data->>'creditAmount')::NUMERIC, 0)), 0) AS total_value
    FROM pharmacy p
    LEFT JOIN return_reports rr ON rr.pharmacy_id = p.id
    WHERE (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id)
    GROUP BY 
      CASE 
        WHEN p.physical_address IS NULL THEN 'Unknown'
        WHEN p.physical_address->>'state' IS NULL THEN 'Unknown'
        WHEN TRIM(p.physical_address->>'state') = '' THEN 'Unknown'
        ELSE TRIM(p.physical_address->>'state')
      END
    ORDER BY total_value DESC, pharmacies_count DESC
  )
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'state', ss.state,
      'pharmacies', ss.pharmacies_count,
      'totalReturns', ss.total_returns,
      'avgReturnValue', CASE WHEN ss.total_returns > 0 THEN ROUND(ss.total_value / ss.total_returns, 2) ELSE 0 END,
      'totalValue', ROUND(ss.total_value, 2)
    ) ORDER BY ss.total_value DESC
  ), '[]'::jsonb)
  INTO v_state_breakdown
  FROM state_stats ss;

  -- ============================================================
  -- BUILD FINAL RESULT
  -- ============================================================
  
  v_result := jsonb_build_object(
    'keyMetrics', jsonb_build_object(
      'totalReturnsValue', jsonb_build_object(
        'value', ROUND(v_total_returns_value, 2),
        'change', v_returns_value_change,
        'changeLabel', 'vs last month'
      ),
      'totalReturns', jsonb_build_object(
        'value', v_total_returns,
        'change', v_total_returns_change,
        'changeLabel', 'vs last month'
      ),
      'avgReturnValue', jsonb_build_object(
        'value', v_avg_return_value,
        'change', v_avg_value_change,
        'changeLabel', 'vs last month'
      ),
      'activePharmacies', jsonb_build_object(
        'value', v_active_pharmacies,
        'change', v_pharmacies_change,
        'changeLabel', 'vs last month'
      )
    ),
    'charts', jsonb_build_object(
      'returnsValueTrend', v_returns_value_trend,
      'topProducts', v_top_products
    ),
    'distributorBreakdown', v_distributor_breakdown,
    'stateBreakdown', v_state_breakdown,
    'scope', jsonb_build_object(
      'buyingGroupId', p_buying_group_id,
      'isGlobal', p_buying_group_id IS NULL
    ),
    'generatedAt', NOW()
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION public.get_admin_analytics(p_buying_group_id uuid) OWNER TO postgres;

--
-- TOC entry 5570 (class 0 OID 0)
-- Dependencies: 498
-- Name: FUNCTION get_admin_analytics(p_buying_group_id uuid); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.get_admin_analytics(p_buying_group_id uuid) IS 'Get all analytics data for admin dashboard: key metrics, trends, top products, distributor and state breakdowns. p_buying_group_id NULL => global (MainAdmin); non-null => scoped to pharmacies where pharmacy.created_by matches.';


--
-- TOC entry 837 (class 1255 OID 169422)
-- Name: get_admin_dashboard_stats(uuid, text, integer, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_admin_dashboard_stats(p_pharmacy_id uuid DEFAULT NULL::uuid, p_period_type text DEFAULT 'monthly'::text, p_periods integer DEFAULT 12, p_buying_group_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result                        JSONB;
    v_total_pharmacies              INTEGER;
    v_pharmacies_this_month         INTEGER;
    v_pharmacies_last_month         INTEGER;
    v_pharmacies_change             NUMERIC;
    v_active_distributors           INTEGER;
    v_distributors_this_month       INTEGER;
    v_distributors_last_month       INTEGER;
    v_distributors_change           NUMERIC;
    v_returns_value                 NUMERIC;
    v_returns_value_this_month      NUMERIC;
    v_returns_value_last_month      NUMERIC;
    v_returns_change                NUMERIC;
    v_pharmacies_list               JSONB;
    v_returns_trend                 JSONB;
    v_start_date                    TIMESTAMP WITH TIME ZONE;
    v_end_date                      TIMESTAMP WITH TIME ZONE;
    v_current_month_start           TIMESTAMP WITH TIME ZONE;
    v_next_month_start              TIMESTAMP WITH TIME ZONE;
    v_last_month_start              TIMESTAMP WITH TIME ZONE;
BEGIN
    v_current_month_start := DATE_TRUNC('month', NOW());
    v_next_month_start    := DATE_TRUNC('month', NOW()) + INTERVAL '1 month';
    v_last_month_start    := DATE_TRUNC('month', NOW()) - INTERVAL '1 month';
    v_end_date            := NOW();

    IF p_period_type = 'yearly' THEN
        v_start_date := DATE_TRUNC('year',  NOW()) - (p_periods || ' years')::INTERVAL;
    ELSE
        v_start_date := DATE_TRUNC('month', NOW()) - (p_periods || ' months')::INTERVAL;
    END IF;

    -- ============================================================
    -- STAT 1: Total Pharmacies (scoped to buying group)
    -- ============================================================

    SELECT COUNT(*)::INTEGER
    INTO v_total_pharmacies
    FROM pharmacy
    WHERE (p_buying_group_id IS NULL OR created_by = p_buying_group_id);

    SELECT COUNT(*)::INTEGER
    INTO v_pharmacies_this_month
    FROM pharmacy
    WHERE created_at >= v_current_month_start
      AND created_at <  v_next_month_start
      AND (p_buying_group_id IS NULL OR created_by = p_buying_group_id);

    SELECT COUNT(*)::INTEGER
    INTO v_pharmacies_last_month
    FROM pharmacy
    WHERE created_at >= v_last_month_start
      AND created_at <  v_current_month_start
      AND (p_buying_group_id IS NULL OR created_by = p_buying_group_id);

    IF v_pharmacies_last_month > 0 THEN
        v_pharmacies_change := ROUND(((v_pharmacies_this_month - v_pharmacies_last_month)::NUMERIC / v_pharmacies_last_month * 100)::NUMERIC, 1);
    ELSE
        v_pharmacies_change := CASE WHEN v_pharmacies_this_month > 0 THEN 100.0 ELSE 0.0 END;
    END IF;

    -- ============================================================
    -- STAT 2: Active Distributors used by this buying group's pharmacies
    -- When p_buying_group_id is NULL (MainAdmin) → all active distributors
    -- When scoped → distinct active distributors referenced in their documents
    -- ============================================================

    IF p_buying_group_id IS NULL THEN
        SELECT COUNT(*)::INTEGER
        INTO v_active_distributors
        FROM reverse_distributors
        WHERE is_active = true;

        SELECT COUNT(*)::INTEGER
        INTO v_distributors_this_month
        FROM reverse_distributors
        WHERE is_active = true
          AND created_at >= v_current_month_start
          AND created_at <  v_next_month_start;

        SELECT COUNT(*)::INTEGER
        INTO v_distributors_last_month
        FROM reverse_distributors
        WHERE is_active = true
          AND created_at >= v_last_month_start
          AND created_at <  v_current_month_start;
    ELSE
        -- Count distinct active distributors actually used by this tenant's pharmacies
        SELECT COUNT(DISTINCT ud.reverse_distributor_id)::INTEGER
        INTO v_active_distributors
        FROM uploaded_documents ud
        JOIN pharmacy p ON p.id = ud.pharmacy_id
        JOIN reverse_distributors rd ON rd.id = ud.reverse_distributor_id
        WHERE rd.is_active = true
          AND p.created_by = p_buying_group_id;

        SELECT COUNT(DISTINCT ud.reverse_distributor_id)::INTEGER
        INTO v_distributors_this_month
        FROM uploaded_documents ud
        JOIN pharmacy p ON p.id = ud.pharmacy_id
        JOIN reverse_distributors rd ON rd.id = ud.reverse_distributor_id
        WHERE rd.is_active = true
          AND p.created_by = p_buying_group_id
          AND ud.uploaded_at >= v_current_month_start
          AND ud.uploaded_at <  v_next_month_start;

        SELECT COUNT(DISTINCT ud.reverse_distributor_id)::INTEGER
        INTO v_distributors_last_month
        FROM uploaded_documents ud
        JOIN pharmacy p ON p.id = ud.pharmacy_id
        JOIN reverse_distributors rd ON rd.id = ud.reverse_distributor_id
        WHERE rd.is_active = true
          AND p.created_by = p_buying_group_id
          AND ud.uploaded_at >= v_last_month_start
          AND ud.uploaded_at <  v_current_month_start;
    END IF;

    IF v_distributors_last_month > 0 THEN
        v_distributors_change := ROUND(((v_distributors_this_month - v_distributors_last_month)::NUMERIC / v_distributors_last_month * 100)::NUMERIC, 1);
    ELSE
        v_distributors_change := CASE WHEN v_distributors_this_month > 0 THEN 100.0 ELSE 0.0 END;
    END IF;

    -- ============================================================
    -- STAT 3: Returns Value (scoped to buying group via pharmacy.created_by)
    -- ============================================================

    SELECT COALESCE(SUM(ud.total_credit_amount), 0)::NUMERIC
    INTO v_returns_value
    FROM uploaded_documents ud
    JOIN pharmacy p ON p.id = ud.pharmacy_id
    WHERE ud.total_credit_amount IS NOT NULL
      AND (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id);

    SELECT COALESCE(SUM(ud.total_credit_amount), 0)::NUMERIC
    INTO v_returns_value_this_month
    FROM uploaded_documents ud
    JOIN pharmacy p ON p.id = ud.pharmacy_id
    WHERE ud.report_date >= v_current_month_start
      AND ud.report_date <  v_next_month_start
      AND ud.total_credit_amount IS NOT NULL
      AND (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id);

    SELECT COALESCE(SUM(ud.total_credit_amount), 0)::NUMERIC
    INTO v_returns_value_last_month
    FROM uploaded_documents ud
    JOIN pharmacy p ON p.id = ud.pharmacy_id
    WHERE ud.report_date >= v_last_month_start
      AND ud.report_date <  v_current_month_start
      AND ud.total_credit_amount IS NOT NULL
      AND (p_buying_group_id IS NULL OR p.created_by = p_buying_group_id);

    IF v_returns_value_last_month > 0 THEN
        v_returns_change := ROUND(((v_returns_value_this_month - v_returns_value_last_month)::NUMERIC / v_returns_value_last_month * 100)::NUMERIC, 1);
    ELSE
        v_returns_change := CASE WHEN v_returns_value_this_month > 0 THEN 100.0 ELSE 0.0 END;
    END IF;

    -- ============================================================
    -- STAT 4: Pharmacies List (scoped to buying group)
    -- ============================================================

    SELECT COALESCE(jsonb_agg(
        jsonb_build_object('id', ph.id, 'name', ph.pharmacy_name)
        ORDER BY ph.pharmacy_name
    ), '[]'::JSONB)
    INTO v_pharmacies_list
    FROM pharmacy ph
    WHERE (p_buying_group_id IS NULL OR ph.created_by = p_buying_group_id);

    -- ============================================================
    -- STAT 5: Returns Value Trend (scoped to buying group + optional pharmacy)
    -- ============================================================

    IF p_period_type = 'yearly' THEN
        WITH years AS (
            SELECT generate_series(
                EXTRACT(YEAR FROM v_start_date)::INTEGER,
                EXTRACT(YEAR FROM v_end_date)::INTEGER
            ) AS year
        ),
        earnings AS (
            SELECT
                EXTRACT(YEAR FROM ud.report_date)::INTEGER        AS year,
                ROUND(SUM(ud.total_credit_amount)::NUMERIC, 2)    AS value,
                COUNT(*)::INTEGER                                  AS documents_count
            FROM uploaded_documents ud
            JOIN pharmacy p ON p.id = ud.pharmacy_id
            WHERE ud.report_date >= v_start_date
              AND ud.report_date <= v_end_date
              AND ud.total_credit_amount IS NOT NULL
              AND (p_pharmacy_id     IS NULL OR ud.pharmacy_id  = p_pharmacy_id)
              AND (p_buying_group_id IS NULL OR p.created_by    = p_buying_group_id)
            GROUP BY EXTRACT(YEAR FROM ud.report_date)
        )
        SELECT COALESCE(jsonb_agg(
            jsonb_build_object(
                'period',         y.year::TEXT,
                'label',          y.year::TEXT,
                'value',          COALESCE(e.value, 0),
                'documentsCount', COALESCE(e.documents_count, 0)
            ) ORDER BY y.year
        ), '[]'::JSONB)
        INTO v_returns_trend
        FROM years y
        LEFT JOIN earnings e ON y.year = e.year;
    ELSE
        WITH months AS (
            SELECT
                TO_CHAR(d::DATE, 'YYYY-MM')       AS period,
                TRIM(TO_CHAR(d::DATE, 'Mon'))      AS label,
                d::DATE                            AS month_date
            FROM generate_series(
                DATE_TRUNC('month', v_start_date),
                DATE_TRUNC('month', v_end_date),
                '1 month'::INTERVAL
            ) d
        ),
        earnings AS (
            SELECT
                TO_CHAR(ud.report_date, 'YYYY-MM')         AS period,
                ROUND(SUM(ud.total_credit_amount)::NUMERIC, 2) AS value,
                COUNT(*)::INTEGER                              AS documents_count
            FROM uploaded_documents ud
            JOIN pharmacy p ON p.id = ud.pharmacy_id
            WHERE ud.report_date >= v_start_date
              AND ud.report_date <= v_end_date
              AND ud.total_credit_amount IS NOT NULL
              AND (p_pharmacy_id     IS NULL OR ud.pharmacy_id  = p_pharmacy_id)
              AND (p_buying_group_id IS NULL OR p.created_by    = p_buying_group_id)
            GROUP BY TO_CHAR(ud.report_date, 'YYYY-MM')
        )
        SELECT COALESCE(jsonb_agg(
            jsonb_build_object(
                'period',         m.period,
                'label',          m.label,
                'value',          COALESCE(e.value, 0),
                'documentsCount', COALESCE(e.documents_count, 0)
            ) ORDER BY m.period
        ), '[]'::JSONB)
        INTO v_returns_trend
        FROM months m
        LEFT JOIN earnings e ON m.period = e.period;
    END IF;

    -- ============================================================
    -- Build final result
    -- ============================================================

    v_result := jsonb_build_object(
        'stats', jsonb_build_object(
            'totalPharmacies', jsonb_build_object(
                'value',       v_total_pharmacies,
                'change',      v_pharmacies_change,
                'changeLabel', 'vs last month'
            ),
            'activeDistributors', jsonb_build_object(
                'value',       v_active_distributors,
                'change',      v_distributors_change,
                'changeLabel', 'vs last month'
            ),
            'returnsValue', jsonb_build_object(
                'value',       ROUND(v_returns_value, 2),
                'change',      v_returns_change,
                'changeLabel', 'vs last month'
            )
        ),
        'pharmacies',       v_pharmacies_list,
        'returnsValueTrend', v_returns_trend,
        'period', jsonb_build_object(
            'type',       p_period_type,
            'periods',    p_periods,
            'startDate',  v_start_date::TEXT,
            'endDate',    v_end_date::TEXT,
            'pharmacyId', p_pharmacy_id
        ),
        'generatedAt', NOW()
    );

    RETURN v_result;
END;
$$;


ALTER FUNCTION public.get_admin_dashboard_stats(p_pharmacy_id uuid, p_period_type text, p_periods integer, p_buying_group_id uuid) OWNER TO postgres;

--
-- TOC entry 673 (class 1255 OID 67418)
-- Name: get_admin_distributor_by_id(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_admin_distributor_by_id(p_distributor_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result JSONB;
    v_distributor JSONB;
    v_total_deals INTEGER;
    v_unique_products_count INTEGER;
BEGIN
    -- Check if distributor exists
    IF NOT EXISTS (SELECT 1 FROM reverse_distributors WHERE id = p_distributor_id) THEN
        RAISE EXCEPTION 'Distributor not found';
    END IF;
    
    -- Get total deals for this distributor
    SELECT COUNT(*)::INTEGER INTO v_total_deals
    FROM custom_packages
    WHERE distributor_id = p_distributor_id;
    
    -- Get unique products count (unique NDCs, latest report_date per NDC)
    SELECT COUNT(DISTINCT latest_ndc.ndc)::INTEGER INTO v_unique_products_count
    FROM (
        SELECT 
            rr.data->>'ndcCode' AS ndc,
            MAX(ud.report_date) AS latest_report_date
        FROM uploaded_documents ud
        INNER JOIN return_reports rr ON rr.document_id = ud.id
        WHERE ud.reverse_distributor_id = p_distributor_id
          AND rr.data->>'ndcCode' IS NOT NULL
          AND rr.data->>'ndcCode' != ''
        GROUP BY rr.data->>'ndcCode'
    ) AS latest_ndc;
    
    -- Get distributor details
    SELECT jsonb_build_object(
        'id', rd.id,
        'companyName', rd.name,
        'contactPerson', COALESCE(rd.contact_person, ''),
        'email', COALESCE(rd.contact_email, ''),
        'phone', COALESCE(rd.contact_phone, ''),
        'address', COALESCE(rd.address->>'street', ''),
        'city', COALESCE(rd.address->>'city', ''),
        'state', COALESCE(rd.address->>'state', ''),
        'zipCode', COALESCE(rd.address->>'zipCode', ''),
        'status', CASE WHEN rd.is_active THEN 'active' ELSE 'inactive' END,
        'licenseNumber', COALESCE(rd.license_number, ''),
        'specializations', COALESCE(rd.specializations, ARRAY[]::TEXT[]),
        'totalDeals', v_total_deals,
        'uniqueProductsCount', COALESCE(v_unique_products_count, 0),
        'code', COALESCE(rd.code, ''),
        'portalUrl', COALESCE(rd.portal_url, ''),
        'supportedFormats', COALESCE(rd.supported_formats, ARRAY[]::TEXT[]),
        'feeRates', COALESCE(rd.fee_rates, '{}'::JSONB),
        'createdAt', rd.created_at
    )
    INTO v_distributor
    FROM reverse_distributors rd
    WHERE rd.id = p_distributor_id;
    
    -- Build result
    v_result := jsonb_build_object(
        'distributor', v_distributor,
        'generatedAt', NOW()
    );
    
    RETURN v_result;
END;
$$;


ALTER FUNCTION public.get_admin_distributor_by_id(p_distributor_id uuid) OWNER TO postgres;

--
-- TOC entry 523 (class 1255 OID 67414)
-- Name: get_admin_distributors_list(text, text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_admin_distributors_list(p_search text DEFAULT NULL::text, p_status text DEFAULT 'all'::text, p_page integer DEFAULT 1, p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result JSONB;
    v_distributors JSONB;
    v_total_count INTEGER;
    v_offset INTEGER;
    v_normalized_search TEXT;
    -- Stats variables (global, not affected by search/filter)
    v_stats_total_distributors INTEGER;
    v_stats_active_distributors INTEGER;
    v_stats_total_deals INTEGER;
BEGIN
    -- Normalize search parameter
    IF p_search IS NOT NULL THEN
        v_normalized_search := TRIM(p_search);
        IF v_normalized_search = '' THEN
            v_normalized_search := NULL;
        END IF;
    ELSE
        v_normalized_search := NULL;
    END IF;
    
    -- Calculate offset
    v_offset := (p_page - 1) * p_limit;
    
    -- Get GLOBAL stats (not affected by search/filter)
    SELECT COUNT(*)::INTEGER INTO v_stats_total_distributors
    FROM reverse_distributors;
    
    SELECT COUNT(*)::INTEGER INTO v_stats_active_distributors
    FROM reverse_distributors
    WHERE is_active = TRUE;
    
    SELECT COUNT(*)::INTEGER INTO v_stats_total_deals
    FROM custom_packages
    WHERE distributor_id IS NOT NULL;
    
    -- Get total count with filters (for pagination)
    SELECT COUNT(*)::INTEGER
    INTO v_total_count
    FROM reverse_distributors rd
    WHERE 
        -- Status filter
        (p_status = 'all' OR 
         (p_status = 'active' AND rd.is_active = TRUE) OR
         (p_status = 'inactive' AND rd.is_active = FALSE))
        -- Search filter (company name, contact person, email, id)
        AND (
            v_normalized_search IS NULL 
            OR LOWER(rd.name) LIKE LOWER('%' || v_normalized_search || '%')
            OR LOWER(COALESCE(rd.contact_person, '')) LIKE LOWER('%' || v_normalized_search || '%')
            OR LOWER(COALESCE(rd.contact_email, '')) LIKE LOWER('%' || v_normalized_search || '%')
            OR CAST(rd.id AS TEXT) LIKE LOWER('%' || v_normalized_search || '%')
            OR LOWER(COALESCE(rd.code, '')) LIKE LOWER('%' || v_normalized_search || '%')
        );
    
    -- Get distributors with all required fields
    WITH distributor_data AS (
        SELECT 
            rd.id,
            rd.name AS "companyName",
            COALESCE(rd.contact_person, '') AS "contactPerson",
            COALESCE(rd.contact_email, '') AS email,
            COALESCE(rd.contact_phone, '') AS phone,
            COALESCE(rd.address->>'street', '') AS address,
            COALESCE(rd.address->>'city', '') AS city,
            COALESCE(rd.address->>'state', '') AS state,
            COALESCE(rd.address->>'zipCode', '') AS "zipCode",
            CASE WHEN rd.is_active THEN 'active' ELSE 'inactive' END AS status,
            COALESCE(rd.license_number, '') AS "licenseNumber",
            COALESCE(rd.specializations, ARRAY[]::TEXT[]) AS specializations,
            -- Count total deals (packages) for this distributor
            (SELECT COUNT(*)::INTEGER FROM custom_packages cp WHERE cp.distributor_id = rd.id) AS "totalDeals",
            -- Count unique products (NDCs) from return_reports, only latest report_date per NDC
            (
                SELECT COUNT(DISTINCT latest_ndc.ndc)::INTEGER
                FROM (
                    -- Get the latest report_date for each NDC for this distributor
                    SELECT 
                        rr.data->>'ndcCode' AS ndc,
                        MAX(ud.report_date) AS latest_report_date
                    FROM uploaded_documents ud
                    INNER JOIN return_reports rr ON rr.document_id = ud.id
                    WHERE ud.reverse_distributor_id = rd.id
                      AND rr.data->>'ndcCode' IS NOT NULL
                      AND rr.data->>'ndcCode' != ''
                    GROUP BY rr.data->>'ndcCode'
                ) AS latest_ndc
            ) AS "uniqueProductsCount",
            rd.created_at AS "createdAt"
        FROM reverse_distributors rd
        WHERE 
            -- Status filter
            (p_status = 'all' OR 
             (p_status = 'active' AND rd.is_active = TRUE) OR
             (p_status = 'inactive' AND rd.is_active = FALSE))
            -- Search filter
            AND (
                v_normalized_search IS NULL 
                OR LOWER(rd.name) LIKE LOWER('%' || v_normalized_search || '%')
                OR LOWER(COALESCE(rd.contact_person, '')) LIKE LOWER('%' || v_normalized_search || '%')
                OR LOWER(COALESCE(rd.contact_email, '')) LIKE LOWER('%' || v_normalized_search || '%')
                OR CAST(rd.id AS TEXT) LIKE LOWER('%' || v_normalized_search || '%')
                OR LOWER(COALESCE(rd.code, '')) LIKE LOWER('%' || v_normalized_search || '%')
            )
        ORDER BY rd.created_at DESC
        LIMIT p_limit
        OFFSET v_offset
    )
    SELECT COALESCE(jsonb_agg(row_to_json(distributor_data)), '[]'::JSONB)
    INTO v_distributors
    FROM distributor_data;
    
    -- Build result with stats included
    v_result := jsonb_build_object(
        'distributors', v_distributors,
        'pagination', jsonb_build_object(
            'page', p_page,
            'limit', p_limit,
            'total', v_total_count,
            'totalPages', CEIL(v_total_count::NUMERIC / p_limit::NUMERIC)::INTEGER
        ),
        'filters', jsonb_build_object(
            'search', v_normalized_search,
            'status', p_status
        ),
        'stats', jsonb_build_object(
            'totalDistributors', v_stats_total_distributors,
            'activeDistributors', v_stats_active_distributors,
            'inactiveDistributors', v_stats_total_distributors - v_stats_active_distributors,
            'totalDeals', v_stats_total_deals
        ),
        'generatedAt', NOW()
    );
    
    RETURN v_result;
END;
$$;


ALTER FUNCTION public.get_admin_distributors_list(p_search text, p_status text, p_page integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 730 (class 1255 OID 55587)
-- Name: get_admin_distributors_stats(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_admin_distributors_stats() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result JSONB;
    v_total_distributors INTEGER;
    v_active_distributors INTEGER;
    v_total_deals INTEGER;
BEGIN
    -- Get total distributors
    SELECT COUNT(*)::INTEGER INTO v_total_distributors
    FROM reverse_distributors;
    
    -- Get active distributors
    SELECT COUNT(*)::INTEGER INTO v_active_distributors
    FROM reverse_distributors
    WHERE is_active = TRUE;
    
    -- Get total deals (custom_packages linked to distributors)
    SELECT COUNT(*)::INTEGER INTO v_total_deals
    FROM custom_packages
    WHERE distributor_id IS NOT NULL;
    
    -- Build result
    v_result := jsonb_build_object(
        'totalDistributors', v_total_distributors,
        'activeDistributors', v_active_distributors,
        'inactiveDistributors', v_total_distributors - v_active_distributors,
        'totalDeals', v_total_deals,
        'generatedAt', NOW()
    );
    
    RETURN v_result;
END;
$$;


