--
-- TOC entry 920 (class 1255 OID 144484)
-- Name: get_batch(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_batch(p_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_row    return_batches;
  v_memos  jsonb;
  v_returns jsonb;
BEGIN
  SELECT * INTO v_row FROM return_batches WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Batch not found');
  END IF;

  SELECT COALESCE(jsonb_agg(_debit_memo_to_json(dm) ORDER BY dm.memo_number), '[]'::jsonb)
    INTO v_memos
    FROM debit_memos dm WHERE dm.batch_id = p_id;

  SELECT COALESCE(jsonb_agg(_rt_to_json(rt) ORDER BY rt.license_plate), '[]'::jsonb)
    INTO v_returns
    FROM return_transactions rt WHERE rt.batch_id = p_id;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'batch',      _batch_to_json(v_row),
      'debitMemos', v_memos,
      'returns',    v_returns
    )
  );
END;
$$;


ALTER FUNCTION public.get_batch(p_id uuid) OWNER TO postgres;

--
-- TOC entry 591 (class 1255 OID 156281)
-- Name: get_batch_permissions(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_batch_permissions(p_batch_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_batch return_batches;
  v_memo_count INTEGER;
BEGIN
  SELECT * INTO v_batch FROM return_batches WHERE id = p_batch_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Batch not found');
  END IF;

  SELECT COUNT(*) INTO v_memo_count FROM debit_memos WHERE batch_id = p_batch_id;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'batchId', p_batch_id,
      'status', v_batch.status,
      'canDelete', v_batch.status = 'open' AND v_memo_count = 0,
      'canUnassignReturns', v_batch.status = 'open',
      'canAssignReturns', v_batch.status = 'open',
      'canClose', v_batch.status = 'open' AND v_batch.total_returns > 0,
      'canSubmitCardinal', v_batch.status = 'closed',
      'hasDebitMemos', v_memo_count > 0,
      'debitMemoCount', v_memo_count
    )
  );
END;
$$;


ALTER FUNCTION public.get_batch_permissions(p_batch_id uuid) OWNER TO postgres;

