--
-- TOC entry 497 (class 1255 OID 169040)
-- Name: get_buying_groups_list(integer, integer, text, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_buying_groups_list(p_page integer DEFAULT 1, p_limit integer DEFAULT 10, p_search text DEFAULT NULL::text, p_status text DEFAULT NULL::text, p_sort_by text DEFAULT 'created_at'::text, p_sort_order text DEFAULT 'desc'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_offset INTEGER;
  v_total INTEGER;
  v_groups JSONB;
  v_stats JSONB;
BEGIN
  v_offset := (p_page - 1) * p_limit;

  -- Stats (using admin table, treating is_active as status, only super_admin role)
  SELECT jsonb_build_object(
    'total', COUNT(*)::INTEGER,
    'active', COUNT(*) FILTER (WHERE a.is_active = true)::INTEGER,
    'inactive', COUNT(*) FILTER (WHERE a.is_active = false)::INTEGER,
    'suspended', 0::INTEGER
  )
  INTO v_stats
  FROM admin a
  WHERE a.role = 'super_admin';

  -- Count
  SELECT COUNT(*)::INTEGER
  INTO v_total
  FROM admin a
  WHERE
    a.role = 'super_admin'
    AND (p_search IS NULL OR p_search = '' OR
      a.name ILIKE '%' || p_search || '%' OR
      a.email ILIKE '%' || p_search || '%')
    AND (p_status IS NULL OR p_status = '' OR p_status = 'all' OR 
      (p_status = 'active' AND a.is_active = true) OR
      (p_status = 'inactive' AND a.is_active = false));

  -- Fetch (treating admin records as buying groups)
  SELECT COALESCE(jsonb_agg(row_data), '[]'::jsonb)
  INTO v_groups
  FROM (
    SELECT jsonb_build_object(
      'id', a.id,
      'name', a.name,
      'contactEmail', a.email,
      'contactPhone', NULL,
      'address', NULL,
      'status', CASE WHEN a.is_active THEN 'active' ELSE 'inactive' END,
      'notes', NULL,
      'createdAt', a.created_at,
      'updatedAt', a.updated_at,
      'adminCount', 1,
      'role', a.role,
      'lastLoginAt', a.last_login_at
    ) AS row_data
    FROM admin a
    WHERE
      a.role = 'super_admin'
      AND (p_search IS NULL OR p_search = '' OR
        a.name ILIKE '%' || p_search || '%' OR
        a.email ILIKE '%' || p_search || '%')
      AND (p_status IS NULL OR p_status = '' OR p_status = 'all' OR 
        (p_status = 'active' AND a.is_active = true) OR
        (p_status = 'inactive' AND a.is_active = false))
    ORDER BY
      CASE WHEN p_sort_order = 'desc' THEN
        CASE p_sort_by
          WHEN 'name' THEN a.name
          WHEN 'status' THEN a.is_active::TEXT
          WHEN 'created_at' THEN a.created_at::TEXT
          ELSE a.created_at::TEXT
        END
      END DESC NULLS LAST,
      CASE WHEN p_sort_order = 'asc' THEN
        CASE p_sort_by
          WHEN 'name' THEN a.name
          WHEN 'status' THEN a.is_active::TEXT
          WHEN 'created_at' THEN a.created_at::TEXT
          ELSE a.created_at::TEXT
        END
      END ASC NULLS LAST
    LIMIT p_limit OFFSET v_offset
  ) sub;

  RETURN jsonb_build_object(
    'buyingGroups', v_groups,
    'stats', v_stats,
    'pagination', jsonb_build_object(
      'page', p_page,
      'limit', p_limit,
      'total', v_total,
      'totalPages', CEIL(v_total::NUMERIC / p_limit)::INTEGER
    )
  );
END;
$$;


ALTER FUNCTION public.get_buying_groups_list(p_page integer, p_limit integer, p_search text, p_status text, p_sort_by text, p_sort_order text) OWNER TO postgres;

--
-- TOC entry 479 (class 1255 OID 123722)
-- Name: get_chat_messages(uuid, uuid, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_chat_messages(p_user_id uuid, p_group_id uuid, p_limit integer DEFAULT 50, p_offset integer DEFAULT 0) RETURNS TABLE(message_id uuid, message_group_id uuid, message_sender_id uuid, sender_name character varying, sender_avatar text, message_type public.chat_message_type, content text, image_url text, thumbnail_url text, reply_to uuid, reply_to_content text, reply_to_sender_name character varying, reply_to_message_type public.chat_message_type, reactions json, created_at timestamp with time zone, delivered_at timestamp with time zone, read_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_removed_at TIMESTAMPTZ;
BEGIN
    -- Check if user is or was a member
    SELECT cgm.removed_at INTO v_removed_at
    FROM chat_group_members cgm
    WHERE cgm.group_id = p_group_id AND cgm.user_id = p_user_id;
    
    IF v_removed_at IS NULL AND NOT EXISTS (
        SELECT 1 FROM chat_group_members cgm
        WHERE cgm.group_id = p_group_id AND cgm.user_id = p_user_id
    ) THEN
        RAISE EXCEPTION 'User is not a member of this group';
    END IF;
    
    RETURN QUERY
    SELECT 
        cm.id AS message_id,
        cm.group_id AS message_group_id,
        cm.sender_id AS message_sender_id,
        p.name AS sender_name,
        p.avatar AS sender_avatar,
        cm.message_type,
        cm.content,
        cm.image_url,
        cm.thumbnail_url,
        cm.reply_to,
        -- Get reply-to message details
        CASE 
            WHEN cm.reply_to IS NOT NULL THEN (
                SELECT cm2.content 
                FROM chat_messages cm2 
                WHERE cm2.id = cm.reply_to
                LIMIT 1
            )
            ELSE NULL
        END AS reply_to_content,
        CASE 
            WHEN cm.reply_to IS NOT NULL THEN (
                SELECT p2.name 
                FROM chat_messages cm2
                LEFT JOIN profiles p2 ON p2.id = cm2.sender_id
                WHERE cm2.id = cm.reply_to
                LIMIT 1
            )
            ELSE NULL
        END AS reply_to_sender_name,
        CASE 
            WHEN cm.reply_to IS NOT NULL THEN (
                SELECT cm2.message_type 
                FROM chat_messages cm2 
                WHERE cm2.id = cm.reply_to
                LIMIT 1
            )
            ELSE NULL
        END AS reply_to_message_type,
        COALESCE(
            (SELECT json_agg(row_to_json(r))
             FROM (
                SELECT 
                    mr.emoji,
                    COUNT(*)::INTEGER as count,
                    json_agg(
                        json_build_object(
                            'userId', mr.user_id,
                            'userName', p2.name,
                            'userAvatar', p2.avatar
                        )
                    ) as users
                FROM message_reactions mr
                LEFT JOIN profiles p2 ON p2.id = mr.user_id
                WHERE mr.message_id = cm.id
                GROUP BY mr.emoji
                ORDER BY mr.emoji
             ) r),
            '[]'::json
        ) AS reactions,
        cm.created_at,
        mrs.delivered_at,
        mrs.read_at
    FROM chat_messages cm
    LEFT JOIN profiles p ON p.id = cm.sender_id
    LEFT JOIN message_read_status mrs ON mrs.message_id = cm.id AND mrs.user_id = p_user_id
    WHERE cm.group_id = p_group_id
    AND (v_removed_at IS NULL OR cm.created_at <= v_removed_at)
    ORDER BY cm.created_at DESC
    LIMIT p_limit
    OFFSET p_offset;
END;
$$;


ALTER FUNCTION public.get_chat_messages(p_user_id uuid, p_group_id uuid, p_limit integer, p_offset integer) OWNER TO postgres;

--
-- TOC entry 555 (class 1255 OID 70397)
-- Name: get_current_deal_of_the_day_info(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_current_deal_of_the_day_info() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_info JSONB;
  v_manual_deal JSONB;
BEGIN
  -- Get manual Deal of the Day if exists
  SELECT jsonb_build_object(
    'id', d.id,
    'dealNumber', d.deal_number,
    'productName', d.product_name,
    'isDealOfTheDay', d.is_deal_of_the_day,
    'dealOfTheDayUntil', d.deal_of_the_day_until,
    'isExpired', d.deal_of_the_day_until IS NOT NULL AND d.deal_of_the_day_until < NOW(),
    'type', 'manual'
  )
  INTO v_manual_deal
  FROM marketplace_deals d
  WHERE d.is_deal_of_the_day = TRUE
  LIMIT 1;
  
  -- Get automatic selection
  SELECT jsonb_build_object(
    'deal', get_deal_of_the_day(),
    'manualDeal', v_manual_deal,
    'hasManualSelection', v_manual_deal IS NOT NULL
  )
  INTO v_info;
  
  RETURN v_info;
END;
$$;


ALTER FUNCTION public.get_current_deal_of_the_day_info() OWNER TO postgres;

--
-- TOC entry 551 (class 1255 OID 144356)
-- Name: get_dea_form_222_data(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_dea_form_222_data(p_transaction_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_txn          return_transactions;
  v_pharmacy     RECORD;
  v_items        jsonb;
  v_item_count   INTEGER;
  v_total_value  DECIMAL(12,2);
BEGIN
  -- Fetch the transaction
  SELECT * INTO v_txn FROM return_transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404,
      'message', 'Return transaction not found');
  END IF;

  -- Fetch pharmacy info
  SELECT
    id, pharmacy_name, npi_number, dea_number, phone, email
  INTO v_pharmacy
  FROM pharmacy
  WHERE id = v_txn.pharmacy_id;

  -- Schedule II items only (dea_form_222_required = true)
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'ndc',              rti.ndc,
      'ndc10',            rti.ndc_10,
      'proprietaryName',  rti.proprietary_name,
      'genericName',      rti.generic_name,
      'manufacturer',     rti.manufacturer,
      'lotNumber',        rti.lot_number,
      'serialNumber',     rti.serial_number,
      'expirationDate',   rti.expiration_date,
      'quantity',         rti.quantity,
      'standardPrice',    rti.standard_price,
      'estimatedValue',   rti.estimated_value,
      'deaSchedule',      rti.dea_schedule,
      'strength',         rti.strength,
      'dosageForm',       rti.dosage_form,
      'returnStatus',     rti.return_status,
      'destination',      rti.destination,
      'isPartial',        rti.is_partial,
      'partialPercentage',rti.partial_percentage
    ) ORDER BY rti.proprietary_name, rti.ndc
  ), '[]'::jsonb)
  INTO v_items
  FROM return_transaction_items rti
  WHERE rti.transaction_id = p_transaction_id
    AND rti.dea_form_222_required = true;

  -- Count & total
  SELECT COUNT(*), COALESCE(SUM(estimated_value), 0)
  INTO v_item_count, v_total_value
  FROM return_transaction_items
  WHERE transaction_id = p_transaction_id
    AND dea_form_222_required = true;

  IF v_item_count = 0 THEN
    RETURN jsonb_build_object('error', true, 'code', 404,
      'message', 'No Schedule II (CII) items found requiring DEA Form 222.');
  END IF;


  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'transaction', jsonb_build_object(
        'id',            v_txn.id,
        'licensePlate',  v_txn.license_plate,
        'status',        v_txn.status,
        'fedexTracking', v_txn.fedex_tracking,
        'finalizedAt',   v_txn.finalized_at,
        'createdAt',     v_txn.created_at
      ),
      'pharmacy', jsonb_build_object(
        'id',        v_pharmacy.id,
        'name',      v_pharmacy.pharmacy_name,
        'npiNumber', v_pharmacy.npi_number,
        'deaNumber', v_pharmacy.dea_number,
        'phone',     v_pharmacy.phone,
        'email',     v_pharmacy.email
      ),
      'summary', jsonb_build_object(
        'totalCiiItems', v_item_count,
        'totalValue',    v_total_value
      ),
      'items', v_items
    )
  );
END;
$$;


ALTER FUNCTION public.get_dea_form_222_data(p_transaction_id uuid) OWNER TO postgres;

--
-- TOC entry 796 (class 1255 OID 70394)
-- Name: get_deal_of_the_day(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_deal_of_the_day() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_deal JSONB;
  v_manual_deal_id UUID;
  v_manual_deal_expired BOOLEAN;
BEGIN
  -- First, check for expired manual Deal of the Day
  UPDATE marketplace_deals
  SET is_deal_of_the_day = FALSE,
      deal_of_the_day_until = NULL,
      updated_at = NOW()
  WHERE is_deal_of_the_day = TRUE
    AND deal_of_the_day_until IS NOT NULL
    AND deal_of_the_day_until < NOW();
  
  -- Try to get manual Deal of the Day (not expired)
  SELECT id, (deal_of_the_day_until IS NOT NULL AND deal_of_the_day_until < NOW())
  INTO v_manual_deal_id, v_manual_deal_expired
  FROM marketplace_deals
  WHERE is_deal_of_the_day = TRUE
    AND status = 'active'
    AND expiry_date >= CURRENT_DATE
    AND quantity > 0
  LIMIT 1;
  
  -- If manual deal exists and not expired, return it
  IF v_manual_deal_id IS NOT NULL AND NOT v_manual_deal_expired THEN
    SELECT jsonb_build_object(
      'id', d.id,
      'dealNumber', d.deal_number,
      'productName', d.product_name,
      'category', d.category,
      'ndc', d.ndc,
      'quantity', d.quantity,
      'originalQuantity', COALESCE(d.original_quantity, d.quantity),
      'soldQuantity', COALESCE(d.original_quantity, d.quantity) - d.quantity,
      'remainingQuantity', d.quantity,
      'minimumBuyQuantity', COALESCE(d.minimum_buy_quantity, 1),
      'unit', d.unit,
      'originalPrice', d.original_price,
      'dealPrice', d.deal_price,
      'savings', ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0),
      'totalSavingsAmount', ROUND((d.original_price - d.deal_price), 2),
      'distributor', d.distributor_name,
      'expiryDate', d.expiry_date,
      'postedDate', d.posted_date,
      'status', d.status,
      'imageUrl', d.image_url,
      'notes', d.notes,
      'isDealOfTheDay', true,
      'dealOfTheDayType', 'manual',
      'dealOfTheDayUntil', d.deal_of_the_day_until
    )
    INTO v_deal
    FROM marketplace_deals d
    WHERE d.id = v_manual_deal_id;
    
    RETURN jsonb_build_object(
      'error', false,
      'deal', v_deal
    );
  END IF;
  
  -- No valid manual deal, get automatic selection
  -- Criteria: Best savings percentage, then newest
  SELECT jsonb_build_object(
    'id', d.id,
    'dealNumber', d.deal_number,
    'productName', d.product_name,
    'category', d.category,
    'ndc', d.ndc,
    'quantity', d.quantity,
    'originalQuantity', COALESCE(d.original_quantity, d.quantity),
    'soldQuantity', COALESCE(d.original_quantity, d.quantity) - d.quantity,
    'remainingQuantity', d.quantity,
    'minimumBuyQuantity', COALESCE(d.minimum_buy_quantity, 1),
    'unit', d.unit,
    'originalPrice', d.original_price,
    'dealPrice', d.deal_price,
    'savings', ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0),
    'totalSavingsAmount', ROUND((d.original_price - d.deal_price), 2),
    'distributor', d.distributor_name,
    'expiryDate', d.expiry_date,
    'postedDate', d.posted_date,
    'status', d.status,
    'imageUrl', d.image_url,
    'notes', d.notes,
    'isDealOfTheDay', true,
    'dealOfTheDayType', 'automatic'
  )
  INTO v_deal
  FROM marketplace_deals d
  WHERE d.status = 'active'
    AND d.expiry_date >= CURRENT_DATE
    AND d.quantity > 0
  ORDER BY 
    ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0) DESC, -- Best savings first
    d.posted_date DESC -- Newest first if tie
  LIMIT 1;
  
  IF v_deal IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'No active deals available for Deal of the Day'
    );
  END IF;
  
  RETURN jsonb_build_object(
    'error', false,
    'deal', v_deal
  );
END;
$$;


ALTER FUNCTION public.get_deal_of_the_day() OWNER TO postgres;

--
-- TOC entry 548 (class 1255 OID 144489)
-- Name: get_debit_memo(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_debit_memo(p_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_memo  debit_memos;
  v_items jsonb;
BEGIN
  SELECT * INTO v_memo FROM debit_memos WHERE id = p_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Debit memo not found');
  END IF;

  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'id',                dmi.id,
      'debitMemoId',       dmi.debit_memo_id,
      'transactionItemId', dmi.transaction_item_id,
      'ndc',               dmi.ndc,
      'productName',       dmi.product_name,
      'quantity',          dmi.quantity,
      'askPrice',          dmi.ask_price,
      'receivedPrice',     dmi.received_price,
      'lotNumber',         dmi.lot_number,
      'expirationDate',    dmi.expiration_date,
      'createdAt',         dmi.created_at
    ) ORDER BY dmi.product_name, dmi.ndc
  ), '[]'::jsonb)
  INTO v_items
  FROM debit_memo_items dmi WHERE dmi.debit_memo_id = p_id;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'memo',  _debit_memo_to_json(v_memo),
      'items', v_items
    )
  );
END;
$$;


ALTER FUNCTION public.get_debit_memo(p_id uuid) OWNER TO postgres;

--
-- TOC entry 570 (class 1255 OID 169388)
-- Name: get_default_warehouse(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_default_warehouse() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_warehouse JSONB;
BEGIN
  SELECT jsonb_build_object(
    'id', w.id,
    'name', w.name,
    'contactName', w.contact_name,
    'phone', w.phone,
    'street', w.street,
    'city', w.city,
    'state', w.state,
    'zip', w.zip,
    'country', w.country,
    'isActive', w.is_active,
    'isDefault', w.is_default,
    'createdAt', w.created_at,
    'updatedAt', w.updated_at
  )
  INTO v_warehouse
  FROM warehouses w
  WHERE w.is_default = true AND w.is_active = true;
  
  -- If no default warehouse, get the first active one
  IF v_warehouse IS NULL THEN
    SELECT jsonb_build_object(
      'id', w.id,
      'name', w.name,
      'contactName', w.contact_name,
      'phone', w.phone,
      'street', w.street,
      'city', w.city,
      'state', w.state,
      'zip', w.zip,
      'country', w.country,
      'isActive', w.is_active,
      'isDefault', w.is_default,
      'createdAt', w.created_at,
      'updatedAt', w.updated_at
    )
    INTO v_warehouse
    FROM warehouses w
    WHERE w.is_active = true
    ORDER BY w.created_at ASC
    LIMIT 1;
  END IF;
  
  RETURN jsonb_build_object(
    'error', false,
    'warehouse', v_warehouse
  );
END;
$$;


ALTER FUNCTION public.get_default_warehouse() OWNER TO postgres;

--
-- TOC entry 513 (class 1255 OID 156265)
-- Name: get_destination_for_ndc(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_destination_for_ndc(p_ndc text) RETURNS text
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_labeler_id TEXT;
  v_destination TEXT;
BEGIN
  v_labeler_id := SUBSTRING(REGEXP_REPLACE(COALESCE(p_ndc, ''), '[^0-9]', '', 'g') FROM 1 FOR 5);
  IF v_labeler_id IS NULL OR LENGTH(TRIM(v_labeler_id)) < 5 THEN
    RETURN NULL;
  END IF;

  SELECT mrp.destination INTO v_destination
  FROM manufacturer_policies mp
  JOIN manufacturer_return_policies mrp ON mp.id = mrp.manufacturer_policy_id
  WHERE mp.labeler_id = v_labeler_id
  ORDER BY mrp.created_at ASC
  LIMIT 1;

  RETURN v_destination;
END;
$$;


ALTER FUNCTION public.get_destination_for_ndc(p_ndc text) OWNER TO postgres;

--
-- TOC entry 850 (class 1255 OID 59640)
-- Name: get_distributor_package_suggestion(uuid, uuid, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_distributor_package_suggestion(p_pharmacy_id uuid, p_distributor_id uuid, p_items jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_result jsonb;
  v_distributor record;
  v_existing_package record;
  v_products jsonb := '[]'::jsonb;
  v_total_items integer := 0;
  v_total_estimated_value numeric := 0;
  v_products_with_pricing integer := 0;
  v_products_without_pricing integer := 0;
  v_item record;
  v_ndc text;
  v_normalized_ndc text;
  v_product_id text;
  v_product_name text;
  v_full integer;
  v_partial integer;
  v_price_per_unit numeric;
  v_total_value numeric;
  v_product_name_from_db text;
  v_already_created boolean := false;
  v_existing_package_info jsonb := null;
  v_distributor_contact jsonb := null;
  v_location text := null;
BEGIN
  -- Step 1: Validate inputs
  IF p_pharmacy_id IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Pharmacy ID is required'
    );
  END IF;

  IF p_distributor_id IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Distributor ID is required'
    );
  END IF;

  IF p_items IS NULL OR jsonb_array_length(p_items) = 0 THEN
    RETURN jsonb_build_object(
      'success', true,
      'data', jsonb_build_object(
        'packages', '[]'::jsonb,
        'totalProducts', 0,
        'totalPackages', 0,
        'totalEstimatedValue', 0,
        'generatedAt', to_char(now(), 'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"'),
        'summary', jsonb_build_object(
          'productsWithPricing', 0,
          'productsWithoutPricing', 0,
          'distributorsUsed', 0,
          'packagesAlreadyCreated', 0
        )
      )
    );
  END IF;

  -- Step 2: Get distributor information
  SELECT 
    rd.id,
    rd.name,
    rd.contact_email,
    rd.contact_phone,
    rd.address,
    rd.fee_rates,
    rd.is_active
  INTO v_distributor
  FROM reverse_distributors rd
  WHERE rd.id = p_distributor_id;

  IF v_distributor IS NULL THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Distributor not found'
    );
  END IF;

  IF NOT v_distributor.is_active THEN
    RETURN jsonb_build_object(
      'success', false,
      'error', 'Distributor is not active'
    );
  END IF;

  -- Build location string from address
  IF v_distributor.address IS NOT NULL THEN
    SELECT string_agg(part, ', ')
    INTO v_location
    FROM (
      SELECT unnest(ARRAY[
        v_distributor.address->>'street',
        v_distributor.address->>'city',
        v_distributor.address->>'state',
        v_distributor.address->>'zipCode',
        v_distributor.address->>'country'
      ]) AS part
    ) parts
    WHERE part IS NOT NULL AND part != '';
  END IF;

  -- Build distributor contact info
  v_distributor_contact := jsonb_build_object(
    'email', v_distributor.contact_email,
    'phone', v_distributor.contact_phone,
    'location', v_location,
    'feeRates', v_distributor.fee_rates
  );

  -- Step 3: Check if a non-delivered package already exists with this distributor
  SELECT 
    cp.id,
    cp.package_number,
    cp.total_items,
    cp.total_estimated_value,
    cp.fee_rate,
    cp.fee_duration,
    cp.created_at
  INTO v_existing_package
  FROM custom_packages cp
  WHERE cp.pharmacy_id = p_pharmacy_id
    AND cp.distributor_id = p_distributor_id
    AND cp.status = false -- Only non-delivered packages
  ORDER BY cp.created_at DESC
  LIMIT 1;

  IF v_existing_package IS NOT NULL THEN
    v_already_created := true;
    v_existing_package_info := jsonb_build_object(
      'id', v_existing_package.id,
      'packageNumber', v_existing_package.package_number,
      'totalItems', v_existing_package.total_items,
      'totalEstimatedValue', v_existing_package.total_estimated_value,
      'feeRate', v_existing_package.fee_rate,
      'feeDuration', v_existing_package.fee_duration,
      'createdAt', v_existing_package.created_at
    );
  END IF;

  -- Step 4: Process each item and get pricing from return reports
  FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
  LOOP
    v_ndc := v_item.value->>'ndc';
    v_normalized_ndc := regexp_replace(v_ndc, '-', '', 'g');
    v_product_id := v_item.value->>'productId';
    v_product_name := v_item.value->>'productName';
    v_full := COALESCE((v_item.value->>'full')::integer, 0);
    v_partial := COALESCE((v_item.value->>'partial')::integer, 0);
    v_price_per_unit := 0;

    -- Skip if NDC is empty
    IF v_ndc IS NULL OR v_ndc = '' THEN
      CONTINUE;
    END IF;

    -- Get product name from database if not provided
    IF v_product_name IS NULL OR v_product_name = '' THEN
      SELECT p.product_name INTO v_product_name_from_db
      FROM products p
      WHERE p.ndc = v_ndc OR regexp_replace(p.ndc, '-', '', 'g') = v_normalized_ndc
      LIMIT 1;
      
      v_product_name := COALESCE(v_product_name_from_db, 'Product ' || v_ndc);
    END IF;

    -- Get latest price from return reports for this distributor and NDC
    -- Filter by unit type: if full > 0, get full-only records; if partial > 0, get partial-only records
    SELECT 
      COALESCE(
        (rr_item.value->>'pricePerUnit')::numeric,
        CASE 
          WHEN COALESCE((rr_item.value->>'quantity')::numeric, 0) > 0 
            AND COALESCE((rr_item.value->>'creditAmount')::numeric, 0) > 0
          THEN (rr_item.value->>'creditAmount')::numeric / (rr_item.value->>'quantity')::numeric
          ELSE 0
        END
      ) AS price_per_unit
    INTO v_price_per_unit
    FROM return_reports rr
    JOIN uploaded_documents ud ON ud.id = rr.document_id
    CROSS JOIN LATERAL jsonb_array_elements(
      CASE 
        WHEN jsonb_typeof(rr.data->'items') = 'array' THEN rr.data->'items'
        WHEN rr.data->'items' IS NOT NULL THEN jsonb_build_array(rr.data->'items')
        WHEN rr.data->>'ndcCode' IS NOT NULL OR rr.data->>'ndc' IS NOT NULL THEN jsonb_build_array(rr.data)
        ELSE '[]'::jsonb
      END
    ) AS rr_item
    WHERE ud.reverse_distributor_id = p_distributor_id
      AND (
        -- Match NDC with or without dashes
        regexp_replace(COALESCE(rr_item.value->>'ndcCode', rr_item.value->>'ndc', ''), '-', '', 'g') = v_normalized_ndc
        OR COALESCE(rr_item.value->>'ndcCode', rr_item.value->>'ndc', '') = v_ndc
      )
      AND (
        -- Unit type filtering
        CASE
          -- If only full units requested, get records with full > 0 and partial = 0
          WHEN v_full > 0 AND v_partial = 0 THEN
            COALESCE((rr_item.value->>'full')::integer, 0) > 0 
            AND COALESCE((rr_item.value->>'partial')::integer, 0) = 0
          -- If only partial units requested, get records with partial > 0 and full = 0
          WHEN v_partial > 0 AND v_full = 0 THEN
            COALESCE((rr_item.value->>'partial')::integer, 0) > 0 
            AND COALESCE((rr_item.value->>'full')::integer, 0) = 0
          -- If both full and partial, accept either type of record
          ELSE true
        END
      )
      AND (
        COALESCE((rr_item.value->>'pricePerUnit')::numeric, 0) > 0
        OR (
          COALESCE((rr_item.value->>'quantity')::numeric, 0) > 0 
          AND COALESCE((rr_item.value->>'creditAmount')::numeric, 0) > 0
        )
      )
    ORDER BY COALESCE(ud.report_date, ud.uploaded_at, rr.created_at) DESC
    LIMIT 1;

    -- Calculate total value
    v_price_per_unit := COALESCE(v_price_per_unit, 0);
    v_total_value := v_price_per_unit * (v_full + v_partial);

    -- Track pricing statistics
    IF v_price_per_unit > 0 THEN
      v_products_with_pricing := v_products_with_pricing + 1;
    ELSE
      v_products_without_pricing := v_products_without_pricing + 1;
    END IF;

    -- Add to products array
    v_products := v_products || jsonb_build_object(
      'ndc', v_ndc,
      'productId', v_product_id,
      'productName', v_product_name,
      'full', v_full,
      'partial', v_partial,
      'pricePerUnit', ROUND(v_price_per_unit::numeric, 2),
      'totalValue', ROUND(v_total_value::numeric, 2)
    );

    -- Update totals
    v_total_items := v_total_items + v_full + v_partial;
    v_total_estimated_value := v_total_estimated_value + v_total_value;
  END LOOP;

  -- Step 5: Build and return the result
  v_result := jsonb_build_object(
    'success', true,
    'data', jsonb_build_object(
      'packages', CASE 
        WHEN jsonb_array_length(v_products) > 0 THEN
          jsonb_build_array(
            jsonb_build_object(
              'distributorName', v_distributor.name,
              'distributorId', v_distributor.id,
              'distributorContact', v_distributor_contact,
              'products', v_products,
              'totalItems', v_total_items,
              'totalEstimatedValue', ROUND(v_total_estimated_value::numeric, 2),
              'averagePricePerUnit', CASE 
                WHEN v_total_items > 0 THEN ROUND((v_total_estimated_value / v_total_items)::numeric, 2)
                ELSE 0
              END,
              'alreadyCreated', v_already_created,
              'existingPackage', v_existing_package_info
            )
          )
        ELSE '[]'::jsonb
      END,
      'totalProducts', jsonb_array_length(v_products),
      'totalPackages', CASE WHEN jsonb_array_length(v_products) > 0 THEN 1 ELSE 0 END,
      'totalEstimatedValue', ROUND(v_total_estimated_value::numeric, 2),
      'generatedAt', to_char(now(), 'YYYY-MM-DD"T"HH24:MI:SS.MS"Z"'),
      'summary', jsonb_build_object(
        'productsWithPricing', v_products_with_pricing,
        'productsWithoutPricing', v_products_without_pricing,
        'distributorsUsed', CASE WHEN jsonb_array_length(v_products) > 0 THEN 1 ELSE 0 END,
        'packagesAlreadyCreated', CASE WHEN v_already_created THEN 1 ELSE 0 END
      )
    )
  );

  RETURN v_result;
END;
$$;


ALTER FUNCTION public.get_distributor_package_suggestion(p_pharmacy_id uuid, p_distributor_id uuid, p_items jsonb) OWNER TO postgres;

--
-- TOC entry 5612 (class 0 OID 0)
-- Dependencies: 850
-- Name: FUNCTION get_distributor_package_suggestion(p_pharmacy_id uuid, p_distributor_id uuid, p_items jsonb); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.get_distributor_package_suggestion(p_pharmacy_id uuid, p_distributor_id uuid, p_items jsonb) IS 'Get package suggestion for a specific distributor. Takes pharmacy_id, distributor_id, and items array. Returns pricing data for that distributor only.';


--
-- TOC entry 581 (class 1255 OID 79825)
-- Name: get_distributor_suggestions(uuid, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_distributor_suggestions(p_pharmacy_id uuid, p_items jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result JSONB;
    v_total_items INTEGER := 0;
    v_item_count INTEGER;
    v_invalid_item JSONB;
    v_missing_ndc TEXT;
    v_missing_product_name TEXT;
BEGIN
    -- =====================================================
    -- SECURITY: Check pharmacy status (block suspended/blacklisted)
    -- =====================================================
    PERFORM check_pharmacy_status(p_pharmacy_id);
    
    -- =====================================================
    -- STEP 1: Basic Validation
    -- =====================================================
    
    -- Validate items array is not empty
    IF p_items IS NULL OR jsonb_array_length(p_items) = 0 THEN
        RAISE EXCEPTION 'At least one item with NDC and full/partial units is required';
    END IF;
    
    -- =====================================================
    -- STEP 2: Create temp table for requested items
    -- =====================================================
    
    DROP TABLE IF EXISTS temp_requested_items;
    CREATE TEMP TABLE temp_requested_items AS
    SELECT 
        TRIM(item->>'ndc') AS ndc,
        REPLACE(TRIM(COALESCE(item->>'ndc', '')), '-', '') AS normalized_ndc,
        item->>'product' AS input_product_name,
        COALESCE((item->>'full')::INTEGER, 0) AS full_count,
        COALESCE((item->>'partial')::INTEGER, 0) AS partial_count
    FROM jsonb_array_elements(p_items) AS item
    WHERE TRIM(COALESCE(item->>'ndc', '')) != '';
    
    -- =====================================================
    -- STEP 3: Validate full/partial counts
    -- =====================================================
    
    SELECT item INTO v_invalid_item
    FROM jsonb_array_elements(p_items) AS item
    WHERE COALESCE((item->>'full')::INTEGER, 0) + COALESCE((item->>'partial')::INTEGER, 0) <= 0
    LIMIT 1;
    
    IF v_invalid_item IS NOT NULL THEN
        RAISE EXCEPTION 'NDC %: At least one of full or partial must be greater than 0', v_invalid_item->>'ndc';
    END IF;
    
    -- =====================================================
    -- STEP 4: Validate items exist in pharmacy inventory
    -- =====================================================
    
    SELECT tri.ndc INTO v_missing_ndc
    FROM temp_requested_items tri
    WHERE NOT EXISTS (
        SELECT 1 FROM product_list_items pli
        WHERE pli.added_by = p_pharmacy_id
        AND (
            REPLACE(COALESCE(pli.ndc::TEXT, ''), '-', '') = tri.normalized_ndc
            OR TRIM(COALESCE(pli.ndc::TEXT, '')) = tri.ndc
        )
    )
    LIMIT 1;
    
    IF v_missing_ndc IS NOT NULL THEN
        -- Get product name for error message
        SELECT COALESCE(
            (SELECT product_name FROM products WHERE REPLACE(COALESCE(ndc::TEXT, ''), '-', '') = REPLACE(v_missing_ndc, '-', '') LIMIT 1),
            'Product ' || v_missing_ndc
        ) INTO v_missing_product_name;
        
        RAISE EXCEPTION 'You don''t have this product in your inventory. NDC: %, Product: %', v_missing_ndc, v_missing_product_name;
    END IF;
    
    -- =====================================================
    -- STEP 5: Calculate total items
    -- =====================================================
    
    SELECT SUM(full_count + partial_count) INTO v_total_items FROM temp_requested_items;
    
    -- =====================================================
    -- STEP 6: Add product names to requested items
    -- =====================================================
    
    DROP TABLE IF EXISTS temp_items_with_names;
    CREATE TEMP TABLE temp_items_with_names AS
    SELECT 
        tri.ndc,
        tri.normalized_ndc,
        tri.full_count,
        tri.partial_count,
        COALESCE(
            NULLIF(tri.input_product_name, ''),
            (SELECT p.product_name FROM products p WHERE REPLACE(COALESCE(p.ndc::TEXT, ''), '-', '') = tri.normalized_ndc LIMIT 1),
            (SELECT pli.product_name FROM product_list_items pli WHERE pli.added_by = p_pharmacy_id AND REPLACE(COALESCE(pli.ndc::TEXT, ''), '-', '') = tri.normalized_ndc LIMIT 1),
            'Product ' || tri.ndc
        ) AS product_name
    FROM temp_requested_items tri;
    
    -- =====================================================
    -- STEP 7: Extract pricing from return_reports
    -- Get latest FULL and PARTIAL prices separately
    -- =====================================================
    
    DROP TABLE IF EXISTS temp_all_prices;
    CREATE TEMP TABLE temp_all_prices AS
    WITH report_items AS (
        -- Extract items from return_reports JSONB data
        -- NOTE: Each row in return_reports has data as a single item object
        SELECT 
            rd.id AS distributor_id,
            rd.name AS distributor_name,
            ud.report_date,
            -- data column IS the item directly (not data->'items')
            REPLACE(COALESCE(rr.data->>'ndcCode', rr.data->>'ndc', ''), '-', '') AS normalized_ndc,
            COALESCE((rr.data->>'full')::INTEGER, 0) AS item_full,
            COALESCE((rr.data->>'partial')::INTEGER, 0) AS item_partial,
            COALESCE(
                (rr.data->>'pricePerUnit')::NUMERIC,
                CASE 
                    WHEN COALESCE((rr.data->>'quantity')::INTEGER, 1) > 0 
                    THEN COALESCE((rr.data->>'creditAmount')::NUMERIC, 0) / GREATEST(COALESCE((rr.data->>'quantity')::INTEGER, 1), 1)
                    ELSE 0 
                END
            ) AS price_per_unit
        FROM return_reports rr
        JOIN uploaded_documents ud ON rr.document_id = ud.id
        JOIN reverse_distributors rd ON ud.reverse_distributor_id = rd.id
        WHERE COALESCE(rr.data->>'ndcCode', rr.data->>'ndc') IS NOT NULL
    )
    SELECT 
        ri.distributor_id,
        ri.distributor_name,
        ri.normalized_ndc,
        ri.report_date,
        ri.price_per_unit,
        -- Is this a FULL price record? (full > 0 AND partial = 0)
        (ri.item_full > 0 AND ri.item_partial = 0) AS is_full_record,
        -- Is this a PARTIAL price record? (partial > 0 AND full = 0)
        (ri.item_partial > 0 AND ri.item_full = 0) AS is_partial_record
    FROM report_items ri
    WHERE ri.price_per_unit > 0
    AND ri.normalized_ndc IN (SELECT normalized_ndc FROM temp_items_with_names);
    
    -- =====================================================
    -- STEP 8: Get latest FULL price per distributor-NDC
    -- =====================================================
    
    DROP TABLE IF EXISTS temp_latest_full_prices;
    CREATE TEMP TABLE temp_latest_full_prices AS
    SELECT DISTINCT ON (distributor_id, normalized_ndc)
        distributor_id,
        distributor_name,
        normalized_ndc,
        price_per_unit AS full_price
    FROM temp_all_prices
    WHERE is_full_record = true
    ORDER BY distributor_id, normalized_ndc, report_date DESC;
    
    -- =====================================================
    -- STEP 9: Get latest PARTIAL price per distributor-NDC
    -- =====================================================
    
    DROP TABLE IF EXISTS temp_latest_partial_prices;
    CREATE TEMP TABLE temp_latest_partial_prices AS
    SELECT DISTINCT ON (distributor_id, normalized_ndc)
        distributor_id,
        distributor_name,
        normalized_ndc,
        price_per_unit AS partial_price
    FROM temp_all_prices
    WHERE is_partial_record = true
    ORDER BY distributor_id, normalized_ndc, report_date DESC;
    
    -- =====================================================
    -- STEP 10: Build final result using CTEs
    -- =====================================================
    
    WITH 
    -- All distributors with their contact info and fee_rates
    all_distributors AS (
        SELECT 
            rd.id AS distributor_id,
            rd.name AS distributor_name,
            rd.contact_email,
            rd.contact_phone,
            NULLIF(TRIM(CONCAT_WS(', ',
                NULLIF(rd.address->>'street', ''),
                NULLIF(rd.address->>'city', ''),
                NULLIF(rd.address->>'state', ''),
                NULLIF(rd.address->>'zipCode', ''),
                NULLIF(rd.address->>'country', '')
            )), '') AS location,
            rd.fee_rates
        FROM reverse_distributors rd
    ),
    
    -- Cross join distributors with requested items and add pricing
    distributor_products AS (
        SELECT 
            ad.distributor_id,
            ad.distributor_name,
            ad.contact_email,
            ad.contact_phone,
            ad.location,
            ad.fee_rates,
            ti.ndc,
            ti.normalized_ndc,
            ti.product_name,
            ti.full_count,
            ti.partial_count,
            lfp.full_price AS full_price_per_unit,
            lpp.partial_price AS partial_price_per_unit,
            -- Calculate total value
            ROUND(
                COALESCE(ti.full_count * lfp.full_price, 0) + 
                COALESCE(ti.partial_count * lpp.partial_price, 0), 
            2) AS total_estimated_value
        FROM all_distributors ad
        CROSS JOIN temp_items_with_names ti
        LEFT JOIN temp_latest_full_prices lfp 
            ON lfp.distributor_id = ad.distributor_id 
            AND lfp.normalized_ndc = ti.normalized_ndc
        LEFT JOIN temp_latest_partial_prices lpp 
            ON lpp.distributor_id = ad.distributor_id 
            AND lpp.normalized_ndc = ti.normalized_ndc
    ),
    
    -- Aggregate products per distributor
    distributor_aggregated AS (
        SELECT 
            dp.distributor_id,
            dp.distributor_name,
            dp.contact_email,
            dp.contact_phone,
            dp.location,
            dp.fee_rates,
            -- Build products array
            jsonb_agg(
                jsonb_build_object(
                    'ndc', dp.ndc,
                    'productName', dp.product_name,
                    'full', dp.full_count,
                    'partial', dp.partial_count,
                    'fullPricePerUnit', ROUND(COALESCE(dp.full_price_per_unit, 0), 2),
                    'partialPricePerUnit', ROUND(COALESCE(dp.partial_price_per_unit, 0), 2),
                    'totalEstimatedValue', dp.total_estimated_value
                )
            ) AS products,
            SUM(dp.full_count + dp.partial_count)::INTEGER AS total_items,
            ROUND(SUM(dp.total_estimated_value), 2) AS total_estimated_value,
            COUNT(*)::INTEGER AS ndcs_count
        FROM distributor_products dp
        GROUP BY dp.distributor_id, dp.distributor_name, dp.contact_email, dp.contact_phone, dp.location, dp.fee_rates
    ),
    
    -- Add row number to identify recommended (first one with highest value)
    distributor_ranked AS (
        SELECT 
            da.*,
            ROW_NUMBER() OVER (ORDER BY da.total_estimated_value DESC) AS rank
        FROM distributor_aggregated da
    ),
    
    -- Build distributors array sorted by total value DESC
    -- First distributor (highest total value) is marked as recommended
    distributors_json AS (
        SELECT jsonb_agg(
            jsonb_build_object(
                'distributorName', dr.distributor_name,
                'distributorId', dr.distributor_id,
                'distributorContact', jsonb_build_object(
                    'email', dr.contact_email,
                    'phone', dr.contact_phone,
                    'location', dr.location
                ),
                'feeRates', dr.fee_rates,
                'products', dr.products,
                'totalItems', dr.total_items,
                'totalEstimatedValue', dr.total_estimated_value,
                'ndcsCount', dr.ndcs_count,
                'recommended', dr.rank = 1  -- First distributor (highest value) is recommended
            ) ORDER BY dr.total_estimated_value DESC
        ) AS distributors
        FROM distributor_ranked dr
    ),
    
    -- Find NDCs without any pricing from any distributor
    ndcs_with_pricing AS (
        SELECT DISTINCT normalized_ndc 
        FROM temp_latest_full_prices
        UNION
        SELECT DISTINCT normalized_ndc 
        FROM temp_latest_partial_prices
    ),
    
    ndcs_without_distributors_json AS (
        SELECT COALESCE(jsonb_agg(
            jsonb_build_object(
                'ndc', ti.ndc,
                'productName', ti.product_name,
                'full', ti.full_count,
                'partial', ti.partial_count,
                'reason', 'No distributor found offering returns for this NDC'
            )
        ), '[]'::JSONB) AS ndcs_without
        FROM temp_items_with_names ti
        WHERE ti.normalized_ndc NOT IN (SELECT normalized_ndc FROM ndcs_with_pricing)
    ),
    
    -- Calculate totals
    totals AS (
        SELECT 
            COALESCE(SUM(da.total_estimated_value), 0) AS grand_total,
            COUNT(*) AS distributor_count
        FROM distributor_aggregated da
    )
    
    -- Build final result
    SELECT jsonb_build_object(
        'distributors', COALESCE((SELECT distributors FROM distributors_json), '[]'::JSONB),
        'ndcsWithoutDistributors', (SELECT ndcs_without FROM ndcs_without_distributors_json),
        'totalItems', v_total_items,
        'totalDistributors', (SELECT distributor_count FROM totals)::INTEGER,
        'totalEstimatedValue', ROUND((SELECT grand_total FROM totals), 2),
        'generatedAt', NOW()
    ) INTO v_result;
    
    -- =====================================================
    -- CLEANUP
    -- =====================================================
    
    DROP TABLE IF EXISTS temp_requested_items;
    DROP TABLE IF EXISTS temp_items_with_names;
    DROP TABLE IF EXISTS temp_all_prices;
    DROP TABLE IF EXISTS temp_latest_full_prices;
    DROP TABLE IF EXISTS temp_latest_partial_prices;
    
    RETURN v_result;
END;
$$;


ALTER FUNCTION public.get_distributor_suggestions(p_pharmacy_id uuid, p_items jsonb) OWNER TO postgres;

--
-- TOC entry 576 (class 1255 OID 67423)
-- Name: get_distributor_unique_products(uuid, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_distributor_unique_products(p_distributor_id uuid, p_page integer DEFAULT 1, p_limit integer DEFAULT 50) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result JSONB;
    v_products JSONB;
    v_total_count INTEGER;
    v_offset INTEGER;
    v_distributor_name TEXT;
BEGIN
    -- Check if distributor exists
    IF NOT EXISTS (SELECT 1 FROM reverse_distributors WHERE id = p_distributor_id) THEN
        RAISE EXCEPTION 'Distributor not found';
    END IF;
    
    -- Get distributor name
    SELECT name INTO v_distributor_name
    FROM reverse_distributors
    WHERE id = p_distributor_id;
    
    -- Calculate offset
    v_offset := (p_page - 1) * p_limit;
    
    -- Get total count of unique NDCs
    SELECT COUNT(*)::INTEGER INTO v_total_count
    FROM (
        SELECT DISTINCT rr.data->>'ndcCode' AS ndc
        FROM uploaded_documents ud
        INNER JOIN return_reports rr ON rr.document_id = ud.id
        WHERE ud.reverse_distributor_id = p_distributor_id
          AND rr.data->>'ndcCode' IS NOT NULL
          AND rr.data->>'ndcCode' != ''
    ) AS unique_ndcs;
    
    -- Get unique products with latest report_date per NDC
    WITH latest_reports AS (
        -- Find the latest report_date for each NDC
        SELECT 
            rr.data->>'ndcCode' AS ndc,
            MAX(ud.report_date) AS latest_report_date
        FROM uploaded_documents ud
        INNER JOIN return_reports rr ON rr.document_id = ud.id
        WHERE ud.reverse_distributor_id = p_distributor_id
          AND rr.data->>'ndcCode' IS NOT NULL
          AND rr.data->>'ndcCode' != ''
        GROUP BY rr.data->>'ndcCode'
    ),
    latest_products AS (
        -- Get the full product details for the latest report per NDC
        SELECT DISTINCT ON (rr.data->>'ndcCode')
            rr.id AS "reportId",
            rr.data->>'ndcCode' AS "ndcCode",
            rr.data->>'itemName' AS "productName",
            rr.data->>'manufacturer' AS manufacturer,
            COALESCE((rr.data->>'creditAmount')::NUMERIC, 0) AS "creditAmount",
            -- Calculate pricePerUnit: use from data if exists, otherwise creditAmount / quantity
            COALESCE(
                (rr.data->>'pricePerUnit')::NUMERIC,
                CASE 
                    WHEN COALESCE((rr.data->>'quantity')::INTEGER, 1) > 0 
                    THEN COALESCE((rr.data->>'creditAmount')::NUMERIC, 0) / GREATEST(COALESCE((rr.data->>'quantity')::INTEGER, 1), 1)
                    ELSE 0 
                END
            ) AS "pricePerUnit",
            -- Calculate quantity: use from data if exists, otherwise full + partial
            COALESCE(
                (rr.data->>'quantity')::INTEGER,
                COALESCE((rr.data->>'full')::INTEGER, 0) + COALESCE((rr.data->>'partial')::INTEGER, 0)
            ) AS quantity,
            COALESCE((rr.data->>'full')::INTEGER, 0) AS "fullUnits",
            COALESCE((rr.data->>'partial')::INTEGER, 0) AS "partialUnits",
            rr.data->>'lotNumber' AS "lotNumber",
            rr.data->>'expirationDate' AS "expirationDate",
            rr.data->>'pkgSz' AS "packageSize",
            ud.report_date AS "reportDate",
            ud.file_name AS "fileName",
            rr.pharmacy_id AS "pharmacyId"
        FROM uploaded_documents ud
        INNER JOIN return_reports rr ON rr.document_id = ud.id
        INNER JOIN latest_reports lr ON lr.ndc = rr.data->>'ndcCode' AND lr.latest_report_date = ud.report_date
        WHERE ud.reverse_distributor_id = p_distributor_id
        ORDER BY rr.data->>'ndcCode', ud.report_date DESC, rr.id
    )
    SELECT COALESCE(jsonb_agg(
        jsonb_build_object(
            'reportId', lp."reportId",
            'ndcCode', lp."ndcCode",
            'productName', lp."productName",
            'manufacturer', lp.manufacturer,
            'creditAmount', ROUND(lp."creditAmount", 2),
            'pricePerUnit', ROUND(lp."pricePerUnit", 2),
            'quantity', lp.quantity,
            'fullUnits', lp."fullUnits",
            'partialUnits', lp."partialUnits",
            'lotNumber', lp."lotNumber",
            'expirationDate', lp."expirationDate",
            'packageSize', lp."packageSize",
            'reportDate', lp."reportDate",
            'fileName', lp."fileName",
            'pharmacyId', lp."pharmacyId"
        )
        ORDER BY lp."reportDate" DESC, lp."productName"
    ), '[]'::JSONB)
    INTO v_products
    FROM (
        SELECT * FROM latest_products
        ORDER BY "reportDate" DESC, "productName"
        LIMIT p_limit
        OFFSET v_offset
    ) lp;
    
    -- Build result
    v_result := jsonb_build_object(
        'distributor', jsonb_build_object(
            'id', p_distributor_id,
            'name', v_distributor_name
        ),
        'products', v_products,
        'pagination', jsonb_build_object(
            'page', p_page,
            'limit', p_limit,
            'total', v_total_count,
            'totalPages', CEIL(v_total_count::NUMERIC / p_limit::NUMERIC)::INTEGER
        ),
        'generatedAt', NOW()
    );
    
    RETURN v_result;
END;
$$;


ALTER FUNCTION public.get_distributor_unique_products(p_distributor_id uuid, p_page integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 906 (class 1255 OID 52030)
-- Name: get_earnings_estimation(uuid, text, date, date); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_earnings_estimation(p_pharmacy_id uuid, p_period_type text, p_start_date date, p_end_date date) RETURNS json
    LANGUAGE plpgsql
    AS $$
DECLARE
  chart_data_result JSON;
  top_missed_result JSON;
  total_actual NUMERIC := 0;
  total_potential NUMERIC := 0;
  total_missed NUMERIC := 0;
  opt_score INTEGER := 100;
  is_optimal BOOLEAN := true;
BEGIN
  -- SECURITY: Check pharmacy status (block suspended/blacklisted)
  PERFORM check_pharmacy_status(p_pharmacy_id);
  
  -- Create temp table for earnings comparison data (used by multiple queries)
  CREATE TEMP TABLE temp_earnings_comparison ON COMMIT DROP AS
  WITH all_pricing AS (
    SELECT 
      UPPER(REGEXP_REPLACE(COALESCE(rr.data->>'ndcCode', rr.data->>'ndc'), '[-\s]', '', 'g')) as normalized_ndc,
      ud.reverse_distributor_id as distributor_id,
      rd.name as distributor_name,
      (rr.data->>'pricePerUnit')::NUMERIC as price_per_unit,
      COALESCE(ud.report_date, rr.created_at::DATE) as report_date,
      CASE 
        WHEN (rr.data->>'full')::NUMERIC > 0 AND COALESCE((rr.data->>'partial')::NUMERIC, 0) = 0 THEN 'full'
        WHEN (rr.data->>'partial')::NUMERIC > 0 AND COALESCE((rr.data->>'full')::NUMERIC, 0) = 0 THEN 'partial'
        ELSE 'mixed'
      END as record_type
    FROM return_reports rr
    JOIN uploaded_documents ud ON rr.document_id = ud.id
    JOIN reverse_distributors rd ON ud.reverse_distributor_id = rd.id
    WHERE (rr.data->>'pricePerUnit')::NUMERIC > 0
      AND COALESCE(rr.data->>'ndcCode', rr.data->>'ndc') IS NOT NULL
      AND (
        ((rr.data->>'full')::NUMERIC > 0 AND COALESCE((rr.data->>'partial')::NUMERIC, 0) = 0)
        OR ((rr.data->>'partial')::NUMERIC > 0 AND COALESCE((rr.data->>'full')::NUMERIC, 0) = 0)
      )
  ),
  best_full_prices AS (
    SELECT DISTINCT ON (normalized_ndc)
      normalized_ndc,
      distributor_id as best_full_distributor_id,
      distributor_name as best_full_distributor_name,
      price_per_unit as best_full_price
    FROM all_pricing
    WHERE record_type = 'full'
    ORDER BY normalized_ndc, report_date DESC, price_per_unit DESC
  ),
  best_partial_prices AS (
    SELECT DISTINCT ON (normalized_ndc)
      normalized_ndc,
      distributor_id as best_partial_distributor_id,
      distributor_name as best_partial_distributor_name,
      price_per_unit as best_partial_price
    FROM all_pricing
    WHERE record_type = 'partial'
    ORDER BY normalized_ndc, report_date DESC, price_per_unit DESC
  ),
  best_prices AS (
    SELECT 
      COALESCE(f.normalized_ndc, p.normalized_ndc) as normalized_ndc,
      f.best_full_price,
      f.best_full_distributor_id,
      f.best_full_distributor_name,
      p.best_partial_price,
      p.best_partial_distributor_id,
      p.best_partial_distributor_name
    FROM best_full_prices f
    FULL OUTER JOIN best_partial_prices p ON f.normalized_ndc = p.normalized_ndc
  ),
  pharmacy_reports AS (
    SELECT 
      rr.id as report_id,
      ud.report_date,
      UPPER(REGEXP_REPLACE(COALESCE(rr.data->>'ndcCode', rr.data->>'ndc'), '[-\s]', '', 'g')) as normalized_ndc,
      COALESCE(rr.data->>'ndcCode', rr.data->>'ndc') as original_ndc,
      COALESCE(rr.data->>'itemName', rr.data->>'productDescription', 'Product ' || COALESCE(rr.data->>'ndcCode', rr.data->>'ndc')) as product_name,
      (rr.data->>'quantity')::NUMERIC as quantity,
      COALESCE((rr.data->>'full')::NUMERIC, 0) as full_qty,
      COALESCE((rr.data->>'partial')::NUMERIC, 0) as partial_qty,
      (rr.data->>'creditAmount')::NUMERIC as credit_amount,
      CASE 
        WHEN (rr.data->>'full')::NUMERIC > 0 AND COALESCE((rr.data->>'partial')::NUMERIC, 0) = 0 THEN 'full'
        WHEN (rr.data->>'partial')::NUMERIC > 0 AND COALESCE((rr.data->>'full')::NUMERIC, 0) = 0 THEN 'partial'
        ELSE 'mixed'
      END as record_type
    FROM return_reports rr
    JOIN uploaded_documents ud ON rr.document_id = ud.id
    WHERE ud.pharmacy_id = p_pharmacy_id
      AND ud.status = 'completed'
      AND ud.report_date >= p_start_date
      AND ud.report_date <= p_end_date
      AND (rr.data->>'creditAmount')::NUMERIC > 0
  )
  SELECT 
    pr.report_id,
    pr.report_date,
    pr.normalized_ndc,
    pr.original_ndc,
    pr.product_name,
    pr.quantity,
    pr.full_qty,
    pr.partial_qty,
    pr.credit_amount,
    pr.record_type,
    CASE 
      WHEN pr.record_type = 'full' THEN bp.best_full_price
      WHEN pr.record_type = 'partial' THEN bp.best_partial_price
      ELSE GREATEST(COALESCE(bp.best_full_price, 0), COALESCE(bp.best_partial_price, 0))
    END as best_price,
    CASE 
      WHEN pr.record_type = 'full' THEN bp.best_full_distributor_id
      WHEN pr.record_type = 'partial' THEN bp.best_partial_distributor_id
      ELSE CASE 
        WHEN COALESCE(bp.best_full_price, 0) >= COALESCE(bp.best_partial_price, 0) THEN bp.best_full_distributor_id
        ELSE bp.best_partial_distributor_id
      END
    END as best_distributor_id,
    CASE 
      WHEN pr.record_type = 'full' THEN bp.best_full_distributor_name
      WHEN pr.record_type = 'partial' THEN bp.best_partial_distributor_name
      ELSE CASE 
        WHEN COALESCE(bp.best_full_price, 0) >= COALESCE(bp.best_partial_price, 0) THEN bp.best_full_distributor_name
        ELSE bp.best_partial_distributor_name
      END
    END as best_distributor_name,
    CASE 
      WHEN pr.record_type = 'full' AND bp.best_full_price > 0 THEN bp.best_full_price * pr.quantity
      WHEN pr.record_type = 'partial' AND bp.best_partial_price > 0 THEN bp.best_partial_price * pr.quantity
      WHEN GREATEST(COALESCE(bp.best_full_price, 0), COALESCE(bp.best_partial_price, 0)) > 0 
        THEN GREATEST(COALESCE(bp.best_full_price, 0), COALESCE(bp.best_partial_price, 0)) * pr.quantity
      ELSE pr.credit_amount
    END as potential_earnings
  FROM pharmacy_reports pr
  LEFT JOIN best_prices bp ON pr.normalized_ndc = bp.normalized_ndc;

  -- Get chart data (period aggregation)
  WITH period_aggregation AS (
    SELECT 
      CASE 
        WHEN p_period_type = 'yearly' THEN EXTRACT(YEAR FROM report_date)::TEXT
        ELSE TO_CHAR(report_date, 'YYYY-MM')
      END as period,
      ROUND(SUM(credit_amount)::NUMERIC, 2) as actual_earnings,
      ROUND(SUM(potential_earnings)::NUMERIC, 2) as potential_earnings
    FROM temp_earnings_comparison
    GROUP BY 
      CASE 
        WHEN p_period_type = 'yearly' THEN EXTRACT(YEAR FROM report_date)::TEXT
        ELSE TO_CHAR(report_date, 'YYYY-MM')
      END
  ),
  periods_yearly AS (
    SELECT 
      year::TEXT as period,
      year::TEXT as label
    FROM generate_series(
      EXTRACT(YEAR FROM p_start_date)::INTEGER,
      EXTRACT(YEAR FROM p_end_date)::INTEGER
    ) as year
    WHERE p_period_type = 'yearly'
  ),
  periods_monthly AS (
    SELECT 
      TO_CHAR(d, 'YYYY-MM') as period,
      TRIM(TO_CHAR(d, 'Month')) || ' ' || EXTRACT(YEAR FROM d)::TEXT as label
    FROM generate_series(
      DATE_TRUNC('month', p_start_date),
      DATE_TRUNC('month', p_end_date),
      '1 month'::INTERVAL
    ) d
    WHERE p_period_type = 'monthly'
  ),
  all_periods_combined AS (
    SELECT * FROM periods_yearly
    UNION ALL
    SELECT * FROM periods_monthly
  )
  SELECT json_agg(
    json_build_object(
      'period', ap.period,
      'label', ap.label,
      'actualEarnings', COALESCE(pa.actual_earnings, 0),
      'potentialEarnings', COALESCE(pa.potential_earnings, 0),
      'difference', COALESCE(pa.potential_earnings, 0) - COALESCE(pa.actual_earnings, 0)
    ) ORDER BY ap.period
  )
  INTO chart_data_result
  FROM all_periods_combined ap
  LEFT JOIN period_aggregation pa ON ap.period = pa.period;

  -- Get top missed opportunities
  WITH ndc_aggregation AS (
    SELECT 
      normalized_ndc,
      original_ndc as ndc_code,
      MAX(product_name) as product_name,
      SUM(quantity)::INTEGER as quantity,
      SUM(full_qty)::INTEGER as full_count,
      SUM(partial_qty)::INTEGER as partial_count,
      ROUND(SUM(credit_amount)::NUMERIC, 2) as actual_earned,
      (array_agg(best_price ORDER BY potential_earnings DESC NULLS LAST))[1] as best_price_per_unit,
      (array_agg(best_distributor_id ORDER BY potential_earnings DESC NULLS LAST))[1] as best_distributor_id,
      (array_agg(best_distributor_name ORDER BY potential_earnings DESC NULLS LAST))[1] as best_distributor_name,
      ROUND(SUM(potential_earnings)::NUMERIC, 2) as potential_earnings
    FROM temp_earnings_comparison
    GROUP BY normalized_ndc, original_ndc
  ),
  missed_opportunities AS (
    SELECT 
      ndc_code,
      product_name,
      quantity,
      full_count,
      partial_count,
      actual_earned,
      best_price_per_unit,
      best_distributor_id,
      best_distributor_name,
      potential_earnings,
      ROUND((potential_earnings - actual_earned)::NUMERIC, 2) as potential_additional_earnings,
      CASE 
        WHEN actual_earned > 0 THEN ROUND(((potential_earnings - actual_earned) / actual_earned * 100)::NUMERIC, 2)
        ELSE 0
      END as percentage_difference,
      (potential_earnings - actual_earned) * 0.6 + 
        CASE WHEN actual_earned > 0 THEN ((potential_earnings - actual_earned) / actual_earned * actual_earned * 0.4) ELSE 0 END as sort_score
    FROM ndc_aggregation
    WHERE potential_earnings - actual_earned > 0.01
  )
  SELECT json_agg(row_data)
  INTO top_missed_result
  FROM (
    SELECT 
      json_build_object(
        'ndcCode', ndc_code,
        'productName', product_name,
        'quantity', quantity,
        'full', full_count,
        'partial', partial_count,
        'actualEarned', actual_earned,
        'bestDistributor', json_build_object(
          'id', COALESCE(best_distributor_id::TEXT, ''),
          'name', COALESCE(best_distributor_name, ''),
          'pricePerUnit', COALESCE(best_price_per_unit, 0),
          'potentialEarnings', potential_earnings
        ),
        'potentialAdditionalEarnings', potential_additional_earnings,
        'percentageDifference', percentage_difference
      ) as row_data
    FROM missed_opportunities
    ORDER BY sort_score DESC
    LIMIT 10
  ) sub;

  -- Get totals
  SELECT 
    COALESCE(ROUND(SUM(credit_amount)::NUMERIC, 2), 0),
    COALESCE(ROUND(SUM(potential_earnings)::NUMERIC, 2), 0)
  INTO total_actual, total_potential
  FROM temp_earnings_comparison;

  total_missed := total_potential - total_actual;
  
  IF total_potential > 0 THEN
    opt_score := ROUND((total_actual / total_potential) * 100)::INTEGER;
  ELSE
    opt_score := 100;
  END IF;
  
  is_optimal := total_missed < 1;

  RETURN json_build_object(
    'summary', json_build_object(
      'totalActualEarnings', total_actual,
      'totalPotentialEarnings', total_potential,
      'totalMissedEarnings', total_missed,
      'optimizationScore', opt_score,
      'isAlreadyOptimal', is_optimal,
      'periodType', p_period_type,
      'dateRange', json_build_object(
        'startDate', p_start_date::TEXT,
        'endDate', p_end_date::TEXT
      )
    ),
    'chartData', COALESCE(chart_data_result, '[]'::JSON),
    'topMissedOpportunities', COALESCE(top_missed_result, '[]'::JSON)
  );
END;
$$;


ALTER FUNCTION public.get_earnings_estimation(p_pharmacy_id uuid, p_period_type text, p_start_date date, p_end_date date) OWNER TO postgres;

--
-- TOC entry 694 (class 1255 OID 148165)
-- Name: get_email_stats(date, date); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_email_stats(p_date_from date DEFAULT NULL::date, p_date_to date DEFAULT NULL::date) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_stats JSONB;
BEGIN
  SELECT jsonb_build_object(
    'total_sent', COUNT(*),
    'delivered', COUNT(*) FILTER (WHERE status = 'delivered'),
    'bounced', COUNT(*) FILTER (WHERE status = 'bounced'),
    'failed', COUNT(*) FILTER (WHERE status = 'failed'),
    'pending', COUNT(*) FILTER (WHERE status = 'sent'),
    'delivery_rate', ROUND(
      (COUNT(*) FILTER (WHERE status = 'delivered')::NUMERIC / 
       NULLIF(COUNT(*), 0) * 100)::NUMERIC, 2
    ),
    'bounce_rate', ROUND(
      (COUNT(*) FILTER (WHERE status = 'bounced')::NUMERIC / 
       NULLIF(COUNT(*), 0) * 100)::NUMERIC, 2
    )
  )
  INTO v_stats
  FROM email_logs
  WHERE (p_date_from IS NULL OR sent_at::date >= p_date_from)
    AND (p_date_to IS NULL OR sent_at::date <= p_date_to);
    
  RETURN v_stats;
END;
$$;


