--
-- TOC entry 509 (class 1255 OID 81562)
-- Name: get_featured_deal(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_featured_deal(p_type text DEFAULT 'day'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_deal JSONB;
  v_manual_deal_id UUID;
  v_manual_deal_expired BOOLEAN;
  v_is_field TEXT;
  v_until_field TEXT;
  v_type_label TEXT;
BEGIN
  -- Validate type
  IF p_type NOT IN ('day', 'week', 'month') THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Invalid type. Must be day, week, or month'
    );
  END IF;

  -- Set field names based on type
  v_type_label := CASE p_type
    WHEN 'day' THEN 'Day'
    WHEN 'week' THEN 'Week'
    WHEN 'month' THEN 'Month'
  END;

  -- First, check for expired manual featured deals and reset them
  IF p_type = 'day' THEN
    UPDATE marketplace_deals
    SET is_deal_of_the_day = FALSE,
        deal_of_the_day_until = NULL,
        updated_at = NOW()
    WHERE is_deal_of_the_day = TRUE
      AND deal_of_the_day_until IS NOT NULL
      AND deal_of_the_day_until < NOW();
      
    -- Get manual deal
    SELECT id, (deal_of_the_day_until IS NOT NULL AND deal_of_the_day_until < NOW())
    INTO v_manual_deal_id, v_manual_deal_expired
    FROM marketplace_deals
    WHERE is_deal_of_the_day = TRUE
      AND status = 'active'
      AND expiry_date >= CURRENT_DATE
      AND quantity > 0
    LIMIT 1;
    
  ELSIF p_type = 'week' THEN
    UPDATE marketplace_deals
    SET is_deal_of_the_week = FALSE,
        deal_of_the_week_until = NULL,
        updated_at = NOW()
    WHERE is_deal_of_the_week = TRUE
      AND deal_of_the_week_until IS NOT NULL
      AND deal_of_the_week_until < NOW();
      
    SELECT id, (deal_of_the_week_until IS NOT NULL AND deal_of_the_week_until < NOW())
    INTO v_manual_deal_id, v_manual_deal_expired
    FROM marketplace_deals
    WHERE is_deal_of_the_week = TRUE
      AND status = 'active'
      AND expiry_date >= CURRENT_DATE
      AND quantity > 0
    LIMIT 1;
    
  ELSIF p_type = 'month' THEN
    UPDATE marketplace_deals
    SET is_deal_of_the_month = FALSE,
        deal_of_the_month_until = NULL,
        updated_at = NOW()
    WHERE is_deal_of_the_month = TRUE
      AND deal_of_the_month_until IS NOT NULL
      AND deal_of_the_month_until < NOW();
      
    SELECT id, (deal_of_the_month_until IS NOT NULL AND deal_of_the_month_until < NOW())
    INTO v_manual_deal_id, v_manual_deal_expired
    FROM marketplace_deals
    WHERE is_deal_of_the_month = TRUE
      AND status = 'active'
      AND expiry_date >= CURRENT_DATE
      AND quantity > 0
    LIMIT 1;
  END IF;

  -- If manual deal exists and not expired, return it
  IF v_manual_deal_id IS NOT NULL AND NOT COALESCE(v_manual_deal_expired, FALSE) THEN
    SELECT jsonb_build_object(
      'id', d.id,
      'dealNumber', d.deal_number,
      'productName', d.product_name,
      'category', d.category,
      'ndc', d.ndc,
      'quantity', d.quantity,
      'originalQuantity', COALESCE(d.original_quantity, d.quantity),
      'soldQuantity', COALESCE(d.original_quantity, d.quantity) - d.quantity,
      'remainingQuantity', d.quantity,
      'minimumBuyQuantity', COALESCE(d.minimum_buy_quantity, 1),
      'unit', d.unit,
      'originalPrice', d.original_price,
      'dealPrice', d.deal_price,
      'savings', ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0),
      'totalSavingsAmount', ROUND((d.original_price - d.deal_price), 2),
      'distributor', d.distributor_name,
      'expiryDate', d.expiry_date,
      'postedDate', d.posted_date,
      'status', d.status,
      'imageUrl', d.image_url,
      'notes', d.notes,
      'isFeaturedDeal', true,
      'featuredDealType', p_type,
      'selectionType', 'manual',
      'featuredUntil', CASE p_type
        WHEN 'day' THEN d.deal_of_the_day_until
        WHEN 'week' THEN d.deal_of_the_week_until
        WHEN 'month' THEN d.deal_of_the_month_until
      END
    )
    INTO v_deal
    FROM marketplace_deals d
    WHERE d.id = v_manual_deal_id;
    
    RETURN jsonb_build_object(
      'error', false,
      'deal', v_deal
    );
  END IF;

  -- No valid manual deal, get automatic selection based on type
  IF p_type = 'day' THEN
    -- Day: Best savings percentage
    SELECT jsonb_build_object(
      'id', d.id,
      'dealNumber', d.deal_number,
      'productName', d.product_name,
      'category', d.category,
      'ndc', d.ndc,
      'quantity', d.quantity,
      'originalQuantity', COALESCE(d.original_quantity, d.quantity),
      'soldQuantity', COALESCE(d.original_quantity, d.quantity) - d.quantity,
      'remainingQuantity', d.quantity,
      'minimumBuyQuantity', COALESCE(d.minimum_buy_quantity, 1),
      'unit', d.unit,
      'originalPrice', d.original_price,
      'dealPrice', d.deal_price,
      'savings', ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0),
      'totalSavingsAmount', ROUND((d.original_price - d.deal_price), 2),
      'distributor', d.distributor_name,
      'expiryDate', d.expiry_date,
      'postedDate', d.posted_date,
      'status', d.status,
      'imageUrl', d.image_url,
      'notes', d.notes,
      'isFeaturedDeal', true,
      'featuredDealType', 'day',
      'selectionType', 'automatic'
    )
    INTO v_deal
    FROM marketplace_deals d
    WHERE d.status = 'active'
      AND d.expiry_date >= CURRENT_DATE
      AND d.quantity > 0
    ORDER BY 
      ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0) DESC,
      d.posted_date DESC
    LIMIT 1;
    
  ELSIF p_type = 'week' THEN
    -- Week: Best savings percentage (excluding deal of the day)
    SELECT jsonb_build_object(
      'id', d.id,
      'dealNumber', d.deal_number,
      'productName', d.product_name,
      'category', d.category,
      'ndc', d.ndc,
      'quantity', d.quantity,
      'originalQuantity', COALESCE(d.original_quantity, d.quantity),
      'soldQuantity', COALESCE(d.original_quantity, d.quantity) - d.quantity,
      'remainingQuantity', d.quantity,
      'minimumBuyQuantity', COALESCE(d.minimum_buy_quantity, 1),
      'unit', d.unit,
      'originalPrice', d.original_price,
      'dealPrice', d.deal_price,
      'savings', ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0),
      'totalSavingsAmount', ROUND((d.original_price - d.deal_price), 2),
      'distributor', d.distributor_name,
      'expiryDate', d.expiry_date,
      'postedDate', d.posted_date,
      'status', d.status,
      'imageUrl', d.image_url,
      'notes', d.notes,
      'isFeaturedDeal', true,
      'featuredDealType', 'week',
      'selectionType', 'automatic'
    )
    INTO v_deal
    FROM marketplace_deals d
    WHERE d.status = 'active'
      AND d.expiry_date >= CURRENT_DATE
      AND d.quantity > 0
      AND d.is_deal_of_the_day = FALSE
    ORDER BY 
      ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0) DESC,
      d.posted_date DESC
    LIMIT 1;
    
  ELSIF p_type = 'month' THEN
    -- Month: Highest total savings potential (excluding day and week)
    SELECT jsonb_build_object(
      'id', d.id,
      'dealNumber', d.deal_number,
      'productName', d.product_name,
      'category', d.category,
      'ndc', d.ndc,
      'quantity', d.quantity,
      'originalQuantity', COALESCE(d.original_quantity, d.quantity),
      'soldQuantity', COALESCE(d.original_quantity, d.quantity) - d.quantity,
      'remainingQuantity', d.quantity,
      'minimumBuyQuantity', COALESCE(d.minimum_buy_quantity, 1),
      'unit', d.unit,
      'originalPrice', d.original_price,
      'dealPrice', d.deal_price,
      'savings', ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0),
      'totalSavingsAmount', ROUND((d.original_price - d.deal_price), 2),
      'distributor', d.distributor_name,
      'expiryDate', d.expiry_date,
      'postedDate', d.posted_date,
      'status', d.status,
      'imageUrl', d.image_url,
      'notes', d.notes,
      'isFeaturedDeal', true,
      'featuredDealType', 'month',
      'selectionType', 'automatic'
    )
    INTO v_deal
    FROM marketplace_deals d
    WHERE d.status = 'active'
      AND d.expiry_date >= CURRENT_DATE
      AND d.quantity > 0
      AND d.is_deal_of_the_day = FALSE
      AND d.is_deal_of_the_week = FALSE
    ORDER BY 
      (d.original_price - d.deal_price) * d.quantity DESC,
      d.posted_date DESC
    LIMIT 1;
  END IF;

  IF v_deal IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'No active deals available for Deal of the ' || v_type_label
    );
  END IF;
  
  RETURN jsonb_build_object(
    'error', false,
    'deal', v_deal
  );
END;
$$;


ALTER FUNCTION public.get_featured_deal(p_type text) OWNER TO postgres;

--
-- TOC entry 770 (class 1255 OID 81566)
-- Name: get_featured_deal_info(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_featured_deal_info(p_type text DEFAULT 'day'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_manual_deal JSONB;
  v_type_label TEXT;
BEGIN
  -- Validate type
  IF p_type NOT IN ('day', 'week', 'month') THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Invalid type. Must be day, week, or month'
    );
  END IF;

  v_type_label := CASE p_type
    WHEN 'day' THEN 'Day'
    WHEN 'week' THEN 'Week'
    WHEN 'month' THEN 'Month'
  END;

  -- Get manual selection based on type
  IF p_type = 'day' THEN
    SELECT jsonb_build_object(
      'id', d.id,
      'dealNumber', d.deal_number,
      'productName', d.product_name,
      'isFeatured', d.is_deal_of_the_day,
      'featuredUntil', d.deal_of_the_day_until,
      'isExpired', d.deal_of_the_day_until IS NOT NULL AND d.deal_of_the_day_until < NOW(),
      'type', 'day',
      'selectionType', 'manual'
    )
    INTO v_manual_deal
    FROM marketplace_deals d
    WHERE d.is_deal_of_the_day = TRUE
    LIMIT 1;
    
  ELSIF p_type = 'week' THEN
    SELECT jsonb_build_object(
      'id', d.id,
      'dealNumber', d.deal_number,
      'productName', d.product_name,
      'isFeatured', d.is_deal_of_the_week,
      'featuredUntil', d.deal_of_the_week_until,
      'isExpired', d.deal_of_the_week_until IS NOT NULL AND d.deal_of_the_week_until < NOW(),
      'type', 'week',
      'selectionType', 'manual'
    )
    INTO v_manual_deal
    FROM marketplace_deals d
    WHERE d.is_deal_of_the_week = TRUE
    LIMIT 1;
    
  ELSIF p_type = 'month' THEN
    SELECT jsonb_build_object(
      'id', d.id,
      'dealNumber', d.deal_number,
      'productName', d.product_name,
      'isFeatured', d.is_deal_of_the_month,
      'featuredUntil', d.deal_of_the_month_until,
      'isExpired', d.deal_of_the_month_until IS NOT NULL AND d.deal_of_the_month_until < NOW(),
      'type', 'month',
      'selectionType', 'manual'
    )
    INTO v_manual_deal
    FROM marketplace_deals d
    WHERE d.is_deal_of_the_month = TRUE
    LIMIT 1;
  END IF;

  RETURN jsonb_build_object(
    'type', p_type,
    'typeLabel', v_type_label,
    'deal', get_featured_deal(p_type),
    'manualDeal', v_manual_deal,
    'hasManualSelection', v_manual_deal IS NOT NULL
  );
END;
$$;


ALTER FUNCTION public.get_featured_deal_info(p_type text) OWNER TO postgres;

--
-- TOC entry 772 (class 1255 OID 44480)
-- Name: get_historical_earnings(uuid, text, date, date); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_historical_earnings(p_pharmacy_id uuid, p_period_type text, p_start_date date, p_end_date date) RETURNS json
    LANGUAGE plpgsql
    AS $$
DECLARE
  period_earnings_result JSON;
  distributor_earnings_result JSON;
  total_earnings_val NUMERIC;
  total_documents_val INTEGER;
  avg_period_earnings NUMERIC;
  periods_with_earnings INTEGER;
BEGIN
  IF p_period_type = 'yearly' THEN
    WITH years AS (
      SELECT generate_series(
        EXTRACT(YEAR FROM p_start_date)::INTEGER,
        EXTRACT(YEAR FROM p_end_date)::INTEGER
      ) as year
    ),
    earnings AS (
      SELECT 
        EXTRACT(YEAR FROM report_date)::INTEGER as year,
        ROUND(SUM(total_credit_amount)::NUMERIC, 2) as earnings,
        COUNT(*)::INTEGER as documents_count
      FROM uploaded_documents
      WHERE pharmacy_id = p_pharmacy_id
        AND report_date >= p_start_date
        AND report_date <= p_end_date
        AND total_credit_amount IS NOT NULL
      GROUP BY EXTRACT(YEAR FROM report_date)
    )
    SELECT json_agg(
      json_build_object(
        'period', y.year::TEXT,
        'label', y.year::TEXT,
        'earnings', COALESCE(e.earnings, 0),
        'documentsCount', COALESCE(e.documents_count, 0)
      ) ORDER BY y.year
    )
    INTO period_earnings_result
    FROM years y
    LEFT JOIN earnings e ON y.year = e.year;
  ELSE
    WITH months AS (
      SELECT 
        TO_CHAR(d::DATE, 'YYYY-MM') as period,
        TRIM(TO_CHAR(d::DATE, 'Month')) || ' ' || EXTRACT(YEAR FROM d::DATE)::TEXT as label,
        d::DATE as month_date
      FROM generate_series(
        DATE_TRUNC('month', p_start_date),
        DATE_TRUNC('month', p_end_date),
        '1 month'::INTERVAL
      ) d
    ),
    earnings AS (
      SELECT 
        TO_CHAR(report_date, 'YYYY-MM') as period,
        ROUND(SUM(total_credit_amount)::NUMERIC, 2) as earnings,
        COUNT(*)::INTEGER as documents_count
      FROM uploaded_documents
      WHERE pharmacy_id = p_pharmacy_id
        AND report_date >= p_start_date
        AND report_date <= p_end_date
        AND total_credit_amount IS NOT NULL
      GROUP BY TO_CHAR(report_date, 'YYYY-MM')
    )
    SELECT json_agg(
      json_build_object(
        'period', m.period,
        'label', m.label,
        'earnings', COALESCE(e.earnings, 0),
        'documentsCount', COALESCE(e.documents_count, 0)
      ) ORDER BY m.period
    )
    INTO period_earnings_result
    FROM months m
    LEFT JOIN earnings e ON m.period = e.period;
  END IF;

  SELECT json_agg(
    json_build_object(
      'distributorId', distributor_id,
      'distributorName', distributor_name,
      'totalEarnings', total_earnings,
      'documentsCount', documents_count
    ) ORDER BY total_earnings DESC
  )
  INTO distributor_earnings_result
  FROM (
    SELECT 
      ud.reverse_distributor_id as distributor_id,
      COALESCE(rd.name, 'Unknown Distributor') as distributor_name,
      ROUND(SUM(ud.total_credit_amount)::NUMERIC, 2) as total_earnings,
      COUNT(*)::INTEGER as documents_count
    FROM uploaded_documents ud
    LEFT JOIN reverse_distributors rd ON ud.reverse_distributor_id = rd.id
    WHERE ud.pharmacy_id = p_pharmacy_id
      AND ud.report_date >= p_start_date
      AND ud.report_date <= p_end_date
      AND ud.total_credit_amount IS NOT NULL
      AND ud.reverse_distributor_id IS NOT NULL
    GROUP BY ud.reverse_distributor_id, rd.name
  ) sub;

  SELECT 
    COALESCE(ROUND(SUM(total_credit_amount)::NUMERIC, 2), 0),
    COALESCE(COUNT(*), 0)
  INTO total_earnings_val, total_documents_val
  FROM uploaded_documents
  WHERE pharmacy_id = p_pharmacy_id
    AND report_date >= p_start_date
    AND report_date <= p_end_date
    AND total_credit_amount IS NOT NULL;

  SELECT COUNT(*)
  INTO periods_with_earnings
  FROM json_array_elements(period_earnings_result) elem
  WHERE (elem->>'earnings')::NUMERIC > 0;

  IF periods_with_earnings > 0 THEN
    avg_period_earnings := ROUND(total_earnings_val / periods_with_earnings, 2);
  ELSE
    avg_period_earnings := 0;
  END IF;

  RETURN json_build_object(
    'periodEarnings', COALESCE(period_earnings_result, '[]'::JSON),
    'totalEarnings', total_earnings_val,
    'averagePeriodEarnings', avg_period_earnings,
    'totalDocuments', total_documents_val,
    'byDistributor', COALESCE(distributor_earnings_result, '[]'::JSON),
    'period', json_build_object(
      'startDate', p_start_date::TEXT,
      'endDate', p_end_date::TEXT,
      'type', p_period_type,
      'periods', CASE 
        WHEN p_period_type = 'yearly' THEN 
          EXTRACT(YEAR FROM p_end_date)::INTEGER - EXTRACT(YEAR FROM p_start_date)::INTEGER
        ELSE
          (EXTRACT(YEAR FROM p_end_date) - EXTRACT(YEAR FROM p_start_date)) * 12 +
          EXTRACT(MONTH FROM p_end_date) - EXTRACT(MONTH FROM p_start_date)
      END
    )
  );
END;
$$;


ALTER FUNCTION public.get_historical_earnings(p_pharmacy_id uuid, p_period_type text, p_start_date date, p_end_date date) OWNER TO postgres;

--
-- TOC entry 754 (class 1255 OID 149354)
-- Name: get_inbox_processing_stats(date, date); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_inbox_processing_stats(p_date_from date DEFAULT NULL::date, p_date_to date DEFAULT NULL::date) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_stats JSONB;
BEGIN
  SELECT jsonb_build_object(
    'total_processed',   COUNT(*),
    'ra_updated',        COUNT(*) FILTER (WHERE status = 'updated'),
    'already_received',  COUNT(*) FILTER (WHERE status = 'already_received'),
    'no_memo_found',     COUNT(*) FILTER (WHERE status = 'no_memo_found'),
    'no_ra_found',       COUNT(*) FILTER (WHERE status = 'no_ra_found'),
    'memo_not_in_db',    COUNT(*) FILTER (WHERE status = 'memo_not_in_db'),
    'update_failed',     COUNT(*) FILTER (WHERE status = 'update_failed'),
    'errors',            COUNT(*) FILTER (WHERE status = 'error'),
    'avg_confidence',    ROUND(COALESCE(AVG(ai_confidence) FILTER (WHERE extracted_ra_number IS NOT NULL), 0)::NUMERIC, 2),
    'success_rate',      CASE
      WHEN COUNT(*) FILTER (WHERE memo_number IS NOT NULL) > 0
      THEN ROUND(
        (COUNT(*) FILTER (WHERE status = 'updated')::NUMERIC /
         NULLIF(COUNT(*) FILTER (WHERE memo_number IS NOT NULL), 0) * 100
        )::NUMERIC, 2)
      ELSE 0
    END
  )
  INTO v_stats
  FROM processed_inbox_emails
  WHERE (p_date_from IS NULL OR processed_at::date >= p_date_from)
    AND (p_date_to IS NULL OR processed_at::date <= p_date_to);

  RETURN v_stats;
END;
$$;


