--
-- TOC entry 845 (class 1255 OID 105438)
-- Name: get_inventory_item_pricing(text[], integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_inventory_item_pricing(p_ndc_codes text[], p_limit integer DEFAULT 100) RETURNS TABLE(ndc_code text, ndc_normalized text, product_name text, distributor_id uuid, distributor_name text, full_price numeric, partial_price numeric, report_date date, email text, phone text, location text)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  WITH normalized_ndcs AS (
    SELECT 
      unnest(p_ndc_codes) AS original_ndc,
      regexp_replace(unnest(p_ndc_codes), '-', '', 'g') AS norm_ndc
  ),
  latest_prices AS (
    SELECT DISTINCT ON (rr.ndc_normalized, rr.distributor_name)
      rr.ndc_code,
      rr.ndc_normalized,
      rr.item_name AS product_name,
      rd.id AS distributor_id,
      rr.distributor_name,
      CASE WHEN rr.item_full > 0 THEN rr.price_per_unit ELSE 0 END AS full_price,
      CASE WHEN rr.item_partial > 0 THEN rr.price_per_unit ELSE 0 END AS partial_price,
      rr.report_date,
      rd.email,
      rd.phone,
      rd.location
    FROM return_reports rr
    LEFT JOIN reverse_distributors rd ON rd.name = rr.distributor_name
    WHERE rr.ndc_normalized = ANY(SELECT norm_ndc FROM normalized_ndcs)
    ORDER BY rr.ndc_normalized, rr.distributor_name, 
             EXTRACT(EPOCH FROM rr.report_date::timestamp) * 1000 DESC,
             rr.price_per_unit ASC
  )
  SELECT 
    lp.ndc_code::TEXT,
    lp.ndc_normalized::TEXT,
    lp.product_name::TEXT,
    lp.distributor_id,
    lp.distributor_name::TEXT,
    lp.full_price,
    lp.partial_price,
    lp.report_date,
    lp.email::TEXT,
    lp.phone::TEXT,
    lp.location::TEXT
  FROM latest_prices lp
  LIMIT p_limit;
END;
$$;


