--
-- TOC entry 781 (class 1255 OID 144354)
-- Name: get_manifest_data(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_manifest_data(p_transaction_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_txn              return_transactions;
  v_pharmacy         RECORD;
  v_processor_name   TEXT;
  v_returnable_items jsonb;
  v_non_returnable   jsonb;
  v_item_count       INTEGER;
  v_returnable_count INTEGER;
  v_non_ret_count    INTEGER;
  v_returnable_value DECIMAL(12,2);
  v_non_ret_value    DECIMAL(12,2);
  v_has_cii          BOOLEAN;
BEGIN
  -- Fetch the transaction
  SELECT * INTO v_txn FROM return_transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404,
      'message', 'Return transaction not found');
  END IF;

  -- Fetch pharmacy info
  SELECT
    id, pharmacy_name, npi_number, dea_number, phone, email
  INTO v_pharmacy
  FROM pharmacy
  WHERE id = v_txn.pharmacy_id;

  -- Fetch processor name
  SELECT name INTO v_processor_name FROM processors WHERE id = v_txn.processor_id;

  -- Returnable items
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'ndc',              rti.ndc,
      'ndc10',            rti.ndc_10,
      'proprietaryName',  rti.proprietary_name,
      'genericName',      rti.generic_name,
      'manufacturer',     rti.manufacturer,
      'lotNumber',        rti.lot_number,
      'expirationDate',   rti.expiration_date,
      'quantity',         rti.quantity,
      'standardPrice',    rti.standard_price,
      'estimatedValue',   rti.estimated_value,
      'destination',      rti.destination,
      'deaSchedule',      rti.dea_schedule,
      'isPartial',        rti.is_partial,
      'partialPercentage',rti.partial_percentage,
      'strength',         rti.strength,
      'dosageForm',       rti.dosage_form
    ) ORDER BY rti.proprietary_name, rti.ndc
  ), '[]'::jsonb)
  INTO v_returnable_items
  FROM return_transaction_items rti
  WHERE rti.transaction_id = p_transaction_id
    AND rti.return_status = 'returnable';

  -- Non-returnable items
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'ndc',                rti.ndc,
      'ndc10',              rti.ndc_10,
      'proprietaryName',    rti.proprietary_name,
      'genericName',        rti.generic_name,
      'manufacturer',       rti.manufacturer,
      'lotNumber',          rti.lot_number,
      'expirationDate',     rti.expiration_date,
      'quantity',           rti.quantity,
      'standardPrice',      rti.standard_price,
      'estimatedValue',     rti.estimated_value,
      'nonReturnableReason',rti.non_returnable_reason,
      'deaSchedule',        rti.dea_schedule,
      'isPartial',          rti.is_partial,
      'partialPercentage',  rti.partial_percentage,
      'destination',        rti.destination,
      'strength',           rti.strength,
      'dosageForm',         rti.dosage_form
    ) ORDER BY rti.proprietary_name, rti.ndc
  ), '[]'::jsonb)
  INTO v_non_returnable
  FROM return_transaction_items rti
  WHERE rti.transaction_id = p_transaction_id
    AND rti.return_status = 'non_returnable';

  -- Counts & values (only returnable + tbd for totalItems)
  SELECT COUNT(*) INTO v_item_count FROM return_transaction_items WHERE transaction_id = p_transaction_id AND return_status IN ('returnable', 'tbd');
  SELECT COUNT(*) INTO v_returnable_count FROM return_transaction_items WHERE transaction_id = p_transaction_id AND return_status = 'returnable';
  v_non_ret_count := 0;
  SELECT COALESCE(SUM(estimated_value), 0) INTO v_returnable_value FROM return_transaction_items WHERE transaction_id = p_transaction_id AND return_status = 'returnable';
  v_non_ret_value := 0;

  -- Check if CII items exist
  SELECT EXISTS(
    SELECT 1 FROM return_transaction_items
    WHERE transaction_id = p_transaction_id
      AND dea_form_222_required = true
  ) INTO v_has_cii;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'transaction', jsonb_build_object(
        'id',                      v_txn.id,
        'licensePlate',            v_txn.license_plate,
        'status',                  v_txn.status,
        'fedexTracking',           v_txn.fedex_tracking,
        'fedexPickupConfirmation', v_txn.fedex_pickup_confirmation,
        'boxCount',                v_txn.box_count,
        'serviceType',             v_txn.service_type,
        'timeIn',                  v_txn.time_in,
        'timeOut',                 v_txn.time_out,
        'finalizedAt',             v_txn.finalized_at,
        'notes',                   v_txn.notes,
        'createdAt',               v_txn.created_at
      ),
      'pharmacy', jsonb_build_object(
        'id',           v_pharmacy.id,
        'name',         v_pharmacy.pharmacy_name,
        'npiNumber',    v_pharmacy.npi_number,
        'deaNumber',    v_pharmacy.dea_number,
        'phone',        v_pharmacy.phone,
        'email',        v_pharmacy.email
      ),
      'processor', jsonb_build_object(
        'id',   v_txn.processor_id,
        'name', v_processor_name
      ),
      'summary', jsonb_build_object(
        'totalItems',             v_item_count,
        'returnableCount',        v_returnable_count,
        'nonReturnableCount',     v_non_ret_count,
        'totalReturnableValue',   v_returnable_value,
        'totalNonReturnableValue',v_non_ret_value,
        'totalValue',             v_returnable_value + v_non_ret_value,
        'hasCiiItems',            v_has_cii
      ),
      'returnableItems',    v_returnable_items,
      'nonReturnableItems', v_non_returnable
    )
  );
END;
$$;


ALTER FUNCTION public.get_manifest_data(p_transaction_id uuid) OWNER TO postgres;

--
-- TOC entry 477 (class 1255 OID 81597)
-- Name: get_manual_featured_deal(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_manual_featured_deal(p_type text DEFAULT 'day'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_manual_deal_id UUID;
  v_manual_deal_expired BOOLEAN := FALSE;
  v_deal JSONB;
BEGIN
  -- Validate type
  IF p_type NOT IN ('day', 'week', 'month') THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Invalid type. Must be day, week, or month'
    );
  END IF;

  -- Clean up expired deals first
  IF p_type = 'day' THEN
    UPDATE marketplace_deals
    SET is_deal_of_the_day = FALSE,
        deal_of_the_day_until = NULL,
        updated_at = NOW()
    WHERE is_deal_of_the_day = TRUE
      AND deal_of_the_day_until IS NOT NULL
      AND deal_of_the_day_until < NOW();
      
    SELECT id, (deal_of_the_day_until IS NOT NULL AND deal_of_the_day_until < NOW())
    INTO v_manual_deal_id, v_manual_deal_expired
    FROM marketplace_deals
    WHERE is_deal_of_the_day = TRUE
      AND status = 'active'
      AND expiry_date >= CURRENT_DATE
      AND quantity > 0
    LIMIT 1;
    
  ELSIF p_type = 'week' THEN
    UPDATE marketplace_deals
    SET is_deal_of_the_week = FALSE,
        deal_of_the_week_until = NULL,
        updated_at = NOW()
    WHERE is_deal_of_the_week = TRUE
      AND deal_of_the_week_until IS NOT NULL
      AND deal_of_the_week_until < NOW();
      
    SELECT id, (deal_of_the_week_until IS NOT NULL AND deal_of_the_week_until < NOW())
    INTO v_manual_deal_id, v_manual_deal_expired
    FROM marketplace_deals
    WHERE is_deal_of_the_week = TRUE
      AND status = 'active'
      AND expiry_date >= CURRENT_DATE
      AND quantity > 0
    LIMIT 1;
    
  ELSIF p_type = 'month' THEN
    UPDATE marketplace_deals
    SET is_deal_of_the_month = FALSE,
        deal_of_the_month_until = NULL,
        updated_at = NOW()
    WHERE is_deal_of_the_month = TRUE
      AND deal_of_the_month_until IS NOT NULL
      AND deal_of_the_month_until < NOW();
      
    SELECT id, (deal_of_the_month_until IS NOT NULL AND deal_of_the_month_until < NOW())
    INTO v_manual_deal_id, v_manual_deal_expired
    FROM marketplace_deals
    WHERE is_deal_of_the_month = TRUE
      AND status = 'active'
      AND expiry_date >= CURRENT_DATE
      AND quantity > 0
    LIMIT 1;
  END IF;

  -- If no manual deal exists or it's expired, return null
  IF v_manual_deal_id IS NULL OR COALESCE(v_manual_deal_expired, FALSE) THEN
    RETURN jsonb_build_object(
      'error', false,
      'deal', null
    );
  END IF;

  -- Return the manual deal
  SELECT jsonb_build_object(
    'id', d.id,
    'dealNumber', d.deal_number,
    'productName', d.product_name,
    'category', d.category,
    'ndc', d.ndc,
    'quantity', d.quantity,
    'originalQuantity', COALESCE(d.original_quantity, d.quantity),
    'soldQuantity', COALESCE(d.original_quantity, d.quantity) - d.quantity,
    'remainingQuantity', d.quantity,
    'minimumBuyQuantity', COALESCE(d.minimum_buy_quantity, 1),
    'unit', d.unit,
    'originalPrice', d.original_price,
    'dealPrice', d.deal_price,
    'savings', ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0),
    'totalSavingsAmount', ROUND((d.original_price - d.deal_price), 2),
    'distributor', d.distributor_name,
    'expiryDate', d.expiry_date,
    'postedDate', d.posted_date,
    'status', d.status,
    'imageUrl', d.image_url,
    'notes', d.notes,
    'isFeaturedDeal', true,
    'featuredDealType', p_type,
    'selectionType', 'manual',
    'featuredUntil', CASE p_type
      WHEN 'day' THEN d.deal_of_the_day_until
      WHEN 'week' THEN d.deal_of_the_week_until
      WHEN 'month' THEN d.deal_of_the_month_until
    END
  )
  INTO v_deal
  FROM marketplace_deals d
  WHERE d.id = v_manual_deal_id;
  
  RETURN jsonb_build_object(
    'error', false,
    'deal', v_deal
  );
END;
$$;


ALTER FUNCTION public.get_manual_featured_deal(p_type text) OWNER TO postgres;

--
-- TOC entry 897 (class 1255 OID 68666)
-- Name: get_marketplace_categories(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_marketplace_categories() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_categories JSONB;
BEGIN
  SELECT COALESCE(
    jsonb_agg(
      jsonb_build_object(
        'value', category,
        'label', category,
        'count', count
      )
      ORDER BY count DESC, category
    ),
    '[]'::jsonb
  )
  INTO v_categories
  FROM (
    SELECT category, COUNT(*)::INTEGER as count
    FROM marketplace_deals
    GROUP BY category
  ) sub;
  
  RETURN jsonb_build_object(
    'categories', v_categories
  );
END;
$$;


ALTER FUNCTION public.get_marketplace_categories() OWNER TO postgres;

--
-- TOC entry 505 (class 1255 OID 70359)
-- Name: get_marketplace_deal_by_id(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_marketplace_deal_by_id(p_deal_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_deal JSONB;
BEGIN
  SELECT jsonb_build_object(
    'id', d.id,
    'dealNumber', d.deal_number,
    'productName', d.product_name,
    'category', d.category,
    'ndc', d.ndc,
    'quantity', d.quantity,
    'originalQuantity', COALESCE(d.original_quantity, d.quantity),
    'soldQuantity', COALESCE(d.original_quantity, d.quantity) - d.quantity,
    'remainingQuantity', d.quantity,
    'minimumBuyQuantity', COALESCE(d.minimum_buy_quantity, 1),
    'unit', d.unit,
    'originalPrice', d.original_price,
    'dealPrice', d.deal_price,
    'savings', ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0),
    'margin', ROUND((d.deal_price / d.original_price * 100), 0),
    'distributorId', d.distributor_id,
    'distributor', d.distributor_name,
    'expiryDate', d.expiry_date,
    'postedDate', d.posted_date,
    'status', d.status,
    'notes', d.notes,
    'imageUrl', d.image_url,
    'createdBy', d.created_by,
    'createdAt', d.created_at,
    'updatedAt', d.updated_at,
    'isDealOfTheDay', COALESCE(d.is_deal_of_the_day, false),
    'dealOfTheDayUntil', d.deal_of_the_day_until,
    'isDealOfTheWeek', COALESCE(d.is_deal_of_the_week, false),
    'dealOfTheWeekUntil', d.deal_of_the_week_until,
    'isDealOfTheMonth', COALESCE(d.is_deal_of_the_month, false),
    'dealOfTheMonthUntil', d.deal_of_the_month_until
  )
  INTO v_deal
  FROM marketplace_deals d
  WHERE d.id = p_deal_id;
  
  IF v_deal IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Deal not found'
    );
  END IF;
  
  RETURN jsonb_build_object(
    'error', false,
    'deal', v_deal
  );
END;
$$;


ALTER FUNCTION public.get_marketplace_deal_by_id(p_deal_id uuid) OWNER TO postgres;

--
-- TOC entry 492 (class 1255 OID 70357)
-- Name: get_marketplace_deals_list(integer, integer, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_marketplace_deals_list(p_page integer DEFAULT 1, p_limit integer DEFAULT 12, p_search text DEFAULT NULL::text, p_category text DEFAULT NULL::text, p_status text DEFAULT NULL::text, p_sort_by text DEFAULT 'posted_date'::text, p_sort_order text DEFAULT 'desc'::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_offset INTEGER;
  v_total INTEGER;
  v_deals JSONB;
  v_stats JSONB;
  v_total_deals INTEGER;
  v_active_deals INTEGER;
  v_sold_deals INTEGER;
  v_expired_deals INTEGER;
  v_total_items BIGINT;
  v_categories JSONB;
BEGIN
  -- Calculate offset
  v_offset := (p_page - 1) * p_limit;
  
  -- First, update any expired deals
  UPDATE marketplace_deals
  SET status = 'expired', updated_at = NOW()
  WHERE status = 'active' AND expiry_date < CURRENT_DATE;
  
  -- Expire any manual featured deals that have passed their expiration
  UPDATE marketplace_deals
  SET is_deal_of_the_day = FALSE,
      deal_of_the_day_until = NULL,
      updated_at = NOW()
  WHERE is_deal_of_the_day = TRUE
    AND deal_of_the_day_until IS NOT NULL
    AND deal_of_the_day_until < NOW();
    
  UPDATE marketplace_deals
  SET is_deal_of_the_week = FALSE,
      deal_of_the_week_until = NULL,
      updated_at = NOW()
  WHERE is_deal_of_the_week = TRUE
    AND deal_of_the_week_until IS NOT NULL
    AND deal_of_the_week_until < NOW();
    
  UPDATE marketplace_deals
  SET is_deal_of_the_month = FALSE,
      deal_of_the_month_until = NULL,
      updated_at = NOW()
  WHERE is_deal_of_the_month = TRUE
    AND deal_of_the_month_until IS NOT NULL
    AND deal_of_the_month_until < NOW();
  
  -- ============================================================
  -- STATS: Calculate statistics
  -- ============================================================
  
  -- Total deals
  SELECT COUNT(*)::INTEGER INTO v_total_deals FROM marketplace_deals;
  
  -- Active deals
  SELECT COUNT(*)::INTEGER INTO v_active_deals FROM marketplace_deals WHERE status = 'active';
  
  -- Sold deals
  SELECT COUNT(*)::INTEGER INTO v_sold_deals FROM marketplace_deals WHERE status = 'sold';
  
  -- Expired deals
  SELECT COUNT(*)::INTEGER INTO v_expired_deals FROM marketplace_deals WHERE status = 'expired';
  
  -- Total items (sum of quantities)
  SELECT COALESCE(SUM(quantity), 0)::BIGINT INTO v_total_items FROM marketplace_deals;
  
  -- Get unique categories
  SELECT COALESCE(jsonb_agg(DISTINCT category ORDER BY category), '[]'::jsonb)
  INTO v_categories
  FROM marketplace_deals;
  
  v_stats := jsonb_build_object(
    'totalDeals', v_total_deals,
    'activeDeals', v_active_deals,
    'soldDeals', v_sold_deals,
    'expiredDeals', v_expired_deals,
    'totalItems', v_total_items,
    'categories', v_categories
  );
  
  -- ============================================================
  -- COUNT: Get total matching records
  -- ============================================================
  
  SELECT COUNT(*)::INTEGER
  INTO v_total
  FROM marketplace_deals d
  WHERE 
    -- Search filter
    (p_search IS NULL OR p_search = '' OR
      d.product_name ILIKE '%' || p_search || '%' OR
      d.distributor_name ILIKE '%' || p_search || '%' OR
      d.deal_number ILIKE '%' || p_search || '%' OR
      d.category ILIKE '%' || p_search || '%')
    -- Category filter
    AND (p_category IS NULL OR p_category = '' OR p_category = 'all' OR d.category = p_category)
    -- Status filter
    AND (p_status IS NULL OR p_status = '' OR p_status = 'all' OR d.status = p_status);
  
  -- ============================================================
  -- FETCH: Get deals with dynamic sorting
  -- ============================================================
  
  SELECT COALESCE(jsonb_agg(deal_row), '[]'::jsonb)
  INTO v_deals
  FROM (
    SELECT jsonb_build_object(
      'id', d.id,
      'dealNumber', d.deal_number,
      'productName', d.product_name,
      'category', d.category,
      'ndc', d.ndc,
      'quantity', d.quantity,
      'originalQuantity', COALESCE(d.original_quantity, d.quantity),
      'soldQuantity', COALESCE(d.original_quantity, d.quantity) - d.quantity,
      'remainingQuantity', d.quantity,
      'minimumBuyQuantity', COALESCE(d.minimum_buy_quantity, 1),
      'unit', d.unit,
      'originalPrice', d.original_price,
      'dealPrice', d.deal_price,
      'savings', ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0),
      'margin', ROUND((d.deal_price / d.original_price * 100), 0),
      'distributorId', d.distributor_id,
      'distributor', d.distributor_name,
      'expiryDate', d.expiry_date,
      'postedDate', d.posted_date,
      'status', d.status,
      'notes', d.notes,
      'imageUrl', d.image_url,
      'createdBy', d.created_by,
      'createdAt', d.created_at,
      'updatedAt', d.updated_at,
      'isDealOfTheDay', COALESCE(d.is_deal_of_the_day, false),
      'dealOfTheDayUntil', d.deal_of_the_day_until,
      'isDealOfTheWeek', COALESCE(d.is_deal_of_the_week, false),
      'dealOfTheWeekUntil', d.deal_of_the_week_until,
      'isDealOfTheMonth', COALESCE(d.is_deal_of_the_month, false),
      'dealOfTheMonthUntil', d.deal_of_the_month_until
    ) AS deal_row
    FROM marketplace_deals d
    WHERE 
      -- Search filter
      (p_search IS NULL OR p_search = '' OR
        d.product_name ILIKE '%' || p_search || '%' OR
        d.distributor_name ILIKE '%' || p_search || '%' OR
        d.deal_number ILIKE '%' || p_search || '%' OR
        d.category ILIKE '%' || p_search || '%')
      -- Category filter
      AND (p_category IS NULL OR p_category = '' OR p_category = 'all' OR d.category = p_category)
      -- Status filter
      AND (p_status IS NULL OR p_status = '' OR p_status = 'all' OR d.status = p_status)
    ORDER BY
      CASE WHEN p_sort_order = 'desc' THEN
        CASE p_sort_by
          WHEN 'product_name' THEN d.product_name
          WHEN 'category' THEN d.category
          WHEN 'distributor' THEN d.distributor_name
          WHEN 'status' THEN d.status
          WHEN 'posted_date' THEN d.posted_date::TEXT
          WHEN 'expiry_date' THEN d.expiry_date::TEXT
          WHEN 'deal_price' THEN LPAD(d.deal_price::TEXT, 20, '0')
          WHEN 'quantity' THEN LPAD(d.quantity::TEXT, 20, '0')
          ELSE d.posted_date::TEXT
        END
      END DESC NULLS LAST,
      CASE WHEN p_sort_order = 'asc' THEN
        CASE p_sort_by
          WHEN 'product_name' THEN d.product_name
          WHEN 'category' THEN d.category
          WHEN 'distributor' THEN d.distributor_name
          WHEN 'status' THEN d.status
          WHEN 'posted_date' THEN d.posted_date::TEXT
          WHEN 'expiry_date' THEN d.expiry_date::TEXT
          WHEN 'deal_price' THEN LPAD(d.deal_price::TEXT, 20, '0')
          WHEN 'quantity' THEN LPAD(d.quantity::TEXT, 20, '0')
          ELSE d.posted_date::TEXT
        END
      END ASC NULLS LAST
    LIMIT p_limit
    OFFSET v_offset
  ) sub;
  
  -- Return result
  RETURN jsonb_build_object(
    'deals', v_deals,
    'stats', v_stats,
    'pagination', jsonb_build_object(
      'page', p_page,
      'limit', p_limit,
      'total', v_total,
      'totalPages', CEIL(v_total::NUMERIC / p_limit)::INTEGER
    )
  );
END;
$$;


ALTER FUNCTION public.get_marketplace_deals_list(p_page integer, p_limit integer, p_search text, p_category text, p_status text, p_sort_by text, p_sort_order text) OWNER TO postgres;

--
-- TOC entry 853 (class 1255 OID 78224)
-- Name: get_marketplace_order_by_id(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_marketplace_order_by_id(p_pharmacy_id uuid, p_order_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_order JSONB;
  v_items JSONB;
BEGIN
  -- Get order (verify it belongs to pharmacy)
  SELECT jsonb_build_object(
    'id', o.id,
    'orderNumber', o.order_number,
    'status', o.status,
    'subtotal', o.subtotal,
    'taxAmount', o.tax_amount,
    'taxRate', o.tax_rate,
    'shippingAmount', o.shipping_amount,
    'discountAmount', o.discount_amount,
    'totalAmount', o.total_amount,
    'totalSavings', o.total_savings,
    'paymentMethodType', o.payment_method_type,
    'paymentMethodLast4', o.payment_method_last4,
    'paymentMethodBrand', o.payment_method_brand,
    'stripeReceiptUrl', o.stripe_receipt_url,
    'notes', o.notes,
    'createdAt', o.created_at,
    'paidAt', o.paid_at,
    'shippedAt', o.shipped_at,
    'deliveredAt', o.delivered_at
  )
  INTO v_order
  FROM marketplace_orders o
  WHERE o.id = p_order_id AND o.pharmacy_id = p_pharmacy_id;
  
  IF v_order IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Order not found'
    );
  END IF;
  
  -- Get order items with image from marketplace_deals
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'id', oi.id,
      'dealId', oi.deal_id,
      'productName', oi.product_name,
      'ndc', oi.ndc,
      'category', oi.category,
      'distributor', oi.distributor,
      'quantity', oi.quantity,
      'unitPrice', oi.unit_price,
      'originalPrice', oi.original_price,
      'lineTotal', oi.line_total,
      'lineSavings', oi.line_savings,
      'imageUrl', d.image_url
    )
  ), '[]'::jsonb)
  INTO v_items
  FROM marketplace_order_items oi
  LEFT JOIN marketplace_deals d ON d.id = oi.deal_id
  WHERE oi.order_id = p_order_id;
  
  v_order := v_order || jsonb_build_object('items', v_items);
  
  RETURN jsonb_build_object(
    'error', false,
    'order', v_order
  );
END;
$$;


ALTER FUNCTION public.get_marketplace_order_by_id(p_pharmacy_id uuid, p_order_id uuid) OWNER TO postgres;

--
-- TOC entry 504 (class 1255 OID 68667)
-- Name: get_marketplace_stats(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_marketplace_stats() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_stats JSONB;
BEGIN
  -- First, update any expired deals
  UPDATE marketplace_deals
  SET status = 'expired', updated_at = NOW()
  WHERE status = 'active' AND expiry_date < CURRENT_DATE;
  
  SELECT jsonb_build_object(
    'totalDeals', COUNT(*)::INTEGER,
    'activeDeals', COUNT(*) FILTER (WHERE status = 'active')::INTEGER,
    'soldDeals', COUNT(*) FILTER (WHERE status = 'sold')::INTEGER,
    'expiredDeals', COUNT(*) FILTER (WHERE status = 'expired')::INTEGER,
    'totalItems', COALESCE(SUM(quantity), 0)::BIGINT,
    'totalValue', COALESCE(SUM(deal_price * quantity), 0)::NUMERIC(12,2),
    'avgSavings', COALESCE(AVG(ROUND(((original_price - deal_price) / original_price * 100), 0)), 0)::NUMERIC(5,2)
  )
  INTO v_stats
  FROM marketplace_deals;
  
  RETURN v_stats;
END;
$$;


ALTER FUNCTION public.get_marketplace_stats() OWNER TO postgres;

--
-- TOC entry 575 (class 1255 OID 156232)
-- Name: get_ndc_pricing(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_ndc_pricing(p_ndc text) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_norm TEXT;
  v_row  ndc_pricing;
BEGIN
  v_norm := LOWER(REPLACE(TRIM(p_ndc), '-', ''));
  IF LENGTH(v_norm) < 10 THEN
    v_norm := LPAD(v_norm, 11, '0');
  END IF;

  SELECT * INTO v_row FROM ndc_pricing WHERE ndc_normalized = v_norm;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'NDC pricing not found');
  END IF;

  RETURN jsonb_build_object('error', false, 'data', _ndc_pricing_to_json(v_row));
END;
$$;


ALTER FUNCTION public.get_ndc_pricing(p_ndc text) OWNER TO postgres;

--
-- TOC entry 620 (class 1255 OID 101570)
-- Name: get_ndc_pricing_index(integer, integer, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_ndc_pricing_index(p_limit integer DEFAULT 10000, p_offset integer DEFAULT 0, p_updated_after timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_results JSONB;
  v_total INTEGER;
BEGIN
  SELECT COUNT(DISTINCT ndc_normalized)::INTEGER INTO v_total
  FROM ndc_pricing_index
  WHERE p_updated_after IS NULL OR updated_at > p_updated_after;

  -- IMPORTANT: Use COALESCE(report_date, uploaded_at, created_at) for ordering
  -- This matches the optimization API's fallback chain for determining "latest" prices
  WITH unique_ndcs AS (
    SELECT DISTINCT ON (ndc_normalized)
      ndc_original,
      ndc_normalized,
      product_name
    FROM ndc_pricing_index
    WHERE p_updated_after IS NULL OR updated_at > p_updated_after
    ORDER BY ndc_normalized, COALESCE(report_date::timestamp, uploaded_at, source_created_at) DESC NULLS LAST
    LIMIT p_limit
    OFFSET p_offset
  ),
  aggregated AS (
    SELECT 
      u.ndc_original,
      u.ndc_normalized,
      u.product_name,
      (
        -- CRITICAL: Group by distributor_name (NOT distributor_id) - same as optimization API
        SELECT jsonb_agg(
          jsonb_build_object(
            'id', d.distributor_id,
            'name', d.distributor_name,
            'email', d.distributor_email,
            'phone', d.distributor_phone,
            'location', d.distributor_location,
            -- CRITICAL FIX: Add ORDER BY to get LATEST price (same as optimization API)
            'fullPrice', COALESCE(
              (SELECT price_per_unit FROM ndc_pricing_index 
               WHERE ndc_normalized = u.ndc_normalized 
                 AND distributor_name = d.distributor_name 
                 AND is_full_record = TRUE
               ORDER BY COALESCE(report_date::timestamp, uploaded_at, source_created_at) DESC NULLS LAST,
                        source_report_id ASC
               LIMIT 1), 0
            ),
            -- CRITICAL FIX: Add ORDER BY to get LATEST price (same as optimization API)
            'partialPrice', COALESCE(
              (SELECT price_per_unit FROM ndc_pricing_index 
               WHERE ndc_normalized = u.ndc_normalized 
                 AND distributor_name = d.distributor_name 
                 AND is_partial_record = TRUE
               ORDER BY COALESCE(report_date::timestamp, uploaded_at, source_created_at) DESC NULLS LAST,
                        source_report_id ASC
               LIMIT 1), 0
            )
          ) ORDER BY d.price_per_unit DESC NULLS LAST
        )
        FROM (
          SELECT DISTINCT ON (distributor_name) *
          FROM ndc_pricing_index
          WHERE ndc_normalized = u.ndc_normalized
          ORDER BY distributor_name, COALESCE(report_date::timestamp, uploaded_at, source_created_at) DESC NULLS LAST
        ) d
      ) AS distributors,
      -- CRITICAL FIX: Get max of LATEST prices per distributor, not max of ALL prices
      (SELECT MAX(latest_price) FROM (
        SELECT DISTINCT ON (distributor_name) price_per_unit AS latest_price
        FROM ndc_pricing_index 
        WHERE ndc_normalized = u.ndc_normalized AND is_full_record = TRUE
        ORDER BY distributor_name, 
                 COALESCE(report_date::timestamp, uploaded_at, source_created_at) DESC NULLS LAST,
                 source_report_id ASC
      ) sub) AS best_full_price,
      -- CRITICAL FIX: Get max of LATEST prices per distributor, not max of ALL prices
      (SELECT MAX(latest_price) FROM (
        SELECT DISTINCT ON (distributor_name) price_per_unit AS latest_price
        FROM ndc_pricing_index 
        WHERE ndc_normalized = u.ndc_normalized AND is_partial_record = TRUE
        ORDER BY distributor_name, 
                 COALESCE(report_date::timestamp, uploaded_at, source_created_at) DESC NULLS LAST,
                 source_report_id ASC
      ) sub) AS best_partial_price,
      (SELECT MAX(updated_at) FROM ndc_pricing_index WHERE ndc_normalized = u.ndc_normalized) AS last_updated
    FROM unique_ndcs u
  )
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'ndc', a.ndc_original,
      'ndcNormalized', a.ndc_normalized,
      'productName', a.product_name,
      'distributors', COALESCE(a.distributors, '[]'::jsonb),
      'bestFullPrice', COALESCE(a.best_full_price, 0),
      'bestPartialPrice', COALESCE(a.best_partial_price, 0),
      'lastUpdated', a.last_updated
    )
  ), '[]'::jsonb) INTO v_results
  FROM aggregated a;

  RETURN jsonb_build_object(
    'data', v_results,
    'total', v_total,
    'limit', p_limit,
    'offset', p_offset
  );
END;
$$;


ALTER FUNCTION public.get_ndc_pricing_index(p_limit integer, p_offset integer, p_updated_after timestamp with time zone) OWNER TO postgres;

--
-- TOC entry 714 (class 1255 OID 52052)
-- Name: get_package_recommendations(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_package_recommendations(p_pharmacy_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result JSONB;
    v_total_products INTEGER := 0;
BEGIN
    -- =====================================================
    -- SECURITY: Check pharmacy status (block suspended/blacklisted)
    -- =====================================================
    PERFORM check_pharmacy_status(p_pharmacy_id);
    
    -- =====================================================
    -- STEP 1: Get all product_list_items for this pharmacy
    -- =====================================================
    
    DROP TABLE IF EXISTS temp_product_items;
    CREATE TEMP TABLE temp_product_items AS
    SELECT 
        pli.id AS product_id,
        pli.ndc,
        REPLACE(COALESCE(pli.ndc::TEXT, ''), '-', '') AS normalized_ndc,
        pli.product_name,
        COALESCE(pli.full_units, 0) AS full_units,
        COALESCE(pli.partial_units, 0) AS partial_units,
        -- Determine what price type this item needs based on inventory
        (COALESCE(pli.partial_units, 0) = 0 AND COALESCE(pli.full_units, 0) > 0) AS needs_full_price,
        (COALESCE(pli.full_units, 0) = 0 AND COALESCE(pli.partial_units, 0) > 0) AS needs_partial_price
    FROM product_list_items pli
    WHERE pli.added_by = p_pharmacy_id;
    
    -- Get total products count
    SELECT COUNT(*) INTO v_total_products FROM temp_product_items;
    
    -- Return empty if no products
    IF v_total_products = 0 THEN
        RETURN jsonb_build_object(
            'packages', '[]'::JSONB,
            'totalProducts', 0,
            'totalPackages', 0,
            'totalEstimatedValue', 0,
            'generatedAt', NOW(),
            'summary', jsonb_build_object(
                'productsWithPricing', 0,
                'productsWithoutPricing', 0,
                'distributorsUsed', 0
            )
        );
    END IF;
    
    -- =====================================================
    -- STEP 2: Extract pricing from return_reports
    -- Get FULL and PARTIAL prices separately
    -- NOTE: Each row in return_reports has data as a single item object
    -- =====================================================
    
    DROP TABLE IF EXISTS temp_all_prices;
    CREATE TEMP TABLE temp_all_prices AS
    WITH report_items AS (
        SELECT 
            rd.id AS distributor_id,
            rd.name AS distributor_name,
            ud.report_date,
            -- data column IS the item directly (not data->'items')
            REPLACE(COALESCE(rr.data->>'ndcCode', rr.data->>'ndc', ''), '-', '') AS normalized_ndc,
            COALESCE((rr.data->>'full')::INTEGER, 0) AS item_full,
            COALESCE((rr.data->>'partial')::INTEGER, 0) AS item_partial,
            COALESCE(
                (rr.data->>'pricePerUnit')::NUMERIC,
                CASE 
                    WHEN COALESCE((rr.data->>'quantity')::INTEGER, 1) > 0 
                    THEN COALESCE((rr.data->>'creditAmount')::NUMERIC, 0) / GREATEST(COALESCE((rr.data->>'quantity')::INTEGER, 1), 1)
                    ELSE 0 
                END
            ) AS price_per_unit
        FROM return_reports rr
        JOIN uploaded_documents ud ON rr.document_id = ud.id
        JOIN reverse_distributors rd ON ud.reverse_distributor_id = rd.id
        WHERE COALESCE(rr.data->>'ndcCode', rr.data->>'ndc') IS NOT NULL
    )
    SELECT 
        ri.distributor_id,
        ri.distributor_name,
        ri.normalized_ndc,
        ri.report_date,
        ri.price_per_unit,
        ri.item_full,
        ri.item_partial,
        -- Is this a FULL price record? (full > 0 AND partial = 0)
        (ri.item_full > 0 AND ri.item_partial = 0) AS is_full_record,
        -- Is this a PARTIAL price record? (partial > 0 AND full = 0)  
        (ri.item_partial > 0 AND ri.item_full = 0) AS is_partial_record
    FROM report_items ri
    WHERE ri.price_per_unit > 0
    AND ri.normalized_ndc IN (SELECT normalized_ndc FROM temp_product_items);
    
    -- =====================================================
    -- STEP 3: Get latest FULL price per distributor-NDC
    -- =====================================================
    
    DROP TABLE IF EXISTS temp_latest_full_prices;
    CREATE TEMP TABLE temp_latest_full_prices AS
    SELECT DISTINCT ON (distributor_id, normalized_ndc)
        distributor_id,
        distributor_name,
        normalized_ndc,
        price_per_unit AS full_price
    FROM temp_all_prices
    WHERE is_full_record = true
    ORDER BY distributor_id, normalized_ndc, report_date DESC;
    
    -- =====================================================
    -- STEP 4: Get latest PARTIAL price per distributor-NDC
    -- =====================================================
    
    DROP TABLE IF EXISTS temp_latest_partial_prices;
    CREATE TEMP TABLE temp_latest_partial_prices AS
    SELECT DISTINCT ON (distributor_id, normalized_ndc)
        distributor_id,
        distributor_name,
        normalized_ndc,
        price_per_unit AS partial_price
    FROM temp_all_prices
    WHERE is_partial_record = true
    ORDER BY distributor_id, normalized_ndc, report_date DESC;
    
    -- =====================================================
    -- STEP 5: Get best price per NDC (matching unit type)
    -- For full items, use full price. For partial items, use partial price.
    -- =====================================================
    
    DROP TABLE IF EXISTS temp_best_prices;
    CREATE TEMP TABLE temp_best_prices AS
    WITH ndc_distributor_prices AS (
        SELECT 
            ti.product_id,
            ti.ndc,
            ti.normalized_ndc,
            ti.product_name,
            ti.full_units,
            ti.partial_units,
            ti.needs_full_price,
            ti.needs_partial_price,
            -- Use COALESCE to get distributor from whichever price table matches
            COALESCE(lfp.distributor_id, lpp.distributor_id) AS distributor_id,
            COALESCE(lfp.distributor_name, lpp.distributor_name) AS distributor_name,
            -- Use the appropriate price based on what the inventory item needs
            CASE 
                WHEN ti.needs_full_price THEN lfp.full_price
                WHEN ti.needs_partial_price THEN lpp.partial_price
                ELSE COALESCE(lfp.full_price, lpp.partial_price)
            END AS price_per_unit
        FROM temp_product_items ti
        LEFT JOIN temp_latest_full_prices lfp 
            ON lfp.normalized_ndc = ti.normalized_ndc
            AND (ti.needs_full_price OR (NOT ti.needs_full_price AND NOT ti.needs_partial_price))
        LEFT JOIN temp_latest_partial_prices lpp 
            ON lpp.normalized_ndc = ti.normalized_ndc
            AND (ti.needs_partial_price OR (NOT ti.needs_full_price AND NOT ti.needs_partial_price))
        WHERE 
            (ti.needs_full_price AND lfp.full_price IS NOT NULL)
            OR (ti.needs_partial_price AND lpp.partial_price IS NOT NULL)
            OR (NOT ti.needs_full_price AND NOT ti.needs_partial_price AND (lfp.full_price IS NOT NULL OR lpp.partial_price IS NOT NULL))
    ),
    -- Rank distributors by price (highest = best) for each product
    ranked_distributors AS (
        SELECT 
            ndp.*,
            ROW_NUMBER() OVER (PARTITION BY ndp.product_id ORDER BY ndp.price_per_unit DESC) AS rank
        FROM ndc_distributor_prices ndp
        WHERE ndp.price_per_unit IS NOT NULL AND ndp.price_per_unit > 0
    )
    -- Select only the best distributor for each product
    SELECT *
    FROM ranked_distributors
    WHERE rank = 1;
    
    -- =====================================================
    -- STEP 6: Get product_ids that already exist in custom packages
    -- These will be EXCLUDED from recommendations entirely
    -- =====================================================
    
    DROP TABLE IF EXISTS temp_existing_product_ids;
    CREATE TEMP TABLE temp_existing_product_ids AS
    SELECT DISTINCT cpi.product_id
    FROM custom_package_items cpi
    JOIN custom_packages cp ON cp.id = cpi.package_id
    WHERE cp.pharmacy_id = p_pharmacy_id
    AND cpi.product_id IS NOT NULL;
    
    -- =====================================================
    -- STEP 7: Build final result
    -- =====================================================
    
    WITH 
    -- Get all distributors with contact info and fee_rates
    all_distributors AS (
        SELECT 
            rd.id AS distributor_id,
            rd.name AS distributor_name,
            rd.contact_email,
            rd.contact_phone,
            NULLIF(TRIM(CONCAT_WS(', ',
                NULLIF(rd.address->>'street', ''),
                NULLIF(rd.address->>'city', ''),
                NULLIF(rd.address->>'state', ''),
                NULLIF(rd.address->>'zipCode', ''),
                NULLIF(rd.address->>'country', '')
            )), '') AS location,
            rd.fee_rates
        FROM reverse_distributors rd
    ),
    
    -- Filter out products that already exist in custom packages
    filtered_products AS (
        SELECT 
            bp.product_id,
            bp.ndc,
            bp.product_name,
            bp.full_units AS new_full,
            bp.partial_units AS new_partial,
            (bp.full_units + bp.partial_units) AS new_total,
            bp.distributor_id,
            bp.distributor_name,
            bp.price_per_unit
        FROM temp_best_prices bp
        WHERE bp.product_id NOT IN (SELECT product_id FROM temp_existing_product_ids)
    ),
    
    -- Aggregate products by distributor
    distributor_packages AS (
        SELECT 
            fp.distributor_id,
            fp.distributor_name,
            ad.contact_email,
            ad.contact_phone,
            ad.location,
            ad.fee_rates,
            jsonb_agg(
                jsonb_build_object(
                    'ndc', fp.ndc,
                    'productId', fp.product_id,
                    'productName', fp.product_name,
                    'full', fp.new_full,
                    'partial', fp.new_partial,
                    'pricePerUnit', ROUND(fp.price_per_unit, 2),
                    'totalValue', ROUND(fp.price_per_unit * fp.new_total, 2)
                )
            ) AS products,
            SUM(fp.new_total)::INTEGER AS total_items,
            ROUND(SUM(fp.price_per_unit * fp.new_total), 2) AS total_estimated_value,
            COUNT(*) AS product_count
        FROM filtered_products fp
        LEFT JOIN all_distributors ad ON ad.distributor_id = fp.distributor_id
        GROUP BY fp.distributor_id, fp.distributor_name, ad.contact_email, ad.contact_phone, ad.location, ad.fee_rates
    ),
    
    -- Build packages array
    packages_json AS (
        SELECT jsonb_agg(
            jsonb_build_object(
                'distributorName', dp.distributor_name,
                'distributorId', dp.distributor_id,
                'distributorContact', jsonb_build_object(
                    'email', dp.contact_email,
                    'phone', dp.contact_phone,
                    'location', dp.location,
                    'feeRates', dp.fee_rates
                ),
                'products', dp.products,
                'totalItems', dp.total_items,
                'totalEstimatedValue', dp.total_estimated_value,
                'averagePricePerUnit', CASE WHEN dp.total_items > 0 THEN ROUND(dp.total_estimated_value / dp.total_items, 2) ELSE 0 END
            ) ORDER BY dp.total_estimated_value DESC
        ) AS packages
        FROM distributor_packages dp
    ),
    
    -- Calculate summary
    summary_data AS (
        SELECT 
            (SELECT COUNT(DISTINCT product_id) FROM temp_best_prices) AS products_with_pricing,
            v_total_products - (SELECT COUNT(DISTINCT product_id) FROM temp_best_prices) AS products_without_pricing,
            (SELECT COUNT(DISTINCT distributor_id) FROM filtered_products) AS distributors_used,
            COALESCE((SELECT SUM(total_estimated_value) FROM distributor_packages), 0) AS total_value,
            (SELECT COUNT(*) FROM distributor_packages) AS total_packages
        FROM (SELECT 1) AS dummy
    )
    
    -- Build final result
    SELECT jsonb_build_object(
        'packages', COALESCE((SELECT packages FROM packages_json), '[]'::JSONB),
        'totalProducts', v_total_products,
        'totalPackages', (SELECT total_packages FROM summary_data)::INTEGER,
        'totalEstimatedValue', ROUND((SELECT total_value FROM summary_data), 2),
        'generatedAt', NOW(),
        'summary', jsonb_build_object(
            'productsWithPricing', (SELECT products_with_pricing FROM summary_data)::INTEGER,
            'productsWithoutPricing', (SELECT products_without_pricing FROM summary_data)::INTEGER,
            'distributorsUsed', (SELECT distributors_used FROM summary_data)::INTEGER
        )
    ) INTO v_result;
    
    -- =====================================================
    -- CLEANUP
    -- =====================================================
    
    DROP TABLE IF EXISTS temp_product_items;
    DROP TABLE IF EXISTS temp_all_prices;
    DROP TABLE IF EXISTS temp_latest_full_prices;
    DROP TABLE IF EXISTS temp_latest_partial_prices;
    DROP TABLE IF EXISTS temp_best_prices;
    DROP TABLE IF EXISTS temp_existing_product_ids;
    
    RETURN v_result;
END;
$$;


