-- Name: list_memos_for_group_shipping(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.list_memos_for_group_shipping(p_destination text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_rows jsonb;
BEGIN
  SELECT COALESCE(jsonb_agg(_debit_memo_to_json(d) ORDER BY d.destination, d.created_at), '[]'::jsonb)
  INTO v_rows
  FROM debit_memos d
  WHERE d.ra_status = 'received'
    AND d.shipped_at IS NULL
    AND d.shipment_group_id IS NULL
    AND d.ra_number IS NOT NULL
    AND TRIM(d.ra_number) != ''
    AND (p_destination IS NULL OR LOWER(d.destination) = LOWER(p_destination));

  RETURN jsonb_build_object(
    'error', false,
    'data', v_rows
  );
END;
$$;


ALTER FUNCTION public.list_memos_for_group_shipping(p_destination text) OWNER TO postgres;

--
-- TOC entry 868 (class 1255 OID 163235)
-- Name: list_pharmacy_roles(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.list_pharmacy_roles(p_parent_pharmacy_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_roles  JSONB;
  v_role   RECORD;
  v_result JSONB := '[]'::jsonb;
  v_perms  JSONB;
  v_count  BIGINT;
BEGIN
  FOR v_role IN
    SELECT id, role_name, description, is_default, created_at, updated_at
    FROM pharmacy_roles
    WHERE parent_pharmacy_id = p_parent_pharmacy_id
    ORDER BY created_at ASC
  LOOP
    SELECT COALESCE(jsonb_agg(pp.permission_key ORDER BY pp.sort_order), '[]'::jsonb)
    INTO v_perms
    FROM pharmacy_role_permissions rp
    JOIN pharmacy_permissions pp ON pp.id = rp.permission_id
    WHERE rp.role_id = v_role.id;

    SELECT COUNT(*) INTO v_count
    FROM pharmacy_branch_role_assignments WHERE role_id = v_role.id;

    v_result := v_result || jsonb_build_object(
      'id',              v_role.id,
      'roleName',        v_role.role_name,
      'description',     v_role.description,
      'isDefault',       v_role.is_default,
      'permissions',     v_perms,
      'assignedCount',   v_count,
      'createdAt',       v_role.created_at,
      'updatedAt',       v_role.updated_at
    );
  END LOOP;

  RETURN jsonb_build_object('error', false, 'data', jsonb_build_object('roles', v_result));
END;
$$;


