--
-- TOC entry 679 (class 1255 OID 142999)
-- Name: list_return_transaction_items(uuid, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.list_return_transaction_items(p_transaction_id uuid, p_return_status text DEFAULT NULL::text, p_search text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_items  jsonb;
  v_total  INT;
  v_ret_val DECIMAL;
  v_nonret_val DECIMAL;
BEGIN
  -- Verify transaction exists
  IF NOT EXISTS (SELECT 1 FROM return_transactions WHERE id = p_transaction_id) THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Return transaction not found');
  END IF;

  SELECT
    COALESCE(jsonb_agg(_rti_to_json(rti) ORDER BY rti.created_at DESC), '[]'::jsonb),
    COUNT(*),
    COALESCE(SUM(CASE WHEN rti.return_status = 'returnable' THEN rti.estimated_value ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN rti.return_status = 'non_returnable' THEN rti.estimated_value ELSE 0 END), 0)
  INTO v_items, v_total, v_ret_val, v_nonret_val
  FROM return_transaction_items rti
  WHERE rti.transaction_id = p_transaction_id
    AND (p_return_status IS NULL OR rti.return_status = p_return_status)
    AND (p_search IS NULL
         OR rti.ndc ILIKE '%' || p_search || '%'
         OR rti.proprietary_name ILIKE '%' || p_search || '%'
         OR rti.manufacturer ILIKE '%' || p_search || '%'
         OR rti.lot_number ILIKE '%' || p_search || '%');

  RETURN jsonb_build_object(
    'items', v_items,
    'summary', jsonb_build_object(
      'totalItems',             v_total,
      'totalReturnableValue',   v_ret_val,
      'totalNonReturnableValue', v_nonret_val,
      'totalValue',             v_ret_val + v_nonret_val
    )
  );
END;
$$;


ALTER FUNCTION public.list_return_transaction_items(p_transaction_id uuid, p_return_status text, p_search text) OWNER TO postgres;

--
-- TOC entry 678 (class 1255 OID 142872)
-- Name: list_return_transactions(uuid, uuid, text, text, text, text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.list_return_transactions(p_pharmacy_id uuid DEFAULT NULL::uuid, p_processor_id uuid DEFAULT NULL::uuid, p_status text DEFAULT NULL::text, p_date_from text DEFAULT NULL::text, p_date_to text DEFAULT NULL::text, p_search text DEFAULT NULL::text, p_page integer DEFAULT 1, p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_offset   INT;
  v_total    INT;
  v_rows     jsonb;
BEGIN
  v_offset := (GREATEST(p_page, 1) - 1) * LEAST(p_limit, 100);

  -- Count
  SELECT COUNT(*) INTO v_total
    FROM return_transactions rt
   WHERE (p_pharmacy_id  IS NULL OR rt.pharmacy_id  = p_pharmacy_id)
     AND (p_processor_id IS NULL OR rt.processor_id = p_processor_id)
     AND (p_status       IS NULL OR rt.status       = p_status)
     AND (p_date_from    IS NULL OR rt.created_at  >= p_date_from::timestamptz)
     AND (p_date_to      IS NULL OR rt.created_at  <= p_date_to::timestamptz)
     AND (p_search       IS NULL OR rt.license_plate ILIKE '%' || p_search || '%');

  -- Data
  SELECT COALESCE(jsonb_agg(row_json ORDER BY created_at DESC), '[]'::jsonb)
    INTO v_rows
    FROM (
      SELECT _rt_to_json(rt) AS row_json, rt.created_at
        FROM return_transactions rt
       WHERE (p_pharmacy_id  IS NULL OR rt.pharmacy_id  = p_pharmacy_id)
         AND (p_processor_id IS NULL OR rt.processor_id = p_processor_id)
         AND (p_status       IS NULL OR rt.status       = p_status)
         AND (p_date_from    IS NULL OR rt.created_at  >= p_date_from::timestamptz)
         AND (p_date_to      IS NULL OR rt.created_at  <= p_date_to::timestamptz)
         AND (p_search       IS NULL OR rt.license_plate ILIKE '%' || p_search || '%')
       ORDER BY rt.created_at DESC
       LIMIT LEAST(p_limit, 100) OFFSET v_offset
    ) sub;

  RETURN jsonb_build_object(
    'transactions', v_rows,
    'pagination', jsonb_build_object(
      'page',       GREATEST(p_page, 1),
      'limit',      LEAST(p_limit, 100),
      'total',      v_total,
      'totalPages', CEIL(v_total::numeric / LEAST(p_limit, 100))
    )
  );
END;
$$;


ALTER FUNCTION public.list_return_transactions(p_pharmacy_id uuid, p_processor_id uuid, p_status text, p_date_from text, p_date_to text, p_search text, p_page integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 539 (class 1255 OID 158944)
-- Name: list_shipped_shipment_groups(integer, integer, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.list_shipped_shipment_groups(p_page integer DEFAULT 1, p_limit integer DEFAULT 20, p_destination text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_offset INTEGER;
  v_total  INTEGER;
  v_rows   jsonb;
  v_dest   TEXT := NULLIF(TRIM(COALESCE(p_destination, '')), '');
  v_lim    INTEGER := GREATEST(COALESCE(NULLIF(p_limit, 0), 20), 1);
BEGIN
  v_offset := (GREATEST(COALESCE(p_page, 1), 1) - 1) * v_lim;

  SELECT COUNT(*) INTO v_total
  FROM shipment_groups sg
  WHERE (
      sg.shipped_at IS NOT NULL
      OR (NULLIF(TRIM(COALESCE(sg.outbound_tracking, '')), '') IS NOT NULL)
    )
    AND (v_dest IS NULL OR LOWER(TRIM(COALESCE(sg.destination, ''))) = LOWER(v_dest));

  SELECT COALESCE(jsonb_agg(row_json ORDER BY shipped_sort DESC NULLS LAST), '[]'::jsonb)
  INTO v_rows
  FROM (
    SELECT
      jsonb_build_object(
        'group', _shipment_group_to_json(sg),
        'memos', (
          SELECT COALESCE(jsonb_agg(_debit_memo_to_json(d) ORDER BY d.created_at), '[]'::jsonb)
          FROM debit_memos d WHERE d.shipment_group_id = sg.id
        )
      ) AS row_json,
      COALESCE(sg.shipped_at, sg.updated_at) AS shipped_sort
    FROM shipment_groups sg
    WHERE (
        sg.shipped_at IS NOT NULL
        OR (NULLIF(TRIM(COALESCE(sg.outbound_tracking, '')), '') IS NOT NULL)
      )
      AND (v_dest IS NULL OR LOWER(TRIM(COALESCE(sg.destination, ''))) = LOWER(v_dest))
    ORDER BY COALESCE(sg.shipped_at, sg.updated_at) DESC
    LIMIT v_lim OFFSET v_offset
  ) sub;

  RETURN jsonb_build_object(
    'error', false,
    'data', v_rows,
    'pagination', jsonb_build_object(
      'page', GREATEST(COALESCE(p_page, 1), 1),
      'limit', v_lim,
      'total', v_total,
      'totalPages', CEIL(v_total::float / v_lim)::integer
    )
  );
END;
$$;


ALTER FUNCTION public.list_shipped_shipment_groups(p_page integer, p_limit integer, p_destination text) OWNER TO postgres;

--
-- TOC entry 629 (class 1255 OID 144332)
-- Name: list_wine_cellar_items(uuid, text, text, text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.list_wine_cellar_items(p_pharmacy_id uuid DEFAULT NULL::uuid, p_status text DEFAULT NULL::text, p_search text DEFAULT NULL::text, p_expected_month text DEFAULT NULL::text, p_page integer DEFAULT 1, p_limit integer DEFAULT 50) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_offset         INT;
  v_total          INT;
  v_rows           jsonb;
  v_total_shelved  INT;
  v_total_ready    INT;
  v_total_value    DECIMAL(12,2);
  v_month_start    DATE;
  v_month_end      DATE;
BEGIN
  v_offset := (GREATEST(p_page, 1) - 1) * LEAST(p_limit, 100);

  -- Parse expected_month filter
  IF p_expected_month IS NOT NULL AND p_expected_month <> '' THEN
    v_month_start := (p_expected_month || '-01')::DATE;
    v_month_end   := (v_month_start + INTERVAL '1 month')::DATE;
  END IF;

  -- Count total matching
  SELECT COUNT(*) INTO v_total
    FROM wine_cellar w
   WHERE (p_pharmacy_id IS NULL OR w.pharmacy_id = p_pharmacy_id)
     AND (p_status IS NULL      OR w.status = p_status)
     AND (p_search IS NULL      OR p_search = '' OR (
           w.ndc            ILIKE '%' || p_search || '%' OR
           w.product_name   ILIKE '%' || p_search || '%' OR
           w.manufacturer   ILIKE '%' || p_search || '%' OR
           w.lot_number     ILIKE '%' || p_search || '%' OR
           w.baggie_barcode ILIKE '%' || p_search || '%'
         ))
     AND (v_month_start IS NULL OR (
           w.expected_returnable_date >= v_month_start
           AND w.expected_returnable_date < v_month_end
         ));

  -- Fetch rows
  SELECT COALESCE(jsonb_agg(row_json ORDER BY date_shelved DESC), '[]'::jsonb)
    INTO v_rows
    FROM (
      SELECT _wc_to_json(w) AS row_json, w.date_shelved
        FROM wine_cellar w
       WHERE (p_pharmacy_id IS NULL OR w.pharmacy_id = p_pharmacy_id)
         AND (p_status IS NULL      OR w.status = p_status)
         AND (p_search IS NULL      OR p_search = '' OR (
               w.ndc            ILIKE '%' || p_search || '%' OR
               w.product_name   ILIKE '%' || p_search || '%' OR
               w.manufacturer   ILIKE '%' || p_search || '%' OR
               w.lot_number     ILIKE '%' || p_search || '%' OR
               w.baggie_barcode ILIKE '%' || p_search || '%'
             ))
         AND (v_month_start IS NULL OR (
               w.expected_returnable_date >= v_month_start
               AND w.expected_returnable_date < v_month_end
             ))
       ORDER BY w.date_shelved DESC
       LIMIT LEAST(p_limit, 100)
      OFFSET v_offset
    ) sub;

  -- Summary stats (across ALL matching, not just current page)
  SELECT
    COALESCE(COUNT(*) FILTER (WHERE w.status = 'shelved'), 0),
    COALESCE(COUNT(*) FILTER (WHERE w.status = 'ready_to_return'), 0),
    COALESCE(SUM(w.estimated_value) FILTER (WHERE w.status IN ('shelved', 'ready_to_return')), 0)
  INTO v_total_shelved, v_total_ready, v_total_value
    FROM wine_cellar w
   WHERE (p_pharmacy_id IS NULL OR w.pharmacy_id = p_pharmacy_id)
     AND (p_status IS NULL      OR w.status = p_status)
     AND (p_search IS NULL      OR p_search = '' OR (
           w.ndc            ILIKE '%' || p_search || '%' OR
           w.product_name   ILIKE '%' || p_search || '%' OR
           w.manufacturer   ILIKE '%' || p_search || '%' OR
           w.lot_number     ILIKE '%' || p_search || '%' OR
           w.baggie_barcode ILIKE '%' || p_search || '%'
         ))
     AND (v_month_start IS NULL OR (
           w.expected_returnable_date >= v_month_start
           AND w.expected_returnable_date < v_month_end
         ));

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'items',   v_rows,
      'summary', jsonb_build_object(
        'totalItems',   v_total,
        'totalShelved', v_total_shelved,
        'totalReady',   v_total_ready,
        'totalValue',   v_total_value
      ),
      'pagination', jsonb_build_object(
        'page',       GREATEST(p_page, 1),
        'limit',      LEAST(p_limit, 100),
        'total',      v_total,
        'totalPages', CEIL(v_total::DECIMAL / LEAST(p_limit, 100))
      )
    )
  );
END;
$$;


ALTER FUNCTION public.list_wine_cellar_items(p_pharmacy_id uuid, p_status text, p_search text, p_expected_month text, p_page integer, p_limit integer) OWNER TO postgres;

