--
-- TOC entry 879 (class 1255 OID 169440)
-- Name: mark_admin_activity_read(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.mark_admin_activity_read(p_activity_id uuid, p_buying_group_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_pharmacy_created_by UUID;
    v_activity_exists BOOLEAN;
BEGIN
    -- Find the activity and verify buying group access
    SELECT p.created_by, TRUE
    INTO v_pharmacy_created_by, v_activity_exists
    FROM admin_recent_activity a
    INNER JOIN pharmacy p ON a.pharmacy_id = p.id
    WHERE a.id = p_activity_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', FALSE,
            'message', 'Activity not found'
        );
    END IF;

    -- Check buying group access (MainAdmin with p_buying_group_id=NULL can access all)
    IF p_buying_group_id IS NOT NULL AND v_pharmacy_created_by <> p_buying_group_id THEN
        RETURN jsonb_build_object(
            'success', FALSE,
            'message', 'Access denied'
        );
    END IF;
    
    -- Update activity to read
    UPDATE admin_recent_activity
    SET is_read = TRUE,
        read_at = NOW()
    WHERE id = p_activity_id;
    
    RETURN jsonb_build_object(
        'success', TRUE,
        'message', 'Activity marked as read',
        'activityId', p_activity_id,
        'markedAt', NOW()
    );
END;
$$;


ALTER FUNCTION public.mark_admin_activity_read(p_activity_id uuid, p_buying_group_id uuid) OWNER TO postgres;

--
-- TOC entry 823 (class 1255 OID 169439)
-- Name: mark_all_admin_activities_read(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.mark_all_admin_activities_read(p_buying_group_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_updated_count INTEGER;
BEGIN
    -- Update all unread activities to read (scoped to buying group)
    UPDATE admin_recent_activity
    SET is_read = TRUE,
        read_at = NOW()
    WHERE (is_read = FALSE OR is_read IS NULL)
    AND (
        p_buying_group_id IS NULL OR 
        pharmacy_id IN (
            SELECT id FROM pharmacy WHERE created_by = p_buying_group_id
        )
    );
    
    -- Get the number of rows updated
    GET DIAGNOSTICS v_updated_count = ROW_COUNT;
    
    RETURN jsonb_build_object(
        'success', TRUE,
        'message', 'All activities marked as read',
        'updatedCount', v_updated_count,
        'markedAt', NOW()
    );
END;
$$;


ALTER FUNCTION public.mark_all_admin_activities_read(p_buying_group_id uuid) OWNER TO postgres;

--
-- TOC entry 737 (class 1255 OID 68668)
-- Name: mark_marketplace_deal_sold(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.mark_marketplace_deal_sold(p_deal_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_current_status TEXT;
BEGIN
  -- Check if deal exists and get current status
  SELECT status INTO v_current_status FROM marketplace_deals WHERE id = p_deal_id;
  
  IF v_current_status IS NULL THEN
    RETURN jsonb_build_object('error', true, 'message', 'Deal not found');
  END IF;
  
  IF v_current_status = 'sold' THEN
    RETURN jsonb_build_object('error', true, 'message', 'Deal is already marked as sold');
  END IF;
  
  IF v_current_status = 'expired' THEN
    RETURN jsonb_build_object('error', true, 'message', 'Cannot sell an expired deal');
  END IF;
  
  -- Update status to sold
  UPDATE marketplace_deals
  SET status = 'sold', updated_at = NOW()
  WHERE id = p_deal_id;
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Deal marked as sold successfully'
  );
END;
$$;


ALTER FUNCTION public.mark_marketplace_deal_sold(p_deal_id uuid) OWNER TO postgres;

--
-- TOC entry 608 (class 1255 OID 144335)
-- Name: mark_wine_cellar_returned(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.mark_wine_cellar_returned(p_id uuid, p_transaction_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_row wine_cellar;
BEGIN
  SELECT * INTO v_row FROM wine_cellar WHERE id = p_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Wine cellar item not found');
  END IF;

  IF v_row.status NOT IN ('shelved', 'ready_to_return') THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Cannot return item with status "%s". Only shelved or ready_to_return items can be returned.', v_row.status));
  END IF;

  -- Validate transaction exists if provided
  IF p_transaction_id IS NOT NULL THEN
    IF NOT EXISTS (SELECT 1 FROM return_transactions WHERE id = p_transaction_id) THEN
      RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Return transaction not found');
    END IF;
  END IF;

  UPDATE wine_cellar SET
    status                     = 'returned',
    returned_in_transaction_id = p_transaction_id,
    returned_at                = NOW()
  WHERE id = p_id
  RETURNING * INTO v_row;

  RETURN jsonb_build_object('error', false, 'data', _wc_to_json(v_row));
END;
$$;


ALTER FUNCTION public.mark_wine_cellar_returned(p_id uuid, p_transaction_id uuid) OWNER TO postgres;

--
-- TOC entry 676 (class 1255 OID 145635)
-- Name: payment_ask_vs_received(text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.payment_ask_vs_received(p_group_by text DEFAULT 'manufacturer'::text, p_period text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_rows jsonb;
  v_totals jsonb;
BEGIN
  IF p_group_by = 'manufacturer' THEN
    SELECT COALESCE(jsonb_agg(row_data ORDER BY (row_data->>'totalAskValue')::decimal DESC), '[]'::jsonb)
    INTO v_rows
    FROM (
      SELECT jsonb_build_object(
        'labelerId',      d.labeler_id,
        'labelerName',    COALESCE(d.labeler_name, ''),
        'memoCount',      COUNT(*),
        'totalItems',     SUM(d.total_items),
        'totalAskValue',  SUM(d.amount_requested),
        'totalReceived',  SUM(d.amount_received),
        'difference',     SUM(d.amount_requested) - SUM(d.amount_received),
        'payPercent',     CASE WHEN SUM(d.amount_requested) > 0
                            THEN ROUND(SUM(d.amount_received) / SUM(d.amount_requested) * 100, 2)
                            ELSE 0 END,
        'paidCount',      SUM(CASE WHEN d.payment_status = 'paid' THEN 1 ELSE 0 END),
        'unpaidCount',    SUM(CASE WHEN d.payment_status IN ('pending', 'partial') THEN 1 ELSE 0 END)
      ) AS row_data
      FROM debit_memos d
      WHERE (p_period IS NULL OR TO_CHAR(d.created_at, 'YYYY-MM') = p_period)
      GROUP BY d.labeler_id, d.labeler_name
    ) sub;
  ELSE
    -- Group by month
    SELECT COALESCE(jsonb_agg(row_data ORDER BY row_data->>'period'), '[]'::jsonb)
    INTO v_rows
    FROM (
      SELECT jsonb_build_object(
        'period',         TO_CHAR(d.created_at, 'YYYY-MM'),
        'memoCount',      COUNT(*),
        'totalAskValue',  SUM(d.amount_requested),
        'totalReceived',  SUM(d.amount_received),
        'difference',     SUM(d.amount_requested) - SUM(d.amount_received),
        'payPercent',     CASE WHEN SUM(d.amount_requested) > 0
                            THEN ROUND(SUM(d.amount_received) / SUM(d.amount_requested) * 100, 2)
                            ELSE 0 END
      ) AS row_data
      FROM debit_memos d
      GROUP BY TO_CHAR(d.created_at, 'YYYY-MM')
    ) sub;
  END IF;

  -- Overall totals
  SELECT jsonb_build_object(
    'totalMemos',      COUNT(*),
    'totalAskValue',   COALESCE(SUM(d.amount_requested), 0),
    'totalReceived',   COALESCE(SUM(d.amount_received), 0),
    'totalDifference', COALESCE(SUM(d.amount_requested) - SUM(d.amount_received), 0),
    'overallPayPercent', CASE WHEN SUM(d.amount_requested) > 0
                           THEN ROUND(SUM(d.amount_received) / SUM(d.amount_requested) * 100, 2)
                           ELSE 0 END
  ) INTO v_totals
  FROM debit_memos d
  WHERE (p_period IS NULL OR TO_CHAR(d.created_at, 'YYYY-MM') = p_period);

  RETURN jsonb_build_object(
    'error', false,
    'data', v_rows,
    'totals', v_totals
  );
END;
$$;


ALTER FUNCTION public.payment_ask_vs_received(p_group_by text, p_period text) OWNER TO postgres;

--
-- TOC entry 684 (class 1255 OID 145633)
-- Name: payment_list_unpaid(text, text, text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.payment_list_unpaid(p_manufacturer text DEFAULT NULL::text, p_destination text DEFAULT NULL::text, p_search text DEFAULT NULL::text, p_page integer DEFAULT 1, p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_offset INTEGER;
  v_total  INTEGER;
  v_rows   jsonb;
  v_total_outstanding DECIMAL(12,2);
BEGIN
  v_offset := (GREATEST(p_page, 1) - 1) * p_limit;

  SELECT COUNT(*), COALESCE(SUM(d.amount_requested - d.amount_received), 0)
    INTO v_total, v_total_outstanding
  FROM debit_memos d
  WHERE d.payment_status IN ('pending', 'partial')
    AND (p_manufacturer IS NULL OR LOWER(d.labeler_name) LIKE '%' || LOWER(p_manufacturer) || '%'
         OR d.labeler_id = p_manufacturer)
    AND (p_destination IS NULL OR d.destination = p_destination)
    AND (p_search IS NULL OR (
      LOWER(d.memo_number) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE(d.labeler_name, '')) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE((SELECT pharmacy_name FROM pharmacy WHERE id = d.pharmacy_id), '')) LIKE '%' || LOWER(p_search) || '%'
    ));

  SELECT COALESCE(jsonb_agg(
    _debit_memo_to_json(d) || jsonb_build_object(
      'daysOutstanding', EXTRACT(DAY FROM NOW() - COALESCE(d.ra_requested_at, d.created_at))::integer,
      'outstandingAmount', d.amount_requested - d.amount_received
    )
    ORDER BY COALESCE(d.ra_requested_at, d.created_at)
  ), '[]'::jsonb)
  INTO v_rows
  FROM (
    SELECT d.*
    FROM debit_memos d
    WHERE d.payment_status IN ('pending', 'partial')
      AND (p_manufacturer IS NULL OR LOWER(d.labeler_name) LIKE '%' || LOWER(p_manufacturer) || '%'
           OR d.labeler_id = p_manufacturer)
      AND (p_destination IS NULL OR d.destination = p_destination)
      AND (p_search IS NULL OR (
        LOWER(d.memo_number) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE(d.labeler_name, '')) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE((SELECT pharmacy_name FROM pharmacy WHERE id = d.pharmacy_id), '')) LIKE '%' || LOWER(p_search) || '%'
      ))
    ORDER BY COALESCE(d.ra_requested_at, d.created_at)
    LIMIT p_limit OFFSET v_offset
  ) d;

  RETURN jsonb_build_object(
    'error', false,
    'data', v_rows,
    'pagination', jsonb_build_object(
      'page', p_page, 'limit', p_limit, 'total', v_total,
      'totalPages', CEIL(v_total::float / p_limit)::integer
    ),
    'summary', jsonb_build_object(
      'totalUnpaid', v_total,
      'totalOutstanding', v_total_outstanding
    )
  );
END;
$$;


ALTER FUNCTION public.payment_list_unpaid(p_manufacturer text, p_destination text, p_search text, p_page integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 602 (class 1255 OID 145636)
-- Name: payment_manufacturer_summary(text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.payment_manufacturer_summary(p_search text DEFAULT NULL::text, p_page integer DEFAULT 1, p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_offset INTEGER;
  v_total  INTEGER;
  v_rows   jsonb;
BEGIN
  v_offset := (GREATEST(p_page, 1) - 1) * p_limit;

  SELECT COUNT(DISTINCT labeler_id) INTO v_total
  FROM debit_memos d
  WHERE (p_search IS NULL OR (
    LOWER(COALESCE(d.labeler_name, '')) LIKE '%' || LOWER(p_search) || '%'
    OR d.labeler_id LIKE '%' || p_search || '%'
  ));

  SELECT COALESCE(jsonb_agg(row_data ORDER BY (row_data->>'outstandingAmount')::decimal DESC), '[]'::jsonb)
  INTO v_rows
  FROM (
    SELECT jsonb_build_object(
      'labelerId',         d.labeler_id,
      'labelerName',       COALESCE(MAX(d.labeler_name), ''),
      'totalMemos',        COUNT(*),
      'unpaidMemos',       SUM(CASE WHEN d.payment_status IN ('pending', 'partial') THEN 1 ELSE 0 END),
      'paidMemos',         SUM(CASE WHEN d.payment_status = 'paid' THEN 1 ELSE 0 END),
      'disputedMemos',     SUM(CASE WHEN d.payment_status = 'disputed' THEN 1 ELSE 0 END),
      'totalAskValue',     SUM(d.amount_requested),
      'totalPaidAmount',   SUM(d.amount_received),
      'outstandingAmount', SUM(d.amount_requested) - SUM(d.amount_received),
      'averagePayPercent', CASE WHEN SUM(d.amount_requested) > 0
                             THEN ROUND(SUM(d.amount_received) / SUM(d.amount_requested) * 100, 2)
                             ELSE 0 END,
      'averageDaysToPay',  COALESCE(
        ROUND(AVG(
          CASE WHEN d.payment_received_at IS NOT NULL AND d.ra_requested_at IS NOT NULL
            THEN EXTRACT(DAY FROM d.payment_received_at - d.ra_requested_at)
            ELSE NULL END
        )::numeric, 0)::integer,
        0
      ),
      'policyAvgPayPercent', (
        SELECT mp.average_pay_percent
        FROM manufacturer_policies mp
        WHERE mp.labeler_id = d.labeler_id
        LIMIT 1
      ),
      'policyAvgDaysToPay', (
        SELECT mp.average_days_to_pay
        FROM manufacturer_policies mp
        WHERE mp.labeler_id = d.labeler_id
        LIMIT 1
      )
    ) AS row_data
    FROM debit_memos d
    WHERE (p_search IS NULL OR (
      LOWER(COALESCE(d.labeler_name, '')) LIKE '%' || LOWER(p_search) || '%'
      OR d.labeler_id LIKE '%' || p_search || '%'
    ))
    GROUP BY d.labeler_id
    ORDER BY SUM(d.amount_requested) - SUM(d.amount_received) DESC
    LIMIT p_limit OFFSET v_offset
  ) sub;

  RETURN jsonb_build_object(
    'error', false,
    'data', v_rows,
    'pagination', jsonb_build_object(
      'page', p_page, 'limit', p_limit, 'total', v_total,
      'totalPages', CEIL(v_total::float / p_limit)::integer
    )
  );
END;
$$;


ALTER FUNCTION public.payment_manufacturer_summary(p_search text, p_page integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 724 (class 1255 OID 145632)
-- Name: payment_record(uuid, numeric, timestamp with time zone, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.payment_record(p_debit_memo_id uuid, p_amount_received numeric, p_payment_date timestamp with time zone DEFAULT now(), p_reference text DEFAULT NULL::text, p_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_memo   debit_memos;
  v_status TEXT;
BEGIN
  SELECT * INTO v_memo FROM debit_memos WHERE id = p_debit_memo_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Debit memo not found');
  END IF;

  IF p_amount_received IS NULL OR p_amount_received < 0 THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'amount_received must be >= 0');
  END IF;

  -- Determine payment status based on amounts
  IF p_amount_received >= v_memo.amount_requested AND v_memo.amount_requested > 0 THEN
    v_status := 'paid';
  ELSIF p_amount_received > 0 THEN
    v_status := 'partial';
  ELSE
    v_status := 'pending';
  END IF;

  UPDATE debit_memos SET
    amount_received     = p_amount_received,
    payment_received_at = p_payment_date,
    payment_reference   = COALESCE(NULLIF(TRIM(p_reference), ''), payment_reference),
    payment_notes       = COALESCE(NULLIF(TRIM(p_notes), ''), payment_notes),
    payment_status      = v_status,
    total_received_value = p_amount_received
  WHERE id = p_debit_memo_id
  RETURNING * INTO v_memo;

  RETURN jsonb_build_object(
    'error', false,
    'data', _debit_memo_to_json(v_memo)
  );
END;
$$;


ALTER FUNCTION public.payment_record(p_debit_memo_id uuid, p_amount_received numeric, p_payment_date timestamp with time zone, p_reference text, p_notes text) OWNER TO postgres;

