--
-- TOC entry 503 (class 1255 OID 145634)
-- Name: payment_send_reminder(uuid, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.payment_send_reminder(p_debit_memo_id uuid, p_sent_by text DEFAULT NULL::text, p_email_override text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
  v_memo       debit_memos;
  v_dest_email TEXT;
  v_dest_name  TEXT;
  v_subject    TEXT;
  v_body       TEXT;
  v_request    ra_requests;
BEGIN
  SELECT * INTO v_memo FROM debit_memos WHERE id = p_debit_memo_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Debit memo not found');
  END IF;

  IF v_memo.payment_status = 'paid' THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'This debit memo is already fully paid.');
  END IF;

  IF p_email_override IS NOT NULL AND p_email_override <> '' THEN
    v_dest_email := p_email_override;
  ELSE
    SELECT rd.contact_email, rd.name
      INTO v_dest_email, v_dest_name
      FROM reverse_distributors rd
      WHERE LOWER(rd.name) = LOWER(v_memo.destination)
        AND rd.is_active = true
      LIMIT 1;
  END IF;

  IF v_dest_email IS NULL OR v_dest_email = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'No contact email found for destination "' || COALESCE(v_memo.destination, 'NULL')
        || '". Add a contact_email in reverse_distributors or provide email_override.');
  END IF;

  v_dest_name := COALESCE(v_dest_name, v_memo.labeler_name, '');
  v_subject := 'Payment Reminder — Debit Memo ' || v_memo.memo_number;
  v_body := 'Outstanding amount: $' || TRIM(TO_CHAR(v_memo.amount_requested - v_memo.amount_received, '999,999,990.00'))
    || ' — Original ask: $' || TRIM(TO_CHAR(v_memo.amount_requested, '999,999,990.00'))
    || ' — Pharmacy: ' || COALESCE((SELECT pharmacy_name FROM pharmacy WHERE id = v_memo.pharmacy_id), '');

  INSERT INTO ra_requests (debit_memo_id, request_type, destination_email, destination_name, subject, body_preview, status, sent_by)
  VALUES (p_debit_memo_id, 'reminder', v_dest_email, v_dest_name, v_subject, v_body, 'sent', p_sent_by)
  RETURNING * INTO v_request;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'memo',    _debit_memo_to_json(v_memo),
      'request', _ra_request_to_json(v_request)
    )
  );
END;
$_$;


ALTER FUNCTION public.payment_send_reminder(p_debit_memo_id uuid, p_sent_by text, p_email_override text) OWNER TO postgres;

--
-- TOC entry 895 (class 1255 OID 163371)
-- Name: pharmacy_admin_create_branch(uuid, text, text, text, text, text, text, text, text, text, text, text, text, text, date, text, integer, date, date, uuid, uuid, uuid[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.pharmacy_admin_create_branch(p_parent_pharmacy_id uuid, p_pharmacy_name text, p_email text, p_contact_name text DEFAULT NULL::text, p_phone text DEFAULT NULL::text, p_fax text DEFAULT NULL::text, p_street text DEFAULT NULL::text, p_city text DEFAULT NULL::text, p_state text DEFAULT NULL::text, p_zip text DEFAULT NULL::text, p_wholesaler text DEFAULT NULL::text, p_wholesaler_account text DEFAULT NULL::text, p_secondary_wholesaler text DEFAULT NULL::text, p_dea_number text DEFAULT NULL::text, p_dea_expiration date DEFAULT NULL::date, p_service_type text DEFAULT 'full_service'::text, p_days_between_visits integer DEFAULT 120, p_last_visit_date date DEFAULT NULL::date, p_next_visit_date date DEFAULT NULL::date, p_processor_id uuid DEFAULT NULL::uuid, p_sales_person_id uuid DEFAULT NULL::uuid, p_pending_role_ids uuid[] DEFAULT NULL::uuid[]) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_parent RECORD;
  v_invite_id UUID;
  v_invite_token TEXT;
  v_rid UUID;
BEGIN
  SELECT id, pharmacy_name, parent_pharmacy_id, status, can_manage_branches
  INTO v_parent FROM pharmacy WHERE id = p_parent_pharmacy_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Parent pharmacy not found');
  END IF;
  IF v_parent.parent_pharmacy_id IS NOT NULL THEN
    RETURN jsonb_build_object('error', true, 'code', 403, 'message', 'Branch pharmacies cannot create sub-branches');
  END IF;
  IF v_parent.can_manage_branches IS NOT TRUE THEN
    RETURN jsonb_build_object('error', true, 'code', 403, 'message', 'This pharmacy does not have branch management capability');
  END IF;
  IF v_parent.status != 'active' THEN
    RETURN jsonb_build_object('error', true, 'code', 403, 'message', 'Parent pharmacy account is not active');
  END IF;

  IF p_pharmacy_name IS NULL OR TRIM(p_pharmacy_name) = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Branch pharmacy name is required');
  END IF;
  IF p_email IS NULL OR TRIM(p_email) = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Email is required');
  END IF;

  IF EXISTS (SELECT 1 FROM pharmacy WHERE email = LOWER(TRIM(p_email))) THEN
    RETURN jsonb_build_object('error', true, 'code', 409, 'message', 'A pharmacy with this email already exists');
  END IF;
  IF EXISTS (SELECT 1 FROM pharmacy_branch_invites
             WHERE email = LOWER(TRIM(p_email)) AND status = 'pending' AND expires_at > NOW()) THEN
    RETURN jsonb_build_object('error', true, 'code', 409, 'message', 'A pending branch invitation already exists for this email');
  END IF;
  IF EXISTS (SELECT 1 FROM pharmacy_invites
             WHERE email = LOWER(TRIM(p_email)) AND status = 'pending' AND expires_at > NOW()) THEN
    RETURN jsonb_build_object('error', true, 'code', 409, 'message', 'A pending pharmacy invitation already exists for this email');
  END IF;

  IF p_service_type NOT IN ('full_service', 'self_service') THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Service type must be full_service or self_service');
  END IF;

  IF p_pending_role_ids IS NOT NULL AND cardinality(p_pending_role_ids) > 0 THEN
    FOREACH v_rid IN ARRAY p_pending_role_ids
    LOOP
      IF NOT EXISTS (
        SELECT 1 FROM pharmacy_roles
        WHERE id = v_rid AND parent_pharmacy_id = p_parent_pharmacy_id
      ) THEN
        RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'One or more role IDs are invalid or do not belong to your pharmacy');
      END IF;
    END LOOP;
  END IF;

  v_invite_token := encode(gen_random_bytes(32), 'hex');

  INSERT INTO pharmacy_branch_invites (
    parent_pharmacy_id, invite_token, email, status, expires_at,
    pharmacy_name, contact_name, phone, fax,
    street, city, state, zip,
    wholesaler, wholesaler_account, secondary_wholesaler,
    dea_number, dea_expiration,
    service_type, days_between_visits,
    last_visit_date, next_visit_date,
    processor_id, sales_person_id,
    pending_role_ids
  ) VALUES (
    p_parent_pharmacy_id, v_invite_token, LOWER(TRIM(p_email)), 'pending',
    NOW() + INTERVAL '7 days',
    TRIM(p_pharmacy_name), p_contact_name, p_phone, p_fax,
    p_street, p_city, p_state, p_zip,
    p_wholesaler, p_wholesaler_account, p_secondary_wholesaler,
    p_dea_number, p_dea_expiration,
    p_service_type, COALESCE(p_days_between_visits, 120),
    p_last_visit_date, p_next_visit_date,
    p_processor_id, p_sales_person_id,
    CASE
      WHEN p_pending_role_ids IS NOT NULL AND cardinality(p_pending_role_ids) > 0 THEN p_pending_role_ids
      ELSE NULL
    END
  ) RETURNING id INTO v_invite_id;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'inviteId', v_invite_id,
      'inviteToken', v_invite_token,
      'email', LOWER(TRIM(p_email)),
      'pharmacyName', TRIM(p_pharmacy_name),
      'parentPharmacyName', v_parent.pharmacy_name
    )
  );
END;
$$;


