--
-- TOC entry 809 (class 1255 OID 145674)
-- Name: pharmacy_payment_calculate(uuid, uuid, numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.pharmacy_payment_calculate(p_pharmacy_id uuid, p_batch_id uuid, p_company_fee_pct numeric DEFAULT 27.0, p_gpo_share_pct numeric DEFAULT 0.0) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_total_credit   DECIMAL(12,2);
  v_company_fee    DECIMAL(12,2);
  v_gpo_share      DECIMAL(12,2);
  v_pharmacy_payout DECIMAL(12,2);
  v_gpo_name       TEXT;
  v_pharmacy_name  TEXT;
  v_batch_name     TEXT;
  v_memo_count     INTEGER;
BEGIN
  -- Validate pharmacy exists
  SELECT pharmacy_name INTO v_pharmacy_name FROM pharmacy WHERE id = p_pharmacy_id;
  IF v_pharmacy_name IS NULL THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Pharmacy not found');
  END IF;

  -- Validate batch exists
  SELECT batch_name INTO v_batch_name FROM return_batches WHERE id = p_batch_id;
  IF v_batch_name IS NULL THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Batch not found');
  END IF;

  -- Get GPO affiliation from pharmacy
  SELECT gpo_affiliation INTO v_gpo_name FROM pharmacy WHERE id = p_pharmacy_id;

  -- Sum all received payments from debit memos for this pharmacy in this batch
  SELECT COALESCE(SUM(amount_received), 0), COUNT(*)
    INTO v_total_credit, v_memo_count
  FROM debit_memos
  WHERE pharmacy_id = p_pharmacy_id
    AND batch_id = p_batch_id
    AND payment_status IN ('paid', 'partial');

  -- Calculate splits
  v_company_fee    := ROUND(v_total_credit * (p_company_fee_pct / 100.0), 2);
  v_gpo_share      := ROUND(v_total_credit * (p_gpo_share_pct / 100.0), 2);
  v_pharmacy_payout := v_total_credit - v_company_fee - v_gpo_share;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'pharmacyId',          p_pharmacy_id,
      'pharmacyName',        v_pharmacy_name,
      'batchId',             p_batch_id,
      'batchName',           v_batch_name,
      'gpoName',             v_gpo_name,
      'totalCreditReceived', v_total_credit,
      'memoCount',           v_memo_count,
      'companyFeePercent',   p_company_fee_pct,
      'companyFee',          v_company_fee,
      'gpoSharePercent',     p_gpo_share_pct,
      'gpoShare',            v_gpo_share,
      'pharmacyPayout',      v_pharmacy_payout
    )
  );
END;
$$;


ALTER FUNCTION public.pharmacy_payment_calculate(p_pharmacy_id uuid, p_batch_id uuid, p_company_fee_pct numeric, p_gpo_share_pct numeric) OWNER TO postgres;

--
-- TOC entry 583 (class 1255 OID 145675)
-- Name: pharmacy_payment_create(uuid, uuid, numeric, numeric, numeric, numeric, numeric, text, text, text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.pharmacy_payment_create(p_pharmacy_id uuid, p_batch_id uuid DEFAULT NULL::uuid, p_total_credit_received numeric DEFAULT 0, p_company_fee_percent numeric DEFAULT 27.0, p_company_fee numeric DEFAULT 0, p_gpo_share numeric DEFAULT 0, p_pharmacy_payout numeric DEFAULT 0, p_payment_method text DEFAULT NULL::text, p_payment_reference text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_created_by uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_payment pharmacy_payments;
  v_gpo_name TEXT;
BEGIN
  -- Validate pharmacy exists
  IF NOT EXISTS (SELECT 1 FROM pharmacy WHERE id = p_pharmacy_id) THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Pharmacy not found');
  END IF;

  -- Validate batch exists (if provided)
  IF p_batch_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM return_batches WHERE id = p_batch_id) THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Batch not found');
  END IF;

  -- Validate payment_method if provided
  IF p_payment_method IS NOT NULL AND p_payment_method NOT IN ('wire', 'check', 'zelle', 'cash') THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Invalid payment_method. Must be: wire, check, zelle, cash');
  END IF;

  -- Check for duplicate pharmacy+batch payment
  IF p_batch_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM pharmacy_payments
    WHERE pharmacy_id = p_pharmacy_id AND batch_id = p_batch_id
      AND status NOT IN ('failed')
  ) THEN
    RETURN jsonb_build_object('error', true, 'code', 409, 'message', 'A payment record already exists for this pharmacy and batch');
  END IF;

  -- Get GPO name from pharmacy
  SELECT gpo_affiliation INTO v_gpo_name FROM pharmacy WHERE id = p_pharmacy_id;

  INSERT INTO pharmacy_payments (
    pharmacy_id, batch_id, total_credit_received, company_fee,
    company_fee_percent, gpo_share, gpo_name, pharmacy_payout,
    payment_method, payment_reference, notes, created_by, status
  ) VALUES (
    p_pharmacy_id, p_batch_id, p_total_credit_received, p_company_fee,
    p_company_fee_percent, p_gpo_share, v_gpo_name, p_pharmacy_payout,
    p_payment_method, p_payment_reference, p_notes, p_created_by, 'pending'
  )
  RETURNING * INTO v_payment;

  RETURN jsonb_build_object(
    'error', false,
    'data', _pharmacy_payment_to_json(v_payment)
  );
END;
$$;


ALTER FUNCTION public.pharmacy_payment_create(p_pharmacy_id uuid, p_batch_id uuid, p_total_credit_received numeric, p_company_fee_percent numeric, p_company_fee numeric, p_gpo_share numeric, p_pharmacy_payout numeric, p_payment_method text, p_payment_reference text, p_notes text, p_created_by uuid) OWNER TO postgres;

--
-- TOC entry 820 (class 1255 OID 145677)
-- Name: pharmacy_payment_get(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.pharmacy_payment_get(p_payment_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_payment pharmacy_payments;
  v_memos   jsonb;
BEGIN
  SELECT * INTO v_payment FROM pharmacy_payments WHERE id = p_payment_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Payment record not found');
  END IF;

  -- Get associated debit memos for this pharmacy + batch
  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'id',               dm.id,
      'memoNumber',       dm.memo_number,
      'labelerName',      dm.labeler_name,
      'destination',      dm.destination,
      'totalItems',       dm.total_items,
      'amountRequested',  dm.amount_requested,
      'amountReceived',   dm.amount_received,
      'paymentStatus',    dm.payment_status
    ) ORDER BY dm.memo_number
  ), '[]'::jsonb)
  INTO v_memos
  FROM debit_memos dm
  WHERE dm.pharmacy_id = v_payment.pharmacy_id
    AND (v_payment.batch_id IS NULL OR dm.batch_id = v_payment.batch_id);

  RETURN jsonb_build_object(
    'error', false,
    'data', _pharmacy_payment_to_json(v_payment) || jsonb_build_object('debitMemos', v_memos)
  );
END;
$$;


ALTER FUNCTION public.pharmacy_payment_get(p_payment_id uuid) OWNER TO postgres;

--
-- TOC entry 753 (class 1255 OID 145678)
-- Name: pharmacy_payment_list(text, text, uuid, text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.pharmacy_payment_list(p_status text DEFAULT NULL::text, p_pharmacy text DEFAULT NULL::text, p_batch_id uuid DEFAULT NULL::uuid, p_search text DEFAULT NULL::text, p_page integer DEFAULT 1, p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_offset INTEGER;
  v_total  INTEGER;
  v_rows   jsonb;
  v_totals jsonb;
BEGIN
  v_offset := (GREATEST(p_page, 1) - 1) * p_limit;

  -- Count
  SELECT COUNT(*)
    INTO v_total
  FROM pharmacy_payments pp
  JOIN pharmacy ph ON ph.id = pp.pharmacy_id
  WHERE (p_status IS NULL OR pp.status = p_status)
    AND (p_batch_id IS NULL OR pp.batch_id = p_batch_id)
    AND (p_pharmacy IS NULL OR (
      LOWER(ph.pharmacy_name) LIKE '%' || LOWER(p_pharmacy) || '%'
      OR ph.store_number = p_pharmacy
    ))
    AND (p_search IS NULL OR (
      LOWER(ph.pharmacy_name) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE(pp.payment_reference, '')) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE(pp.gpo_name, '')) LIKE '%' || LOWER(p_search) || '%'
      OR ph.store_number = p_search
    ));

  -- Aggregate totals
  SELECT jsonb_build_object(
    'totalPayments',        COUNT(*),
    'totalCreditReceived',  COALESCE(SUM(pp.total_credit_received), 0),
    'totalCompanyFee',      COALESCE(SUM(pp.company_fee), 0),
    'totalGpoShare',        COALESCE(SUM(pp.gpo_share), 0),
    'totalPharmacyPayout',  COALESCE(SUM(pp.pharmacy_payout), 0),
    'paidCount',            COUNT(*) FILTER (WHERE pp.status = 'paid'),
    'pendingCount',         COUNT(*) FILTER (WHERE pp.status = 'pending'),
    'processingCount',      COUNT(*) FILTER (WHERE pp.status = 'processing')
  )
  INTO v_totals
  FROM pharmacy_payments pp
  JOIN pharmacy ph ON ph.id = pp.pharmacy_id
  WHERE (p_status IS NULL OR pp.status = p_status)
    AND (p_batch_id IS NULL OR pp.batch_id = p_batch_id)
    AND (p_pharmacy IS NULL OR (
      LOWER(ph.pharmacy_name) LIKE '%' || LOWER(p_pharmacy) || '%'
      OR ph.store_number = p_pharmacy
    ))
    AND (p_search IS NULL OR (
      LOWER(ph.pharmacy_name) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE(pp.payment_reference, '')) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE(pp.gpo_name, '')) LIKE '%' || LOWER(p_search) || '%'
      OR ph.store_number = p_search
    ));

  -- Data rows
  SELECT COALESCE(jsonb_agg(
    _pharmacy_payment_to_json(pp)
    ORDER BY pp.created_at DESC
  ), '[]'::jsonb)
  INTO v_rows
  FROM (
    SELECT pp.*
    FROM pharmacy_payments pp
    JOIN pharmacy ph ON ph.id = pp.pharmacy_id
    WHERE (p_status IS NULL OR pp.status = p_status)
      AND (p_batch_id IS NULL OR pp.batch_id = p_batch_id)
      AND (p_pharmacy IS NULL OR (
        LOWER(ph.pharmacy_name) LIKE '%' || LOWER(p_pharmacy) || '%'
        OR ph.store_number = p_pharmacy
      ))
      AND (p_search IS NULL OR (
        LOWER(ph.pharmacy_name) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE(pp.payment_reference, '')) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE(pp.gpo_name, '')) LIKE '%' || LOWER(p_search) || '%'
        OR ph.store_number = p_search
      ))
    ORDER BY pp.created_at DESC
    LIMIT p_limit OFFSET v_offset
  ) pp;

  RETURN jsonb_build_object(
    'error', false,
    'data', v_rows,
    'pagination', jsonb_build_object(
      'page', p_page, 'limit', p_limit, 'total', v_total,
      'totalPages', CEIL(v_total::float / p_limit)::integer
    ),
    'summary', v_totals
  );
END;
$$;


ALTER FUNCTION public.pharmacy_payment_list(p_status text, p_pharmacy text, p_batch_id uuid, p_search text, p_page integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 832 (class 1255 OID 145680)
-- Name: pharmacy_payment_my_payments(uuid, text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.pharmacy_payment_my_payments(p_pharmacy_id uuid, p_status text DEFAULT NULL::text, p_page integer DEFAULT 1, p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_offset   INTEGER;
  v_total    INTEGER;
  v_rows     jsonb;
  v_summary  jsonb;
BEGIN
  -- Validate pharmacy exists
  IF NOT EXISTS (SELECT 1 FROM pharmacy WHERE id = p_pharmacy_id) THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Pharmacy not found');
  END IF;

  v_offset := (GREATEST(p_page, 1) - 1) * p_limit;

  -- Count
  SELECT COUNT(*)
    INTO v_total
  FROM pharmacy_payments pp
  WHERE pp.pharmacy_id = p_pharmacy_id
    AND (p_status IS NULL OR pp.status = p_status);

  -- Summary totals for this pharmacy
  SELECT jsonb_build_object(
    'totalCredits',        COALESCE(SUM(pp.total_credit_received), 0),
    'totalFees',           COALESCE(SUM(pp.company_fee + pp.gpo_share), 0),
    'totalPayout',         COALESCE(SUM(pp.pharmacy_payout), 0),
    'paidPayouts',         COALESCE(SUM(pp.pharmacy_payout) FILTER (WHERE pp.status = 'paid'), 0),
    'pendingPayouts',      COALESCE(SUM(pp.pharmacy_payout) FILTER (WHERE pp.status IN ('pending', 'processing')), 0),
    'totalPayments',       COUNT(*),
    'paidCount',           COUNT(*) FILTER (WHERE pp.status = 'paid'),
    'pendingCount',        COUNT(*) FILTER (WHERE pp.status IN ('pending', 'processing'))
  )
  INTO v_summary
  FROM pharmacy_payments pp
  WHERE pp.pharmacy_id = p_pharmacy_id;

  -- Data
  SELECT COALESCE(jsonb_agg(
    _pharmacy_payment_to_json(pp)
    ORDER BY pp.created_at DESC
  ), '[]'::jsonb)
  INTO v_rows
  FROM (
    SELECT pp.*
    FROM pharmacy_payments pp
    WHERE pp.pharmacy_id = p_pharmacy_id
      AND (p_status IS NULL OR pp.status = p_status)
    ORDER BY pp.created_at DESC
    LIMIT p_limit OFFSET v_offset
  ) pp;

  RETURN jsonb_build_object(
    'error', false,
    'data', v_rows,
    'pagination', jsonb_build_object(
      'page', p_page, 'limit', p_limit, 'total', v_total,
      'totalPages', CEIL(v_total::float / p_limit)::integer
    ),
    'summary', v_summary
  );
END;
$$;


ALTER FUNCTION public.pharmacy_payment_my_payments(p_pharmacy_id uuid, p_status text, p_page integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 736 (class 1255 OID 145679)
-- Name: pharmacy_payment_summary(text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.pharmacy_payment_summary(p_search text DEFAULT NULL::text, p_page integer DEFAULT 1, p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_offset INTEGER;
  v_total  INTEGER;
  v_rows   jsonb;
BEGIN
  v_offset := (GREATEST(p_page, 1) - 1) * p_limit;

  -- Count distinct pharmacies
  SELECT COUNT(DISTINCT pp.pharmacy_id)
    INTO v_total
  FROM pharmacy_payments pp
  JOIN pharmacy ph ON ph.id = pp.pharmacy_id
  WHERE p_search IS NULL OR (
    LOWER(ph.pharmacy_name) LIKE '%' || LOWER(p_search) || '%'
    OR LOWER(COALESCE(ph.gpo_affiliation, '')) LIKE '%' || LOWER(p_search) || '%'
    OR ph.store_number = p_search
  );

  -- Grouped data
  SELECT COALESCE(jsonb_agg(row_data ORDER BY total_payout DESC), '[]'::jsonb)
  INTO v_rows
  FROM (
    SELECT jsonb_build_object(
      'pharmacyId',           pp.pharmacy_id,
      'pharmacyName',         MAX(ph.pharmacy_name),
      'storeNumber',          MAX(ph.store_number),
      'gpoAffiliation',      MAX(ph.gpo_affiliation),
      'totalPayments',        COUNT(*),
      'totalCreditReceived',  SUM(pp.total_credit_received),
      'totalCompanyFee',      SUM(pp.company_fee),
      'totalGpoShare',        SUM(pp.gpo_share),
      'totalPayout',          SUM(pp.pharmacy_payout),
      'paidCount',            COUNT(*) FILTER (WHERE pp.status = 'paid'),
      'pendingCount',         COUNT(*) FILTER (WHERE pp.status IN ('pending', 'processing')),
      'lastPaidAt',           MAX(pp.paid_at)
    ) AS row_data,
    SUM(pp.pharmacy_payout) AS total_payout
    FROM pharmacy_payments pp
    JOIN pharmacy ph ON ph.id = pp.pharmacy_id
    WHERE p_search IS NULL OR (
      LOWER(ph.pharmacy_name) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE(ph.gpo_affiliation, '')) LIKE '%' || LOWER(p_search) || '%'
      OR ph.store_number = p_search
    )
    GROUP BY pp.pharmacy_id
    ORDER BY total_payout DESC
    LIMIT p_limit OFFSET v_offset
  ) sub;

  RETURN jsonb_build_object(
    'error', false,
    'data', v_rows,
    'pagination', jsonb_build_object(
      'page', p_page, 'limit', p_limit, 'total', v_total,
      'totalPages', CEIL(v_total::float / p_limit)::integer
    )
  );
END;
$$;


ALTER FUNCTION public.pharmacy_payment_summary(p_search text, p_page integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 829 (class 1255 OID 145676)
-- Name: pharmacy_payment_update(uuid, text, text, text, timestamp with time zone, text, numeric, numeric, numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.pharmacy_payment_update(p_payment_id uuid, p_status text DEFAULT NULL::text, p_payment_method text DEFAULT NULL::text, p_payment_reference text DEFAULT NULL::text, p_paid_at timestamp with time zone DEFAULT NULL::timestamp with time zone, p_notes text DEFAULT NULL::text, p_company_fee numeric DEFAULT NULL::numeric, p_company_fee_pct numeric DEFAULT NULL::numeric, p_gpo_share numeric DEFAULT NULL::numeric, p_pharmacy_payout numeric DEFAULT NULL::numeric, p_total_credit numeric DEFAULT NULL::numeric) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_payment pharmacy_payments;
BEGIN
  SELECT * INTO v_payment FROM pharmacy_payments WHERE id = p_payment_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Payment record not found');
  END IF;

  -- Validate status if provided
  IF p_status IS NOT NULL AND p_status NOT IN ('pending', 'processing', 'paid', 'failed', 'disputed') THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Invalid status. Must be: pending, processing, paid, failed, disputed');
  END IF;

  -- Validate payment_method if provided
  IF p_payment_method IS NOT NULL AND p_payment_method NOT IN ('wire', 'check', 'zelle', 'cash') THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Invalid payment_method. Must be: wire, check, zelle, cash');
  END IF;

  UPDATE pharmacy_payments SET
    status              = COALESCE(p_status, status),
    payment_method      = COALESCE(p_payment_method, payment_method),
    payment_reference   = COALESCE(p_payment_reference, payment_reference),
    paid_at             = CASE
                            WHEN p_status = 'paid' AND paid_at IS NULL THEN COALESCE(p_paid_at, NOW())
                            WHEN p_paid_at IS NOT NULL THEN p_paid_at
                            ELSE paid_at
                          END,
    notes               = COALESCE(p_notes, notes),
    company_fee         = COALESCE(p_company_fee, company_fee),
    company_fee_percent = COALESCE(p_company_fee_pct, company_fee_percent),
    gpo_share           = COALESCE(p_gpo_share, gpo_share),
    pharmacy_payout     = COALESCE(p_pharmacy_payout, pharmacy_payout),
    total_credit_received = COALESCE(p_total_credit, total_credit_received)
  WHERE id = p_payment_id
  RETURNING * INTO v_payment;

  RETURN jsonb_build_object(
    'error', false,
    'data', _pharmacy_payment_to_json(v_payment)
  );
END;
$$;


ALTER FUNCTION public.pharmacy_payment_update(p_payment_id uuid, p_status text, p_payment_method text, p_payment_reference text, p_paid_at timestamp with time zone, p_notes text, p_company_fee numeric, p_company_fee_pct numeric, p_gpo_share numeric, p_pharmacy_payout numeric, p_total_credit numeric) OWNER TO postgres;

--
-- TOC entry 841 (class 1255 OID 156252)
-- Name: prevent_locked_legacy_return_item_updates(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.prevent_locked_legacy_return_item_updates() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_return_status TEXT;
BEGIN
  -- Get the return status
  SELECT status INTO v_return_status 
  FROM returns 
  WHERE id = COALESCE(NEW.return_id, OLD.return_id);
  
  -- Block modifications on locked returns
  IF is_legacy_return_locked(v_return_status) THEN
    RAISE EXCEPTION 'Cannot modify items on return with status "%". Return is locked after shipment.', v_return_status;
  END IF;
  
  RETURN COALESCE(NEW, OLD);
END;
$$;


ALTER FUNCTION public.prevent_locked_legacy_return_item_updates() OWNER TO postgres;

--
-- TOC entry 491 (class 1255 OID 156251)
-- Name: prevent_locked_legacy_return_updates(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.prevent_locked_legacy_return_updates() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Allow status transitions (handled by specific logic)
  IF TG_OP = 'UPDATE' AND OLD.status != NEW.status THEN
    RETURN NEW;
  END IF;
  
  -- Block other updates on locked returns
  IF TG_OP = 'UPDATE' AND is_legacy_return_locked(OLD.status) THEN
    RAISE EXCEPTION 'Cannot modify return with status "%". Return is locked after shipment.', OLD.status;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.prevent_locked_legacy_return_updates() OWNER TO postgres;

--
-- TOC entry 634 (class 1255 OID 156243)
-- Name: prevent_locked_return_item_updates(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.prevent_locked_return_item_updates() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_return_status TEXT;
BEGIN
  SELECT status INTO v_return_status
  FROM return_transactions
  WHERE id = COALESCE(NEW.transaction_id, OLD.transaction_id);

  IF NOT is_return_transaction_locked(v_return_status) THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  IF TG_OP = 'INSERT' THEN
    RAISE EXCEPTION 'Cannot add items to a "%" return. Return is locked.', v_return_status;
  END IF;

  IF TG_OP = 'DELETE' THEN
    RAISE EXCEPTION 'Cannot delete items on a "%" return. Return is locked.', v_return_status;
  END IF;

  -- UPDATE: block only core immutable product data fields.
  -- Allow: classification fields, warehouse verification fields
  -- (verified, actual_quantity, condition_notes), and wine_cellar_id.
  IF OLD.ndc                   IS DISTINCT FROM NEW.ndc
  OR OLD.ndc_10                IS DISTINCT FROM NEW.ndc_10
  OR OLD.proprietary_name      IS DISTINCT FROM NEW.proprietary_name
  OR OLD.generic_name          IS DISTINCT FROM NEW.generic_name
  OR OLD.manufacturer          IS DISTINCT FROM NEW.manufacturer
  OR OLD.package_description   IS DISTINCT FROM NEW.package_description
  OR OLD.dosage_form           IS DISTINCT FROM NEW.dosage_form
  OR OLD.strength              IS DISTINCT FROM NEW.strength
  OR OLD.route                 IS DISTINCT FROM NEW.route
  OR OLD.lot_number            IS DISTINCT FROM NEW.lot_number
  OR OLD.serial_number         IS DISTINCT FROM NEW.serial_number
  OR OLD.expiration_date       IS DISTINCT FROM NEW.expiration_date
  OR OLD.standard_price        IS DISTINCT FROM NEW.standard_price
  OR OLD.quantity              IS DISTINCT FROM NEW.quantity
  OR OLD.full_package_size     IS DISTINCT FROM NEW.full_package_size
  OR OLD.is_partial            IS DISTINCT FROM NEW.is_partial
  OR OLD.partial_percentage    IS DISTINCT FROM NEW.partial_percentage
  OR OLD.estimated_value       IS DISTINCT FROM NEW.estimated_value
  OR OLD.dea_schedule          IS DISTINCT FROM NEW.dea_schedule
  OR OLD.dea_form_222_required IS DISTINCT FROM NEW.dea_form_222_required
  OR OLD.product_type          IS DISTINCT FROM NEW.product_type THEN
    RAISE EXCEPTION
      'Cannot modify core item data on a "%" return. '
      'Only classification and warehouse verification fields can be updated.',
      v_return_status;
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.prevent_locked_return_item_updates() OWNER TO postgres;

--
-- TOC entry 512 (class 1255 OID 156241)
-- Name: prevent_locked_return_updates(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.prevent_locked_return_updates() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF OLD.status IS DISTINCT FROM NEW.status THEN
    RETURN NEW;
  END IF;

  IF OLD.verified_at IS DISTINCT FROM NEW.verified_at
     OR OLD.verified_by IS DISTINCT FROM NEW.verified_by
     OR OLD.pieces_received IS DISTINCT FROM NEW.pieces_received
     OR OLD.verified_integrity IS DISTINCT FROM NEW.verified_integrity
     OR OLD.received_in_warehouse_date IS DISTINCT FROM NEW.received_in_warehouse_date THEN
    RETURN NEW;
  END IF;

  IF OLD.batch_id IS DISTINCT FROM NEW.batch_id THEN
    RETURN NEW;
  END IF;

  IF is_return_transaction_locked(OLD.status) THEN
    IF OLD.fedex_tracking IS DISTINCT FROM NEW.fedex_tracking
       OR OLD.fedex_pickup_confirmation IS DISTINCT FROM NEW.fedex_pickup_confirmation
       OR OLD.service_type IS DISTINCT FROM NEW.service_type THEN
      RAISE EXCEPTION 'Cannot modify tracking/service type on a "%" return.', OLD.status;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.prevent_locked_return_updates() OWNER TO postgres;

--
-- TOC entry 717 (class 1255 OID 144527)
-- Name: ra_generate_reminder_email(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ra_generate_reminder_email(p_debit_memo_id uuid, p_email_override text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $_$
DECLARE
  v_memo         debit_memos;
  v_pharm_name   TEXT;
  v_dest_email   TEXT;
  v_dest_name    TEXT;
  v_request_count INTEGER;
  v_subject      TEXT;
  v_body         TEXT;
BEGIN
  SELECT * INTO v_memo FROM debit_memos WHERE id = p_debit_memo_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Debit memo not found');
  END IF;

  SELECT pharmacy_name INTO v_pharm_name FROM pharmacy WHERE id = v_memo.pharmacy_id;

  SELECT COUNT(*) INTO v_request_count FROM ra_requests WHERE debit_memo_id = p_debit_memo_id;

  IF p_email_override IS NOT NULL AND p_email_override <> '' THEN
    v_dest_email := p_email_override;
    v_dest_name  := COALESCE(v_memo.labeler_name, '');
  ELSE
    SELECT rd.contact_email, rd.name
      INTO v_dest_email, v_dest_name
      FROM reverse_distributors rd
      WHERE LOWER(rd.name) = LOWER(v_memo.destination)
        AND rd.is_active = true
      LIMIT 1;
  END IF;

  v_subject := 'REMINDER: Return Authorization Request — ' || v_memo.memo_number || ' (Follow-up #' || v_request_count || ')';

  v_body := 'Dear ' || COALESCE(v_dest_name, 'Returns Department') || ','
    || E'\n\n' || 'This is a follow-up regarding our Return Authorization request for Debit Memo ' || v_memo.memo_number || '.'
    || E'\n' || 'Original request was sent on: ' || COALESCE(TO_CHAR(v_memo.ra_requested_at, 'Month DD, YYYY'), 'N/A')
    || E'\n\n' || 'Pharmacy: ' || COALESCE(v_pharm_name, '')
    || E'\n' || 'Items: ' || v_memo.total_items
    || E'\n' || 'Total Ask Value: $' || TRIM(TO_CHAR(v_memo.total_ask_value, '999,999,990.00'))
    || E'\n\n' || 'We kindly request that you send us the RA number at your earliest convenience.'
    || E'\n\n' || 'Thank you,'
    || E'\n' || 'PharmaCollect Returns Department';

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'to',            v_dest_email,
      'toName',        v_dest_name,
      'subject',       v_subject,
      'body',          v_body,
      'memoNumber',    v_memo.memo_number,
      'pharmacyName',  COALESCE(v_pharm_name, ''),
      'requestCount',  v_request_count,
      'originalDate',  v_memo.ra_requested_at
    )
  );
END;
$_$;


ALTER FUNCTION public.ra_generate_reminder_email(p_debit_memo_id uuid, p_email_override text) OWNER TO postgres;

--
-- TOC entry 649 (class 1255 OID 144526)
-- Name: ra_generate_request_email(uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ra_generate_request_email(p_debit_memo_id uuid, p_email_override text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $_$
DECLARE
  v_memo       debit_memos;
  v_pharm_name TEXT;
  v_pharm_addr TEXT;
  v_dest_email TEXT;
  v_dest_name  TEXT;
  v_items      jsonb;
  v_subject    TEXT;
  v_body       TEXT;
BEGIN
  SELECT * INTO v_memo FROM debit_memos WHERE id = p_debit_memo_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Debit memo not found');
  END IF;

  -- Pharmacy info
  SELECT pharmacy_name,
    CONCAT_WS(', ',
      NULLIF(TRIM(physical_address->>'street'), ''),
      NULLIF(TRIM(physical_address->>'city'), ''),
      NULLIF(TRIM(physical_address->>'state'), ''),
      NULLIF(TRIM(physical_address->>'zip'), '')
    )
  INTO v_pharm_name, v_pharm_addr
  FROM pharmacy WHERE id = v_memo.pharmacy_id;

  -- Destination email: override > reverse_distributors lookup by destination
  IF p_email_override IS NOT NULL AND p_email_override <> '' THEN
    v_dest_email := p_email_override;
    v_dest_name  := COALESCE(v_memo.labeler_name, '');
  ELSE
    SELECT rd.contact_email, rd.name
      INTO v_dest_email, v_dest_name
      FROM reverse_distributors rd
      WHERE LOWER(rd.name) = LOWER(v_memo.destination)
        AND rd.is_active = true
      LIMIT 1;
  END IF;

  -- Line items
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'ndc', di.ndc,
    'productName', di.product_name,
    'quantity', di.quantity,
    'askPrice', di.ask_price,
    'lotNumber', di.lot_number,
    'expirationDate', di.expiration_date
  ) ORDER BY di.product_name), '[]'::jsonb)
  INTO v_items
  FROM debit_memo_items di WHERE di.debit_memo_id = p_debit_memo_id;

  v_subject := 'Return Authorization Request — ' || v_memo.memo_number;

  v_body := 'Dear ' || COALESCE(v_dest_name, 'Returns Department') || ','
    || E'\n\n' || 'We are requesting Return Authorization for the following items:'
    || E'\n\n' || 'Debit Memo: ' || v_memo.memo_number
    || E'\n' || 'Pharmacy: ' || COALESCE(v_pharm_name, '')
    || E'\n' || 'Address: ' || COALESCE(v_pharm_addr, '')
    || E'\n' || 'Items: ' || v_memo.total_items
    || E'\n' || 'Total Ask Value: $' || TRIM(TO_CHAR(v_memo.total_ask_value, '999,999,990.00'))
    || E'\n\n' || 'Please respond with the Return Authorization number at your earliest convenience.'
    || E'\n\n' || 'Thank you,'
    || E'\n' || 'PharmaCollect Returns Department';

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'to',           v_dest_email,
      'toName',       v_dest_name,
      'subject',      v_subject,
      'body',         v_body,
      'memoNumber',   v_memo.memo_number,
      'pharmacyName', COALESCE(v_pharm_name, ''),
      'destination',  v_memo.destination,
      'labelerName',  v_memo.labeler_name,
      'totalItems',   v_memo.total_items,
      'totalAskValue',v_memo.total_ask_value,
      'items',        v_items
    )
  );
END;
$_$;


ALTER FUNCTION public.ra_generate_request_email(p_debit_memo_id uuid, p_email_override text) OWNER TO postgres;

--
-- TOC entry 911 (class 1255 OID 144525)
-- Name: ra_list_outbound_shipments(text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ra_list_outbound_shipments(p_search text DEFAULT NULL::text, p_page integer DEFAULT 1, p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_offset INTEGER;
  v_total  INTEGER;
  v_rows   jsonb;
BEGIN
  v_offset := (GREATEST(p_page, 1) - 1) * p_limit;

  SELECT COUNT(*) INTO v_total
  FROM debit_memos d
  WHERE d.shipped_at IS NOT NULL
    AND (p_search IS NULL OR (
      LOWER(d.memo_number) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE(d.outbound_tracking, '')) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE(d.labeler_name, '')) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE((SELECT pharmacy_name FROM pharmacy WHERE id = d.pharmacy_id), '')) LIKE '%' || LOWER(p_search) || '%'
    ));

  SELECT COALESCE(jsonb_agg(_debit_memo_to_json(d) ORDER BY d.shipped_at DESC), '[]'::jsonb)
  INTO v_rows
  FROM (
    SELECT d.*
    FROM debit_memos d
    WHERE d.shipped_at IS NOT NULL
      AND (p_search IS NULL OR (
        LOWER(d.memo_number) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE(d.outbound_tracking, '')) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE(d.labeler_name, '')) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE((SELECT pharmacy_name FROM pharmacy WHERE id = d.pharmacy_id), '')) LIKE '%' || LOWER(p_search) || '%'
      ))
    ORDER BY d.shipped_at DESC
    LIMIT p_limit OFFSET v_offset
  ) d;

  RETURN jsonb_build_object(
    'error', false,
    'data', v_rows,
    'pagination', jsonb_build_object(
      'page', p_page, 'limit', p_limit, 'total', v_total,
      'totalPages', CEIL(v_total::float / p_limit)::integer
    )
  );
END;
$$;


ALTER FUNCTION public.ra_list_outbound_shipments(p_search text, p_page integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 735 (class 1255 OID 144522)
-- Name: ra_list_outstanding(text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ra_list_outstanding(p_search text DEFAULT NULL::text, p_page integer DEFAULT 1, p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_offset INTEGER;
  v_total  INTEGER;
  v_rows   jsonb;
BEGIN
  v_offset := (GREATEST(p_page, 1) - 1) * p_limit;

  SELECT COUNT(*) INTO v_total
  FROM debit_memos d
  WHERE d.ra_status = 'requested'
    AND d.ra_received_at IS NULL
    AND (p_search IS NULL OR (
      LOWER(d.memo_number) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE(d.labeler_name, '')) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE((SELECT pharmacy_name FROM pharmacy WHERE id = d.pharmacy_id), '')) LIKE '%' || LOWER(p_search) || '%'
    ));

  SELECT COALESCE(jsonb_agg(_debit_memo_to_json(d) ORDER BY d.tickler_date NULLS LAST, d.ra_requested_at), '[]'::jsonb)
  INTO v_rows
  FROM (
    SELECT d.*
    FROM debit_memos d
    WHERE d.ra_status = 'requested'
      AND d.ra_received_at IS NULL
      AND (p_search IS NULL OR (
        LOWER(d.memo_number) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE(d.labeler_name, '')) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE((SELECT pharmacy_name FROM pharmacy WHERE id = d.pharmacy_id), '')) LIKE '%' || LOWER(p_search) || '%'
      ))
    ORDER BY d.tickler_date NULLS LAST, d.ra_requested_at
    LIMIT p_limit OFFSET v_offset
  ) d;

  RETURN jsonb_build_object(
    'error', false,
    'data', v_rows,
    'pagination', jsonb_build_object(
      'page', p_page, 'limit', p_limit, 'total', v_total,
      'totalPages', CEIL(v_total::float / p_limit)::integer
    )
  );
END;
$$;


ALTER FUNCTION public.ra_list_outstanding(p_search text, p_page integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 901 (class 1255 OID 144523)
-- Name: ra_list_overdue(text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ra_list_overdue(p_search text DEFAULT NULL::text, p_page integer DEFAULT 1, p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_offset INTEGER;
  v_total  INTEGER;
  v_rows   jsonb;
BEGIN
  v_offset := (GREATEST(p_page, 1) - 1) * p_limit;

  SELECT COUNT(*) INTO v_total
  FROM debit_memos d
  WHERE d.ra_received_at IS NULL
    AND d.ra_status IN ('requested', 'overdue')
    AND d.tickler_date IS NOT NULL
    AND d.tickler_date < CURRENT_DATE
    AND (p_search IS NULL OR (
      LOWER(d.memo_number) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE(d.labeler_name, '')) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE((SELECT pharmacy_name FROM pharmacy WHERE id = d.pharmacy_id), '')) LIKE '%' || LOWER(p_search) || '%'
    ));

  SELECT COALESCE(jsonb_agg(_debit_memo_to_json(d) ORDER BY d.tickler_date, d.ra_requested_at), '[]'::jsonb)
  INTO v_rows
  FROM (
    SELECT d.*
    FROM debit_memos d
    WHERE d.ra_received_at IS NULL
      AND d.ra_status IN ('requested', 'overdue')
      AND d.tickler_date IS NOT NULL
      AND d.tickler_date < CURRENT_DATE
      AND (p_search IS NULL OR (
        LOWER(d.memo_number) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE(d.labeler_name, '')) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE((SELECT pharmacy_name FROM pharmacy WHERE id = d.pharmacy_id), '')) LIKE '%' || LOWER(p_search) || '%'
      ))
    ORDER BY d.tickler_date, d.ra_requested_at
    LIMIT p_limit OFFSET v_offset
  ) d;

  RETURN jsonb_build_object(
    'error', false,
    'data', v_rows,
    'pagination', jsonb_build_object(
      'page', p_page, 'limit', p_limit, 'total', v_total,
      'totalPages', CEIL(v_total::float / p_limit)::integer
    )
  );
END;
$$;


ALTER FUNCTION public.ra_list_overdue(p_search text, p_page integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 745 (class 1255 OID 144521)
-- Name: ra_list_tracking(text, text, date, date, text, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ra_list_tracking(p_ra_status text DEFAULT NULL::text, p_destination text DEFAULT NULL::text, p_date_from date DEFAULT NULL::date, p_date_to date DEFAULT NULL::date, p_search text DEFAULT NULL::text, p_page integer DEFAULT 1, p_limit integer DEFAULT 20) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_offset   INTEGER;
  v_total    INTEGER;
  v_rows     jsonb;
BEGIN
  v_offset := (GREATEST(p_page, 1) - 1) * p_limit;

  SELECT COUNT(*) INTO v_total
  FROM debit_memos d
  WHERE (p_ra_status IS NULL OR d.ra_status = p_ra_status)
    AND (p_destination IS NULL OR d.destination = p_destination)
    AND (p_date_from IS NULL OR d.ra_requested_at >= p_date_from)
    AND (p_date_to IS NULL OR d.ra_requested_at <= (p_date_to + INTERVAL '1 day'))
    AND (p_search IS NULL OR (
      LOWER(d.memo_number) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE(d.labeler_name, '')) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE(d.ra_number, '')) LIKE '%' || LOWER(p_search) || '%'
      OR LOWER(COALESCE((SELECT pharmacy_name FROM pharmacy WHERE id = d.pharmacy_id), '')) LIKE '%' || LOWER(p_search) || '%'
    ));

  SELECT COALESCE(jsonb_agg(_debit_memo_to_json(d) ORDER BY
    CASE d.ra_status
      WHEN 'overdue' THEN 1
      WHEN 'requested' THEN 2
      WHEN 'pending' THEN 3
      WHEN 'received' THEN 4
      WHEN 'shipped' THEN 5
    END,
    d.tickler_date NULLS LAST
  ), '[]'::jsonb)
  INTO v_rows
  FROM (
    SELECT d.*
    FROM debit_memos d
    WHERE (p_ra_status IS NULL OR d.ra_status = p_ra_status)
      AND (p_destination IS NULL OR d.destination = p_destination)
      AND (p_date_from IS NULL OR d.ra_requested_at >= p_date_from)
      AND (p_date_to IS NULL OR d.ra_requested_at <= (p_date_to + INTERVAL '1 day'))
      AND (p_search IS NULL OR (
        LOWER(d.memo_number) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE(d.labeler_name, '')) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE(d.ra_number, '')) LIKE '%' || LOWER(p_search) || '%'
        OR LOWER(COALESCE((SELECT pharmacy_name FROM pharmacy WHERE id = d.pharmacy_id), '')) LIKE '%' || LOWER(p_search) || '%'
      ))
    ORDER BY
      CASE d.ra_status
        WHEN 'overdue' THEN 1
        WHEN 'requested' THEN 2
        WHEN 'pending' THEN 3
        WHEN 'received' THEN 4
        WHEN 'shipped' THEN 5
      END,
      d.tickler_date NULLS LAST
    LIMIT p_limit OFFSET v_offset
  ) d;

  RETURN jsonb_build_object(
    'error', false,
    'data', v_rows,
    'pagination', jsonb_build_object(
      'page', p_page,
      'limit', p_limit,
      'total', v_total,
      'totalPages', CEIL(v_total::float / p_limit)::integer
    ),
    'summary', jsonb_build_object(
      'pending',   (SELECT COUNT(*) FROM debit_memos WHERE ra_status = 'pending'),
      'requested', (SELECT COUNT(*) FROM debit_memos WHERE ra_status = 'requested'),
      'received',  (SELECT COUNT(*) FROM debit_memos WHERE ra_status = 'received'),
      'shipped',   (SELECT COUNT(*) FROM debit_memos WHERE ra_status = 'shipped'),
      'overdue',   (SELECT COUNT(*) FROM debit_memos WHERE ra_status = 'overdue'
                     OR (ra_status = 'requested' AND tickler_date IS NOT NULL AND tickler_date < CURRENT_DATE))
    )
  );
END;
$$;


ALTER FUNCTION public.ra_list_tracking(p_ra_status text, p_destination text, p_date_from date, p_date_to date, p_search text, p_page integer, p_limit integer) OWNER TO postgres;

--
-- TOC entry 793 (class 1255 OID 144519)
-- Name: ra_receive(uuid, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ra_receive(p_debit_memo_id uuid, p_ra_number text, p_pdf_url text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_memo debit_memos;
BEGIN
  SELECT * INTO v_memo FROM debit_memos WHERE id = p_debit_memo_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Debit memo not found');
  END IF;

  IF p_ra_number IS NULL OR TRIM(p_ra_number) = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'RA number is required');
  END IF;

  UPDATE debit_memos SET
    ra_number = TRIM(p_ra_number),
    ra_received_at = NOW(),
    ra_status = 'received'
  WHERE id = p_debit_memo_id;

  SELECT * INTO v_memo FROM debit_memos WHERE id = p_debit_memo_id;

  RETURN jsonb_build_object(
    'error', false,
    'data', _debit_memo_to_json(v_memo)
  );
END;
$$;


ALTER FUNCTION public.ra_receive(p_debit_memo_id uuid, p_ra_number text, p_pdf_url text) OWNER TO postgres;

--
-- TOC entry 658 (class 1255 OID 144520)
-- Name: ra_resend_request(uuid, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ra_resend_request(p_debit_memo_id uuid, p_sent_by text DEFAULT NULL::text, p_email_override text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
  v_memo         debit_memos;
  v_dest_email   TEXT;
  v_dest_name    TEXT;
  v_subject      TEXT;
  v_body_preview TEXT;
  v_request      ra_requests;
  v_count        INTEGER;
BEGIN
  SELECT * INTO v_memo FROM debit_memos WHERE id = p_debit_memo_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Debit memo not found');
  END IF;

  -- Count existing requests
  SELECT COUNT(*) INTO v_count FROM ra_requests WHERE debit_memo_id = p_debit_memo_id;

  IF p_email_override IS NOT NULL AND p_email_override <> '' THEN
    v_dest_email := p_email_override;
  ELSE
    SELECT rd.contact_email, rd.name
      INTO v_dest_email, v_dest_name
      FROM reverse_distributors rd
      WHERE LOWER(rd.name) = LOWER(v_memo.destination)
        AND rd.is_active = true
      LIMIT 1;
  END IF;

  IF v_dest_email IS NULL OR v_dest_email = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'No contact email found for destination "' || COALESCE(v_memo.destination, 'NULL')
        || '". Add a contact_email in reverse_distributors or provide email_override.');
  END IF;

  IF v_dest_name IS NULL THEN
    v_dest_name := COALESCE(v_memo.labeler_name, '');
  END IF;

  v_subject := 'REMINDER: RA Request — Debit Memo ' || v_memo.memo_number || ' (Follow-up #' || v_count || ')';
  v_body_preview := 'Follow-up RA request for ' || v_memo.total_items || ' item(s), '
    || 'Total Ask Value: $' || TRIM(TO_CHAR(v_memo.total_ask_value, '999,999,990.00'))
    || ' — Original request sent: ' || COALESCE(TO_CHAR(v_memo.ra_requested_at, 'YYYY-MM-DD'), 'N/A');

  INSERT INTO ra_requests (debit_memo_id, request_type, destination_email, destination_name, subject, body_preview, status, sent_by)
  VALUES (p_debit_memo_id, 'reminder', v_dest_email, v_dest_name, v_subject, v_body_preview, 'sent', p_sent_by)
  RETURNING * INTO v_request;

  -- Bump tickler date forward by 7 days
  UPDATE debit_memos SET tickler_date = (NOW() + INTERVAL '7 days')::date
  WHERE id = p_debit_memo_id;

  SELECT * INTO v_memo FROM debit_memos WHERE id = p_debit_memo_id;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'memo',    _debit_memo_to_json(v_memo),
      'request', _ra_request_to_json(v_request)
    )
  );
END;
$_$;


ALTER FUNCTION public.ra_resend_request(p_debit_memo_id uuid, p_sent_by text, p_email_override text) OWNER TO postgres;

--
-- TOC entry 914 (class 1255 OID 144518)
-- Name: ra_send_request(uuid, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ra_send_request(p_debit_memo_id uuid, p_sent_by text DEFAULT NULL::text, p_email_override text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
  v_memo         debit_memos;
  v_dest_email   TEXT;
  v_dest_name    TEXT;
  v_subject      TEXT;
  v_body_preview TEXT;
  v_request      ra_requests;
BEGIN
  SELECT * INTO v_memo FROM debit_memos WHERE id = p_debit_memo_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Debit memo not found');
  END IF;

  -- Look up destination email from reverse_distributors
  IF p_email_override IS NOT NULL AND p_email_override <> '' THEN
    v_dest_email := p_email_override;
  ELSE
    SELECT rd.contact_email, rd.name
      INTO v_dest_email, v_dest_name
      FROM reverse_distributors rd
      WHERE LOWER(rd.name) = LOWER(v_memo.destination)
        AND rd.is_active = true
      LIMIT 1;
  END IF;

  IF v_dest_email IS NULL OR v_dest_email = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'No contact email found for destination "' || COALESCE(v_memo.destination, 'NULL')
        || '". Please add a contact_email in the reverse_distributors table for this destination, or provide an email_override.');
  END IF;

  IF v_dest_name IS NULL THEN
    v_dest_name := COALESCE(v_memo.destination, '');
  END IF;

  -- Build email subject and preview
  v_subject := 'RA Request — Debit Memo ' || v_memo.memo_number;
  v_body_preview := 'Requesting Return Authorization for ' || v_memo.total_items || ' item(s), '
    || 'Total Ask Value: $' || TRIM(TO_CHAR(v_memo.total_ask_value, '999,999,990.00'))
    || ' — Pharmacy: ' || COALESCE((SELECT pharmacy_name FROM pharmacy WHERE id = v_memo.pharmacy_id), '')
    || ' — Destination: ' || COALESCE(v_memo.destination, 'N/A');

  -- Create the RA request log
  INSERT INTO ra_requests (debit_memo_id, request_type, destination_email, destination_name, subject, body_preview, status, sent_by)
  VALUES (p_debit_memo_id, 'initial', v_dest_email, v_dest_name, v_subject, v_body_preview, 'sent', p_sent_by)
  RETURNING * INTO v_request;

  -- Update memo
  UPDATE debit_memos SET
    ra_status = 'requested',
    ra_requested_at = NOW()
  WHERE id = p_debit_memo_id;

  -- Compute tickler = 14 days from now (default follow-up window)
  IF v_memo.tickler_date IS NULL THEN
    UPDATE debit_memos SET tickler_date = (NOW() + INTERVAL '14 days')::date
    WHERE id = p_debit_memo_id;
  END IF;

  -- Re-read the memo for response
  SELECT * INTO v_memo FROM debit_memos WHERE id = p_debit_memo_id;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'memo',    _debit_memo_to_json(v_memo),
      'request', _ra_request_to_json(v_request)
    )
  );
END;
$_$;


ALTER FUNCTION public.ra_send_request(p_debit_memo_id uuid, p_sent_by text, p_email_override text) OWNER TO postgres;

--
-- TOC entry 646 (class 1255 OID 144524)
-- Name: ra_ship_debit_memo(uuid, text, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ra_ship_debit_memo(p_debit_memo_id uuid, p_outbound_tracking text, p_shipped_at timestamp with time zone DEFAULT now()) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_memo debit_memos;
BEGIN
  SELECT * INTO v_memo FROM debit_memos WHERE id = p_debit_memo_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Debit memo not found');
  END IF;

  IF v_memo.ra_number IS NULL OR TRIM(v_memo.ra_number) = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'Cannot ship without an RA number. Record RA received first.');
  END IF;

  IF p_outbound_tracking IS NULL OR TRIM(p_outbound_tracking) = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Outbound tracking number is required');
  END IF;

  UPDATE debit_memos SET
    outbound_tracking = TRIM(p_outbound_tracking),
    shipped_at = p_shipped_at,
    ra_status = 'shipped'
  WHERE id = p_debit_memo_id;

  SELECT * INTO v_memo FROM debit_memos WHERE id = p_debit_memo_id;

  RETURN jsonb_build_object(
    'error', false,
    'data', _debit_memo_to_json(v_memo)
  );
END;
$$;


ALTER FUNCTION public.ra_ship_debit_memo(p_debit_memo_id uuid, p_outbound_tracking text, p_shipped_at timestamp with time zone) OWNER TO postgres;

