  WHERE id = p_admin_id;

  SELECT jsonb_build_object(
    'id', s.id,
    'email', s.email,
    'name', s.name
  )
  INTO v_admin
  FROM sub_main_admin s
  WHERE s.id = p_admin_id;

  RETURN jsonb_build_object('error', false, 'message', 'Invite resent', 'admin', v_admin);
END;
$$;


