--
-- TOC entry 587 (class 1255 OID 169289)
-- Name: resolve_domain_to_buying_group(text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.resolve_domain_to_buying_group(p_hostname text, p_role_hint text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_result JSONB;
  v_hostname TEXT;
  v_role TEXT;
BEGIN
  v_hostname := LOWER(TRIM(p_hostname));
  v_role := LOWER(TRIM(p_role_hint));

  IF v_hostname IS NULL OR v_hostname = '' THEN
    RETURN jsonb_build_object('error', true, 'message', 'Hostname is required');
  END IF;

  SELECT jsonb_build_object(
    'buying_group_id', bgd.buying_group_id,
    'domain', bgd.domain,
    'portal_type',
      CASE
        WHEN v_role = 'admin' THEN 'admin'
        WHEN v_role = 'pharmacy' THEN 'pharmacy'
        WHEN v_hostname = bgd.admin_hostname THEN 'admin'
        WHEN v_hostname = bgd.pharmacy_hostname THEN 'pharmacy'
        ELSE 'unknown'
      END,
    'is_active', bgd.is_active,
    'buying_group_name', a.name
  )
  INTO v_result
  FROM buying_group_domains bgd
  JOIN admin a ON a.id = bgd.buying_group_id
  WHERE bgd.is_active = true
    AND a.is_active = true
    AND (
      -- When role hint is provided, only match the corresponding column
      (v_role = 'admin' AND bgd.admin_hostname = v_hostname)
      OR (v_role = 'pharmacy' AND bgd.pharmacy_hostname = v_hostname)
      -- When no role hint, match any column
      OR (v_role IS NULL AND (
        bgd.admin_hostname = v_hostname
        OR bgd.pharmacy_hostname = v_hostname
        OR bgd.domain = v_hostname
      ))
    )
  LIMIT 1;

  IF v_result IS NULL THEN
    RETURN jsonb_build_object('error', true, 'message', 'Domain not recognized');
  END IF;

  RETURN jsonb_build_object('error', false, 'data', v_result);
END;
$$;


ALTER FUNCTION public.resolve_domain_to_buying_group(p_hostname text, p_role_hint text) OWNER TO postgres;

--
-- TOC entry 502 (class 1255 OID 156235)
-- Name: resolve_ndc_price(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.resolve_ndc_price(p_ndc text) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
  v_norm TEXT;
  v_row  ndc_pricing;
BEGIN
  v_norm := LOWER(REPLACE(TRIM(p_ndc), '-', ''));
  IF LENGTH(v_norm) < 10 THEN
    v_norm := LPAD(v_norm, 11, '0');
  END IF;

  SELECT * INTO v_row FROM ndc_pricing WHERE ndc_normalized = v_norm;

  IF NOT FOUND THEN
    RETURN jsonb_build_object(
      'found', false,
      'currentPrice', NULL,
      'estimatedStorePrice', NULL,
      'priceSource', NULL,
      'closeOutDestination', NULL
    );
  END IF;

    RETURN jsonb_build_object(
      'found', true,
      'currentPrice',         v_row.current_price,
      'estimatedStorePrice',  v_row.estimated_store_price,
      'priceSource',          v_row.price_source,
      'closeOutDestination',  v_row.close_out_destination,
      'lastPriceUpdate',      v_row.last_price_update,
      'productName',          v_row.product_name
    );
END;
$$;


