      COALESCE(rr.data->>'ndcCode', rr.data->>'ndc') IS NOT NULL
      AND TRIM(COALESCE(rr.data->>'ndcCode', rr.data->>'ndc', '')) != ''
      AND TRIM(COALESCE(
        rd.name,
        rr.data->>'reverseDistributor',
