      -- Get full and partial counts
      COALESCE((rr.data->>'full')::INTEGER, 0) AS item_full,
      COALESCE((rr.data->>'partial')::INTEGER, 0) AS item_partial,
      -- Calculate price per unit
      COALESCE(
        (rr.data->>'pricePerUnit')::DECIMAL,
        CASE 
          WHEN COALESCE((rr.data->>'quantity')::INTEGER, 1) > 0 
            AND COALESCE((rr.data->>'creditAmount')::DECIMAL, 0) > 0
          THEN COALESCE((rr.data->>'creditAmount')::DECIMAL, 0) / COALESCE((rr.data->>'quantity')::INTEGER, 1)
          ELSE 0 
        END
      ) AS price_per_unit,
      -- Get product name
      COALESCE(
        NULLIF(TRIM(rr.data->>'itemName'), ''),
        NULLIF(TRIM(rr.data->>'productName'), ''),
        NULLIF(TRIM(rr.data->>'product_name'), ''),
        NULLIF(TRIM(rr.data->>'product'), ''),
        NULLIF(TRIM(rr.data->>'description'), ''),
        NULLIF(TRIM(rr.data->>'drugName'), ''),
        NULLIF(TRIM(rr.data->>'name'), '')
      ) AS product_name,
      -- JavaScript equivalent timestamp
      CASE 
        WHEN ud.report_date IS NOT NULL THEN EXTRACT(EPOCH FROM ud.report_date::TIMESTAMP WITH TIME ZONE) * 1000
        WHEN ud.uploaded_at IS NOT NULL THEN EXTRACT(EPOCH FROM ud.uploaded_at) * 1000
        WHEN rr.created_at IS NOT NULL THEN EXTRACT(EPOCH FROM rr.created_at) * 1000
        ELSE 0
      END AS sort_date_ms,
      COALESCE(ud.report_date::TIMESTAMP WITH TIME ZONE, ud.uploaded_at, rr.created_at) AS sort_date
    FROM return_reports rr
    JOIN uploaded_documents ud ON rr.document_id = ud.id
    LEFT JOIN reverse_distributors rd ON ud.reverse_distributor_id = rd.id
    -- NO NDC FILTERING - get ALL records like optimization service
  ),
  
  -- Step 2: Sort ALL records like JavaScript does (lines 1904-1910)
  all_reports_sorted AS (
    SELECT *,
      ROW_NUMBER() OVER (ORDER BY sort_date_ms DESC, created_at ASC, id ASC) as global_sort_order
    FROM all_reports_unfiltered
  ),
  
  -- Step 3: Filter to matching NDCs AFTER sorting (like optimization service does in forEach)
  matched_reports AS (
    SELECT *
    FROM all_reports_sorted
    WHERE 
      ndc_normalized = v_search_normalized
      AND distributor_name != 'Unknown Distributor'
      AND ndc_code IS NOT NULL
      AND TRIM(ndc_code) != ''
  ),
  
  -- Step 3: Get LATEST FULL price per distributor using DISTINCT ON with global sort order
  -- This exactly replicates the optimization service's "first match wins" logic (lines 753-754)
  full_prices AS (
    SELECT DISTINCT ON (distributor_name)
      distributor_name,
      distributor_id,
      contact_email,
      contact_phone,
      address,
      ndc_code,
      ndc_normalized,
      product_name,
      price_per_unit AS full_price,
      sort_date
    FROM matched_reports
    WHERE item_full > 0 AND item_partial = 0  -- isFullRecord check (line 750)
      AND price_per_unit > 0  -- Only valid prices (line 702)
    ORDER BY distributor_name, sort_date_ms DESC, created_at ASC, id ASC
  ),
  
  -- Step 4: Get LATEST PARTIAL price per distributor using DISTINCT ON with global sort order
  -- This exactly replicates the optimization service's "first match wins" logic (lines 758-759)
  partial_prices AS (
    SELECT DISTINCT ON (distributor_name)
      distributor_name,
      distributor_id,
      contact_email,
      contact_phone,
      address,
      ndc_code,
      ndc_normalized,
      product_name,
      price_per_unit AS partial_price,
      sort_date
    FROM matched_reports
    WHERE item_partial > 0 AND item_full = 0  -- isPartialRecord check (line 751)
      AND price_per_unit > 0  -- Only valid prices
    ORDER BY distributor_name, sort_date_ms DESC, created_at ASC, id ASC
  ),
  
  -- Step 5: Get unique NDC info (use latest record for product name)
  ndc_info AS (
    SELECT DISTINCT ON (ndc_normalized)
      ndc_code,
      ndc_normalized,
      product_name
    FROM matched_reports
    WHERE product_name IS NOT NULL
    ORDER BY ndc_normalized, sort_date DESC NULLS LAST
  ),
  
  -- Step 6: Combine full and partial prices per distributor
  -- This mirrors optimization service logic at lines 1044-1060:
  -- fullPrice = distributorNdcToFullPriceMap[distributorNdcKey] || 0
  -- partialPrice = distributorNdcToPartialPriceMap[distributorNdcKey] || 0
  -- price = fullPrice > 0 ? fullPrice : partialPrice (search mode, lines 1051-1059)
  combined_distributors AS (
    SELECT 
      COALESCE(f.distributor_name, p.distributor_name) AS distributor_name,
      COALESCE(f.distributor_id, p.distributor_id) AS distributor_id,
      COALESCE(f.contact_email, p.contact_email) AS contact_email,
      COALESCE(f.contact_phone, p.contact_phone) AS contact_phone,
      COALESCE(f.address, p.address) AS address,
      COALESCE(f.ndc_code, p.ndc_code) AS ndc_code,
      COALESCE(f.ndc_normalized, p.ndc_normalized) AS ndc_normalized,
      COALESCE(f.product_name, p.product_name) AS product_name,
      COALESCE(f.full_price, 0) AS full_price,
      COALESCE(p.partial_price, 0) AS partial_price,
      -- price: Use full price if available, otherwise partial (same as optimization service lines 1051-1059)
      CASE 
        WHEN COALESCE(f.full_price, 0) > 0 THEN f.full_price
        ELSE COALESCE(p.partial_price, 0)
      END AS price,
      GREATEST(COALESCE(f.sort_date, '1970-01-01'::timestamp), COALESCE(p.sort_date, '1970-01-01'::timestamp)) AS sort_date
    FROM full_prices f
    FULL OUTER JOIN partial_prices p ON f.distributor_name = p.distributor_name
    -- Filter out distributors with no valid price
    WHERE COALESCE(f.full_price, 0) > 0 OR COALESCE(p.partial_price, 0) > 0
  ),
  
  -- Step 7: Build final result in format matching optimization API response
  final_result AS (
    SELECT 
      COALESCE(ni.ndc_code, (SELECT ndc_code FROM combined_distributors LIMIT 1)) AS ndc_original,
      v_search_normalized AS ndc_normalized,
      COALESCE(ni.product_name, (SELECT product_name FROM combined_distributors WHERE product_name IS NOT NULL LIMIT 1)) AS product_name,
      -- Build distributors array sorted by price DESC (highest first = best) - same as line 1133
      (
        SELECT COALESCE(jsonb_agg(
          jsonb_build_object(
            'id', cd.distributor_id,
            'name', cd.distributor_name,
            'fullPrice', cd.full_price,
            'partialPrice', cd.partial_price,
            'email', cd.contact_email,
            'phone', cd.contact_phone,
            'location', CASE 
              WHEN cd.address IS NOT NULL THEN 
                CONCAT_WS(', ', 
                  cd.address->>'city', 
                  cd.address->>'state'
                )
              ELSE NULL 
            END,
            'reportDate', cd.sort_date
          ) ORDER BY cd.price DESC NULLS LAST
        ), '[]'::jsonb)
        FROM combined_distributors cd
      ) AS distributors,
      -- Best full price (max of all distributors' latest full prices)
      (SELECT COALESCE(MAX(full_price), 0) FROM combined_distributors) AS best_full_price,
      -- Best partial price (max of all distributors' latest partial prices)
      (SELECT COALESCE(MAX(partial_price), 0) FROM combined_distributors) AS best_partial_price
    FROM ndc_info ni
    -- Use RIGHT JOIN to ensure we get results even if ndc_info is empty
    RIGHT JOIN (SELECT 1) dummy ON TRUE
    LIMIT 1
  )
  
  -- Build final response
  SELECT 
    CASE 
      WHEN EXISTS (SELECT 1 FROM combined_distributors) THEN
        jsonb_agg(
          jsonb_build_object(
            'ndc', fr.ndc_original,
            'ndcNormalized', fr.ndc_normalized,
            'productName', fr.product_name,
            'distributors', fr.distributors,
            'bestFullPrice', fr.best_full_price,
            'bestPartialPrice', fr.best_partial_price,
            -- Additional fields matching Recommendation interface
            'recommendedDistributor', COALESCE((fr.distributors->0->>'name'), ''),
            'recommendedDistributorId', (fr.distributors->0->>'id'),
            'fullPricePerUnit', fr.best_full_price,
            'partialPricePerUnit', fr.best_partial_price,
            'alternativeDistributors', COALESCE(
              (SELECT jsonb_agg(d) FROM jsonb_array_elements(fr.distributors) d OFFSET 1),
              '[]'::jsonb
            )
          )
        )
      ELSE '[]'::jsonb
    END,
    CASE WHEN EXISTS (SELECT 1 FROM combined_distributors) THEN 1 ELSE 0 END
  INTO v_results, v_count
  FROM final_result fr;
  
  RETURN jsonb_build_object(
    'results', COALESCE(v_results, '[]'::jsonb),
    'count', COALESCE(v_count, 0),
    'searchTerm', p_search
  );
END;
$$;


ALTER FUNCTION public.search_ndc_pricing_v2(p_search text, p_limit integer) OWNER TO postgres;

--
-- TOC entry 709 (class 1255 OID 103032)
-- Name: search_ndc_pricing_v3(text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.search_ndc_pricing_v3(p_search text, p_limit integer DEFAULT 50) RETURNS TABLE(ndc text, product_name text, distributor_id uuid, distributor_name text, contact_email text, contact_phone text, address text, full_price numeric, partial_price numeric, report_date timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_search_normalized TEXT;
BEGIN
  -- Normalize search term (remove dashes, convert to lowercase)
  v_search_normalized := LOWER(REPLACE(TRIM(p_search), '-', ''));
  
  RETURN QUERY
  WITH all_reports_unfiltered AS (
    SELECT 
      rr.id,
      rr.data,
      rr.document_id,
      rr.created_at,
      ud.report_date,
      ud.uploaded_at,
      rd.id AS distributor_id,
      rd.name AS rd_name,
      rd.contact_email,
      rd.contact_phone,
      rd.address,
      -- Extract NDC (same as optimization service line 509)
      COALESCE(rr.data->>'ndcCode', rr.data->>'ndc') AS ndc_code,
      -- Normalize NDC (same as optimization service line 519)
      LOWER(REPLACE(COALESCE(rr.data->>'ndcCode', rr.data->>'ndc', ''), '-', '')) AS ndc_normalized,
      -- Get distributor name with SAME fallback chain as optimization service (lines 455-458)
      TRIM(COALESCE(
        rd.name,
        rr.data->>'reverseDistributor',
        rr.data->'reverseDistributorInfo'->>'name',
        'Unknown Distributor'
      )) AS distributor_name,
      -- Get full and partial counts (same as optimization service lines 522-523)
      COALESCE((rr.data->>'full')::INTEGER, 0) AS item_full,
      COALESCE((rr.data->>'partial')::INTEGER, 0) AS item_partial,
      -- Calculate price per unit (same as optimization service line 689)
      COALESCE(
        (rr.data->>'pricePerUnit')::DECIMAL,
        CASE 
          WHEN COALESCE((rr.data->>'quantity')::INTEGER, 1) > 0 
            AND COALESCE((rr.data->>'creditAmount')::DECIMAL, 0) > 0
          THEN COALESCE((rr.data->>'creditAmount')::DECIMAL, 0) / COALESCE((rr.data->>'quantity')::INTEGER, 1)
          ELSE 0 
        END
      ) AS price_per_unit,
      -- Get product name (same priority as optimization service line 622)
      COALESCE(
        NULLIF(TRIM(rr.data->>'itemName'), ''),
        NULLIF(TRIM(rr.data->>'productName'), ''),
        NULLIF(TRIM(rr.data->>'product_name'), ''),
        NULLIF(TRIM(rr.data->>'product'), ''),
        NULLIF(TRIM(rr.data->>'description'), ''),
        NULLIF(TRIM(rr.data->>'drugName'), ''),
        NULLIF(TRIM(rr.data->>'name'), '')
      ) AS product_name,
      -- Sort date calculation - EXACT JavaScript replication  
      CASE 
        WHEN ud.report_date IS NOT NULL THEN EXTRACT(EPOCH FROM ud.report_date::TIMESTAMP WITH TIME ZONE) * 1000
        WHEN ud.uploaded_at IS NOT NULL THEN EXTRACT(EPOCH FROM ud.uploaded_at) * 1000
        WHEN rr.created_at IS NOT NULL THEN EXTRACT(EPOCH FROM rr.created_at) * 1000
        ELSE 0
      END AS sort_date_ms,
      COALESCE(ud.report_date::TIMESTAMP WITH TIME ZONE, ud.uploaded_at, rr.created_at) AS sort_date
    FROM return_reports rr
    JOIN uploaded_documents ud ON rr.document_id = ud.id
    LEFT JOIN reverse_distributors rd ON ud.reverse_distributor_id = rd.id
    WHERE 
      COALESCE(rr.data->>'ndcCode', rr.data->>'ndc') IS NOT NULL
      AND TRIM(COALESCE(rr.data->>'ndcCode', rr.data->>'ndc', '')) != ''
      AND TRIM(COALESCE(
        rd.name,
        rr.data->>'reverseDistributor',
        rr.data->'reverseDistributorInfo'->>'name',
        'Unknown Distributor'
      )) != 'Unknown Distributor'
  ),
  
  -- Step 2: Sort ALL records like JavaScript does (lines 341-352)
  all_reports_sorted AS (
    SELECT *
    FROM all_reports_unfiltered
    ORDER BY sort_date_ms DESC, created_at DESC, id ASC
  ),
  
  -- Step 3: Filter to matching NDCs AFTER sorting (like optimization service does in forEach)
  matched_reports AS (
    SELECT *
    FROM all_reports_sorted
    WHERE 
      ndc_normalized = v_search_normalized
      AND distributor_name != 'Unknown Distributor'
      AND ndc_code IS NOT NULL
      AND TRIM(ndc_code) != ''
  ),
  
  -- Step 4: Get LATEST FULL price per distributor using DISTINCT ON with global sort order
  -- This exactly replicates the optimization service's "first match wins" logic (lines 753-754)
  full_prices AS (
    SELECT DISTINCT ON (distributor_name)
      distributor_name,
      distributor_id,
      contact_email,
      contact_phone,
      address,
      ndc_code,
      ndc_normalized,
      product_name,
      price_per_unit AS full_price,
      sort_date
    FROM matched_reports
    WHERE item_full > 0 AND item_partial = 0  -- isFullRecord check (line 750)
      AND price_per_unit > 0  -- Only valid prices (line 702)
    ORDER BY distributor_name, sort_date_ms DESC, created_at DESC, id ASC
  ),
  
  -- Step 5: Get LATEST PARTIAL price per distributor using DISTINCT ON with global sort order
  -- This exactly replicates the optimization service's "first match wins" logic (lines 758-759)
  partial_prices AS (
    SELECT DISTINCT ON (distributor_name)
      distributor_name,
      distributor_id,
      contact_email,
      contact_phone,
      address,
      ndc_code,
      ndc_normalized,
      product_name,
      price_per_unit AS partial_price,
      sort_date
    FROM matched_reports
    WHERE item_partial > 0 AND item_full = 0  -- isPartialRecord check (line 751)
      AND price_per_unit > 0  -- Only valid prices
    ORDER BY distributor_name, sort_date_ms DESC, created_at DESC, id ASC
  ),
  
  -- Step 6: Combine full and partial prices per distributor
  combined_prices AS (
    SELECT 
      COALESCE(fp.distributor_name, pp.distributor_name) AS distributor_name,
      COALESCE(fp.distributor_id, pp.distributor_id) AS distributor_id,
      COALESCE(fp.contact_email, pp.contact_email) AS contact_email,
      COALESCE(fp.contact_phone, pp.contact_phone) AS contact_phone,
      COALESCE(fp.address, pp.address) AS address,
      COALESCE(fp.ndc_code, pp.ndc_code) AS ndc_code,
      COALESCE(fp.ndc_normalized, pp.ndc_normalized) AS ndc_normalized,
      COALESCE(fp.product_name, pp.product_name) AS product_name,
      COALESCE(fp.full_price, 0) AS full_price,
      COALESCE(pp.partial_price, 0) AS partial_price,
      COALESCE(fp.sort_date, pp.sort_date) AS sort_date
    FROM full_prices fp
    FULL OUTER JOIN partial_prices pp ON fp.distributor_name = pp.distributor_name
  )
  
  -- Step 7: Return results with final price selection logic (lines 1051-1059)
  SELECT 
    cp.ndc_code AS ndc,
    cp.product_name,
    cp.distributor_id,
    cp.distributor_name,
    cp.contact_email,
    cp.contact_phone,
    cp.address,
    cp.full_price,
    cp.partial_price,
    cp.sort_date AS report_date
  FROM combined_prices cp
  WHERE cp.distributor_name IS NOT NULL
    AND (cp.full_price > 0 OR cp.partial_price > 0)
  ORDER BY 
    -- Sort by best price (optimization service uses fullPrice > 0 ? fullPrice : partialPrice)
    CASE 
      WHEN cp.full_price > 0 THEN cp.full_price 
      ELSE cp.partial_price 
    END DESC
  LIMIT p_limit;
END;
$$;


ALTER FUNCTION public.search_ndc_pricing_v3(p_search text, p_limit integer) OWNER TO postgres;

--
-- TOC entry 827 (class 1255 OID 123707)
-- Name: send_connection_request(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.send_connection_request(p_sender_id uuid, p_receiver_id uuid, p_message text DEFAULT NULL::text) RETURNS json
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_existing_connection UUID;
    v_existing_request UUID;
    v_existing_status request_status;
    v_result JSON;
BEGIN
    -- Check if already connected
    SELECT id INTO v_existing_connection
    FROM connections
    WHERE (user_id = p_sender_id AND connected_user_id = p_receiver_id)
       OR (user_id = p_receiver_id AND connected_user_id = p_sender_id);
    
    IF v_existing_connection IS NOT NULL THEN
        RETURN json_build_object('success', false, 'error', 'Already connected');
    END IF;
    
    -- Check if request already exists (same direction)
    SELECT id, status INTO v_existing_request, v_existing_status
    FROM connection_requests
    WHERE sender_id = p_sender_id AND receiver_id = p_receiver_id;
    
    IF v_existing_request IS NOT NULL THEN
        IF v_existing_status = 'pending' THEN
            RETURN json_build_object('success', false, 'error', 'Request already sent');
        ELSIF v_existing_status = 'accepted' OR v_existing_status = 'declined' THEN
            -- Stale accepted (not in connections) or declined: allow re-requesting by resetting to pending
            -- Update created_at to NOW() so the timestamp shows when the request was re-sent, not when it was originally created
            UPDATE connection_requests
            SET status = 'pending', message = p_message, created_at = NOW(), updated_at = NOW()
            WHERE id = v_existing_request;
            -- Create notification for receiver
            INSERT INTO notifications (user_id, type, message, related_user_id)
            VALUES (p_receiver_id, 'connection',
                    (SELECT name FROM profiles WHERE id = p_sender_id) || ' sent you a connection request',
                    p_sender_id);
            RETURN json_build_object('success', true, 'request_id', v_existing_request, 'message', 'Request sent successfully');
        END IF;
    END IF;
    
    -- Check if there's a pending request from the other user
    SELECT id INTO v_existing_request
    FROM connection_requests
    WHERE sender_id = p_receiver_id AND receiver_id = p_sender_id AND status = 'pending';
    
    IF v_existing_request IS NOT NULL THEN
        -- Auto-accept the existing request
        UPDATE connection_requests SET status = 'accepted', updated_at = NOW()
        WHERE id = v_existing_request;
        
        -- Create bidirectional connections
        INSERT INTO connections (user_id, connected_user_id, relationship)
        VALUES (p_sender_id, p_receiver_id, 'friend')
        ON CONFLICT (user_id, connected_user_id) DO NOTHING;
        
        INSERT INTO connections (user_id, connected_user_id, relationship)
        VALUES (p_receiver_id, p_sender_id, 'friend')
        ON CONFLICT (user_id, connected_user_id) DO NOTHING;
        
        RETURN json_build_object('success', true, 'message', 'Connection created (mutual request)');
    END IF;
    
    -- Create new request (no existing row for this sender_id, receiver_id)
    INSERT INTO connection_requests (sender_id, receiver_id, message)
    VALUES (p_sender_id, p_receiver_id, p_message)
    RETURNING json_build_object(
        'success', true,
        'request_id', id,
        'message', 'Request sent successfully'
    ) INTO v_result;
    
    -- Create notification for receiver
    INSERT INTO notifications (user_id, type, message, related_user_id)
    VALUES (p_receiver_id, 'connection',
            (SELECT name FROM profiles WHERE id = p_sender_id) || ' sent you a connection request',
            p_sender_id);
    
    RETURN v_result;
END;
$$;


ALTER FUNCTION public.send_connection_request(p_sender_id uuid, p_receiver_id uuid, p_message text) OWNER TO postgres;

--
-- TOC entry 695 (class 1255 OID 70395)
-- Name: set_deal_of_the_day(uuid, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.set_deal_of_the_day(p_deal_id uuid, p_expires_at timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_deal RECORD;
BEGIN
  -- Validate deal exists and is active
  SELECT id, product_name, status, expiry_date, quantity
  INTO v_deal
  FROM marketplace_deals
  WHERE id = p_deal_id;
  
  IF v_deal.id IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Deal not found'
    );
  END IF;
  
  IF v_deal.status != 'active' THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Only active deals can be set as Deal of the Day'
    );
  END IF;
  
  IF v_deal.expiry_date < CURRENT_DATE THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Expired deals cannot be set as Deal of the Day'
    );
  END IF;
  
  IF v_deal.quantity <= 0 THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Deals with no remaining quantity cannot be set as Deal of the Day'
    );
  END IF;
  
  -- Unset previous Deal of the Day
  UPDATE marketplace_deals
  SET is_deal_of_the_day = FALSE,
      deal_of_the_day_until = NULL,
      updated_at = NOW()
  WHERE is_deal_of_the_day = TRUE;
  
  -- Set new Deal of the Day
  UPDATE marketplace_deals
  SET is_deal_of_the_day = TRUE,
      deal_of_the_day_until = p_expires_at,
      updated_at = NOW()
  WHERE id = p_deal_id;
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Deal of the Day updated successfully',
    'dealId', p_deal_id,
    'productName', v_deal.product_name,
    'expiresAt', p_expires_at
  );
END;
$$;


ALTER FUNCTION public.set_deal_of_the_day(p_deal_id uuid, p_expires_at timestamp with time zone) OWNER TO postgres;

--
-- TOC entry 696 (class 1255 OID 81564)
-- Name: set_featured_deal(uuid, text, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.set_featured_deal(p_deal_id uuid, p_type text DEFAULT 'day'::text, p_expires_at timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_deal RECORD;
  v_type_label TEXT;
BEGIN
  -- Validate type
  IF p_type NOT IN ('day', 'week', 'month') THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Invalid type. Must be day, week, or month'
    );
  END IF;

  v_type_label := CASE p_type
    WHEN 'day' THEN 'Day'
    WHEN 'week' THEN 'Week'
    WHEN 'month' THEN 'Month'
  END;

  -- Validate deal exists and is active
  SELECT id, product_name, status, expiry_date, quantity
  INTO v_deal
  FROM marketplace_deals
  WHERE id = p_deal_id;
  
  IF v_deal.id IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Deal not found'
    );
  END IF;
  
  IF v_deal.status != 'active' THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Only active deals can be set as Deal of the ' || v_type_label
    );
  END IF;
  
  IF v_deal.expiry_date < CURRENT_DATE THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Expired deals cannot be set as Deal of the ' || v_type_label
    );
  END IF;
  
  IF v_deal.quantity <= 0 THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Deals with no remaining quantity cannot be set as Deal of the ' || v_type_label
    );
  END IF;

  -- Unset previous featured deal and set new one based on type
  IF p_type = 'day' THEN
    UPDATE marketplace_deals
    SET is_deal_of_the_day = FALSE,
        deal_of_the_day_until = NULL,
        updated_at = NOW()
    WHERE is_deal_of_the_day = TRUE;
    
    UPDATE marketplace_deals
    SET is_deal_of_the_day = TRUE,
        deal_of_the_day_until = p_expires_at,
        updated_at = NOW()
    WHERE id = p_deal_id;
    
  ELSIF p_type = 'week' THEN
    UPDATE marketplace_deals
    SET is_deal_of_the_week = FALSE,
        deal_of_the_week_until = NULL,
        updated_at = NOW()
    WHERE is_deal_of_the_week = TRUE;
    
    UPDATE marketplace_deals
    SET is_deal_of_the_week = TRUE,
        deal_of_the_week_until = p_expires_at,
        updated_at = NOW()
    WHERE id = p_deal_id;
    
  ELSIF p_type = 'month' THEN
    UPDATE marketplace_deals
    SET is_deal_of_the_month = FALSE,
        deal_of_the_month_until = NULL,
        updated_at = NOW()
    WHERE is_deal_of_the_month = TRUE;
    
    UPDATE marketplace_deals
    SET is_deal_of_the_month = TRUE,
        deal_of_the_month_until = p_expires_at,
        updated_at = NOW()
    WHERE id = p_deal_id;
  END IF;
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Deal of the ' || v_type_label || ' updated successfully',
    'dealId', p_deal_id,
    'productName', v_deal.product_name,
    'type', p_type,
    'expiresAt', p_expires_at
  );
END;
$$;


ALTER FUNCTION public.set_featured_deal(p_deal_id uuid, p_type text, p_expires_at timestamp with time zone) OWNER TO postgres;

--
-- TOC entry 552 (class 1255 OID 158927)
-- Name: ship_memo_group(uuid, text, timestamp with time zone, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.ship_memo_group(p_group_id uuid, p_outbound_tracking text, p_shipped_at timestamp with time zone DEFAULT now(), p_fedex_shipment_id text DEFAULT NULL::text, p_fedex_labels jsonb DEFAULT NULL::jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_group       shipment_groups;
  v_memo_count  INTEGER;
BEGIN
  -- Get the group
  SELECT * INTO v_group FROM shipment_groups WHERE id = p_group_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Shipment group not found');
  END IF;

  IF v_group.shipped_at IS NOT NULL THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Shipment group is already shipped');
  END IF;

  IF p_outbound_tracking IS NULL OR TRIM(p_outbound_tracking) = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Outbound tracking number is required');
  END IF;

  -- Update the group (COALESCE: clients often pass NULL for p_shipped_at; PG defaults do not apply to explicit NULL)
  UPDATE shipment_groups SET
    outbound_tracking = TRIM(p_outbound_tracking),
    shipped_at = COALESCE(p_shipped_at, NOW()),
    fedex_shipment_id = p_fedex_shipment_id,
    fedex_labels = p_fedex_labels
  WHERE id = p_group_id;

  -- Update all memos in the group
  UPDATE debit_memos SET
    outbound_tracking = TRIM(p_outbound_tracking),
    shipped_at = COALESCE(p_shipped_at, NOW()),
    ra_status = 'shipped'
  WHERE shipment_group_id = p_group_id;

  GET DIAGNOSTICS v_memo_count = ROW_COUNT;

  -- Return updated group info
  SELECT * INTO v_group FROM shipment_groups WHERE id = p_group_id;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'group', _shipment_group_to_json(v_group),
      'memosShipped', v_memo_count
    )
  );
END;
$$;


ALTER FUNCTION public.ship_memo_group(p_group_id uuid, p_outbound_tracking text, p_shipped_at timestamp with time zone, p_fedex_shipment_id text, p_fedex_labels jsonb) OWNER TO postgres;

--
-- TOC entry 718 (class 1255 OID 144487)
-- Name: submit_cardinal(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.submit_cardinal(p_batch_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_batch return_batches;
BEGIN
  SELECT * INTO v_batch FROM return_batches WHERE id = p_batch_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Batch not found');
  END IF;

  IF v_batch.status <> 'closed' THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Batch is "%s". Must be closed before submitting.', v_batch.status));
  END IF;

  UPDATE return_batches SET
    status                 = 'submitted',
    cardinal_file_generated = TRUE,
    cardinal_submitted_at   = NOW()
  WHERE id = p_batch_id
  RETURNING * INTO v_batch;

  RETURN jsonb_build_object('error', false, 'data', _batch_to_json(v_batch));
END;
$$;


ALTER FUNCTION public.submit_cardinal(p_batch_id uuid) OWNER TO postgres;

