-- TOC entry 699 (class 1255 OID 169449)
-- Name: sync_business_name_from_admin(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.sync_business_name_from_admin() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- When an admin with super_admin role updates their name, sync to admin_settings
  IF NEW.role = 'super_admin' AND OLD.name IS DISTINCT FROM NEW.name THEN
    UPDATE admin_settings 
    SET business_name = NEW.name, 
        updated_at = NOW() 
    WHERE buying_group_id IS NULL OR id = 1;
  END IF;
  
  RETURN NEW;
END;
$$;


