--
-- TOC entry 874 (class 1255 OID 169319)
-- Name: update_admin_pharmacy_status(uuid, text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_admin_pharmacy_status(p_pharmacy_id uuid, p_new_status text, p_buying_group_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result JSONB;
    v_exists BOOLEAN;
    v_old_status TEXT;
BEGIN
    IF p_new_status NOT IN ('pending', 'active', 'suspended', 'blacklisted') THEN
        RETURN jsonb_build_object(
            'error', true,
            'message', 'Invalid status. Must be one of: pending, active, suspended, blacklisted',
            'code', 400
        );
    END IF;

    SELECT EXISTS(
        SELECT 1 FROM pharmacy
        WHERE id = p_pharmacy_id
          AND (p_buying_group_id IS NULL OR created_by = p_buying_group_id)
    )
    INTO v_exists;

    IF NOT v_exists THEN
        RETURN jsonb_build_object(
            'error', true,
            'message', 'Pharmacy not found',
            'code', 404
        );
    END IF;

    SELECT status INTO v_old_status FROM pharmacy WHERE id = p_pharmacy_id;

    UPDATE pharmacy
    SET status = p_new_status, updated_at = NOW()
    WHERE id = p_pharmacy_id;

    v_result := get_admin_pharmacy_by_id(p_pharmacy_id, p_buying_group_id);
    v_result := v_result || jsonb_build_object(
        'statusChange', jsonb_build_object(
            'from', v_old_status,
            'to', p_new_status
        )
    );

    RETURN v_result;
END;
$$;


