--
-- TOC entry 700 (class 1255 OID 169354)
-- Name: update_admin_settings(text, text, text, text, boolean, boolean, boolean, boolean, text, text, text, text, text, text, text, text, text, text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_admin_settings(p_site_name text DEFAULT NULL::text, p_site_email text DEFAULT NULL::text, p_timezone text DEFAULT NULL::text, p_language text DEFAULT NULL::text, p_email_notifications boolean DEFAULT NULL::boolean, p_document_approval_notif boolean DEFAULT NULL::boolean, p_payment_notif boolean DEFAULT NULL::boolean, p_shipment_notif boolean DEFAULT NULL::boolean, p_warehouse_name text DEFAULT NULL::text, p_warehouse_street text DEFAULT NULL::text, p_warehouse_city text DEFAULT NULL::text, p_warehouse_state text DEFAULT NULL::text, p_warehouse_zip text DEFAULT NULL::text, p_warehouse_country text DEFAULT NULL::text, p_warehouse_phone text DEFAULT NULL::text, p_warehouse_contact_name text DEFAULT NULL::text, p_business_name text DEFAULT NULL::text, p_logo_url text DEFAULT NULL::text, p_buying_group_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_settings JSONB;
BEGIN
  -- Validate timezone if provided
  IF p_timezone IS NOT NULL AND p_timezone NOT IN (
    'America/New_York', 'America/Chicago', 'America/Denver', 'America/Los_Angeles',
    'America/Phoenix', 'America/Anchorage', 'Pacific/Honolulu', 'UTC'
  ) THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Invalid timezone'
    );
  END IF;
  
  -- Validate language if provided
  IF p_language IS NOT NULL AND p_language NOT IN ('en', 'es', 'fr') THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Invalid language'
    );
  END IF;
  
  -- Insert or update settings for this buying group using UPSERT
  INSERT INTO admin_settings (
    buying_group_id, site_name, site_email, timezone, language,
    email_notifications, document_approval_notif, payment_notif, shipment_notif,
    warehouse_name, warehouse_street, warehouse_city, warehouse_state, warehouse_zip,
    warehouse_country, warehouse_phone, warehouse_contact_name, business_name, logo_url,
    created_at, updated_at
  )
  VALUES (
    p_buying_group_id,
    COALESCE(p_site_name, 'PharmAdmin'),
    COALESCE(p_site_email, 'admin@pharmadmin.com'),
    COALESCE(p_timezone, 'America/New_York'),
    COALESCE(p_language, 'en'),
    COALESCE(p_email_notifications, true),
    COALESCE(p_document_approval_notif, true),
    COALESCE(p_payment_notif, true),
    COALESCE(p_shipment_notif, true),
    p_warehouse_name, p_warehouse_street, p_warehouse_city, p_warehouse_state, p_warehouse_zip,
    p_warehouse_country, p_warehouse_phone, p_warehouse_contact_name, p_business_name, p_logo_url,
    NOW(), NOW()
  )
  ON CONFLICT (buying_group_id) WHERE buying_group_id IS NOT NULL
  DO UPDATE SET
    site_name = COALESCE(p_site_name, admin_settings.site_name),
    site_email = COALESCE(p_site_email, admin_settings.site_email),
    timezone = COALESCE(p_timezone, admin_settings.timezone),
    language = COALESCE(p_language, admin_settings.language),
    email_notifications = COALESCE(p_email_notifications, admin_settings.email_notifications),
    document_approval_notif = COALESCE(p_document_approval_notif, admin_settings.document_approval_notif),
    payment_notif = COALESCE(p_payment_notif, admin_settings.payment_notif),
    shipment_notif = COALESCE(p_shipment_notif, admin_settings.shipment_notif),
    warehouse_name = COALESCE(p_warehouse_name, admin_settings.warehouse_name),
    warehouse_street = COALESCE(p_warehouse_street, admin_settings.warehouse_street),
    warehouse_city = COALESCE(p_warehouse_city, admin_settings.warehouse_city),
    warehouse_state = COALESCE(p_warehouse_state, admin_settings.warehouse_state),
    warehouse_zip = COALESCE(p_warehouse_zip, admin_settings.warehouse_zip),
    warehouse_country = COALESCE(p_warehouse_country, admin_settings.warehouse_country),
    warehouse_phone = COALESCE(p_warehouse_phone, admin_settings.warehouse_phone),
    warehouse_contact_name = COALESCE(p_warehouse_contact_name, admin_settings.warehouse_contact_name),
    business_name = COALESCE(p_business_name, admin_settings.business_name),
    logo_url = COALESCE(p_logo_url, admin_settings.logo_url),
    updated_at = NOW();
  
  -- Handle global settings (MainAdmin) separately due to different conflict condition
  IF p_buying_group_id IS NULL THEN
    -- For global settings, use a different approach since we can't use buying_group_id in ON CONFLICT
    UPDATE admin_settings
    SET
      site_name = COALESCE(p_site_name, site_name),
      site_email = COALESCE(p_site_email, site_email),
      timezone = COALESCE(p_timezone, timezone),
      language = COALESCE(p_language, language),
      email_notifications = COALESCE(p_email_notifications, email_notifications),
      document_approval_notif = COALESCE(p_document_approval_notif, document_approval_notif),
      payment_notif = COALESCE(p_payment_notif, payment_notif),
      shipment_notif = COALESCE(p_shipment_notif, shipment_notif),
      warehouse_name = COALESCE(p_warehouse_name, warehouse_name),
      warehouse_street = COALESCE(p_warehouse_street, warehouse_street),
      warehouse_city = COALESCE(p_warehouse_city, warehouse_city),
      warehouse_state = COALESCE(p_warehouse_state, warehouse_state),
      warehouse_zip = COALESCE(p_warehouse_zip, warehouse_zip),
      warehouse_country = COALESCE(p_warehouse_country, warehouse_country),
      warehouse_phone = COALESCE(p_warehouse_phone, warehouse_phone),
      warehouse_contact_name = COALESCE(p_warehouse_contact_name, warehouse_contact_name),
      business_name = COALESCE(p_business_name, business_name),
      logo_url = COALESCE(p_logo_url, logo_url),
      updated_at = NOW()
    WHERE buying_group_id IS NULL;
    
    -- If no global settings row exists, create one
    IF NOT FOUND THEN
      INSERT INTO admin_settings (
        buying_group_id, site_name, site_email, timezone, language,
        email_notifications, document_approval_notif, payment_notif, shipment_notif,
        warehouse_name, warehouse_street, warehouse_city, warehouse_state, warehouse_zip,
        warehouse_country, warehouse_phone, warehouse_contact_name, business_name, logo_url,
        created_at, updated_at
      )
      VALUES (
        NULL,
        COALESCE(p_site_name, 'PharmAdmin'),
        COALESCE(p_site_email, 'admin@pharmadmin.com'),
        COALESCE(p_timezone, 'America/New_York'),
        COALESCE(p_language, 'en'),
        COALESCE(p_email_notifications, true),
        COALESCE(p_document_approval_notif, true),
        COALESCE(p_payment_notif, true),
        COALESCE(p_shipment_notif, true),
        p_warehouse_name, p_warehouse_street, p_warehouse_city, p_warehouse_state, p_warehouse_zip,
        p_warehouse_country, p_warehouse_phone, p_warehouse_contact_name, p_business_name, p_logo_url,
        NOW(), NOW()
      );
    END IF;
  END IF;
  
  -- Fetch updated/created settings
  SELECT jsonb_build_object(
    'siteName', s.site_name,
    'siteEmail', s.site_email,
    'timezone', s.timezone,
    'language', s.language,
    'emailNotifications', s.email_notifications,
    'documentApprovalNotif', s.document_approval_notif,
    'paymentNotif', s.payment_notif,
    'shipmentNotif', s.shipment_notif,
    'warehouseName', s.warehouse_name,
    'warehouseStreet', s.warehouse_street,
    'warehouseCity', s.warehouse_city,
    'warehouseState', s.warehouse_state,
    'warehouseZip', s.warehouse_zip,
    'warehouseCountry', s.warehouse_country,
    'warehousePhone', s.warehouse_phone,
    'warehouseContactName', s.warehouse_contact_name,
    'businessName', s.business_name,
    'logoUrl', s.logo_url,
    'createdAt', s.created_at,
    'updatedAt', s.updated_at
  )
  INTO v_settings
  FROM admin_settings s
  WHERE (
    (p_buying_group_id IS NULL AND s.buying_group_id IS NULL)
    OR (p_buying_group_id IS NOT NULL AND s.buying_group_id = p_buying_group_id)
  );
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Settings updated successfully',
    'settings', v_settings
  );
END;
$$;


ALTER FUNCTION public.update_admin_settings(p_site_name text, p_site_email text, p_timezone text, p_language text, p_email_notifications boolean, p_document_approval_notif boolean, p_payment_notif boolean, p_shipment_notif boolean, p_warehouse_name text, p_warehouse_street text, p_warehouse_city text, p_warehouse_state text, p_warehouse_zip text, p_warehouse_country text, p_warehouse_phone text, p_warehouse_contact_name text, p_business_name text, p_logo_url text, p_buying_group_id uuid) OWNER TO postgres;

--
-- TOC entry 518 (class 1255 OID 169429)
-- Name: update_admin_user(uuid, text, text, text, boolean, jsonb, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_admin_user(p_admin_id uuid, p_name text DEFAULT NULL::text, p_email text DEFAULT NULL::text, p_role text DEFAULT NULL::text, p_is_active boolean DEFAULT NULL::boolean, p_permissions jsonb DEFAULT NULL::jsonb, p_buying_group_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_admin JSONB;
  v_existing_email TEXT;
  v_current_role TEXT;
  v_effective_role TEXT;
BEGIN
  -- Check if admin exists
  SELECT role INTO v_current_role FROM admin WHERE id = p_admin_id;
  IF v_current_role IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Admin user not found'
    );
  END IF;
  
  -- Validate role if provided
  IF p_role IS NOT NULL AND p_role NOT IN ('super_admin', 'manager', 'reviewer', 'support') THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Invalid role. Must be one of: super_admin, manager, reviewer, support'
    );
  END IF;
  
  -- Check email uniqueness if email is being updated
  IF p_email IS NOT NULL THEN
    SELECT email INTO v_existing_email FROM admin WHERE email = p_email AND id != p_admin_id;
    IF v_existing_email IS NOT NULL THEN
      RETURN jsonb_build_object(
        'error', true,
        'message', 'Email already exists'
      );
    END IF;
  END IF;

  -- Validate buying_group_id if provided
  v_effective_role := COALESCE(p_role, v_current_role);
  IF p_buying_group_id IS NOT NULL AND v_effective_role <> 'super_admin' THEN
    IF NOT EXISTS (
      SELECT 1 FROM admin WHERE id = p_buying_group_id AND role = 'super_admin'
    ) THEN
      RETURN jsonb_build_object(
        'error', true,
        'message', 'Invalid buying_group_id: must reference an existing super_admin'
      );
    END IF;
  END IF;
  
  -- Update admin
  UPDATE admin
  SET
    name = COALESCE(p_name, name),
    email = COALESCE(p_email, email),
    role = COALESCE(p_role, role),
    is_active = COALESCE(p_is_active, is_active),
    permissions = COALESCE(p_permissions, permissions),
    buying_group_id = CASE
      -- super_admin rows always self-reference their own id
      WHEN COALESCE(p_role, role) = 'super_admin' THEN id
      -- otherwise, update to the supplied value if provided, else keep existing
      ELSE COALESCE(p_buying_group_id, buying_group_id)
    END,
    updated_at = NOW()
  WHERE id = p_admin_id;
  
  -- Fetch updated admin
  SELECT jsonb_build_object(
    'id', a.id,
    'email', a.email,
    'name', a.name,
    'role', a.role,
    'roleDisplay', CASE a.role
      WHEN 'super_admin' THEN 'Super Admin'
      WHEN 'manager' THEN 'Manager'
      WHEN 'reviewer' THEN 'Reviewer'
      WHEN 'support' THEN 'Support'
      ELSE a.role
    END,
    'isActive', a.is_active,
    'status', CASE WHEN a.is_active THEN 'active' ELSE 'inactive' END,
    'permissions', COALESCE(a.permissions, '[]'::jsonb),
    'buyingGroupId', a.buying_group_id,
    'lastLoginAt', a.last_login_at,
    'createdAt', a.created_at,
    'updatedAt', a.updated_at
  )
  INTO v_admin
  FROM admin a
  WHERE a.id = p_admin_id;
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Admin user updated successfully',
    'admin', v_admin
  );
END;
$$;


