--
-- TOC entry 779 (class 1255 OID 86314)
-- Name: update_marketplace_deal(uuid, text, text, integer, text, numeric, numeric, text, date, text, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_marketplace_deal(p_deal_id uuid, p_product_name text DEFAULT NULL::text, p_category text DEFAULT NULL::text, p_quantity integer DEFAULT NULL::integer, p_unit text DEFAULT NULL::text, p_original_price numeric DEFAULT NULL::numeric, p_deal_price numeric DEFAULT NULL::numeric, p_distributor_name text DEFAULT NULL::text, p_expiry_date date DEFAULT NULL::date, p_ndc text DEFAULT NULL::text, p_status text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_image_url text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_deal JSONB;
  v_current_status TEXT;
BEGIN
  -- Check if deal exists
  SELECT status INTO v_current_status FROM marketplace_deals WHERE id = p_deal_id;
  
  IF v_current_status IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Deal not found'
    );
  END IF;
  
  -- Validate unit if provided
  IF p_unit IS NOT NULL AND p_unit NOT IN ('bottles', 'boxes', 'units', 'packs') THEN
    RETURN jsonb_build_object('error', true, 'message', 'Invalid unit. Must be: bottles, boxes, units, packs');
  END IF;
  
  -- Validate status if provided
  IF p_status IS NOT NULL AND p_status NOT IN ('active', 'sold', 'expired') THEN
    RETURN jsonb_build_object('error', true, 'message', 'Invalid status. Must be: active, sold, expired');
  END IF;
  
  -- Validate quantity if provided
  IF p_quantity IS NOT NULL AND p_quantity <= 0 THEN
    RETURN jsonb_build_object('error', true, 'message', 'Quantity must be greater than 0');
  END IF;
  
  -- Validate prices if provided
  IF p_original_price IS NOT NULL AND p_original_price <= 0 THEN
    RETURN jsonb_build_object('error', true, 'message', 'Original price must be greater than 0');
  END IF;
  
  IF p_deal_price IS NOT NULL AND p_deal_price <= 0 THEN
    RETURN jsonb_build_object('error', true, 'message', 'Deal price must be greater than 0');
  END IF;
  
  -- Update deal
  UPDATE marketplace_deals
  SET
    product_name = COALESCE(p_product_name, product_name),
    category = COALESCE(p_category, category),
    ndc = COALESCE(p_ndc, ndc),
    quantity = COALESCE(p_quantity, quantity),
    unit = COALESCE(p_unit, unit),
    original_price = COALESCE(p_original_price, original_price),
    deal_price = COALESCE(p_deal_price, deal_price),
    distributor_name = COALESCE(p_distributor_name, distributor_name),
    expiry_date = COALESCE(p_expiry_date, expiry_date),
    status = COALESCE(p_status, status),
    notes = COALESCE(p_notes, notes),
    image_url = COALESCE(p_image_url, image_url),
    updated_at = NOW()
  WHERE id = p_deal_id;
  
  -- Fetch updated deal
  SELECT jsonb_build_object(
    'id', d.id,
    'dealNumber', d.deal_number,
    'productName', d.product_name,
    'category', d.category,
    'ndc', d.ndc,
    'quantity', d.quantity,
    'unit', d.unit,
    'originalPrice', d.original_price,
    'dealPrice', d.deal_price,
    'savings', ROUND(((d.original_price - d.deal_price) / d.original_price * 100), 0),
    'margin', ROUND((d.deal_price / d.original_price * 100), 0),
    'distributorId', d.distributor_id,
    'distributor', d.distributor_name,
    'expiryDate', d.expiry_date,
    'postedDate', d.posted_date,
    'status', d.status,
    'notes', d.notes,
    'imageUrl', d.image_url,
    'createdAt', d.created_at,
    'updatedAt', d.updated_at,
    'isDealOfTheDay', COALESCE(d.is_deal_of_the_day, false),
    'dealOfTheDayUntil', d.deal_of_the_day_until,
    'isDealOfTheWeek', COALESCE(d.is_deal_of_the_week, false),
    'dealOfTheWeekUntil', d.deal_of_the_week_until,
    'isDealOfTheMonth', COALESCE(d.is_deal_of_the_month, false),
    'dealOfTheMonthUntil', d.deal_of_the_month_until
  )
  INTO v_deal
  FROM marketplace_deals d
  WHERE d.id = p_deal_id;
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Deal updated successfully',
    'deal', v_deal
  );
END;
$$;


ALTER FUNCTION public.update_marketplace_deal(p_deal_id uuid, p_product_name text, p_category text, p_quantity integer, p_unit text, p_original_price numeric, p_deal_price numeric, p_distributor_name text, p_expiry_date date, p_ndc text, p_status text, p_notes text, p_image_url text) OWNER TO postgres;

--
-- TOC entry 568 (class 1255 OID 78223)
-- Name: update_marketplace_order_payment(text, text, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.update_marketplace_order_payment(p_stripe_checkout_session_id text, p_stripe_payment_intent_id text, p_stripe_payment_status text, p_payment_method_type text DEFAULT NULL::text, p_payment_method_last4 text DEFAULT NULL::text, p_payment_method_brand text DEFAULT NULL::text, p_stripe_receipt_url text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_order_id UUID;
  v_order_number TEXT;
  v_pharmacy_id UUID;
  v_new_status TEXT;
  v_order_item RECORD;
BEGIN
  -- Find order by checkout session ID
  SELECT id, order_number, pharmacy_id
  INTO v_order_id, v_order_number, v_pharmacy_id
  FROM marketplace_orders
  WHERE stripe_checkout_session_id = p_stripe_checkout_session_id;
  
  IF v_order_id IS NULL THEN
    RETURN jsonb_build_object(
      'error', true,
      'message', 'Order not found for session: ' || p_stripe_checkout_session_id
    );
  END IF;
  
  -- Determine new status based on payment status
  IF p_stripe_payment_status IN ('succeeded', 'paid') THEN
    v_new_status := 'paid';
  ELSIF p_stripe_payment_status = 'processing' THEN
    v_new_status := 'processing';
  ELSIF p_stripe_payment_status IN ('failed', 'canceled') THEN
    v_new_status := 'cancelled';
  ELSE
    v_new_status := 'pending';
  END IF;
  
  -- Update order
  UPDATE marketplace_orders
  SET
    status = v_new_status,
    stripe_payment_intent_id = p_stripe_payment_intent_id,
    stripe_payment_status = p_stripe_payment_status,
    payment_method_type = p_payment_method_type,
    payment_method_last4 = p_payment_method_last4,
    payment_method_brand = p_payment_method_brand,
    stripe_receipt_url = p_stripe_receipt_url,
    paid_at = CASE WHEN v_new_status = 'paid' THEN NOW() ELSE paid_at END,
    cancelled_at = CASE WHEN v_new_status = 'cancelled' THEN NOW() ELSE cancelled_at END,
    updated_at = NOW()
  WHERE id = v_order_id;
  
  -- If payment successful, reduce deal quantities and clear cart
  IF v_new_status = 'paid' THEN
    -- Reduce quantities from deals
    FOR v_order_item IN
      SELECT deal_id, quantity
      FROM marketplace_order_items
      WHERE order_id = v_order_id
    LOOP
      UPDATE marketplace_deals
      SET 
        quantity = quantity - v_order_item.quantity,
        status = CASE 
          WHEN quantity - v_order_item.quantity <= 0 THEN 'sold'
          ELSE status
        END,
        updated_at = NOW()
      WHERE id = v_order_item.deal_id;
    END LOOP;
    
    -- Clear the pharmacy's cart
    DELETE FROM pharmacy_cart_items
    WHERE cart_id = (SELECT id FROM pharmacy_cart WHERE pharmacy_id = v_pharmacy_id);
  END IF;
  
  RETURN jsonb_build_object(
    'error', false,
    'message', 'Order payment updated',
    'orderNumber', v_order_number,
    'newStatus', v_new_status
  );
END;
$$;


ALTER FUNCTION public.update_marketplace_order_payment(p_stripe_checkout_session_id text, p_stripe_payment_intent_id text, p_stripe_payment_status text, p_payment_method_type text, p_payment_method_last4 text, p_payment_method_brand text, p_stripe_receipt_url text) OWNER TO postgres;

