--
-- TOC entry 599 (class 1255 OID 169291)
-- Name: upsert_buying_group_domain(uuid, text, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.upsert_buying_group_domain(p_buying_group_id uuid, p_domain text, p_admin_hostname text DEFAULT NULL::text, p_pharmacy_hostname text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_id UUID;
  v_domain TEXT;
  v_admin_host TEXT;
  v_pharmacy_host TEXT;
BEGIN
  IF NOT EXISTS (SELECT 1 FROM admin WHERE id = p_buying_group_id AND role = 'super_admin') THEN
    RETURN jsonb_build_object('error', true, 'message', 'Buying group not found');
  END IF;

  -- Clean all hostnames: strip protocol, paths, ports
  v_domain := clean_hostname(p_domain);
  v_admin_host := clean_hostname(p_admin_hostname);
  v_pharmacy_host := clean_hostname(p_pharmacy_hostname);

  IF v_domain IS NULL OR v_domain = '' THEN
    RETURN jsonb_build_object('error', true, 'message', 'Domain is required');
  END IF;

  INSERT INTO buying_group_domains (buying_group_id, domain, admin_hostname, pharmacy_hostname)
  VALUES (p_buying_group_id, v_domain, v_admin_host, v_pharmacy_host)
  ON CONFLICT (domain) DO UPDATE SET
    buying_group_id   = EXCLUDED.buying_group_id,
    admin_hostname    = COALESCE(EXCLUDED.admin_hostname, buying_group_domains.admin_hostname),
    pharmacy_hostname = COALESCE(EXCLUDED.pharmacy_hostname, buying_group_domains.pharmacy_hostname),
    updated_at        = NOW()
  RETURNING id INTO v_id;

  RETURN jsonb_build_object('error', false, 'message', 'Domain configured', 'id', v_id);
END;
$$;


ALTER FUNCTION public.upsert_buying_group_domain(p_buying_group_id uuid, p_domain text, p_admin_hostname text, p_pharmacy_hostname text) OWNER TO postgres;

--
-- TOC entry 507 (class 1255 OID 156231)
-- Name: upsert_ndc_pricing(jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.upsert_ndc_pricing(p_data jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_ndc             TEXT;
  v_ndc_normalized  TEXT;
  v_row             ndc_pricing;
BEGIN
  v_ndc := TRIM(p_data->>'ndc');
  IF v_ndc IS NULL OR v_ndc = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'NDC code is required');
  END IF;

  v_ndc_normalized := LOWER(REPLACE(v_ndc, '-', ''));
  IF LENGTH(v_ndc_normalized) < 10 THEN
    v_ndc_normalized := LPAD(v_ndc_normalized, 11, '0');
  END IF;

  INSERT INTO ndc_pricing (
    ndc, ndc_normalized, product_name,
    current_price, last_price, estimated_store_price, last_reimbursement,
    price_source, close_out_destination,
    last_price_update, created_by, updated_by
  ) VALUES (
    v_ndc,
    v_ndc_normalized,
    NULLIF(TRIM(p_data->>'productName'), ''),
    (p_data->>'currentPrice')::DECIMAL,
    NULL,
    (p_data->>'estimatedStorePrice')::DECIMAL,
    (p_data->>'lastReimbursement')::DECIMAL,
    NULLIF(TRIM(p_data->>'priceSource'), ''),
    NULLIF(TRIM(p_data->>'closeOutDestination'), ''),
    COALESCE((p_data->>'lastPriceUpdate')::TIMESTAMPTZ, NOW()),
    (p_data->>'userId')::UUID,
    (p_data->>'userId')::UUID
  )
  ON CONFLICT (ndc_normalized) DO UPDATE SET
    ndc                  = COALESCE(NULLIF(TRIM(EXCLUDED.ndc), ''), ndc_pricing.ndc),
    product_name         = COALESCE(NULLIF(TRIM(EXCLUDED.product_name), ''), ndc_pricing.product_name),
    last_price           = ndc_pricing.current_price,
    current_price        = COALESCE(EXCLUDED.current_price, ndc_pricing.current_price),
    estimated_store_price = COALESCE(EXCLUDED.estimated_store_price, ndc_pricing.estimated_store_price),
    last_reimbursement   = COALESCE(EXCLUDED.last_reimbursement, ndc_pricing.last_reimbursement),
    price_source         = COALESCE(NULLIF(TRIM(EXCLUDED.price_source), ''), ndc_pricing.price_source),
    close_out_destination = COALESCE(NULLIF(TRIM(EXCLUDED.close_out_destination), ''), ndc_pricing.close_out_destination),
    last_price_update    = COALESCE(EXCLUDED.last_price_update, NOW()),
    updated_by           = EXCLUDED.updated_by
  RETURNING * INTO v_row;

  RETURN jsonb_build_object('error', false, 'data', _ndc_pricing_to_json(v_row));
END;
$$;


ALTER FUNCTION public.upsert_ndc_pricing(p_data jsonb) OWNER TO postgres;

--
-- TOC entry 791 (class 1255 OID 169294)
-- Name: validate_admin_tenant_access(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.validate_admin_tenant_access(p_admin_id uuid, p_tenant_buying_group_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_role TEXT;
  v_admin_bg UUID;
  v_resolved_bg UUID;
BEGIN
  SELECT role, buying_group_id
    INTO v_role, v_admin_bg
  FROM admin
  WHERE id = p_admin_id;

  IF v_role IS NULL THEN
    RETURN jsonb_build_object('error', true, 'message', 'Admin not found', 'code', 404);
  END IF;

  -- The buying_group_id this admin effectively belongs to
  IF v_role = 'super_admin' THEN
    v_resolved_bg := p_admin_id;
  ELSE
    v_resolved_bg := v_admin_bg;
  END IF;

  -- If a tenant context is present, enforce it
  IF p_tenant_buying_group_id IS NOT NULL THEN
    IF v_resolved_bg IS NULL OR v_resolved_bg <> p_tenant_buying_group_id THEN
      RETURN jsonb_build_object(
        'error', true,
        'message', 'You do not have access to this portal',
        'code', 403
      );
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'error', false,
    'buying_group_id', v_resolved_bg
  );
END;
$$;


ALTER FUNCTION public.validate_admin_tenant_access(p_admin_id uuid, p_tenant_buying_group_id uuid) OWNER TO postgres;

--
-- TOC entry 732 (class 1255 OID 156255)
-- Name: validate_legacy_return_deletion(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.validate_legacy_return_deletion(p_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
  v_status TEXT;
  v_is_locked BOOLEAN;
BEGIN
  -- Check if returns table exists
  IF NOT EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'returns') THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Legacy returns system not available');
  END IF;
  
  -- Get current status
  EXECUTE 'SELECT status FROM returns WHERE id = $1' INTO v_status USING p_id;
  
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Return not found');
  END IF;
  
  v_is_locked := is_legacy_return_locked(v_status);
  
  IF v_is_locked THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Cannot delete return with status "%s". Return is locked after shipment.', v_status));
  END IF;
  
  RETURN jsonb_build_object('error', false, 'message', 'Deletion allowed');
END;
$_$;


ALTER FUNCTION public.validate_legacy_return_deletion(p_id uuid) OWNER TO postgres;

