--
-- TOC entry 758 (class 1255 OID 86310)
-- Name: validate_pharmacy_cart(uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.validate_pharmacy_cart(p_pharmacy_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_cart_id UUID;
  v_issues JSONB := '[]'::jsonb;
  v_valid_items JSONB;
  v_subtotal NUMERIC(12, 2);
  v_total_savings NUMERIC(12, 2);
  v_item_count INTEGER;
  v_issue_record RECORD;
BEGIN
  -- Get cart ID
  SELECT id INTO v_cart_id
  FROM pharmacy_cart
  WHERE pharmacy_id = p_pharmacy_id;
  
  IF v_cart_id IS NULL THEN
    RETURN jsonb_build_object(
      'valid', false,
      'message', 'Cart is empty',
      'issues', '[]'::jsonb,
      'items', '[]'::jsonb
    );
  END IF;
  
  -- Find items with issues (deal not active, quantity exceeds stock, or below minimum)
  -- Note: If available quantity < minimum_buy_quantity, then remaining stock becomes the effective minimum
  FOR v_issue_record IN
    SELECT 
      ci.id as item_id,
      ci.deal_id,
      d.product_name,
      ci.quantity as cart_quantity,
      d.quantity as available_quantity,
      COALESCE(d.minimum_buy_quantity, 1) as minimum_buy_quantity,
      -- Effective minimum: the lesser of minimum_buy_quantity and available_quantity
      LEAST(COALESCE(d.minimum_buy_quantity, 1), d.quantity) as effective_minimum,
      d.status as deal_status,
      CASE 
        WHEN d.status != 'active' THEN 'Deal is no longer available (status: ' || d.status || ')'
        WHEN ci.quantity > d.quantity THEN 'Quantity in cart (' || ci.quantity || ') exceeds available stock (' || d.quantity || ')'
        -- Only flag as below minimum if cart quantity is less than the effective minimum
        WHEN ci.quantity < LEAST(COALESCE(d.minimum_buy_quantity, 1), d.quantity) THEN 
          'Minimum order quantity is ' || LEAST(COALESCE(d.minimum_buy_quantity, 1), d.quantity) || ' units'
        ELSE NULL
      END as issue
    FROM pharmacy_cart_items ci
    JOIN marketplace_deals d ON d.id = ci.deal_id
    WHERE ci.cart_id = v_cart_id
      AND (
        d.status != 'active' 
        OR ci.quantity > d.quantity
        OR ci.quantity < LEAST(COALESCE(d.minimum_buy_quantity, 1), d.quantity)
      )
  LOOP
    v_issues := v_issues || jsonb_build_object(
      'itemId', v_issue_record.item_id,
      'dealId', v_issue_record.deal_id,
      'productName', v_issue_record.product_name,
      'issue', v_issue_record.issue
    );
  END LOOP;
  
  -- Get valid items and totals
  -- Valid items must: be active, not exceed stock, and meet effective minimum (min of minimum_buy_quantity and available stock)
  SELECT 
    COALESCE(jsonb_agg(
      jsonb_build_object(
        'id', ci.id,
        'dealId', ci.deal_id,
        'productName', d.product_name,
        'ndc', d.ndc,
        'category', d.category,
        'distributor', d.distributor_name,
        'quantity', ci.quantity,
        'unitPrice', ci.unit_price,
        'originalPrice', ci.original_price,
        'totalPrice', ci.quantity * ci.unit_price,
        'savings', (ci.original_price - ci.unit_price) * ci.quantity,
        'savingsPercent', ROUND(((ci.original_price - ci.unit_price) / ci.original_price * 100), 0),
        'imageUrl', d.image_url,
        'availableQuantity', d.quantity,
        'minimumBuyQuantity', COALESCE(d.minimum_buy_quantity, 1),
        'effectiveMinimum', LEAST(COALESCE(d.minimum_buy_quantity, 1), d.quantity),
        'unit', d.unit,
        'dealStatus', d.status,
        'expiryDate', d.expiry_date,
        'addedAt', ci.added_at
      )
      ORDER BY ci.added_at DESC
    ), '[]'::jsonb),
    COALESCE(SUM(ci.quantity * ci.unit_price), 0),
    COALESCE(SUM((ci.original_price - ci.unit_price) * ci.quantity), 0),
    COUNT(*)::INTEGER
  INTO v_valid_items, v_subtotal, v_total_savings, v_item_count
  FROM pharmacy_cart_items ci
  JOIN marketplace_deals d ON d.id = ci.deal_id
  WHERE ci.cart_id = v_cart_id
    AND d.status = 'active'
    AND ci.quantity <= d.quantity
    AND ci.quantity >= LEAST(COALESCE(d.minimum_buy_quantity, 1), d.quantity);
  
  RETURN jsonb_build_object(
    'valid', jsonb_array_length(v_issues) = 0,
    'message', CASE 
      WHEN jsonb_array_length(v_issues) = 0 THEN 'Cart is valid and ready for checkout'
      ELSE 'Some items in your cart have issues'
    END,
    'issues', v_issues,
    'items', v_valid_items,
    'summary', jsonb_build_object(
      'itemCount', v_item_count,
      'subtotal', v_subtotal,
      'totalSavings', v_total_savings,
      'estimatedTax', ROUND(v_subtotal * 0.08, 2),
      'total', ROUND(v_subtotal * 1.08, 2)
    )
  );
END;
$$;


ALTER FUNCTION public.validate_pharmacy_cart(p_pharmacy_id uuid) OWNER TO postgres;

--
-- TOC entry 865 (class 1255 OID 169295)
-- Name: validate_pharmacy_tenant_access(uuid, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.validate_pharmacy_tenant_access(p_pharmacy_id uuid, p_tenant_buying_group_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_created_by UUID;
BEGIN
  SELECT created_by
    INTO v_created_by
  FROM pharmacy
  WHERE id = p_pharmacy_id;

  -- NOTE: pharmacy rows are not required to have created_by populated
  -- historically. When no tenant enforcement is required, we still return
  -- whatever value is present (can be NULL).

  IF p_tenant_buying_group_id IS NOT NULL THEN
    IF v_created_by IS NULL OR v_created_by <> p_tenant_buying_group_id THEN
      RETURN jsonb_build_object(
        'error', true,
        'message', 'You do not have access to this portal',
        'code', 403
      );
    END IF;
  END IF;

  RETURN jsonb_build_object(
    'error', false,
    'buying_group_id', v_created_by
  );
END;
$$;


ALTER FUNCTION public.validate_pharmacy_tenant_access(p_pharmacy_id uuid, p_tenant_buying_group_id uuid) OWNER TO postgres;

--
-- TOC entry 613 (class 1255 OID 169053)
-- Name: validate_sub_admin_invite_token(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.validate_sub_admin_invite_token(p_invite_token text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_admin JSONB;
BEGIN
  SELECT jsonb_build_object(
    'id', s.id,
    'email', s.email,
    'name', s.name
  )
  INTO v_admin
  FROM sub_main_admin s
  WHERE s.invite_token = p_invite_token
    AND s.invite_expires_at > NOW()
    AND s.invite_accepted_at IS NULL;

  IF v_admin IS NULL THEN
    RETURN jsonb_build_object('error', true, 'message', 'Invalid or expired invite token');
  END IF;

  RETURN jsonb_build_object('error', false, 'admin', v_admin);
END;
$$;


ALTER FUNCTION public.validate_sub_admin_invite_token(p_invite_token text) OWNER TO postgres;

--
-- TOC entry 784 (class 1255 OID 163225)
-- Name: verify_branch_invite(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.verify_branch_invite(p_token text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_invite RECORD;
  v_parent_name TEXT;
  v_address JSONB;
BEGIN
  IF p_token IS NULL OR TRIM(p_token) = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'Invite token is required');
  END IF;

  SELECT * INTO v_invite FROM pharmacy_branch_invites WHERE invite_token = TRIM(p_token);

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404, 'message', 'Invalid invite link');
  END IF;
  IF v_invite.status = 'completed' THEN
    RETURN jsonb_build_object('error', true, 'code', 400, 'message', 'This invite has already been used. Please log in instead.');
  END IF;
  IF v_invite.expires_at < NOW() THEN
    UPDATE pharmacy_branch_invites SET status = 'expired' WHERE id = v_invite.id;
    RETURN jsonb_build_object('error', true, 'code', 410, 'message', 'This invite link has expired. Please contact your pharmacy administrator.');
  END IF;

  SELECT pharmacy_name INTO v_parent_name FROM pharmacy WHERE id = v_invite.parent_pharmacy_id;

  v_address := jsonb_build_object(
    'street', COALESCE(v_invite.street, ''),
    'city',   COALESCE(v_invite.city, ''),
    'state',  COALESCE(v_invite.state, ''),
    'zip',    COALESCE(v_invite.zip, '')
  );

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'inviteId',          v_invite.id,
      'email',             v_invite.email,
      'pharmacyName',      v_invite.pharmacy_name,
      'parentPharmacyName',v_parent_name,
      'contactName',       v_invite.contact_name,
      'phone',             v_invite.phone,
      'fax',               v_invite.fax,
      'deaNumber',         v_invite.dea_number,
      'physicalAddress',   v_address,
      'serviceType',       v_invite.service_type,
      'wholesaler',        v_invite.wholesaler,
      'wholesalerAccount', v_invite.wholesaler_account,
      'isBranch',          true
    )
  );
END;
$$;


ALTER FUNCTION public.verify_branch_invite(p_token text) OWNER TO postgres;

