--
-- TOC entry 941 (class 1255 OID 144393)
-- Name: warehouse_receive_return(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.warehouse_receive_return(p_fedex_tracking text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_row return_transactions;
BEGIN
  IF p_fedex_tracking IS NULL OR TRIM(p_fedex_tracking) = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'FedEx tracking number is required');
  END IF;

  SELECT * INTO v_row
    FROM return_transactions
   WHERE LOWER(TRIM(fedex_tracking)) = LOWER(TRIM(p_fedex_tracking));

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404,
      'message', format('No return found with tracking number "%s"', TRIM(p_fedex_tracking)));
  END IF;

  IF v_row.status NOT IN ('finalized') THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Return has status "%s". Only finalized returns can be received.', v_row.status));
  END IF;

  IF v_row.received_in_warehouse_date IS NOT NULL THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'This return has already been received in the warehouse.');
  END IF;

  UPDATE return_transactions SET
    status                      = 'received',
    received_in_warehouse_date  = NOW()
  WHERE id = v_row.id
  RETURNING * INTO v_row;

  RETURN jsonb_build_object('error', false, 'data', _rt_to_json(v_row));
END;
$$;


ALTER FUNCTION public.warehouse_receive_return(p_fedex_tracking text) OWNER TO postgres;

--
-- TOC entry 627 (class 1255 OID 144398)
-- Name: warehouse_report_discrepancy(uuid, text, uuid, text, text, integer, integer, text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.warehouse_report_discrepancy(p_transaction_id uuid, p_type text, p_item_id uuid DEFAULT NULL::uuid, p_ndc text DEFAULT NULL::text, p_product_name text DEFAULT NULL::text, p_expected_quantity integer DEFAULT NULL::integer, p_actual_quantity integer DEFAULT NULL::integer, p_notes text DEFAULT NULL::text, p_reported_by uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_txn  return_transactions;
  v_disc warehouse_discrepancies;
BEGIN
  SELECT * INTO v_txn FROM return_transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404,
      'message', 'Return transaction not found');
  END IF;

  IF p_type NOT IN ('missing', 'extra', 'damaged', 'wrong_store', 'other') THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Invalid discrepancy type "%s". Must be: missing, extra, damaged, wrong_store, other', p_type));
  END IF;

  INSERT INTO warehouse_discrepancies (
    transaction_id, item_id, type, ndc, product_name,
    expected_quantity, actual_quantity, notes, reported_by
  ) VALUES (
    p_transaction_id, p_item_id, p_type, p_ndc, p_product_name,
    p_expected_quantity, p_actual_quantity, p_notes, p_reported_by
  ) RETURNING * INTO v_disc;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'id',               v_disc.id,
      'transactionId',    v_disc.transaction_id,
      'itemId',           v_disc.item_id,
      'type',             v_disc.type,
      'ndc',              v_disc.ndc,
      'productName',      v_disc.product_name,
      'expectedQuantity', v_disc.expected_quantity,
      'actualQuantity',   v_disc.actual_quantity,
      'notes',            v_disc.notes,
      'status',           v_disc.status,
      'reportedBy',       v_disc.reported_by,
      'createdAt',        v_disc.created_at
    )
  );
END;
$$;


ALTER FUNCTION public.warehouse_report_discrepancy(p_transaction_id uuid, p_type text, p_item_id uuid, p_ndc text, p_product_name text, p_expected_quantity integer, p_actual_quantity integer, p_notes text, p_reported_by uuid) OWNER TO postgres;

--
-- TOC entry 927 (class 1255 OID 165649)
-- Name: warehouse_resolve_discrepancy(uuid, text, text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.warehouse_resolve_discrepancy(p_discrepancy_id uuid, p_resolution text, p_resolution_notes text DEFAULT NULL::text, p_resolved_by uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_disc warehouse_discrepancies;
BEGIN
  SELECT * INTO v_disc FROM warehouse_discrepancies WHERE id = p_discrepancy_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404,
      'message', 'Discrepancy not found');
  END IF;

  IF v_disc.status <> 'open' THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Discrepancy is already %s', v_disc.status));
  END IF;

  IF p_resolution NOT IN ('resolved', 'dismissed') THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'Resolution must be: resolved or dismissed');
  END IF;

  UPDATE warehouse_discrepancies SET
    status           = p_resolution,
    resolution_notes = p_resolution_notes,
    resolved_by      = p_resolved_by,
    resolved_at      = NOW()
  WHERE id = p_discrepancy_id
  RETURNING * INTO v_disc;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'id',              v_disc.id,
      'transactionId',   v_disc.transaction_id,
      'itemId',          v_disc.item_id,
      'type',            v_disc.type,
      'ndc',             v_disc.ndc,
      'productName',     v_disc.product_name,
      'expectedQuantity',v_disc.expected_quantity,
      'actualQuantity',  v_disc.actual_quantity,
      'notes',           v_disc.notes,
      'status',          v_disc.status,
      'resolutionNotes', v_disc.resolution_notes,
      'resolvedBy',      v_disc.resolved_by,
      'resolvedAt',      v_disc.resolved_at,
      'createdAt',       v_disc.created_at
    )
  );
END;
$$;


