--
-- TOC entry 565 (class 1255 OID 150574)
-- Name: warehouse_scan_box(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.warehouse_scan_box(p_tracking_number text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_row            return_transactions;
  v_tracking       TEXT;
  v_total_packages INTEGER;
  v_scanned        JSONB;
  v_scanned_count  INTEGER;
  v_all_scanned    BOOLEAN;
  v_key            TEXT;
  v_val            TEXT;
  v_found_key      TEXT;
BEGIN
  v_tracking := LOWER(TRIM(p_tracking_number));

  IF v_tracking IS NULL OR v_tracking = '' THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'Tracking number is required');
  END IF;

  -- Find the return: match against fedex_tracking OR any value in package_tracking
  SELECT * INTO v_row
    FROM return_transactions
   WHERE (
      LOWER(TRIM(fedex_tracking)) = v_tracking
      OR EXISTS (
        SELECT 1
          FROM jsonb_each_text(COALESCE(package_tracking, '{}'::jsonb)) kv
         WHERE LOWER(TRIM(kv.value)) = v_tracking
      )
   )
   AND status IN ('finalized', 'scanning')
   LIMIT 1;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404,
      'message', format('No finalized return found with tracking number "%s"', TRIM(p_tracking_number)));
  END IF;

  -- Determine total expected packages
  IF v_row.package_tracking IS NOT NULL AND jsonb_typeof(v_row.package_tracking) = 'object' THEN
    SELECT COUNT(*) INTO v_total_packages
      FROM jsonb_each_text(v_row.package_tracking);
  ELSE
    v_total_packages := 1;
  END IF;

  -- Find which package key this tracking number belongs to
  v_found_key := NULL;
  IF v_row.package_tracking IS NOT NULL AND jsonb_typeof(v_row.package_tracking) = 'object' THEN
    FOR v_key, v_val IN SELECT kv.key, kv.value FROM jsonb_each_text(v_row.package_tracking) kv LOOP
      IF LOWER(TRIM(v_val)) = v_tracking THEN
        v_found_key := v_key;
        EXIT;
      END IF;
    END LOOP;
  END IF;

  -- If not found in package_tracking, it's the master tracking
  IF v_found_key IS NULL THEN
    IF LOWER(TRIM(v_row.fedex_tracking)) = v_tracking THEN
      v_found_key := 'master';
    ELSE
      RETURN jsonb_build_object('error', true, 'code', 400,
        'message', 'Tracking number does not match any package in this return');
    END IF;
  END IF;

  -- Build current scanned state
  v_scanned := COALESCE(v_row.scanned_packages, '{}'::jsonb);

  -- Check if already scanned
  IF v_scanned ? v_found_key THEN
    RETURN jsonb_build_object(
      'error', false,
      'alreadyScanned', true,
      'message', format('Package "%s" (tracking %s) was already scanned', v_found_key, TRIM(p_tracking_number)),
      'data', _rt_to_json(v_row),
      'scanProgress', jsonb_build_object(
        'totalPackages', v_total_packages,
        'scannedCount', (SELECT COUNT(*) FROM jsonb_object_keys(v_scanned)),
        'allScanned', (SELECT COUNT(*) FROM jsonb_object_keys(v_scanned)) >= v_total_packages
      )
    );
  END IF;

  -- Record the scan with timestamp
  v_scanned := v_scanned || jsonb_build_object(v_found_key, NOW()::TEXT);

  -- Count scanned
  SELECT COUNT(*) INTO v_scanned_count FROM jsonb_object_keys(v_scanned);

  -- Check if all packages scanned
  v_all_scanned := v_scanned_count >= v_total_packages;

  -- Update the return
  IF v_all_scanned THEN
    UPDATE return_transactions SET
      scanned_packages           = v_scanned,
      status                     = 'received',
      received_in_warehouse_date = NOW()
    WHERE id = v_row.id
    RETURNING * INTO v_row;
  ELSE
    UPDATE return_transactions SET
      scanned_packages = v_scanned,
      status           = 'scanning'
    WHERE id = v_row.id
    RETURNING * INTO v_row;
  END IF;

  RETURN jsonb_build_object(
    'error', false,
    'alreadyScanned', false,
    'message', CASE
      WHEN v_all_scanned THEN 'All packages scanned! Return is now received.'
      ELSE format('Package "%s" scanned (%s of %s)', v_found_key, v_scanned_count, v_total_packages)
    END,
    'data', _rt_to_json(v_row),
    'scanProgress', jsonb_build_object(
      'totalPackages', v_total_packages,
      'scannedCount', v_scanned_count,
      'allScanned', v_all_scanned,
      'scannedKeys', (SELECT jsonb_agg(k) FROM jsonb_object_keys(v_scanned) AS k)
    )
  );
END;
$$;


ALTER FUNCTION public.warehouse_scan_box(p_tracking_number text) OWNER TO postgres;

--
-- TOC entry 857 (class 1255 OID 165645)
-- Name: warehouse_start_verification(uuid, integer, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.warehouse_start_verification(p_transaction_id uuid, p_box_count integer, p_verified_by uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_txn          return_transactions;
  v_expected_box INTEGER;
  v_total_items  INTEGER;
  v_box_match    BOOLEAN;
BEGIN
  SELECT * INTO v_txn FROM return_transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404,
      'message', 'Return transaction not found');
  END IF;

  IF v_txn.status NOT IN ('received') THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Cannot start verification for status "%s". Must be received.', v_txn.status));
  END IF;

  IF p_box_count IS NULL OR p_box_count < 0 THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'Box count must be a non-negative integer');
  END IF;

  v_expected_box := COALESCE(v_txn.box_count, 0);
  v_box_match    := (p_box_count = v_expected_box) OR (v_expected_box = 0);

  SELECT COUNT(*) INTO v_total_items
    FROM return_transaction_items WHERE transaction_id = p_transaction_id;

  -- Record the box count + start verification
  UPDATE return_transactions SET
    pieces_received    = p_box_count,
    verified_by        = COALESCE(p_verified_by, verified_by),
    verified_at        = NOW()
  WHERE id = p_transaction_id
  RETURNING * INTO v_txn;

  -- If box counts don't match, auto-create a discrepancy
  IF NOT v_box_match THEN
    INSERT INTO warehouse_discrepancies (
      transaction_id, type, expected_quantity, actual_quantity,
      notes, reported_by
    ) VALUES (
      p_transaction_id, 'other', v_expected_box, p_box_count,
      format('Box count mismatch: expected %s, received %s', v_expected_box, p_box_count),
      p_verified_by
    );
  END IF;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'transaction',    _rt_to_json(v_txn),
      'expectedBoxes',  v_expected_box,
      'receivedBoxes',  p_box_count,
      'boxCountMatch',  v_box_match,
      'totalItems',     v_total_items
    )
  );
END;
$$;


ALTER FUNCTION public.warehouse_start_verification(p_transaction_id uuid, p_box_count integer, p_verified_by uuid) OWNER TO postgres;

--
-- TOC entry 904 (class 1255 OID 144397)
-- Name: warehouse_verify_item(uuid, uuid, boolean, integer, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.warehouse_verify_item(p_transaction_id uuid, p_item_id uuid, p_verified boolean DEFAULT true, p_actual_quantity integer DEFAULT NULL::integer, p_condition_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_txn  return_transactions;
  v_item return_transaction_items;
BEGIN
  SELECT * INTO v_txn FROM return_transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404,
      'message', 'Return transaction not found');
  END IF;

  IF v_txn.status <> 'received' THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Cannot verify items in a return with status "%s". Must be received.', v_txn.status));
  END IF;

  SELECT * INTO v_item
    FROM return_transaction_items
   WHERE id = p_item_id AND transaction_id = p_transaction_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404,
      'message', 'Item not found in this return');
  END IF;

  UPDATE return_transaction_items SET
    verified        = p_verified,
    actual_quantity = COALESCE(p_actual_quantity, actual_quantity),
    condition_notes = COALESCE(p_condition_notes, condition_notes)
  WHERE id = p_item_id
  RETURNING * INTO v_item;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'id',                  v_item.id,
      'transactionId',       v_item.transaction_id,
      'ndc',                 v_item.ndc,
      'proprietaryName',     v_item.proprietary_name,
      'genericName',         v_item.generic_name,
      'manufacturer',        v_item.manufacturer,
      'lotNumber',           v_item.lot_number,
      'expirationDate',      v_item.expiration_date,
      'quantity',            v_item.quantity,
      'actualQuantity',      v_item.actual_quantity,
      'verified',            v_item.verified,
      'conditionNotes',      v_item.condition_notes,
      'returnStatus',        v_item.return_status,
      'destination',         v_item.destination,
      'estimatedValue',      v_item.estimated_value,
      'estimatedStorePrice', v_item.estimated_store_price,
      'estimatedStoreValue', v_item.estimated_store_value
    )
  );
END;
$$;


ALTER FUNCTION public.warehouse_verify_item(p_transaction_id uuid, p_item_id uuid, p_verified boolean, p_actual_quantity integer, p_condition_notes text) OWNER TO postgres;

--
-- TOC entry 822 (class 1255 OID 165646)
-- Name: warehouse_verify_item_v2(uuid, uuid, text, integer, text, uuid); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.warehouse_verify_item_v2(p_transaction_id uuid, p_item_id uuid, p_verification_status text, p_actual_quantity integer DEFAULT NULL::integer, p_condition_notes text DEFAULT NULL::text, p_reported_by uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_txn   return_transactions;
  v_item  return_transaction_items;
  v_disc  warehouse_discrepancies;
BEGIN
  SELECT * INTO v_txn FROM return_transactions WHERE id = p_transaction_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404,
      'message', 'Return transaction not found');
  END IF;

  IF v_txn.status NOT IN ('received') THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', format('Cannot verify items for status "%s". Must be received.', v_txn.status));
  END IF;

  IF p_verification_status NOT IN ('correct', 'damaged', 'missing', 'wrong_item') THEN
    RETURN jsonb_build_object('error', true, 'code', 400,
      'message', 'verification_status must be: correct, damaged, missing, or wrong_item');
  END IF;

  SELECT * INTO v_item
    FROM return_transaction_items
   WHERE id = p_item_id AND transaction_id = p_transaction_id;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('error', true, 'code', 404,
      'message', 'Item not found in this return');
  END IF;

  -- Update the item.
  -- return_status logic (references to columns are OLD values):
  --   • non-correct  → 'non_returnable' always
  --   • correct AND previously non-correct (re-verify) → 'returnable'
  --   • correct AND first verify / was already correct → keep current
  UPDATE return_transaction_items SET
    verified            = (p_verification_status = 'correct'),
    verification_status = p_verification_status,
    actual_quantity     = COALESCE(p_actual_quantity, actual_quantity),
    condition_notes     = COALESCE(p_condition_notes, condition_notes),
    return_status       = CASE
      WHEN p_verification_status != 'correct'
        THEN 'non_returnable'
      WHEN p_verification_status = 'correct'
        AND verification_status IS NOT NULL
        AND verification_status != 'correct'
        THEN 'returnable'
      ELSE return_status
    END
  WHERE id = p_item_id
  RETURNING * INTO v_item;

  -- Auto-create discrepancy for non-correct items
  IF p_verification_status IN ('damaged', 'missing', 'wrong_item') THEN
    INSERT INTO warehouse_discrepancies (
      transaction_id, item_id, type, ndc, product_name,
      expected_quantity, actual_quantity, notes, reported_by
    ) VALUES (
      p_transaction_id,
      p_item_id,
      CASE p_verification_status
        WHEN 'damaged'    THEN 'damaged'
        WHEN 'missing'    THEN 'missing'
        WHEN 'wrong_item' THEN 'other'
      END,
      v_item.ndc,
      COALESCE(v_item.proprietary_name, v_item.generic_name),
      v_item.quantity,
      p_actual_quantity,
      COALESCE(p_condition_notes, format('Item marked as %s during verification', p_verification_status)),
      p_reported_by
    ) RETURNING * INTO v_disc;
  END IF;

  -- Recalculate stored totals on the return transaction so that
  -- list endpoints, batch value calculations, etc. are always current.
  UPDATE return_transactions SET
    total_returnable_value = (
      SELECT COALESCE(SUM(estimated_value), 0)
        FROM return_transaction_items
       WHERE transaction_id = p_transaction_id
         AND return_status = 'returnable'
    ),
    total_non_returnable_value = (
      SELECT COALESCE(SUM(estimated_value), 0)
        FROM return_transaction_items
       WHERE transaction_id = p_transaction_id
         AND return_status = 'non_returnable'
    )
  WHERE id = p_transaction_id;

  RETURN jsonb_build_object(
    'error', false,
    'data', jsonb_build_object(
      'id',                 v_item.id,
      'transactionId',      v_item.transaction_id,
      'ndc',                v_item.ndc,
      'proprietaryName',    v_item.proprietary_name,
      'genericName',        v_item.generic_name,
      'manufacturer',       v_item.manufacturer,
      'lotNumber',          v_item.lot_number,
      'expirationDate',     v_item.expiration_date,
      'quantity',           v_item.quantity,
      'actualQuantity',     v_item.actual_quantity,
      'verified',           v_item.verified,
      'verificationStatus', v_item.verification_status,
      'conditionNotes',     v_item.condition_notes,
      'returnStatus',       v_item.return_status,
      'destination',        v_item.destination,
      'estimatedValue',     v_item.estimated_value,
      'discrepancyId',      CASE WHEN v_disc.id IS NOT NULL THEN v_disc.id ELSE NULL END
    )
  );
END;
$$;


ALTER FUNCTION public.warehouse_verify_item_v2(p_transaction_id uuid, p_item_id uuid, p_verification_status text, p_actual_quantity integer, p_condition_notes text, p_reported_by uuid) OWNER TO postgres;

