-- TOC entry 5834 (class 0 OID 0)
-- Dependencies: 822
-- Name: FUNCTION warehouse_verify_item_v2(p_transaction_id uuid, p_item_id uuid, p_verification_status text, p_actual_quantity integer, p_condition_notes text, p_reported_by uuid); Type: COMMENT; Schema: public; Owner: postgres
--

