--
-- TOC entry 445 (class 1259 OID 149324)
-- Name: email_logs_with_memo_info; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.email_logs_with_memo_info AS
 SELECT el.id,
    el.ra_request_id,
    el.smtp_message_id,
    el.email_type,
    el.recipient_email,
    el.subject,
    el.status,
    el.sent_at,
    el.delivered_at,
    el.bounced_at,
    el.error_message,
    el.smtp_response,
    el.created_at,
    el.updated_at,
    r.debit_memo_id,
    dm.memo_number,
    p.pharmacy_name,
    dm.destination,
    dm.labeler_name,
    dm.total_ask_value
   FROM (((public.email_logs el
     JOIN public.ra_requests r ON ((el.ra_request_id = r.id)))
     LEFT JOIN public.debit_memos dm ON ((r.debit_memo_id = dm.id)))
     LEFT JOIN public.pharmacy p ON ((dm.pharmacy_id = p.id)))
  ORDER BY el.sent_at DESC;


