 SELECT pie.id,
    pie.email_uid,
    pie.email_message_id,
    pie.from_address,
    pie.to_address,
    pie.subject,
    pie.received_at,
    pie.processed_at,
    pie.memo_number,
    pie.debit_memo_id,
    pie.extracted_ra_number,
    pie.ai_confidence,
    pie.ai_raw_response,
    pie.status,
    pie.error_message,
    pie.created_at,
    dm.memo_number AS dm_memo_number,
